Sep "Suite 86 -- Maskable shortcut icons + OPTICS label wrap"
$manifestSrc86 = Read-Src "manifest.json"
$manifest86    = $manifestSrc86 | ConvertFrom-Json
$shorts86      = if ($manifest86.shortcuts -is [array]) { $manifest86.shortcuts } else { @() }
