# 87.4  all skill values in FNV getSkillKeys() OR 'Critical Chance'
$fnvSkillKeys87 = @('barter','energy_weapons','explosives','guns','lockpick','medicine','melee_weapons','repair','science','sneak','speech','survival','unarmed')
