# 125.8  game-agnostic (Protocol 38) -- no game literals in either half of the split readout
Check (-not (($sessFn125 + $logPanel125 + $statusPanel125) -match 'New Vegas|Mojave|\bFNV\b|\bFO3\b|Capital Wasteland|Vault 101')) `
