Check (($render126 -match 'function markLocationVisited\(loc\)') -and ($markFn126 -match 'recordLocationVisit\(loc\)') -and ($markFn126 -match 'saveState\(\)') -and ($markFn126 -match '_rerenderMapPreservingScroll\(\)')) `
