# (Phase 3 · Piece 2: the drawer bank has no "all" drawer, so the fail-safe
# reset lands on "weapon" instead.)
$ctxPanelsFn136 = [regex]::Match($render136, '(?s)function _updateContextPanels\(\)[\s\S]*?\n\}').Value
Check (
    ($html136 -match 'id="invFilterMods"') -and
    ($render136 -match "_activeDef\(\)\.hasWeaponMods") -and
    ($render136 -match "getElementById\('invFilterMods'\)") -and
    ($ctxPanelsFn136 -match "setInvFilter\('weapon'\)")
) '136.7: the inventory Mods filter button is hidden per-game via _updateContextPanels() + GAME_DEFS.hasWeaponMods, with a fail-safe reset off the mod filter'

# 136.8  U10: adjustAffinity(idx, delta) -- clamps 0-100, persists + re-renders
$adjFn136 = [regex]::Match($render136, '(?s)function adjustAffinity\(idx, delta\)[\s\S]*?\n\}').Value
Check (
    ($adjFn136 -match 'Math\.max\(0, Math\.min\(100,') -and
    ($adjFn136 -match 'state\.squad\[idx\]\.affinity') -and
    ($adjFn136 -match 'saveState\(\)') -and
    ($adjFn136 -match 'renderSquad\(\)')
) '136.8: adjustAffinity(idx, delta) exists, clamps 0-100, and persists + re-renders'

# 136.9  U10: native [+]/[-] affinity buttons always rendered on every squad row
# (Phase 3 · Piece 2 SQUAD ROSTER restyled the aria-label wording to
# "Raise/Lower ... affinity", matching the approved mockup.)
$squadFn136 = [regex]::Match($render136, '(?s)function renderSquad\(\)[\s\S]*?\n\}').Value
Check (
    ($squadFn136 -match 'adjustAffinity\(\$\{i\},5\)') -and
    ($squadFn136 -match 'adjustAffinity\(\$\{i\},-5\)') -and
    ($squadFn136 -match 'aria-label="Raise \$\{escapeHtml\(member\.name\)\} affinity"') -and
    ($squadFn136 -match 'aria-label="Lower \$\{escapeHtml\(member\.name\)\} affinity"') -and
    (-not ($squadFn136 -match 'member\.affinity !== undefined'))
) '136.9: renderSquad() always renders the [+]/[-] affinity buttons (real <button>s with aria-labels), not gated behind member.affinity being pre-set'

# 136.10  U10: newly-added squad members seed affinity: 0
$addSquadFn136 = [regex]::Match($render136, '(?s)function addSquadMember\(\)[\s\S]*?\n\}').Value
Check ($addSquadFn136 -match 'affinity:\s*0,') '136.10: addSquadMember() seeds affinity: 0 for newly-added companions'

# 136.11  Escape-ratchet: [TIMELINE] registered in Suite 113's RETIRED-macro list
Check ($RETIRED113 -contains '[TIMELINE]') '136.11: [TIMELINE] is registered in the Suite 113 RETIRED-macro list (self-referential escape-ratchet guard)'

# 136.12  Game-agnostic (Protocol 38): weapon-mods gate is data-driven, not a ctx literal
Check (
    (-not ($render136 -match "ctx === 'FO3' \?.*hasWeaponMods")) -and
    (-not ($render136 -match "ctx === 'FNV' \?.*hasWeaponMods"))
) '136.12: the weapon-mods gate is data-driven via GAME_DEFS, not a hardcoded ctx literal ternary'

# 136.13  UTF-8 integrity (Protocol 39) spot-check
Check (
    ($render136.Contains([char]0x26A0 + ' INSUFFICIENT RESERVES')) -and
    (-not ($render136 -match 'â€|â–|�'))
) '136.13: the THREAT ammo-advisory glyph is clean UTF-8 (no double-encoding, no replacement chars)'

# ===========================================================
# Suite 137 -- Step 2 (v2.8.0) Phase 0 U11/U12: hygiene ledgers + modal
# consolidation (14 tests). Mirrors JS Suite 137. The JS runner's 137.6 is a
# TRUE behavioral proof (executes confirmAction() in a Node vm sandbox against
# a synthetic DOM and asserts the resolved boolean); this PS1 mirror does the
# structural analogue everywhere else in this file already does for
# JS-vm-only behavioral suites -- it checks confirmAction()'s body shape
# (Promise + resolve(true) on CONFIRM + the shared onClose->resolve(false)
# path) rather than re-executing it.
# ===========================================================
Sep "Suite 137 -- Step 2 Phase 0 U11/U12 hygiene ledgers + modal consolidation"
$arch137     = Read-Src "ARCHITECTURE.md"
$dbNv137     = Read-Src "js/db_nv.js"
$dbFo3137    = Read-Src "js/db_fo3.js"
$core137     = Read-Src "js/ui-core.js"
$render137   = Read-Src "js/ui-render.js"
$saves137    = Read-Src "js/ui-saves.js"
$cloud137    = Read-Src "js/cloud.js"
$api137      = Read-Src "js/api.js"
$state137    = Read-Src "js/state.js"

# 137.1  U11: per-game data parity ledger, every row GENUINE or GAP
Check (
    ($arch137 -match 'Parity ledger') -and
    ($arch137 -match 'per-game data asymmetry') -and
    ($arch137 -match '\*\*GENUINE\*\*') -and
    ($arch137 -match '\*\*GAP\*\*')
) '137.1: ARCHITECTURE.md carries the U11 per-game data parity ledger with GENUINE/GAP verdicts'

# 137.2  U11: reserved-column register (ARCHITECTURE.md + both db headers)
Check (
    ($arch137 -match 'Reserved-column register') -and
    ($dbNv137 -match 'RESERVED-COLUMN REGISTER') -and
    ($dbFo3137 -match 'RESERVED-COLUMN REGISTER') -and
    ($dbNv137 -match 'PARKED-FOR-REMOVAL') -and
    ($dbFo3137 -match 'PARKED-FOR-REMOVAL')
) '137.2: reserved-column register is committed in ARCHITECTURE.md AND both db_nv.js/db_fo3.js headers'

# 137.3  U11: skill-less (FO4) degradation audit + the skillKeys:[] requirement
Check (
    ($arch137 -match 'Skill-less \(FO4-class\) degradation audit') -and
    ($arch137 -match 'skillKeys:\s*\[\]')
) '137.3: ARCHITECTURE.md carries the U11 skill-less audit + the skillKeys:[] requirement for a future FO4 entry'

# 137.4  U12: openModal() and confirmAction() both defined in ui-core.js
Check (
    ($core137 -match 'function openModal\s*\(') -and ($core137 -match 'function confirmAction\s*\(')
) '137.4: openModal() and confirmAction() are both defined in ui-core.js'

# 137.5  U12: confirmAction() is Promise-based; CONFIRM resolves true, every
#        other exit resolves false via the shared onClose path
$confirmActionBody137 = Get-FunctionBody $core137 'confirmAction'
Check (
    ($confirmActionBody137 -match 'new Promise\(') -and
    ($confirmActionBody137 -match 'onClose:\s*\(\)\s*=>\s*settle\(false\)') -and
    ($confirmActionBody137 -match 'settle\(true\)')
) '137.5: confirmAction() is Promise-based; CONFIRM resolves true, every other exit (CANCEL/CLOSE/Escape) resolves false via the shared onClose path'

# 137.6  BEHAVIORAL (structural mirror -- see file header note above; the JS
#        runner actually executes confirmAction() in a vm sandbox and drives
#        real CONFIRM/CANCEL/close clicks). Mirrors the same shape 137.5
#        checks plus the settle() single-resolution guard (idempotent --
#        a second settle() call after Yes cannot flip the result to false).
Check (
    ($confirmActionBody137 -match 'if\s*\(\s*resolved\s*\)\s*return') -and
    ($confirmActionBody137 -match 'resolved\s*=\s*true') -and
    ($confirmActionBody137 -match "getElementById\('modalConfirmYes'\)") -and
    ($confirmActionBody137 -match "getElementById\('modalConfirmNo'\)")
) 'confirmAction() behavioral (structural mirror): settle() is single-resolution-guarded; both CONFIRM and CANCEL buttons are wired (see JS runner for the real behavioral proof)'

# 137.7  U12: openModal() is the single entry point -- exactly two occurrences
#        of "_openSysModal(" exist: the declaration and the one call inside openModal()
$occCount137 = ([regex]::Matches($core137, '_openSysModal\s*\(')).Count
$declOrCallOnly137 = ($core137 -match 'function\s+_openSysModal\s*\(') -and `
    ($core137 -match 'openModal\s*\([\s\S]{0,400}_openSysModal\s*\(\s*\)')
Check (($occCount137 -eq 2) -and $declOrCallOnly137) `
    '137.7: no function outside openModal() calls the low-level _openSysModal() primitive directly (single consolidated driver)'

# 137.8  U12: exactly one Tab-key focus-trap targets #sysModal in ui-core.js
$trapMatches137 = [regex]::Matches($core137, "getElementById\(\s*'sysModal'\s*\)[\s\S]{0,200}querySelectorAll\(")
Check ($trapMatches137.Count -eq 1) `
    '137.8: exactly one focus-trap implementation targets #sysModal in ui-core.js (single driver, D-2)'

# 137.9  U12: no raw alert( or confirm( call remains in any served js/*.js file
#        (comments stripped first so explanatory doc comments don't false-positive)
function Strip-Comments137($src) {
    $noBlock = [regex]::Replace($src, '(?s)/\*.*?\*/', '')
    return [regex]::Replace($noBlock, '//[^\r\n]*', '')
}
$servedFiles137 = @(
    @{ Name = 'js/api.js'; Src = $api137 },
    @{ Name = 'js/state.js'; Src = $state137 },
    @{ Name = 'js/ui-core.js'; Src = $core137 },
    @{ Name = 'js/ui-render.js'; Src = $render137 },
    @{ Name = 'js/ui-saves.js'; Src = $saves137 },
    @{ Name = 'js/cloud.js'; Src = $cloud137 }
)
$offenders137 = @()
foreach ($f in $servedFiles137) {
    $clean = Strip-Comments137 $f.Src
    if ($clean -match '\balert\s*\(') { $offenders137 += ($f.Name + ' (alert)') }
    if ($clean -match '\bconfirm\s*\(') { $offenders137 += ($f.Name + ' (confirm)') }
}
Check ($offenders137.Count -eq 0) `
    ('no raw alert(/confirm( call remains in served js/*.js (Step 2 Phase 0 U12 purge)' + $(if ($offenders137.Count) { ' -- found: ' + ($offenders137 -join ', ') } else { '' }))

# 137.10  U12: every destructive/confirm-gated path awaits confirmAction()
function Get-WindowFnBody137($src, $name) {
    $assignIdx = $src.IndexOf("window.$name =")
    if ($assignIdx -lt 0) { return '' }
    $braceIdx = $src.IndexOf('{', $assignIdx)
    if ($braceIdx -lt 0) { return '' }
    $depth = 0; $i = $braceIdx
    while ($i -lt $src.Length) {
        if ($src[$i] -eq '{') { $depth++ }
        elseif ($src[$i] -eq '}') { $depth--; if ($depth -eq 0) { return $src.Substring($braceIdx, $i - $braceIdx + 1) } }
        $i++
    }
    return ''
}
$gatedSites137 = @(
    @{ File = 'ui-core.js'; Src = $core137; Fn = 'wipeTerminal'; Window = $false },
    @{ File = 'ui-core.js'; Src = $core137; Fn = 'clearChat'; Window = $false },
    @{ File = 'ui-render.js'; Src = $render137; Fn = 'doCraft'; Window = $false },
    @{ File = 'ui-render.js'; Src = $render137; Fn = 'doScrap'; Window = $false },
    @{ File = 'ui-render.js'; Src = $render137; Fn = 'doBuy'; Window = $false },
    @{ File = 'ui-render.js'; Src = $render137; Fn = 'doSell'; Window = $false },
    @{ File = 'ui-render.js'; Src = $render137; Fn = 'doLoot'; Window = $false },
    # P5 (Step 2 Phase 1): loadFromSlot's confirm gates moved into the shared
    # _applySlotEnvelope core (Protocol 22); restoreSlotVersion is a new gated path.
    @{ File = 'ui-saves.js'; Src = $saves137; Fn = '_applySlotEnvelope'; Window = $false },
    @{ File = 'ui-saves.js'; Src = $saves137; Fn = 'restoreSlotVersion'; Window = $false },
    # P6: importBundle is a new destructive whole-history restore path.
    @{ File = 'ui-saves.js'; Src = $saves137; Fn = 'importBundle'; Window = $false },
    @{ File = 'ui-saves.js'; Src = $saves137; Fn = 'restoreRollingBackup'; Window = $false },
    @{ File = 'ui-saves.js'; Src = $saves137; Fn = 'handleFileUpload'; Window = $false },
    @{ File = 'cloud.js'; Src = $cloud137; Fn = 'loadCloudSave'; Window = $true },
    @{ File = 'cloud.js'; Src = $cloud137; Fn = 'deleteCloudSave'; Window = $true }
)
$missing137 = @()
foreach ($g in $gatedSites137) {
    $body = if ($g.Window) { Get-WindowFnBody137 $g.Src $g.Fn } else { Get-FunctionBody $g.Src $g.Fn }
    if (-not ($body -match 'confirmAction\s*\(')) { $missing137 += ($g.File + ':' + $g.Fn) }
}
Check ($missing137.Count -eq 0) `
    ('every destructive path awaits confirmAction() (Protocol 34 gate preserved)' + $(if ($missing137.Count) { ' -- missing in: ' + ($missing137 -join ', ') } else { '' }))

# 137.11  U12: doCraft/doScrap split into confirm-gate wrapper + synchronous
#         _craftApply/_scrapApply mutation core
Check (
    ($render137 -match 'function _craftPrepare\s*\(') -and
    ($render137 -match 'function _craftApply\s*\(') -and
    ($render137 -match 'function _scrapPrepare\s*\(') -and
    ($render137 -match 'function _scrapApply\s*\(') -and
    ((Get-FunctionBody $render137 'doCraft') -match '_craftApply\(') -and
    ((Get-FunctionBody $render137 'doScrap') -match '_scrapApply\(')
) '137.11: doCraft/doScrap split into confirm-gate wrapper + synchronous _craftApply/_scrapApply mutation core'

# 137.12  U12: restoreRollingBackup split into confirm-gate wrapper +
#         _restoreBackupApply mutation core
Check (
    ($saves137 -match 'function _restoreBackupApply\s*\(') -and
    ((Get-FunctionBody $saves137 'restoreRollingBackup') -match '_restoreBackupApply\(')
) '137.12: restoreRollingBackup split into confirm-gate wrapper + _restoreBackupApply mutation core'

# 137.13  U12: the firmware-update dialog (_triggerUpdate) stays separate --
#         not folded into openModal()/confirmAction() (Suite 65 exception)
$html137 = Read-Src "index.html"
$triggerBody137 = Get-FunctionBody $html137 '_triggerUpdate'
Check (
    (-not ($triggerBody137 -match 'openModal\s*\(')) -and (-not ($triggerBody137 -match 'confirmAction\s*\('))
) '137.13: index.html _triggerUpdate (the blocking firmware-update dialog) is NOT folded into openModal()/confirmAction() -- stays a deliberate separate exception (Suite 65)'

# 137.14  U12: window.prompt() sites remain -- explicitly out of scope
Check (
    ($cloud137 -match '\bprompt\s*\(') -and ($saves137 -match '\bprompt\s*\(')
) '137.14: window.prompt() sites (cloud.js label input, ui-saves.js backup picker) remain -- explicitly out of U12 scope, not silently dropped'

# ===========================================================
# Suite 138 -- Step 2 (v2.8.0) Phase 1 P1: IndexedDB durability shadow +
# write-through (12 tests). Mirrors JS Suite 138. New js/idb.js is an async
# Promise-returning KV engine over IndexedDB with two object stores
# ('meta'/'campaign') so the Protocol 23 two-store boundary is structural in
# IndexedDB too. It is written through the single MetaStore choke point as a
# fire-and-forget mirror of every device-pref write; READS STAY 100% ON
# localStorage (no read flip in P1). These are structural guards -- the REAL
# IndexedDB behavioral proof (round-trip + fail-safe) runs in tests/test.html
# (Protocol 40 -- the browser is the only runner with a native IndexedDB).
# ===========================================================
Sep "Suite 138 -- P1 IndexedDB durability shadow + write-through"
$idb138   = Read-Src "js/idb.js"
$state138 = Read-Src "js/state.js"
$sw138    = Read-Src "sw.js"
$html138  = Read-Src "index.html"

# 138.1  js/idb.js is an IIFE that publishes window.IdbStore
Check (
    ($idb138 -match '\(function \(\)\s*\{') -and ($idb138 -match 'window\.IdbStore = IdbStore')
) '138.1: js/idb.js is an IIFE that publishes window.IdbStore'

# 138.2  the new served module is precached in sw.js ASSETS (Suite 49 sibling)
Check ($sw138 -match '\./js/idb\.js') '138.2: js/idb.js is precached in sw.js ASSETS'

# 138.3  idb.js loads before state.js (which calls it) and before the boot loader
$iIdb138    = $html138.IndexOf('js/idb.js')
$iState138  = $html138.IndexOf('js/state.js')
$iLoader138 = $html138.IndexOf('GAME_FILES')
Check (
    ($iIdb138 -gt -1) -and ($iState138 -gt -1) -and ($iLoader138 -gt -1) -and
    ($iIdb138 -lt $iState138) -and ($iIdb138 -lt $iLoader138)
) '138.3: index.html loads js/idb.js before state.js and before the GAME_FILES boot loader'

# 138.4  the IdbStore API surface is complete
Check (
    ($idb138 -match 'set\(store, key, value\)') -and
    ($idb138 -match 'get\(store, key\)') -and
    ($idb138 -match 'remove\(store, key\)') -and
    ($idb138 -match 'keys\(store\)') -and
    ($idb138 -match 'getAll\(store\)') -and
    ($idb138 -match 'get available\(\)')
) '138.4: IdbStore exposes set/get/remove/keys/getAll + the available flag'

# 138.5  two object stores ('meta' + 'campaign') -- two-store boundary in IDB
Check (
    ($idb138 -match "const STORES = \[\s*'meta',\s*'campaign'\s*\]") -and
    ($idb138 -match 'createObjectStore\(name\)')
) "138.5: idb.js creates both 'meta' and 'campaign' object stores (two-store boundary in IDB)"

# 138.6  WRITE-THROUGH: MetaStore.set/remove mirror via the single _idbShadow seam
Check (
    ($state138 -match 'function _idbShadow\(') -and
    ($state138 -match "_idbShadow\('set', key, val\)") -and
    ($state138 -match "_idbShadow\('remove', key\)")
) '138.6: MetaStore.set/remove route the write-through through the single _idbShadow('

# 138.7  NO READ FLIP: MetaStore.get reads localStorage only
$getBody138 = ''
if ($state138 -match 'get\(key\)\s*\{([\s\S]*?)\}\s*catch') { $getBody138 = $matches[1] }
Check (
    ($getBody138 -match 'localStorage\.getItem\(key\)') -and (-not ($getBody138 -match 'IdbStore|_idbShadow'))
) '138.7: MetaStore.get reads localStorage only -- no IdbStore read flip (read authority unchanged)'

# 138.8  checksums REUSE window.computeSaveChecksum -- no second hash (Protocol 22)
Check (
    ($idb138 -match 'window\.computeSaveChecksum\(') -and (-not ($idb138 -match '0x811c9dc5'))
) '138.8: idb.js reuses window.computeSaveChecksum (no duplicate hash implementation)'

# 138.9  FAIL-SAFE: feature-detect factory + resolve(null) instead of throwing
Check (
    ($idb138 -match 'function _idbFactory\(') -and ($idb138 -match 'resolve\(null\)')
) '138.9: idb.js feature-detects IndexedDB and degrades to a null (no-op) handle when absent'

# 138.10  RESOLVE-SOFT: ops resolve to a fallback; write-through swallows rejection
Check (
    ($idb138 -match 'resolve\(fallback\)') -and ($state138 -match '\.catch\(\(\)\s*=>\s*\{\}\)')
) '138.10: idb.js ops resolve-soft on error and _idbShadow swallows a rejected shadow promise'

# 138.11  BOUNDARY: no campaign-key literal in idb.js; the device write-through
#         (_idbShadow body) targets only 'meta'. Scoped to _idbShadow because P3
#         added legitimate 'campaign'-store writes elsewhere in state.js.
$idbShadowBody138 = Get-FunctionBody $state138 '_idbShadow'
Check (
    (-not ($idb138 -match 'robco_v8|robco_slot|robco_backup|robco_chat|robco_playstyle|robco_v7|robco_last_cloud_push')) -and
    ($idbShadowBody138 -match "window\.IdbStore\.set\('meta'") -and
    ($idbShadowBody138 -match "window\.IdbStore\.remove\('meta'") -and
    (-not ($idbShadowBody138 -match "'campaign'"))
) "138.11: no campaign-key literal in idb.js; the device write-through (_idbShadow) targets only the 'meta' store"

# 138.12  game-agnostic (Protocol 38): a pure KV engine -- zero game literals
Check (
    -not ($idb138 -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '138.12: idb.js is game-agnostic (no FNV/FO3/Fallout literals -- a pure key/value engine)'

# ===========================================================
# Suite 139 -- Step 2 (v2.8.0) Phase 1 P2: device-pref boot hydration +
# reconciliation (12 tests). Mirrors JS Suite 139. window.onload becomes async
# and awaits _hydrateMetaFromIdb() BEFORE the rest of boot reads device prefs.
# AUTHORITY RULE: localStorage is the source of record -- it wins when present;
# the one exception is RECOVERY (restore a key IDB has but localStorage is
# MISSING, only if its checksum re-verifies). BACKFILL mirrors localStorage-only
# device keys into IDB. The await is BOUNDED (Promise.race vs a budget) so a
# hung IndexedDB never hangs boot. Only the 'meta' store is touched. Structural
# guards here; the REAL IndexedDB behavioral proof runs in tests/test.html
# (Protocol 40 -- the browser is the only runner with a native IndexedDB).
# ===========================================================
Sep "Suite 139 -- P2 device-pref boot hydration + reconciliation"
$uiCore139   = Read-Src "js/ui-core.js"
$idb139      = Read-Src "js/idb.js"
$reconcile139 = Get-FunctionBody $uiCore139 '_reconcileMetaFromIdb'
$hydrate139   = Get-FunctionBody $uiCore139 '_hydrateMetaFromIdb'

# window.onload body (brace-matched from the async declaration)
$onload139 = ''
$olStart139 = $uiCore139.IndexOf('window.onload = async function () {')
if ($olStart139 -ge 0) {
    $bStart139 = $uiCore139.IndexOf('{', $olStart139)
    $depth139 = 0
    $i139 = $bStart139
    while ($i139 -lt $uiCore139.Length) {
        $ch139 = $uiCore139[$i139]
        if ($ch139 -eq '{') { $depth139++ }
        elseif ($ch139 -eq '}') { $depth139--; if ($depth139 -eq 0) { break } }
        $i139++
    }
    $onload139 = $uiCore139.Substring($bStart139, $i139 - $bStart139 + 1)
}

# 139.1  both the awaited boot phase and its reconciliation core are defined
Check (
    ($uiCore139 -match 'async function _reconcileMetaFromIdb\s*\(') -and
    ($uiCore139 -match 'function _hydrateMetaFromIdb\s*\(')
) '139.1: ui-core.js defines _reconcileMetaFromIdb() (core) and _hydrateMetaFromIdb() (awaited boot phase)'

# 139.2  window.onload is async and awaits the hydration (async-before-sync boot)
Check (
    ($uiCore139 -match 'window\.onload = async function \(\) \{') -and
    ($onload139 -match 'await _hydrateMetaFromIdb\(\)')
) '139.2: window.onload is async and awaits _hydrateMetaFromIdb() (async-before-sync boot)'

# 139.3  the awaited hydration runs BEFORE every device-pref consumer in boot
$iHydrate139 = $onload139.IndexOf('await _hydrateMetaFromIdb()')
Check (
    ($iHydrate139 -ge 0) -and
    ($onload139.IndexOf('_restoreApiKeyAndChatHistory()') -gt $iHydrate139) -and
    ($onload139.IndexOf('_restoreOpticsPreference()') -gt $iHydrate139) -and
    ($onload139.IndexOf('_restoreDevicePrefs()') -gt $iHydrate139)
) '139.3: the awaited hydration runs before every device-pref consumer (API key / optics / device prefs)'

# 139.4  BOUNDED await -- Promise.race against a timeout budget guards a hung IDB
Check (
    ($uiCore139 -match '_META_HYDRATE_BUDGET_MS') -and
    ($hydrate139 -match 'Promise\.race\(') -and
    ($hydrate139 -match 'setTimeout\(resolve, _META_HYDRATE_BUDGET_MS\)')
) '139.4: _hydrateMetaFromIdb() bounds the await (Promise.race vs _META_HYDRATE_BUDGET_MS) -- a hung IDB never hangs boot'

# 139.5  AUTHORITY / RECOVERY: localStorage-present wins; recovery only when missing
Check (
    ($reconcile139 -match 'if \(lsV !== null\) continue;') -and
    ($reconcile139 -match 'MetaStore\.set\(key, rec\.value\)')
) '139.5: recovery restores localStorage from IDB only when localStorage is missing (localStorage-present wins)'

# 139.6  CORRUPT-DATA FAIL-SAFE: verify checksum before restoring (mismatch -> skip)
Check (
    ($reconcile139 -match "computeSaveChecksum\(rec\.value, \[\], ''\) !== rec\.checksum") -and
    ($reconcile139 -match "getRaw\('meta', key\)")
) '139.6: reconciliation verifies the IDB record checksum (via getRaw) before restoring -- corrupt records are skipped'

# 139.7  IdbStore.getRaw exists and returns the checksum-bearing envelope
Check (
    ($idb139 -match 'getRaw\(store, key\)') -and ($idb139 -match "'value' in rec \? rec : null")
) '139.7: IdbStore.getRaw() returns the full { value, checksum, ... } envelope (enables the checksum verify)'

# 139.8  BACKFILL restricted to registered device keys + IDB-only (never localStorage)
Check (
    ($reconcile139 -match '!MetaStore\.has\(key\)\) continue;') -and
    ($reconcile139 -match "IdbStore\.set\('meta', key, v\)")
) '139.8: backfill is gated on MetaStore.has (registered device keys only) and writes IDB only, never localStorage'

# 139.9  TWO-STORE BOUNDARY: only 'meta', never 'campaign', no campaign-key literal
Check (
    (-not ($reconcile139 -match "'campaign'")) -and
    (-not ($reconcile139 -match 'robco_v8|robco_slot|robco_backup|robco_chat|robco_playstyle|robco_v7')) -and
    ($reconcile139 -match "keys\('meta'\)")
) "139.9: reconciliation touches only the 'meta' store -- no 'campaign' store, no campaign-key literal (two-store boundary)"

# 139.10  FAIL-SAFE: resolves immediately when IdbStore absent; never rejects
Check (
    ($hydrate139 -match '!window\.IdbStore\) return Promise\.resolve\(\)') -and
    ($hydrate139 -match '\.catch\(\(\) => \{\}\)')
) '139.10: _hydrateMetaFromIdb() resolves immediately when IdbStore is absent and never rejects (fail-safe boot)'

# 139.11  Phase-0 boot invariants preserved: no phase dropped; boot sequence intact
$bootSeq139 = Get-FunctionBody $uiCore139 '_runBootSequenceAndBriefing'
$stillCalled139 = @('_hydrateStateFromStorage()', '_restoreApiKeyAndChatHistory()', '_runBootSequenceAndBriefing()', '_wireUnloadFlush()', 'routeLaunchShortcut()')
$allCalled139 = (@($stillCalled139 | Where-Object { -not $onload139.Contains($_) }).Count -eq 0)
Check (
    $allCalled139 -and ($bootSeq139 -match 'runBootSequence\(')
) '139.11: no boot phase dropped by the async wrapper; _runBootSequenceAndBriefing still invokes runBootSequence (WU-B10 boot window intact)'

# 139.12  game-agnostic (Protocol 38): the reconcile/hydrate path has no game literals
Check (
    -not (($reconcile139 + $hydrate139) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '139.12: the P2 reconciliation/hydration path is game-agnostic (no game literals)'

# ===========================================================
# Suite 140 -- Step 2 (v2.8.0) Phase 1 P3: cold-store (save slots + rolling
# backups) moved IDB-PRIMARY (12 tests). Mirrors JS Suite 140. Cold-store lives
# in the IDB 'campaign' object store (slot_<n> / backup_<n>) with localStorage as
# a synchronous mirror + fallback. Writes go IDB-primary + best-effort
# localStorage (a quota failure is non-fatal -- IDB is the durable home, the
# ceiling relief); reads take the NEWER of {IDB, localStorage} by _coldStamp.
# Migration is fire-and-forget, idempotent, additive-only (never removes a
# localStorage copy). Two-store boundary: cold store uses 'campaign' only. The
# REAL IndexedDB migration/round-trip/fallback proof runs in tests/test.html.
# ===========================================================
Sep "Suite 140 -- P3 cold-store IDB-primary (save slots + rolling backups)"
$state140    = Read-Src "js/state.js"
$uiSaves140  = Read-Src "js/ui-saves.js"
$uiAcct140   = Read-Src "js/ui-account.js"
$cloud140    = Read-Src "js/cloud.js"
$uiCore140   = Read-Src "js/ui-core.js"
$coldRead140    = Get-FunctionBody $state140 '_coldReadObj'
$coldWrite140   = Get-FunctionBody $state140 '_coldWriteObj'
$migrate140     = Get-FunctionBody $state140 '_migrateColdStoreToIdb'
$saveBody140    = Get-FunctionBody $uiSaves140 'saveToSlot'
$loadBody140    = Get-FunctionBody $uiSaves140 'loadFromSlot'
$restoreBody140 = Get-FunctionBody $uiSaves140 'restoreRollingBackup'

# 140.1  cold-store accessors + migration defined + exposed on window
Check (
    ($state140 -match 'function _coldReadObj\s*\(') -and
    ($state140 -match 'function _coldWriteObj\s*\(') -and
    ($state140 -match 'function _coldStamp\s*\(') -and
    ($state140 -match 'function _migrateColdStoreToIdb\s*\(') -and
    ($state140 -match 'window\._coldReadObj =') -and
    ($state140 -match 'window\._coldWriteObj =') -and
    ($state140 -match 'window\._migrateColdStoreToIdb =')
) '140.1: state.js defines + exposes _coldReadObj / _coldWriteObj / _coldStamp / _migrateColdStoreToIdb'

# 140.2  TWO-STORE BOUNDARY: cold-store accessors use 'campaign' only, never 'meta'
Check (
    ($coldRead140 -match "'campaign'") -and ($coldWrite140 -match "'campaign'") -and ($migrate140 -match "'campaign'") -and
    (-not ($coldRead140 -match "'meta'")) -and (-not ($coldWrite140 -match "'meta'")) -and (-not ($migrate140 -match "'meta'"))
) "140.2: cold-store accessors use the 'campaign' object store only, never 'meta' (two-store boundary)"

# 140.3  saveToSlot async + IDB-primary via _coldWriteObj
Check (
    ($uiSaves140 -match 'async function saveToSlot') -and
    ($saveBody140 -match "_coldWriteObj\(_slotKey\(slotNum\), 'slot_' \+ slotNum")
) '140.3: saveToSlot is async and writes IDB-primary via _coldWriteObj'

# 140.4  loadFromSlot IDB-primary via _coldReadObj + localStorage fallback
Check (
    ($loadBody140 -match "_coldReadObj\(_slotKey\(slotNum\), 'slot_' \+ slotNum\)") -and
    ($loadBody140 -match 'localStorage\.getItem\(_slotKey\(slotNum\)\)')
) '140.4: loadFromSlot reads IDB-primary via _coldReadObj with a localStorage fallback'

# 140.5  snapRollingBackup mirrors the ring slot into the IDB 'campaign' store
Check (
    $state140 -match "IdbStore\.set\('campaign', 'backup_' \+ \(ptr \+ 1\)"
) "140.5: snapRollingBackup mirrors the backup into the IDB 'campaign' store (backup_<n>)"

# 140.6  getRollingBackupsAsync (union) + restore uses it; sync one stays
Check (
    ($state140 -match 'window\.getRollingBackupsAsync = async function') -and
    ($restoreBody140 -match 'await window\.getRollingBackupsAsync\(\)') -and
    ($state140 -match 'window\.getRollingBackups = function')
) '140.6: getRollingBackupsAsync (union) exists and restoreRollingBackup uses it; getRollingBackups stays synchronous'

# 140.7  NEWEST-WINS: _coldReadObj resolves divergence by _coldStamp (IDB ties)
Check (
    $coldRead140 -match '_coldStamp\(idbObj\) >= _coldStamp\(lsObj\)'
) '140.7: _coldReadObj resolves an IDB/localStorage divergence newest-wins by _coldStamp (IDB wins ties)'

# 140.8  MIGRATION additive + idempotent + never removes localStorage
Check (
    ($migrate140 -match '!idbObj \|\| _coldStamp\(lsObj\) > _coldStamp\(idbObj\)') -and
    (-not ($migrate140 -match 'removeItem')) -and
    (-not ($coldWrite140 -match 'removeItem'))
) '140.8: migration copies only when IDB is absent or localStorage is strictly newer (idempotent, additive-only -- never removes localStorage)'

# 140.9  CEILING RELIEF / FAIL-SAFE: write persists on either store + boot migration
Check (
    ($coldWrite140 -match 'return idbOk \|\| lsOk;') -and
    ($coldWrite140 -match 'catch \(_\) \{') -and
    ($uiCore140 -match '_migrateColdStoreToIdb\(\)')
) '140.9: _coldWriteObj persists on either store (localStorage quota non-fatal -- ceiling relief); boot fires the migration'

# 140.10  renderSavesList surfaces IDB-only save slots
Check (
    $uiAcct140 -match "IdbStore\.get\('campaign', 'slot_' \+ n\)"
) '140.10: renderSavesList surfaces IDB-only save slots (oversized saves localStorage could not hold)'

# 140.11  cloud upload reads slots via the IDB-primary union
Check (
    $cloud140 -match "_coldReadObj\('robco_slot_' \+ n, 'slot_' \+ n\)"
) '140.11: cloud syncLocalSavesToCloud reads slots via the IDB-primary union (_coldReadObj)'

# 140.12  game-agnostic (Protocol 38): the cold-store path has no game literals
Check (
    -not (($coldRead140 + $coldWrite140 + $migrate140) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '140.12: the P3 cold-store accessors are game-agnostic (no game literals)'

# ===========================================================
# Suite 141 -- Step 2 (v2.8.0) Phase 1 P4: Terminal Record -- structured
# eventLog (12 tests). Mirrors JS Suite 141. eventLog is the ONE canonical
# campaign history ({t,rt,type,text} records via the single _logEvent() writer);
# campaign_notes returns to a MANUAL notebook. The [T#] migration
# (_migrateEventLog) non-lossily splits legacy campaign_notes -- [T#] auto-log
# strings MOVE to eventLog, manual notes STAY. Player-authority: the AI can't
# overwrite the notebook (its notes route to eventLog, deduped) and can never
# author eventLog directly. Crossroads + Incident are views over the Record.
# ===========================================================
Sep "Suite 141 -- P4 Terminal Record (structured eventLog + [T#] migration)"
$state141     = Read-Src "js/state.js"
$api141       = Read-Src "js/api.js"
$uiCore141    = Read-Src "js/ui-core.js"
$uiRender141  = Read-Src "js/ui-render.js"
$html141      = Read-Src "index.html"
$logEventBody = Get-FunctionBody $state141 '_logEvent'
$migrateEvBody = Get-FunctionBody $state141 '_migrateEventLog'
$inferBody141 = Get-FunctionBody $state141 '_inferEventType'
$migrateStateBody141 = Get-FunctionBody $state141 'migrateState'
$addNoteBody141 = Get-FunctionBody $uiRender141 'addCampaignNote'

# 141.1  eventLog default present alongside campaign_notes
Check (
    ($state141 -match 'eventLog: \[\]') -and ($state141 -match 'campaign_notes: \[\]')
) '141.1: state defaults include eventLog: [] (Terminal Record) alongside campaign_notes: []'

# 141.2  _logEvent is the single structured writer (t/rt/type/text + cap)
Check (
    ($state141 -match 'function _logEvent\(type, text\)') -and
    ($logEventBody -match 'state\.eventLog\.push\(') -and
    ($logEventBody -match 'type: String\(type\)') -and
    ($logEventBody -match 'text: String\(text\)') -and
    ($logEventBody -match 'EVENTLOG_CAP')
) '141.2: _logEvent() is the single writer -- pushes a structured {t,rt,type,text} record, capped at EVENTLOG_CAP'

# 141.3  auto-log subscribers re-pointed to _logEvent; _logCampaignEvent retired
Check (
    (-not ($state141 -match '_logCampaignEvent')) -and
    (-not ($api141 -match '_logCampaignEvent')) -and
    ($state141 -match "RobcoEvents\.on\('level\.up'[\s\S]{0,120}_logEvent\('level'")
) '141.3: the RobcoEvents auto-log subscribers write via _logEvent(); the old _logCampaignEvent is fully retired (state.js + api.js)'

# 141.4  the [T#] migration: MOVE [T#] strings to eventLog, KEEP manual notes
Check (
    ($state141 -match 'function _migrateEventLog\(s\)') -and
    ($migrateEvBody -match 'T\(\\d\+\)') -and
    ($migrateEvBody -match 'manual\.push\(n\)') -and
    ($migrateEvBody -match 's\.campaign_notes = manual') -and
    ($migrateEvBody -match '_inferEventType')
) '141.4: _migrateEventLog moves [T#]-prefixed auto-log strings into eventLog and leaves manual notes in campaign_notes (non-lossy split)'

# 141.5  migration runs from migrateState AND the v8 boot fast-path
Check (
    ($migrateStateBody141 -match '_migrateEventLog\(s\)') -and
    ($migrateStateBody141 -match 's\.eventLog\b') -and
    ($uiCore141 -match '_migrateEventLog\(state\)')
) '141.5: migrateState and the ui-core v8 boot fast-path both run _migrateEventLog (existing v8 saves migrate too)'

# 141.6  sanitizeImportedContainer coerces eventLog to typed records (Protocol 4)
Check (
    ($api141 -match 'o\.eventLog = o\.eventLog') -and
    ($api141 -match "type: _str\(e\.type \|\| 'log'\)") -and
    ($api141 -match "text: _str\(e\.text \|\| ''\)")
) '141.6: sanitizeImportedContainer coerces eventLog into typed {t,rt,type,text} records (born-compliant, Protocol 4)'

# 141.7  AI re-point: no overwrite of the notebook; AI notes -> eventLog, deduped
Check (
    (-not ($api141 -match 'state\.campaign_notes = parsed\.campaign_notes')) -and
    ($api141 -match "parsed\.campaign_notes[\s\S]{0,400}_logEvent\('log', text\)") -and
    ($api141 -match '_seenEvents')
) "141.7: the AI no longer overwrites campaign_notes -- its notes route to eventLog as deduped 'log' events (player authority)"

# 141.8  player-authority: the manual notebook stays user-editable
Check (
    $addNoteBody141 -match 'state\.campaign_notes\.push'
) '141.8: addCampaignNote() still writes campaign_notes -- the manual notebook stays fully user-editable'

# 141.9  Crossroads + Incident are views over the Record (read eventLog)
Check (
    ($uiRender141 -match 'state\.eventLog[\s\S]{0,80}\.slice\(-20\)') -and
    ($uiRender141 -match 'incidentDisplay') -and
    ($uiRender141 -match 'MILESTONES') -and
    ($api141 -match '\(state && state\.eventLog\)')
) '141.9: the Crossroads (all events) and Incident (milestone-filtered) views read state.eventLog; _nativeCrossroads reads it too'

# 141.10  the Incident Log sub-panel exists (Protocol UI-2: data-sub-id)
Check (
    ($html141 -match 'id="incidentDisplay"') -and ($html141 -match 'data-sub-id="incident_log"')
) '141.10: index.html has the Incident Log sub-panel (#incidentDisplay + data-sub-id -- Protocol UI-2)'

# 141.11  player-authority: the AI can NEVER author the Record directly
Check (
    (-not ($api141 -match 'state\.eventLog = parsed\.eventLog')) -and (-not ($api141 -match 'parsed\.eventLog'))
) '141.11: autoImportState never lets the AI write eventLog directly -- the Record is code-authored (player authority)'

# 141.12  game-agnostic (Protocol 38): the Record path has no game literals
Check (
    -not (($logEventBody + $migrateEvBody + $inferBody141) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '141.12: the Terminal Record writer/migration/inference are game-agnostic (no game literals)'

# ===========================================================
# Suite 142 -- Step 2 (v2.8.0) Phase 1 P5: Save version history -- a per-slot
# revision ring (12 tests). Mirrors JS Suite 142. Each save slot retains up to
# SLOT_VERSION_CAP prior revisions in the IDB 'campaign' store (key
# slot_<n>_versions), IDB-ONLY so it rides the P3 IndexedDB headroom and never
# consumes the localStorage ceiling. saveToSlot captures the slot's PRIOR contents
# before overwriting; the user can view + (destructively, confirm-gated) restore
# any revision through the SAME _applySlotEnvelope core loadFromSlot uses
# (Protocol 22). Fail-safe: no IDB -> no version history offered, save/load
# byte-identical to pre-P5. Structural guards here; the real-IndexedDB behavioral
# proof lives in tests/test.html (Suite 14 -- PowerShell has no IndexedDB).
# ===========================================================
Sep "Suite 142 -- P5 save version history (per-slot revision ring)"
$state142    = Read-Src "js/state.js"
$uiSaves142  = Read-Src "js/ui-saves.js"
$uiAcct142   = Read-Src "js/ui-account.js"
$readVers142     = Get-FunctionBody $state142 'readSlotVersions'
$pushVers142     = Get-FunctionBody $state142 'pushSlotVersion'
$saveBody142     = Get-FunctionBody $uiSaves142 'saveToSlot'
$applyBody142    = Get-FunctionBody $uiSaves142 '_applySlotEnvelope'
$restoreVer142   = Get-FunctionBody $uiSaves142 'restoreSlotVersion'
$viewVer142      = Get-FunctionBody $uiSaves142 'viewSlotVersions'
$loadBody142     = Get-FunctionBody $uiSaves142 'loadFromSlot'

# 142.1  the version-ring API is defined + exposed on window
Check (
    ($state142 -match 'function _slotVersionsIdbKey\s*\(') -and
    ($state142 -match 'const SLOT_VERSION_CAP =') -and
    ($state142 -match 'async function readSlotVersions\s*\(') -and
    ($state142 -match 'window\.readSlotVersions = readSlotVersions') -and
    ($state142 -match 'async function pushSlotVersion\s*\(') -and
    ($state142 -match 'window\.pushSlotVersion = pushSlotVersion')
) '142.1: state.js defines SLOT_VERSION_CAP + _slotVersionsIdbKey and exposes window.readSlotVersions / window.pushSlotVersion'

# 142.2  TWO-STORE BOUNDARY: the version ring uses the 'campaign' store only
Check (
    ($readVers142 -match "'campaign'") -and
    ($pushVers142 -match "'campaign'") -and
    (-not ($readVers142 -match "'meta'")) -and
    (-not ($pushVers142 -match "'meta'"))
) "142.2: the version ring uses the 'campaign' object store only, never 'meta' (two-store boundary -- Protocol 23)"

# 142.3  pushSlotVersion is newest-first (unshift) + bounded (slice to cap)
Check (
    ($pushVers142 -match '\.unshift\(priorEnv\)') -and
    ($pushVers142 -match '\.slice\(0, SLOT_VERSION_CAP\)')
) '142.3: pushSlotVersion prepends newest-first (unshift) and caps the ring at SLOT_VERSION_CAP (slice) -- bounded'

# 142.4  FAIL-SAFE: both accessors guard on window.IdbStore and never throw
Check (
    ($readVers142 -match 'if \(!window\.IdbStore\) return \[\]') -and
    ($readVers142 -match 'catch \(_\) \{\s*return \[\]') -and
    ($pushVers142 -match 'if \(!window\.IdbStore \|\| !priorEnv\) return;') -and
    ($pushVers142 -match 'try \{') -and
    ($pushVers142 -match 'catch \(_\) \{\}')
) '142.4: readSlotVersions / pushSlotVersion guard on window.IdbStore and are wrapped so they never throw (fail-safe -> [] / no-op)'

# 142.5  IDB-ONLY: the version ring is never mirrored to localStorage
Check (
    (-not ($readVers142 -match 'localStorage')) -and
    (-not ($pushVers142 -match 'localStorage'))
) '142.5: the version ring is IDB-only -- never written to localStorage (rides IDB headroom, never the ~5MB ceiling)'

# 142.6  saveToSlot captures the PRIOR envelope via pushSlotVersion BEFORE the write
Check (
    ($saveBody142 -match 'await window\.pushSlotVersion\(slotNum, _prior\)') -and
    ($saveBody142.IndexOf('pushSlotVersion') -lt $saveBody142.IndexOf('_coldWriteObj'))
) '142.6: saveToSlot captures the slot prior contents via pushSlotVersion BEFORE overwriting it (capture-before-overwrite)'

# 142.7  Protocol 22 -- ONE apply core: _applySlotEnvelope called by BOTH
#         loadFromSlot AND restoreSlotVersion (no parallel restore implementation)
Check (
    ($uiSaves142 -match 'async function _applySlotEnvelope\s*\(') -and
    ($loadBody142 -match '_applySlotEnvelope\(env, slotNum\)') -and
    ($restoreVer142 -match "_applySlotEnvelope\(env, slotNum, \{ verb: 'version restored' \}\)")
) '142.7: loadFromSlot and restoreSlotVersion both apply through the SHARED _applySlotEnvelope core (Protocol 22 -- no parallel restore path)'

# 142.8  the apply core routes through the same integrity + backup + migrate path
Check (
    ($applyBody142 -match 'verifySaveEnvelope\(env\)') -and
    ($applyBody142 -match 'snapRollingBackup\(\)') -and
    ($applyBody142 -match 'migrateState\(env\.version')
) '142.8: _applySlotEnvelope verifies the envelope, snapshots a rolling backup before applying, and migrates state (same path as loadFromSlot)'

# 142.9  restoreSlotVersion is confirm-gated BEFORE applying (destructive -> P34)
Check (
    ($restoreVer142 -match 'await confirmAction\(\{') -and
    ($restoreVer142 -match "confirmLabel: 'RESTORE VERSION'") -and
    ($restoreVer142 -match 'if \(!ok\) return;') -and
    ($restoreVer142.IndexOf('confirmAction') -lt $restoreVer142.IndexOf('_applySlotEnvelope'))
) '142.9: restoreSlotVersion is confirm-gated (confirmAction) BEFORE the apply core -- destructive restore honors Protocol 34'

# 142.10  viewSlotVersions renders via the shared modal + escapes dynamic fields
Check (
    ($viewVer142 -match 'openModal\(\{') -and
    ($viewVer142 -match 'escapeHtml\(') -and
    ($viewVer142 -match 'restoreSlotVersion\(')
) '142.10: viewSlotVersions renders through openModal, escapes dynamic fields (escapeHtml), and wires per-row restoreSlotVersion'

# 142.11  FAIL-SAFE AFFORDANCE: VERS button only when IdbStore present + versions
Check (
    ($uiAcct142 -match "window\.IdbStore && typeof window\.readSlotVersions === 'function'") -and
    ($uiAcct142 -match 'versionCounts\[') -and
    ($uiAcct142 -match 'viewSlotVersions\(')
) '142.11: renderSavesList offers the version-history affordance only when IndexedDB is present and the slot has revisions (fail-safe)'

# 142.12  game-agnostic (Protocol 38): the P5 code carries no game literals
Check (
    -not (($readVers142 + $pushVers142 + $restoreVer142 + $viewVer142) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '142.12: the P5 version-history code is game-agnostic (no game literals)'

# ===========================================================
# Suite 143 -- Step 2 (v2.8.0) Phase 1 P6: Full backup bundle (13 tests). Mirrors
# JS Suite 143. Export the ENTIRE local history (live container + every save slot
# with its P5 version ring + rolling-backup ring + chat + playstyle) to one
# portable version-stamped + checksummed file, and import it back. Import is
# DESTRUCTIVE -> confirm-gated (Protocol 34); the container restore routes through
# the SAME _writeImportedContainer core handleFileUpload uses (Protocol 22); a
# bad-shape / bad-checksum bundle is rejected with NO partial apply. Bundle carries
# campaign/save data ONLY -- device prefs ('meta' store) excluded (Protocol 23).
# The real-IndexedDB round-trip is proven in tests/test.html (Suite 15).
# ===========================================================
Sep "Suite 143 -- P6 full backup bundle (export/import whole history)"
$state143     = Read-Src "js/state.js"
$uiSaves143   = Read-Src "js/ui-saves.js"
$indexHtml143 = Read-Src "index.html"
$buildBody143     = Get-FunctionBody $state143 'buildFullBundle'
$verifyCkBody143  = Get-FunctionBody $state143 'verifyBundleChecksum'
$applyBody143     = Get-FunctionBody $state143 'applyBundleData'
$writeContainer143 = Get-FunctionBody $state143 '_writeImportedContainer'
$exportBody143    = Get-FunctionBody $uiSaves143 'exportFullBundle'
$importBody143    = Get-FunctionBody $uiSaves143 'importBundle'
$uploadBody143    = Get-FunctionBody $uiSaves143 'handleFileUpload'

# 143.1  the bundle data-layer API is defined + exposed on window
Check (
    ($state143 -match 'async function buildFullBundle\s*\(') -and
    ($state143 -match 'window\.buildFullBundle = buildFullBundle') -and
    ($state143 -match 'function verifyBundleChecksum\s*\(') -and
    ($state143 -match 'window\.verifyBundleChecksum = verifyBundleChecksum') -and
    ($state143 -match 'function isValidBundleShape\s*\(') -and
    ($state143 -match 'function _writeImportedContainer\s*\(') -and
    ($state143 -match 'async function applyBundleData\s*\(') -and
    ($state143 -match 'window\.applyBundleData = applyBundleData')
) '143.1: state.js defines + exposes buildFullBundle / verifyBundleChecksum / isValidBundleShape / _writeImportedContainer / applyBundleData'

# 143.2  the envelope is stamped + checksummed with the SHARED helper (Protocol 22)
Check (
    ($buildBody143 -match 'bundle: true') -and
    ($buildBody143 -match 'bundleVersion:') -and
    ($buildBody143 -match 'schemaVersion: APP_VERSION') -and
    ($buildBody143 -match 'window\.computeSaveChecksum\(')
) '143.2: the bundle envelope is version-stamped and checksummed via computeSaveChecksum (Protocol 22 -- no forked hash)'

# 143.3  buildFullBundle gathers the whole history
Check (
    ($buildBody143 -match 'robco_v8: _v8') -and
    ($buildBody143 -match 'readSlotVersions\(n\)') -and
    ($buildBody143 -match 'versions:') -and
    ($buildBody143 -match 'getRollingBackupsAsync\(\)') -and
    ($buildBody143 -match 'slots,') -and
    ($buildBody143 -match 'backups,')
) '143.3: buildFullBundle gathers the live container + every slot (with its P5 version ring) + the rolling-backup ring + chat + playstyle'

# 143.4  BOUNDARY: the bundle is campaign/save data only -- no device 'meta' store
Check (
    (-not ($buildBody143 -match "'meta'")) -and
    (-not ($buildBody143 -match 'MetaStore')) -and
    (-not ($applyBody143 -match "'meta'")) -and
    (-not ($applyBody143 -match 'MetaStore'))
) "143.4: the bundle excludes device prefs -- buildFullBundle/applyBundleData never touch the 'meta' store / MetaStore (two-store boundary, Protocol 23)"

# 143.5  verifyBundleChecksum recomputes over the same fields + requires a match
Check (
    ($verifyCkBody143 -match 'window\.computeSaveChecksum\(') -and
    ($verifyCkBody143 -match 'robco_v8: parsed\.robco_v8, slots: parsed\.slots, backups: parsed\.backups') -and
    ($verifyCkBody143 -match 'if \(!parsed \|\| !parsed\.checksum\) return false;') -and
    ($verifyCkBody143 -match 'expected === parsed\.checksum')
) '143.5: verifyBundleChecksum recomputes over {robco_v8,slots,backups}+chat+playstyle and returns true only when a seal is present and matches'

# 143.6  isValidBundleShape requires the discriminator + container + both arrays
Check (
    ($state143 -match 'parsed\.bundle === true') -and
    ($state143 -match 'Array\.isArray\(parsed\.slots\)') -and
    ($state143 -match 'Array\.isArray\(parsed\.backups\)')
) '143.6: isValidBundleShape requires bundle===true + a robco_v8 container + slots[]/backups[] arrays'

# 143.7  Protocol 22: handleFileUpload routes through the SHARED container core
Check (
    ($writeContainer143 -match 'sanitizeImportedContainer\(parsed\.robco_v8\)') -and
    ($uploadBody143 -match 'window\._writeImportedContainer\(parsed\)') -and
    (-not ($uploadBody143 -match '_sanitized'))
) '143.7: handleFileUpload restores its container via the shared _writeImportedContainer core (Protocol 22 -- one container-apply path)'

# 143.8  applyBundleData restores slots VERBATIM (checksum-preserving) + rings
Check (
    ($applyBody143 -match "_coldWriteObj\('robco_slot_' \+ s\.n, 'slot_' \+ s\.n, s\.envelope\)") -and
    ($applyBody143 -match "IdbStore\.set\('campaign', 'slot_' \+ s\.n \+ '_versions', s\.versions\)") -and
    (-not ($applyBody143 -match 'migrateState\('))
) '143.8: applyBundleData restores each slot envelope VERBATIM (preserving its checksum) + its version ring to the campaign store -- no per-slot mutation'

# 143.9  UNDO SAFETY: snap BEFORE apply; live ring never overwritten
Check (
    ($importBody143 -match 'window\.snapRollingBackup\(\)') -and
    ($importBody143.IndexOf('window.snapRollingBackup()') -lt $importBody143.IndexOf('await window.applyBundleData(')) -and
    (-not ($applyBody143 -match 'robco_backup_'))
) '143.9: importBundle takes a rolling backup (undo point) BEFORE applyBundleData, which never overwrites the live rolling-backup ring'

# 143.10  import is confirm-gated AND validates shape+checksum before any apply
Check (
    ($importBody143 -match "confirmLabel: 'RESTORE ALL'") -and
    ($importBody143 -match 'isValidBundleShape\(parsed\)') -and
    ($importBody143 -match 'verifyBundleChecksum\(parsed\)') -and
    ($importBody143.IndexOf('isValidBundleShape') -lt $importBody143.IndexOf('applyBundleData')) -and
    ($importBody143.IndexOf('verifyBundleChecksum') -lt $importBody143.IndexOf('applyBundleData'))
) '143.10: importBundle is confirm-gated (RESTORE ALL) and validates shape + checksum BEFORE any apply (bad bundle -> reject, no partial apply)'

# 143.11  handleFileUpload auto-detects a bundle and routes it to importBundle
Check (
    ($uploadBody143 -match 'parsed\.bundle === true') -and
    ($uploadBody143 -match 'await importBundle\(parsed\)')
) '143.11: handleFileUpload detects a full-backup bundle (parsed.bundle===true) and routes it to importBundle'

# 143.12  export is a DELIBERATE user action via _downloadBlob + index.html button
Check (
    ($exportBody143 -match '_downloadBlob\(') -and
    ($exportBody143 -match 'window\.buildFullBundle\(\)') -and
    ($indexHtml143 -match 'onclick="exportFullBundle\(\)"')
) '143.12: exportFullBundle writes the file via _downloadBlob on a deliberate index.html button press (user-initiated, not automatic)'

# 143.13  game-agnostic (Protocol 38): the P6 code has no game literals
Check (
    -not (($buildBody143 + $verifyCkBody143 + $applyBody143 + $exportBody143 + $importBody143) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '143.13: the P6 full-backup bundle code is game-agnostic (no game literals)'

# ===========================================================
# Suite 144 -- Step 2 (v2.8.0) Phase 1 P7: Offline cloud-push queue (12 tests).
# Mirrors JS Suite 144. Resilience for a USER-INITIATED manual cloud push ONLY --
# NEVER an auto-push on a state/stat change (cloud sync stays manual-only). A push
# the user pressed while offline / that failed on network is enqueued (device-local,
# IDB 'campaign' store, bounded + contentHash-deduped) and flushed on reconnect via
# the SAME additive addDoc uploader (_uploadSaveDoc; Protocol 22/34), gated by the
# offlineQueue kill-switch flag (Protocol 32/33) + every manual-button auth guard.
# The storage round-trip is proven live in tests/test.html (Suite 16).
# ===========================================================
Sep "Suite 144 -- P7 offline cloud-push queue (manual-push resilience)"
$state144 = Read-Src "js/state.js"
$cloud144 = Read-Src "js/cloud.js"
$uiCore144 = Read-Src "js/ui-core.js"
$api144 = Read-Src "js/api.js"
$readQ144 = Get-FunctionBody $state144 'readCloudQueue'
$enqQ144 = Get-FunctionBody $state144 'enqueueCloudPush'
$writeQ144 = Get-FunctionBody $state144 'writeCloudQueue'
$saveStateBody144 = Get-FunctionBody $state144 'saveState'
$flushBody144 = Get-FunctionBody $cloud144 'flushCloudQueue'
$uploadBody144 = Get-FunctionBody $cloud144 '_uploadSaveDoc'
$updateMathBody144 = Get-FunctionBody $uiCore144 'updateMath'
$autoImportBody144 = Get-FunctionBody $api144 'autoImportState'
# saveCurrentToCloud is a window-assignment expression -- brace-match from it.
$scStart144 = $cloud144.IndexOf('window.saveCurrentToCloud =')
$saveCloudBody144 = ''
if ($scStart144 -ge 0) {
    $b = $cloud144.IndexOf('{', $scStart144); $d = 0
    for ($j = $b; $j -lt $cloud144.Length; $j++) {
        if ($cloud144[$j] -eq '{') { $d++ } elseif ($cloud144[$j] -eq '}') { $d--; if ($d -eq 0) { $saveCloudBody144 = $cloud144.Substring($b, $j - $b + 1); break } }
    }
}

# 144.1  the queue data-layer API is defined + exposed on window
Check (
    ($state144 -match 'const CLOUD_QUEUE_CAP =') -and
    ($state144 -match 'const CLOUD_QUEUE_IDB_KEY =') -and
    ($state144 -match 'async function readCloudQueue\s*\(') -and
    ($state144 -match 'window\.readCloudQueue = readCloudQueue') -and
    ($state144 -match 'async function enqueueCloudPush\s*\(') -and
    ($state144 -match 'window\.enqueueCloudPush = enqueueCloudPush') -and
    ($state144 -match 'async function writeCloudQueue\s*\(') -and
    ($state144 -match 'window\.writeCloudQueue = writeCloudQueue')
) '144.1: state.js defines CLOUD_QUEUE_CAP/CLOUD_QUEUE_IDB_KEY + exposes readCloudQueue / enqueueCloudPush / writeCloudQueue'

# 144.2  BOUNDARY: the queue uses the 'campaign' store only, never 'meta'
Check (
    ($readQ144 -match "'campaign'") -and ($enqQ144 -match "'campaign'") -and ($writeQ144 -match "'campaign'") -and
    (-not ($readQ144 -match "'meta'")) -and (-not ($enqQ144 -match "'meta'")) -and (-not ($writeQ144 -match "'meta'"))
) "144.2: the cloud-push queue uses the 'campaign' object store only, never 'meta' (two-store boundary -- the payload is campaign save data)"

# 144.3  enqueue dedups by contentHash + is bounded (slice to CLOUD_QUEUE_CAP)
Check (
    ($enqQ144 -match 'x\.contentHash === item\.contentHash') -and
    ($enqQ144 -match '\.slice\(-CLOUD_QUEUE_CAP\)')
) '144.3: enqueueCloudPush dedups by contentHash (same push twice is a no-op) and caps the queue at CLOUD_QUEUE_CAP'

# 144.4  FAIL-SAFE: the accessors guard on window.IdbStore and never throw
Check (
    ($readQ144 -match 'if \(!window\.IdbStore\) return \[\];') -and
    ($readQ144 -match 'catch \(_\) \{\s*return \[\];') -and
    ($enqQ144 -match 'if \(!window\.IdbStore \|\| !item\) return false;') -and
    ($enqQ144 -match 'catch \(_\) \{\s*return false;')
) '144.4: the queue accessors guard on window.IdbStore and are wrapped so they never throw (fail-safe -> [] / false)'

# 144.5  kill-switch: offlineQueue flag registered + gates the enqueue + flush
Check (
    ($cloud144 -match 'offlineQueue: true') -and
    ($saveCloudBody144 -match "isFeatureEnabled\('offlineQueue'\)") -and
    ($flushBody144 -match "isFeatureEnabled\('offlineQueue'\)")
) "144.5: cloud.js registers the offlineQueue kill-switch flag (default enabled) and gates both enqueue and flush on isFeatureEnabled('offlineQueue') (Protocol 32/33)"

# 144.6  Protocol 22/34: ONE additive uploader used by BOTH push + flush
Check (
    ($cloud144 -match 'async function _uploadSaveDoc\s*\(') -and
    ($uploadBody144 -match 'addDoc\(') -and
    (-not ($uploadBody144 -match 'setDoc\(')) -and
    ($saveCloudBody144 -match '_uploadSaveDoc\(') -and
    ($flushBody144 -match '_uploadSaveDoc\(')
) '144.6: a single additive uploader _uploadSaveDoc (addDoc, never setDoc -- Protocol 34) is reused by BOTH saveCurrentToCloud and flushCloudQueue (Protocol 22 -- no forked uploader)'

# 144.7  enqueue happens ONLY on offline / network-fail, ONLY in the manual push
Check (
    ($saveCloudBody144 -match 'navigator\.onLine === false') -and
    ($saveCloudBody144 -match '_isOfflineError\(e\)') -and
    ($saveCloudBody144 -match 'enqueueCloudPush\(payload\)') -and
    (-not ($flushBody144 -match 'enqueueCloudPush'))
) '144.7: saveCurrentToCloud enqueues only on an offline/network failure of the user-pressed push; the flush never enqueues (retry-only)'

# 144.8  flush guards: kill-switch + auth (non-anonymous) + online + reentrancy + uid-scope
Check (
    ($flushBody144 -match '_currentUser\.isAnonymous') -and
    ($flushBody144 -match 'navigator\.onLine === false') -and
    ($flushBody144 -match '_flushingQueue') -and
    ($flushBody144 -match 'item\.uid !== _currentUid')
) '144.8: flushCloudQueue is guarded by cloudSync/offlineQueue + a non-anonymous auth check + online + a reentrancy flag, and is uid-scoped (only the current account queued pushes flush)'

# 144.9  flush drops sent/duplicate items, keeps failed ones (bounded retry)
Check (
    ($flushBody144 -match 'remaining\.push\(item\)') -and
    ($flushBody144 -match 'stopped = true') -and
    ($flushBody144 -match 'writeCloudQueue\(remaining\)') -and
    ($uploadBody144 -match 'contentHash')
) '144.9: flushCloudQueue drops uploaded/duplicate items and re-persists the remaining (failed) ones -- bounded retry, never lost, never duplicated (contentHash dedup in _uploadSaveDoc)'

# 144.10  flush is triggered by connectivity return + sign-in -- NEVER a save path
Check (
    ($cloud144 -match "addEventListener\('online',") -and
    ($cloud144 -match 'flushCloudQueue\(\)') -and
    ($cloud144 -match 'onAuthStateChanged')
) "144.10: the flush is wired to the 'online' connectivity event and to sign-in (onAuthStateChanged), not to any save/state-change path"

# 144.11  NEVER-AUTO-PUSH invariant (extends Suite 23.4/23.5)
Check (
    (-not ($saveStateBody144 -match 'enqueueCloudPush|flushCloudQueue|saveCurrentToCloud|_uploadSaveDoc')) -and
    (-not ($updateMathBody144 -match 'enqueueCloudPush|flushCloudQueue|_uploadSaveDoc')) -and
    (-not ($autoImportBody144 -match 'enqueueCloudPush|flushCloudQueue|saveCurrentToCloud|_uploadSaveDoc'))
) '144.11: never-auto-push -- saveState / updateMath / autoImportState never enqueue, flush, or push to the cloud (cloud sync stays manual-only)'

# 144.12  game-agnostic (Protocol 38): the queue + flush code has no game literals
Check (
    -not (($readQ144 + $enqQ144 + $writeQ144 + $flushBody144 + $uploadBody144) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '144.12: the P7 queue + flush code is game-agnostic (no game literals)'

# ===========================================================
# Suite 145 -- Step 2 (v2.8.0) Phase 1 P8: Global Immersion dial (10 tests).
# Mirrors JS Suite 145. ONE device-level control (Full/Balanced/Minimal) for how
# much of the atmosphere layer runs. DEVICE PREFERENCE (MetaStore robco_immersion) --
# NOT campaign state (never rides the save/cloud; Protocol 23). Born-compliant seam:
# getImmersionTier / immersionAllows / setImmersionTier (state.js) are what the ~10
# Phase-2 ambient consumers subscribe to; default 'full' preserves today's behavior.
# The memory-cycle flash is the one existing consumer wired as proof-of-seam. The
# pref round-trip + thresholds are proven live in tests/test.html (Suite 17).
# ===========================================================
Sep "Suite 145 -- P8 global immersion dial (Full/Balanced/Minimal)"
$state145 = Read-Src "js/state.js"
$uiCore145 = Read-Src "js/ui-core.js"
$indexHtml145 = Read-Src "index.html"
$getTierBody145 = Get-FunctionBody $state145 'getImmersionTier'
$allowsBody145 = Get-FunctionBody $state145 'immersionAllows'
$setTierBody145 = Get-FunctionBody $state145 'setImmersionTier'
$memCycleReg145 = Get-FunctionBody $uiCore145 '_startAmbientTimers'
$initImmBody145 = Get-FunctionBody $uiCore145 'initImmersion'

# 145.1  robco_immersion registered as a DEVICE pref in META_MANIFEST (default 'full')
Check (
    $state145 -match "robco_immersion:\s*\{[^}]*type:\s*'string'[^}]*default:\s*'full'"
) "145.1: state.js registers robco_immersion in META_MANIFEST as a device pref (type string, default 'full')"

# 145.2  the gate-helper API is defined + exposed on window
Check (
    ($state145 -match "const IMMERSION_KEY = 'robco_immersion'") -and
    ($state145 -match "const IMMERSION_TIERS = \['minimal', 'balanced', 'full'\]") -and
    ($state145 -match 'function getImmersionTier\s*\(') -and
    ($state145 -match 'window\.getImmersionTier = getImmersionTier') -and
    ($state145 -match 'function immersionAllows\s*\(') -and
    ($state145 -match 'window\.immersionAllows = immersionAllows') -and
    ($state145 -match 'function setImmersionTier\s*\(') -and
    ($state145 -match 'window\.setImmersionTier = setImmersionTier')
) '145.2: state.js defines IMMERSION_KEY/IMMERSION_TIERS + exposes getImmersionTier / immersionAllows / setImmersionTier'

# 145.3  getImmersionTier reads MetaStore + fail-safe default 'full'
Check (
    ($getTierBody145 -match 'MetaStore\.get\(IMMERSION_KEY\)') -and
    ($getTierBody145 -match "IMMERSION_TIERS\.indexOf\(v\) !== -1 \? v : 'full'")
) "145.3: getImmersionTier reads the MetaStore device key and fails safe to 'full' for an unknown/absent value"

# 145.4  immersionAllows is a rank compare; an unknown requirement fails OPEN
Check (
    ($allowsBody145 -match 'IMMERSION_TIERS\.indexOf\(requiredTier\)') -and
    ($allowsBody145 -match 'if \(req === -1\) return true;') -and
    ($allowsBody145 -match 'IMMERSION_TIERS\.indexOf\(getImmersionTier\(\)\) >= req')
) '145.4: immersionAllows(required) returns rank(current) >= rank(required); an unrecognised requirement fails open (returns true)'

# 145.5  setImmersionTier validates (unknown -> 'full') and writes ONLY MetaStore
Check (
    ($setTierBody145 -match "IMMERSION_TIERS\.indexOf\(tier\) !== -1 \? tier : 'full'") -and
    ($setTierBody145 -match 'MetaStore\.set\(IMMERSION_KEY, t\)')
) "145.5: setImmersionTier coerces an unknown level to 'full' and persists via MetaStore (device pref)"

# 145.6  BOUNDARY: the dial is a DEVICE pref -- the helpers never touch campaign state
Check (
    (-not (($getTierBody145 + $allowsBody145 + $setTierBody145) -match '\bstate\.')) -and
    (-not (($getTierBody145 + $allowsBody145 + $setTierBody145) -match 'localStorage'))
) '145.6: the immersion helpers never read/write campaign state or raw localStorage -- device pref only, through MetaStore (two-store boundary)'

# 145.7  ui-core.js has the DOM control + boot restore, wired into boot
Check (
    ($uiCore145 -match 'function _updateImmersionUI\s*\(') -and
    ($uiCore145 -match 'function onImmersionChange\s*\(') -and
    ($uiCore145 -match 'function initImmersion\s*\(') -and
    ($initImmBody145 -match 'getImmersionTier\(\)') -and
    ($uiCore145 -match 'initImmersion\(\);')
) '145.7: ui-core.js defines _updateImmersionUI / onImmersionChange / initImmersion, and initImmersion() is called from boot (restores the saved level)'

# 145.8  index.html has the accessible <select> control (3 levels) + status readout
Check (
    ($indexHtml145 -match 'id="immersionSelect"') -and
    ($indexHtml145 -match 'onchange="onImmersionChange\(this\.value\)"') -and
    ($indexHtml145 -match 'aria-label="Ambient immersion level') -and
    ($indexHtml145 -match 'font-size:\s*16px') -and
    ($indexHtml145 -match 'value="full"') -and
    ($indexHtml145 -match 'value="balanced"') -and
    ($indexHtml145 -match 'value="minimal"') -and
    ($indexHtml145 -match 'id="immersionStatus"')
) '145.8: index.html has #immersionSelect (Full/Balanced/Minimal) with onImmersionChange + aria-label + 16px font + #immersionStatus (Protocol UI-5/17)'

# 145.9  proof-of-seam: memory-cycle flash respects the dial -- since A2 the gate is
#        the runtime's tier check (mem-cycle observer registered at tier 'balanced').
Check (
    $memCycleReg145 -match "id:\s*'mem-cycle'[\s\S]*?tier:\s*'balanced'"
) "145.9: the memory-cycle flash is dial-gated by the runtime -- registered as a tier 'balanced' observer (Full/Balanced fire, Minimal silent; single enforcement point)"

# 145.10  game-agnostic (Protocol 38): the dial code has no game literals
Check (
    -not (($getTierBody145 + $allowsBody145 + $setTierBody145 + $initImmBody145) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '145.10: the P8 immersion-dial code is game-agnostic (no game literals)'

# ===========================================================
# Suite 146 -- Step 2 (v2.8.0) Phase 2 A1: Ambient Runtime core (15 tests).
# Mirrors JS Suite 146. The one heartbeat + observer registry + central dial
# enforcement, ADDITIVE: A1 tracks the canonical terminal state (OFF->COLD_BOOT->
# READY->ACTIVE->IDLE->STANDBY->SHUTDOWN) in PARALLEL with the existing standby/
# timers, which stay untouched (A2 migrates them). Structural + boundary guards
# here; the state machine + observer gating + live dial gate are proven
# behaviorally in tests/test.html (Suite 18). Prime invariant #1 -- the HARD
# atmosphere/save boundary -- is gate-guarded by 146.12 (runtime.js writes
# nothing durable).
# ===========================================================
Sep "Suite 146 -- A1 Ambient Runtime core (state machine + scheduler + observer registry)"
$runtime146 = Read-Src "js/runtime.js"
$sw146 = Read-Src "sw.js"
$index146 = Read-Src "index.html"
$uiCore146 = Read-Src "js/ui-core.js"
$transitionBody146 = Get-FunctionBody $runtime146 'transition'
$beatBody146 = Get-FunctionBody $runtime146 '_beat'
$initRt146 = Get-FunctionBody $runtime146 'initAmbientRuntime'

# 146.1  js/runtime.js exists on disk (served file)
Check (
    Test-Path (Join-Path $Root "js/runtime.js")
) '146.1: js/runtime.js exists on disk (A1 new served file)'

# 146.2  ./js/runtime.js is precached in sw.js ASSETS
Check (
    $sw146 -match "'\./js/runtime\.js'"
) "146.2: './js/runtime.js' is listed in sw.js ASSETS (PWA precaches the runtime)"

# 146.3  index.html loads runtime.js and orders it BEFORE ui-core.js
Check (
    ($index146 -match '<script src="js/runtime\.js"></script>') -and
    ($index146.IndexOf('js/runtime.js') -lt $index146.IndexOf('js/ui-core.js'))
) '146.3: index.html loads js/runtime.js as a static tag ordered before js/ui-core.js'

# 146.4  window.AmbientRuntime exposes the full API surface
Check (
    ($runtime146 -match 'window\.AmbientRuntime = AmbientRuntime') -and
    ($runtime146 -match 'getState:\s*getState') -and
    ($runtime146 -match 'register:\s*register') -and
    ($runtime146 -match 'transition:\s*transition') -and
    ($runtime146 -match 'shutdown:\s*shutdown') -and
    ($runtime146 -match 'start:\s*start')
) '146.4: runtime.js exposes window.AmbientRuntime with getState / register / transition / shutdown / start'

# 146.5  the canonical 7-state machine is present, in lifecycle order
Check (
    $runtime146 -match "RUNTIME_STATES\s*=\s*\['OFF',\s*'COLD_BOOT',\s*'READY',\s*'ACTIVE',\s*'IDLE',\s*'STANDBY',\s*'SHUTDOWN'\]"
) '146.5: RUNTIME_STATES declares the canonical OFF->COLD_BOOT->READY->ACTIVE->IDLE->STANDBY->SHUTDOWN machine'

# 146.6  register() takes the documented observer spec and returns an unregister handle
Check (
    ($runtime146 -match 'function register\(spec\)') -and
    ($runtime146 -match 'spec\.cadenceMs') -and
    ($runtime146 -match 'spec\.states') -and
    ($runtime146 -match 'spec\.tier') -and
    ($runtime146 -match 'spec\.onTick') -and
    ($runtime146 -match 'spec\.onEnter') -and
    ($runtime146 -match 'spec\.onExit') -and
    ($runtime146 -match 'return function unregister\(\)')
) '146.6: register({id,cadenceMs,states,tier,onTick,onEnter,onExit}) reads every spec field and returns an unregister() handle'

# 146.7  ONE heartbeat: a single setInterval scheduler + a per-observer try/catch
Check (
    ([regex]::Matches($runtime146, 'setInterval\(_beat,').Count -eq 1) -and
    ($beatBody146 -match 'o\.onTick\(\)') -and
    ($beatBody146 -match '(?s)try \{.*o\.onTick\(\).*\} catch \(_\) \{')
) '146.7: one heartbeat (single setInterval(_beat)) runs every observer, each onTick wrapped in try/catch (one bad observer cannot break the beat)'

# 146.8  CENTRAL DIAL ENFORCEMENT: the ONE place immersionAllows is checked, live, fail-open
Check (
    ($runtime146 -match 'immersionAllows') -and
    ($beatBody146 -match 'if \(!_allows\(o\.tier\)\) continue;') -and
    ($runtime146 -match "typeof window\.immersionAllows === 'function' \? window\.immersionAllows\(tier\) : true")
) '146.8: the heartbeat gates every observer on _allows(tier) -> immersionAllows (single enforcement point), re-evaluated live, failing open when unavailable'

# 146.9  transition() is validated (unknown target + illegal edge rejected) and idempotent
Check (
    ($transitionBody146 -match 'RUNTIME_STATES\.indexOf\(to\) === -1\) return false') -and
    ($transitionBody146 -match 'if \(to === from\) return false') -and
    ($transitionBody146 -match 'LEGAL\[from\] && LEGAL\[from\]\.indexOf\(to\) !== -1')
) '146.9: transition() rejects an unknown target and an illegal edge, and is idempotent (to === from is a no-op)'

# 146.10  initAmbientRuntime() registers the ONE inert self-test observer and starts
Check (
    ($runtime146 -match 'function initAmbientRuntime\(\)') -and
    ($runtime146 -match 'window\.initAmbientRuntime = initAmbientRuntime') -and
    ($initRt146 -match "id:\s*'runtime-selftest'") -and
    ($initRt146 -match "tier:\s*'minimal'") -and
    ($initRt146 -match "states:\s*\['ACTIVE'\]") -and
    ($initRt146 -match 'start\(\);')
) "146.10: initAmbientRuntime() registers the inert 'runtime-selftest' observer (states ACTIVE, tier minimal) and starts the heartbeat"

# 146.11  wired into boot: ui-core.js window.onload calls initAmbientRuntime() after _wireStandby
Check (
    ($uiCore146 -match 'initAmbientRuntime\(\);') -and
    ($uiCore146.IndexOf('_wireStandby();') -lt $uiCore146.IndexOf('initAmbientRuntime();'))
) '146.11: window.onload calls initAmbientRuntime() after _wireStandby (so the STANDBY observer is registered before the runtime starts)'

# 146.12  HARD atmosphere/save boundary: runtime.js writes NOTHING durable to the campaign
Check (
    (-not ($runtime146 -match 'saveState')) -and
    (-not ($runtime146 -match 'robco_v8')) -and
    (-not ($runtime146 -match 'localStorage')) -and
    (-not ($runtime146 -match '_logEvent')) -and
    (-not ($runtime146 -match 'eventLog')) -and
    (-not ($runtime146 -match '\bstate\.[a-zA-Z_]'))
) '146.12: no-durable-write boundary -- runtime.js never calls saveState / touches robco_v8 / localStorage / eventLog / _logEvent / campaign state (device+in-memory only)'

# 146.13  BOOT-ORDER (U7): IIFE-wrapped; cross-file reads are typeof-guarded (fail-open)
Check (
    ($runtime146 -match '(?m)^\(function \(\) \{') -and
    ($runtime146 -match "typeof window\.immersionAllows === 'function'") -and
    ($runtime146 -match "window\.RobcoEvents && typeof window\.RobcoEvents\.emit === 'function'")
) '146.13: runtime.js top level only defines window.AmbientRuntime (IIFE-wrapped); every cross-file read (immersionAllows/RobcoEvents) is typeof-guarded and fails open (U7 boot-order lesson)'

# 146.14  game-agnostic (Protocol 38): pure lifecycle logic, no game literals
Check (
    -not ($runtime146 -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '146.14: the A1 Ambient Runtime is game-agnostic (no game literals -- pure lifecycle logic)'

# 146.15  forceState() TEST-ONLY escape hatch: transition(to, opts) accepts an
#         opts.force flag that bypasses the LEGAL adjacency check (unknown-target
#         + idempotent guards still apply, unchanged), forceState(to) is the sole
#         caller of that flag, is exposed on window.AmbientRuntime, and no
#         production call site anywhere in the file passes force:true (the
#         validated transition(to) -- every real caller -- keeps enforcing LEGAL
#         edges unchanged). Guards the RobCo U.O.S. Test Console fix where only
#         an adjacent-state button worked.
Check (
    ($runtime146 -match 'function transition\(to, opts\)') -and
    ($transitionBody146 -match 'var force = !!\(opts && opts\.force\);') -and
    ($transitionBody146 -match 'if \(!force && !\(LEGAL\[from\] && LEGAL\[from\]\.indexOf\(to\) !== -1\)\) return false;') -and
    ($runtime146 -match 'function forceState\(to\) \{\s*return transition\(to, \{ force: true \}\);\s*\}') -and
    ($runtime146 -match 'forceState:\s*forceState') -and
    ([regex]::Matches($runtime146, 'force:\s*true').Count -eq 1)
) '146.15: transition(to, opts.force) bypasses the LEGAL adjacency map only via forceState(to) (exposed on AmbientRuntime); exactly one force:true call site in the whole file -- no production path forces a state, and the validated transition(to) keeps enforcing LEGAL edges unchanged'

# ===========================================================
# Suite 147 -- Step 2 (v2.8.0) Phase 2 A2.1: Standby machine -> runtime observer (7 tests).
# Mirrors JS Suite 147. The tab-standby dim + audio ducking is migrated off its own
# blur/focus/visibilitychange listeners onto the Ambient Runtime's STANDBY state:
# _wireStandby now registers ONE coordinator observer (states ['STANDBY'], tier
# 'minimal') whose onEnter/onExit are the unchanged enterStandby/exitStandby. The
# runtime (A1) owns the blur/focus/visibility -> STANDBY/ACTIVE transitions, so the
# old direct listeners are retired (no double-wiring, no double-dim). Behavior-
# identical at every tier (standby is essential feedback -> tier 'minimal').
# ===========================================================
Sep "Suite 147 -- A2.1 standby machine migrated onto the Ambient Runtime (STANDBY observer)"
$uiCore147 = Read-Src "js/ui-core.js"
$wireStandbyBody147 = Get-FunctionBody $uiCore147 '_wireStandby'
$enterBody147 = Get-FunctionBody $uiCore147 'enterStandby'
$exitBody147 = Get-FunctionBody $uiCore147 'exitStandby'

# 147.1  _wireStandby registers a runtime observer with id 'standby'
Check (
    ($wireStandbyBody147 -match 'AmbientRuntime\.register\(\{') -and
    ($wireStandbyBody147 -match "id:\s*'standby'")
) "147.1: _wireStandby registers an AmbientRuntime observer (id 'standby') -- standby is now runtime-driven"

# 147.2  the standby observer runs in STANDBY at tier 'minimal' (essential -- never quiets)
Check (
    ($wireStandbyBody147 -match "states:\s*\['STANDBY'\]") -and
    ($wireStandbyBody147 -match "tier:\s*'minimal'")
) "147.2: the standby observer declares states ['STANDBY'] and tier 'minimal' (essential feedback, never dial-quieted)"

# 147.3  its lifecycle hooks are the unchanged enterStandby / exitStandby
Check (
    ($wireStandbyBody147 -match 'onEnter:\s*enterStandby') -and
    ($wireStandbyBody147 -match 'onExit:\s*exitStandby')
) '147.3: the standby observer folds enterStandby/exitStandby into the runtime STANDBY on-enter/on-exit'

# 147.4  the OLD direct blur/focus/visibilitychange listeners are retired from _wireStandby
Check (
    (-not ($wireStandbyBody147 -match "addEventListener\(\s*'blur'")) -and
    (-not ($wireStandbyBody147 -match "addEventListener\(\s*'focus'")) -and
    (-not ($wireStandbyBody147 -match "addEventListener\(\s*'visibilitychange'"))
) '147.4: _wireStandby no longer wires blur/focus/visibilitychange directly (retired -- the runtime drives STANDBY/ACTIVE)'

# 147.5  enterStandby still ducks the AUDIO on standby -- stops the self-scheduling geiger
#        + audio heartbeat and ramps the CRT hum down. (A2 moved the uptime/memory-cycle
#        interval management out: those observers auto-pause, so no interval is cleared.)
Check (
    ($enterBody147 -match 'geigerRunning = false') -and
    ($enterBody147 -match 'stopHeartbeat\(\)') -and
    (-not ($enterBody147 -match 'clearInterval\('))
) '147.5: enterStandby ducks the audio (stops geiger + heartbeat, hum-down) and no longer clears any interval (uptime/mem-cycle observers auto-pause)'

# 147.6  exitStandby still restores on wake (wake tone, un-dim, geiger resume, updateMath)
#        but no longer manually restarts clocks (observers auto-resume on ACTIVE re-entry).
Check (
    ($exitBody147 -match 'playWakeTone\(\)') -and
    ($exitBody147 -match "classList\.remove\('standby'\)") -and
    ($exitBody147 -match 'setGeigerRate\(') -and
    ($exitBody147 -match 'updateMath\(\)') -and
    (-not ($exitBody147 -match '_startUptimeClock\(\)')) -and
    (-not ($exitBody147 -match '_startMemCycle\(\)'))
) '147.6: exitStandby plays the wake tone, un-dims, resumes geiger + re-syncs updateMath, and no longer manually restarts the clocks (observers auto-resume)'

# 147.7  enterStandby/exitStandby keep their idempotency guard
Check (
    ($enterBody147 -match 'if \(_standbyActive\) return;') -and
    ($exitBody147 -match 'if \(!_standbyActive\) return;')
) '147.7: enterStandby/exitStandby retain the _standbyActive idempotency guard (no double-dim even if called twice)'

# ===========================================================
# Suite 148 -- Step 2 (v2.8.0) Phase 2 A2.2: fixed-cadence timers -> runtime observers (7 tests).
# Mirrors JS Suite 148. The three fixed-cadence loops -- uptime clock (1s), memory-cycle
# flash (15min), overseer-log flush (30s) -- migrate off their setIntervals onto the
# Ambient Runtime as observers. Two runtime refinements make it byte-identical: register()
# seeds _lastTick to now (first tick one cadence later, like setInterval), and transition()
# restarts an observer's cadence clock when it re-enters its state set (paused-then-resumed
# behaves like a setInterval cleared on standby and restarted on wake). Tiers give the dial
# teeth ONLY below default: uptime + overseer 'minimal' (never quiet), mem-cycle 'balanced'
# (silent at Minimal). The migrated bodies write nothing durable to the campaign.
# ===========================================================
Sep "Suite 148 -- A2.2 uptime clock + memory cycle + overseer flush migrated to runtime observers"
$runtime148 = Read-Src "js/runtime.js"
$uiCore148 = Read-Src "js/ui-core.js"
$registerBody148 = Get-FunctionBody $runtime148 'register'
$transitionBody148 = Get-FunctionBody $runtime148 'transition'
$startAmbient148 = Get-FunctionBody $uiCore148 '_startAmbientTimers'
$initOverseer148 = Get-FunctionBody $uiCore148 'initOverseerLog'
$tickUptime148 = Get-FunctionBody $uiCore148 '_tickUptimeClock'
$tickMem148 = Get-FunctionBody $uiCore148 '_tickMemCycle'

# 148.1  register() seeds _lastTick to now -- setInterval parity (no immediate first fire)
Check (
    $registerBody148 -match '_lastTick:\s*_now\(\)'
) '148.1: register() seeds _lastTick to _now() so a cadenceMs>0 observer first ticks one full cadence after registration (setInterval parity, not an immediate fire)'

# 148.2  transition() restarts the cadence clock on state-set entry (byte-identical wake)
Check (
    ($transitionBody148 -match 'nowIn && !wasIn') -and
    ($transitionBody148 -match 'o\._lastTick = _now\(\)')
) '148.2: transition() resets an observer _lastTick when it (re-)enters its state set -- cadence restarts on wake, matching the old clear-on-standby / restart-on-wake timing'

# 148.3  uptime-clock observer: awake states only, tier minimal, 1s cadence
Check (
    ($startAmbient148 -match "id:\s*'uptime-clock'") -and
    ($startAmbient148 -match "states:\s*\['ACTIVE',\s*'IDLE'\]") -and
    ($startAmbient148 -match "tier:\s*'minimal'") -and
    ($startAmbient148 -match 'cadenceMs:\s*1000')
) "148.3: the uptime clock is a runtime observer (states ['ACTIVE','IDLE'], tier 'minimal', cadence 1000ms) -- pauses on standby, never dial-quieted"

# 148.4  mem-cycle observer: awake states, tier balanced (dial teeth), 15-min cadence
Check (
    ($startAmbient148 -match "id:\s*'mem-cycle'") -and
    ($startAmbient148 -match "tier:\s*'balanced'") -and
    ($startAmbient148 -match 'cadenceMs:\s*900000')
) "148.4: the memory-cycle flash is a runtime observer (tier 'balanced', cadence 900000ms) -- dial-gated by the runtime, silent at Minimal (its former immersionAllows('balanced') gate)"

# 148.5  overseer-flush observer: runs in ALL live states incl. STANDBY, tier minimal, 30s
Check (
    ($initOverseer148 -match "id:\s*'overseer-flush'") -and
    ($initOverseer148 -match "states:\s*\['READY',\s*'ACTIVE',\s*'IDLE',\s*'STANDBY'\]") -and
    ($initOverseer148 -match "tier:\s*'minimal'") -and
    ($initOverseer148 -match 'cadenceMs:\s*30000')
) "148.5: the overseer flush is a runtime observer including STANDBY (power-on accounting keeps ticking while blurred), tier 'minimal', cadence 30000ms"

# 148.6  the old standalone setInterval timers for these three are retired -- ui-core.js
#        no longer calls setInterval at all (the runtime heartbeat is the one scheduler)
Check (
    (-not ($uiCore148 -match 'function\s+_startUptimeClock')) -and
    (-not ($uiCore148 -match 'function\s+_startMemCycle')) -and
    (-not ($uiCore148 -match '_overseerFlushTimer')) -and
    ([regex]::Matches($uiCore148, 'setInterval\(').Count -eq 0)
) '148.6: the standalone uptime/mem-cycle/overseer setIntervals are retired -- ui-core.js no longer calls setInterval (the runtime heartbeat is the single scheduler)'

# 148.7  no-durable-write: the migrated observer bodies never write the campaign save
Check (
    (-not ($tickUptime148 -match 'saveState|robco_v8|_logEvent|\beventLog\b')) -and
    (-not ($tickMem148 -match 'saveState|robco_v8|_logEvent|\beventLog\b')) -and
    (-not ($initOverseer148 -match 'saveState|robco_v8|_logEvent|\beventLog\b'))
) '148.7: the migrated uptime/mem-cycle/overseer observer bodies never write the campaign save (robco_v8 / saveState / eventLog / _logEvent) -- device + DOM only (atmosphere/save boundary)'

# ===========================================================
# Suite 149 -- Developer Console: the ONE canonical dev/debug console (16 tests).
# Mirrors JS Suite 149. A live inspector + trigger panel for the Ambient
# Runtime. This IS the canonical developer/debug console the roadmap's
# hacking minigame will later unlock in normal builds -- not a throwaway test
# panel. Visibility is centralized in ONE gate, _devConsoleUnlocked(): today
# it delegates verbatim to the EXACT SAME env signal the changelog viewer
# (Suite 62 / WU-C11) uses to hide [Unreleased] on production --
# _isStagingEnv(), never re-implemented -- so dev/staging builds skip the
# hack entirely. Fail-safe to HIDDEN -- any uncertainty defaults to
# production behavior. On production it stays false until a future
# minigame-unlock check is added to that same one function (the seam is
# documented in a comment right on it). The panel markup lives inert inside a
# <template> (the WU-E2 disabled-banner pattern) so it can never render by
# accident. Writes NOTHING durable to the campaign (runtime state + the
# existing Immersion device pref only). 149.8's both-sides proof is a
# STRUCTURAL mirror of the JS eval-based behavioral test (PowerShell has no
# JS eval) -- same convention as Suite 62.5.
# ===========================================================
Sep "Suite 149 -- Developer Console: the ONE canonical dev/debug console"
$testConsole149 = Read-Src "js/test-console.js"
$sw149 = Read-Src "sw.js"
$index149 = Read-Src "index.html"
$uiCore149 = Read-Src "js/ui-core.js"
$runtime149 = Read-Src "js/runtime.js"
$initTestConsoleBody149 = Get-FunctionBody $testConsole149 'initTestConsole'
$isStagingBody149 = Get-FunctionBody $testConsole149 '_devConsoleUnlocked'

# 149.1  js/test-console.js exists on disk (new served file)
Check (
    Test-Path (Join-Path $Root "js/test-console.js")
) '149.1: js/test-console.js exists on disk (Test Console new served file)'

# 149.2  ./js/test-console.js is precached in sw.js ASSETS
Check (
    $sw149 -match "'\./js/test-console\.js'"
) "149.2: './js/test-console.js' is listed in sw.js ASSETS (PWA precaches the console)"

# 149.3  index.html loads test-console.js AFTER ui-core.js and before api.js
Check (
    ($index149 -match '<script src="js/test-console\.js"></script>') -and
    ($index149.IndexOf('<script src="js/ui-core.js"></script>') -lt $index149.IndexOf('<script src="js/test-console.js"></script>')) -and
    ($index149.IndexOf('<script src="js/test-console.js"></script>') -lt $index149.IndexOf('<script src="js/api.js"></script>'))
) '149.3: index.html loads js/test-console.js as a static tag ordered after js/ui-core.js and before js/api.js'

# 149.4  the panel markup lives inert inside <template id="testConsoleTemplate">
#        (WU-E2 disabled-by-default pattern) with a separate mount point outside it
Check (
    ($index149 -match '<template id="testConsoleTemplate">') -and
    ($index149 -match 'id="testConsolePanel"') -and
    ($index149 -match 'id="testConsoleTransitions"') -and
    ($index149 -match 'id="testConsoleImmersionSelect"') -and
    ($index149 -match 'id="testConsoleObservers"') -and
    ($index149 -match '<div id="testConsoleMount"></div>')
) '149.4: index.html carries the inert <template id="testConsoleTemplate"> (panel/transitions/immersion-select/observers) plus a separate #testConsoleMount clone target'

# 149.5  window.onload calls initTestConsole() after initAmbientRuntime()
Check (
    $uiCore149 -match '(?s)initAmbientRuntime\(\);.*?initTestConsole\(\);'
) '149.5: window.onload calls initTestConsole() after initAmbientRuntime() (the runtime must exist first)'

# 149.6  initTestConsole() gates on _devConsoleUnlocked() as its very first
#        statement -- fail-safe-to-hidden, mirroring the WU-C11 changelog env
#        gate -- and is wrapped so a console failure can never break boot.
Check (
    ($initTestConsoleBody149 -match "(?s)^\{\s*try\s*\{\s*\n\s*if \(!_devConsoleUnlocked\(\)\) return;") -and
    ($initTestConsoleBody149 -match '\} catch \(_\) \{')
) '149.6: initTestConsole() returns immediately unless _devConsoleUnlocked() is true (fail-safe-to-hidden, checked first) and is wrapped in try/catch'

# 149.7  _devConsoleUnlocked() is the ONE canonical gate (Protocol 22 -- not
#        several re-derived checks) and today REUSES ui-core.js's
#        _isStagingEnv() verbatim -- no re-implementation of the
#        env-detection logic -- failing OPEN (false = hidden) on any throw or
#        missing function. The minigame-unlock seam is documented right on
#        the function so a future unlock check has one obvious home.
Check (
    ($isStagingBody149 -match "typeof window\._isStagingEnv === 'function' \? window\._isStagingEnv\(\) : false") -and
    ($isStagingBody149 -match '(?s)catch \(_\) \{\s*return false;') -and
    (-not ($testConsole149 -match 'meta\[name="robco-env"\]')) -and
    (-not ($testConsole149 -match 'pages\.dev'))
) '149.7: _devConsoleUnlocked() calls window._isStagingEnv() verbatim (no re-implemented env-detection logic) and fails open to false (hidden) on any uncertainty'

# 149.8  BOTH-SIDES (structural mirror of the JS eval-based behavioral proof --
#        PowerShell has no JS eval, same convention as Suite 62.5): the ternary
#        guarantees true only propagates when _isStagingEnv() itself returns
#        true, and the catch guarantees any throw resolves to false (hidden).
Check (
    ($isStagingBody149 -match "\? window\._isStagingEnv\(\) : false") -and
    ($isStagingBody149 -match '(?s)try \{.*catch \(_\) \{\s*return false;')
) 'env-aware Developer Console: hidden (false) when the staging signal is missing/throws/false, shown (true) only when it is genuinely true (both-sides structural mirror)'

# 149.9  HARD atmosphere/save boundary: test-console.js never writes the
#        campaign save -- no saveState, no robco_v8, no eventLog/_logEvent,
#        no direct localStorage (device prefs route through the reused
#        onImmersionChange/getImmersionTier setters, never a raw write here).
Check (
    -not ($testConsole149 -match 'saveState|robco_v8|_logEvent|\beventLog\b|localStorage\.')
) '149.9: test-console.js never calls saveState / touches robco_v8 / localStorage / eventLog / _logEvent (device + in-memory only -- Phase-2 prime invariant #1)'

# 149.10  the Immersion-tier control REUSES the real dial's own setter
#         (onImmersionChange/getImmersionTier) rather than re-implementing
#         setImmersionTier persistence, and keeps the real #immersionSelect in sync.
Check (
    ($testConsole149 -match 'window\.onImmersionChange\(sel\.value\)') -and
    ($testConsole149 -match 'window\.getImmersionTier\(\)') -and
    ($testConsole149 -match "getElementById\('immersionSelect'\)") -and
    (-not ($testConsole149 -match 'setImmersionTier'))
) "149.10: the console reuses the real dial's own onImmersionChange()/getImmersionTier() (Protocol 22) and mirrors the real #immersionSelect -- never a parallel setImmersionTier call"

# 149.11  runtime.js exposes a READ-ONLY observer introspection API --
#         listObservers() returns plain data (id/states/tier/cadenceMs) only,
#         never the onTick/onEnter/onExit closures -- consumed by the console.
Check (
    ($runtime149 -match 'function listObservers\(\)') -and
    ($runtime149 -match 'listObservers:\s*listObservers') -and
    ($runtime149 -match '_observers\.map\(function \(o\) \{') -and
    ($runtime149 -match 'return \{ id: o\.id, states: o\.states\.slice\(\), tier: o\.tier, cadenceMs: o\.cadenceMs \};')
) '149.11: AmbientRuntime.listObservers() is a read-only introspection API -- a plain-data map (id/states/tier/cadenceMs), never the onTick/onEnter/onExit closures'

# 149.12  dynamic content (state names, observer ids/states/tier/cadence) is
#         escaped before being written into innerHTML (XSS-safe)
Check (
    ([regex]::Matches($testConsole149, 'escapeHtml\(')).Count -ge 5
) '149.12: transition-button labels and the observer read-out run every dynamic value through escapeHtml() before innerHTML (XSS-safe)'

# 149.13  game-agnostic (Protocol 38): pure dev-tooling, no game literals
Check (
    -not ($testConsole149 -match 'FNV|FO3|New Vegas|Fallout 3')
) '149.13: the Developer Console is game-agnostic (no FNV/FO3/game-title literals -- pure dev tooling)'

# 149.14  the minigame-unlock seam is documented on _devConsoleUnlocked()
#         itself, so a future refactor can't silently lose the one place a
#         hacking-minigame unlock check is meant to be added.
Check (
    ($testConsole149 -match 'MINIGAME-UNLOCK SEAM') -and
    ($testConsole149 -match 'canonical dev/debug console')
) "149.14: _devConsoleUnlocked() carries a documented MINIGAME-UNLOCK SEAM comment marking it as the one hook a future hacking minigame will flip -- this is the canonical console, not a throwaway test panel"

# 149.15  owner report fix: only the 4 states with a VISIBLE A3 ambient effect
#         (IDLE/STANDBY/SHUTDOWN/OFF) get a force button -- COLD_BOOT/READY/ACTIVE
#         were dead buttons (normal-op states, no observer of their own) and are
#         filtered out. Every remaining button still routes through
#         AmbientRuntime.forceState() (bypassing the LEGAL adjacency map), with the
#         retired SHUTDOWN-only special case (AmbientRuntime.shutdown()) still gone.
Check (
    ($testConsole149 -match "VISIBLE_EFFECT_STATES = \['IDLE', 'STANDBY', 'SHUTDOWN', 'OFF'\]") -and
    ($testConsole149 -match 'VISIBLE_EFFECT_STATES\.indexOf\(s\) !== -1') -and
    ($testConsole149 -match 'window\.AmbientRuntime\.forceState\(target\)') -and
    (-not ($testConsole149 -match "target === 'SHUTDOWN'")) -and
    (-not ($testConsole149 -match 'window\.AmbientRuntime\.shutdown\(\)')) -and
    ($testConsole149 -match "typeof window\.AmbientRuntime\.transition === 'function'")
) '149.15: only the 4 states with a visible A3 ambient effect (IDLE/STANDBY/SHUTDOWN/OFF) get a force button -- COLD_BOOT/READY/ACTIVE (dead buttons, owner report) are filtered out; every remaining button still routes through AmbientRuntime.forceState(target), the retired SHUTDOWN-only special case stays gone'

# 149.16  owner report fix: REBOOT replays the real boot sequence (resetting the
#         boot screen's display/classList first, since it's hidden via style, never
#         removed from the DOM) and WAKE -> ACTIVE is the one-click undo for the
#         IDLE/STANDBY/SHUTDOWN/OFF force buttons -- both replace the retired
#         COLD_BOOT/READY/ACTIVE buttons, and neither writes the campaign save.
$rebootFn149 = Get-FunctionBody $testConsole149 '_rebootFromConsole'
$wakeFn149 = Get-FunctionBody $testConsole149 '_wakeToActive'
Check (
    ($rebootFn149 -match "bootScreen\.style\.display = ''") -and
    ($rebootFn149 -match "classList\.remove\('boot-fade-out', 'boot-degraded'\)") -and
    ($rebootFn149 -match "window\.runBootSequence === 'function'\) window\.runBootSequence\(\)") -and
    ($wakeFn149 -match "window\.AmbientRuntime\.forceState\('ACTIVE'\)") -and
    ($testConsole149 -match '_wireResetControls\(panel\)') -and
    (-not (($rebootFn149 + $wakeFn149) -match 'saveState|robco_v8|localStorage\.'))
) '149.16: REBOOT resets the boot screen then replays window.runBootSequence(); WAKE -> ACTIVE force-states back to ACTIVE (the undo for the IDLE/STANDBY/SHUTDOWN/OFF buttons); neither touches the campaign save (owner report fix)'

# ===========================================================
# Suite 150 -- Step 2 (v2.8.0) Phase 2 A3: IDLE/STANDBY/SHUTDOWN ambient
# experiences (9 tests). Mirrors JS Suite 150. The showcase consumers of the
# runtime states: _wireAmbientExperiences() (ui-core.js) registers three
# dial-gated observers -- idle-phosphor (tier balanced), standby-deepen (tier
# balanced, layered OVER the A2 essential 'minimal'-tier dim, unchanged), and
# shutdown-crt (tier full, degrading to a plain instant cut below Full).
# onEnter/onExit are NOT tier-gated by the runtime itself (only onTick is --
# see runtime.js's _beat()), so each observer's onEnter checks
# immersionAllows() itself before toggling its body class; onExit always
# cleans up unconditionally (no leaked class). shutdown-crt's states include
# OFF so its one-shot animation trigger survives the internal SHUTDOWN->OFF
# cascade (shutdown() fires both synchronously) without re-firing. A
# companion fix in exitStandby() (A2, unchanged otherwise) closes a race
# found while verifying this unit (Protocol 42): the wake sequence (tone +
# audio ramp + chat line) must fire ONLY on a genuine return to active use,
# never on a power-down -- and a shutdown can land either as a direct
# STANDBY->SHUTDOWN edge OR partway through the 650ms wake window that
# already started. Rather than a single up-front check (which only catches
# the direct edge), the shared _isShuttingDown() helper is re-checked at EACH
# half's own fire time: once synchronously before the tone, again inside the
# setTimeout before the ramp/chat/geiger-resync -- so either half
# independently no-ops the moment it discovers the terminal is powering
# down, closing both races. Pure CSS + classList toggles; the atmosphere/
# save boundary and Protocol 38 (game-agnostic) are gate-guarded below.
# ===========================================================
Sep "Suite 150 -- A3 IDLE/STANDBY/SHUTDOWN ambient experiences"
$uiCore150 = Read-Src "js/ui-core.js"
$css150 = Read-Src "css/terminal.css"
$wireAmbient150 = Get-FunctionBody $uiCore150 '_wireAmbientExperiences'
$exitStandbyBody150 = Get-FunctionBody $uiCore150 'exitStandby'
$isShuttingDownBody150 = Get-FunctionBody $uiCore150 '_isShuttingDown'

# 150.1  _wireAmbientExperiences() is wired into window.onload after
#        _wireStandby() and before initAmbientRuntime() (registration order)
Check (
    $uiCore150 -match '(?s)_wireStandby\(\);.*?_wireAmbientExperiences\(\);.*?initAmbientRuntime\(\);'
) '150.1: window.onload calls _wireAmbientExperiences() after _wireStandby() and before initAmbientRuntime()'

# 150.2  idle-phosphor observer: states ['IDLE'], tier 'balanced', gates its
#        own onEnter on immersionAllows('balanced'), onExit always cleans up
Check (
    ($wireAmbient150 -match "id:\s*'idle-phosphor'") -and
    ($wireAmbient150 -match "states:\s*\['IDLE'\]") -and
    ($wireAmbient150 -match "tier:\s*'balanced'") -and
    ($wireAmbient150 -match "(?s)if \(typeof immersionAllows === 'function' && !immersionAllows\('balanced'\)\) return;\s*\n\s*document\.body\.classList\.add\('rt-idle'\);") -and
    ($wireAmbient150 -match "onExit:\s*\(\)\s*=>\s*document\.body\.classList\.remove\('rt-idle'\)")
) "150.2: idle-phosphor observer (states ['IDLE'], tier 'balanced') gates onEnter's 'rt-idle' class add on immersionAllows('balanced'); onExit unconditionally removes it"

# 150.3  standby-deepen observer: states ['STANDBY'], tier 'balanced', same
#        gate-on-enter/unconditional-exit pattern, layered over the A2 dim
Check (
    ($wireAmbient150 -match "id:\s*'standby-deepen'") -and
    ($wireAmbient150 -match "states:\s*\['STANDBY'\]") -and
    (([regex]::Matches($wireAmbient150, "tier:\s*'balanced'")).Count -eq 2) -and
    ($wireAmbient150 -match "document\.body\.classList\.add\('standby-deep'\)") -and
    ($wireAmbient150 -match "onExit:\s*\(\)\s*=>\s*document\.body\.classList\.remove\('standby-deep'\)")
) "150.3: standby-deepen observer (states ['STANDBY'], tier 'balanced') adds/removes 'standby-deep' as an ADDITIONAL flourish over the unchanged tier-'minimal' A2 dim"

# 150.4  shutdown-crt observer: states include BOTH 'SHUTDOWN' and 'OFF' (so
#        the one-shot animation survives the internal SHUTDOWN->OFF cascade),
#        tier 'full', force-clears any lingering idle/standby class first,
#        and picks the full-flourish vs plain-cut class via immersionAllows('full')
Check (
    ($wireAmbient150 -match "id:\s*'shutdown-crt'") -and
    ($wireAmbient150 -match "states:\s*\['SHUTDOWN',\s*'OFF'\]") -and
    ($wireAmbient150 -match "tier:\s*'full'") -and
    ($wireAmbient150 -match "classList\.remove\('rt-idle', 'standby-deep', 'standby'\)") -and
    ($wireAmbient150 -match "classList\.add\(full \? 'rt-shutdown' : 'rt-shutdown-plain'\)") -and
    ($wireAmbient150 -match "classList\.remove\('rt-shutdown', 'rt-shutdown-plain'\)")
) "150.4: shutdown-crt observer (states ['SHUTDOWN','OFF'], tier 'full') force-clears any lingering idle/standby flourish, then adds the full-flourish or plain-cut class per immersionAllows('full'); onExit removes both on leaving the set"

# 150.5  _isShuttingDown() is the single SHUTDOWN/OFF check, and exitStandby()
#        re-checks it at EACH half's own fire time: once synchronously BEFORE
#        playWakeTone() (that half's fire time is now), and again as the
#        FIRST statement inside the setTimeout body (that half's fire time is
#        650ms later) -- not just a single up-front check, which would only
#        catch a direct STANDBY->SHUTDOWN edge and miss a shutdown landing
#        mid-window after the tone already played.
Check (
    ($isShuttingDownBody150 -match "AmbientRuntime\.getState\(\) === 'SHUTDOWN' \|\| AmbientRuntime\.getState\(\) === 'OFF'") -and
    ($exitStandbyBody150 -match "(?s)if \(_isShuttingDown\(\)\) return;.*?playWakeTone\(\);") -and
    ($exitStandbyBody150 -match "(?s)setTimeout\(\(\) => \{\s*\n(?:\s*//.*\n)*\s*if \(_isShuttingDown\(\)\) return;")
) "150.5: _isShuttingDown() is re-checked at each half's own fire time in exitStandby() -- synchronously before playWakeTone(), and again as the first statement inside the delayed setTimeout body -- so a shutdown landing either as a direct edge OR mid-window both no-op their half of the wake sequence"

# 150.6  HARD atmosphere/save boundary (Phase-2 prime invariant #1): none of
#        the new A3 code writes anything durable to the campaign
Check (
    -not (($wireAmbient150 + $exitStandbyBody150 + $isShuttingDownBody150) -match 'saveState|robco_v8|_logEvent|\beventLog\b|localStorage\.(set|get)Item')
) '150.6: _wireAmbientExperiences(), exitStandby(), and _isShuttingDown() never call saveState / touch robco_v8 / localStorage / eventLog / _logEvent (device+in-memory+DOM classList only)'

# 150.7  CSS: every new body class is defined, standby-deep uses ::before
#        (not ::after, which body.standby already owns for its diegetic
#        text) so the two coexist without clobbering each other, and the
#        SHUTDOWN cover's z-index exceeds #bootScreen's so a genuine
#        shutdown always wins visually over any other overlay
Check (
    ($css150 -match 'body\.rt-idle \.container') -and
    ($css150 -match 'body\.rt-idle::after') -and
    ($css150 -match 'body\.standby-deep::before') -and
    (-not ($css150 -match 'body\.standby-deep::after')) -and
    ($css150 -match 'body\.rt-shutdown \.container') -and
    ($css150 -match "(?s)body\.rt-shutdown::after,\s*\n\s*body\.rt-shutdown-plain::after") -and
    ($css150 -match '(?s)#bootScreen\s*\{.*?z-index:\s*100000;') -and
    ($css150 -match "(?s)body\.rt-shutdown::after,\s*\n\s*body\.rt-shutdown-plain::after\s*\{.*?z-index:\s*100001;")
) "150.7: terminal.css defines rt-idle/standby-deep/rt-shutdown(-plain); standby-deep uses ::before (never ::after, which body.standby owns) so the two dims coexist; the shutdown cover's z-index (100001) exceeds #bootScreen's (100000) so shutdown always wins visually"

# 150.8  reduced-motion: every new keyframe animation is a plain `animation:`
#        declaration (caught by the existing blanket * prefers-reduced-motion
#        rule -- no bespoke per-class reduced-motion override was added, since
#        none is needed)
Check (
    ($css150 -match '@keyframes idle-breathe') -and
    ($css150 -match '@keyframes standby-breathe') -and
    ($css150 -match '@keyframes crt-power-off') -and
    ($css150 -match '@keyframes shutdown-cover \{') -and
    ($css150 -match '@keyframes shutdown-cover-plain') -and
    ($css150 -match 'animation: idle-breathe') -and
    ($css150 -match 'animation: standby-breathe') -and
    ($css150 -match 'animation: crt-power-off') -and
    ($css150 -match 'animation: shutdown-cover ') -and
    ($css150 -match 'animation: shutdown-cover-plain')
) '150.8: every A3 keyframe (idle-breathe/standby-breathe/crt-power-off/shutdown-cover/shutdown-cover-plain) is applied via a plain `animation:` declaration, so the existing global prefers-reduced-motion block (animation-duration:0.01ms + iteration-count:1 on *) neutralises all of them to their static/instant final frame -- no bespoke override needed'

# 150.9  game-agnostic (Protocol 38): pure lifecycle/CSS atmosphere, no game literals
Check (
    -not (($wireAmbient150 + $exitStandbyBody150 + $isShuttingDownBody150) -match 'FNV|FO3|Fallout|New Vegas|Mojave|Capital Wasteland')
) '150.9: the A3 ambient experiences are game-agnostic (no game literals -- pure lifecycle/CSS atmosphere)'

# 150.10  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#         has no JS execution sandbox -- same convention as Suite 149.8): the
#         three scenarios the JS side actually EXECUTES are locked here as
#         source-shape guards instead -- (a) the direct-edge guard sits before
#         playWakeTone() [confirmed by 150.5 above]; (b) the normal-wake body
#         (tone + chat line + updateMath) is completely unchanged/unguarded
#         other than the two _isShuttingDown() checks; (c) the mid-window
#         guard is the FIRST statement inside the setTimeout, before ANY of
#         the ramp/chat/updateMath side effects, so a state change during the
#         650ms delay is caught before any of them run.
Check (
    ($exitStandbyBody150 -match "playWakeTone\(\);") -and
    ($exitStandbyBody150 -match "appendToChat\('> COURIER RETURNED\. SYNCHRONIZING TELEMETRY\.\.\.', 'sys', true\);") -and
    ($exitStandbyBody150 -match "updateMath\(\);") -and
    ($exitStandbyBody150 -match "(?s)setTimeout\(\(\) => \{\s*\n(?:\s*//.*\n)*\s*if \(_isShuttingDown\(\)\) return;\s*\n\s*document\.body\.classList\.remove\('standby'\);") -and
    ($exitStandbyBody150.IndexOf('if (_isShuttingDown()) return;') -lt $exitStandbyBody150.LastIndexOf('if (_isShuttingDown()) return;')) -and
    (([regex]::Matches($exitStandbyBody150, 'if \(_isShuttingDown\(\)\) return;')).Count -eq 2)
) "150.10: structural mirror of the JS behavioral proof -- exactly two _isShuttingDown() checks exist (one before the tone, one as the first statement inside the setTimeout, strictly before classList.remove/chat/updateMath), and the normal-wake body (tone/chat line/updateMath) is otherwise unchanged"

# ===========================================================
# Suite 151 -- Step 2 (v2.8.0) Phase 2 B1: Command-Line MODE system
# (18 tests). Mirrors JS Suite 151. The inline mode pill (TERMINAL/
# OVERSEER) in the Comm-Link input, the one-off `/`/`@` override
# prefixes, quick-log routing (killed/caps/arrived/rep) onto existing
# native setters, and a TERMINAL-mode autocomplete extension of the
# shared registry-autocomplete singleton.
# ===========================================================
Sep "Suite 151 -- Step 2 Phase 2 B1: Command-Line MODE system"
$stateSrc151 = Read-Src "js/state.js"
$apiSrc151 = Read-Src "js/api.js"
$uiCoreSrc151 = Read-Src "js/ui-core.js"
$uiSavesSrc151 = Read-Src "js/ui-saves.js"
$htmlSrc151 = Read-Src "index.html"
$cssSrc151 = Read-Src "css/terminal.css"

# 151.1  robco_input_mode is registered as a DEVICE PREFERENCE (MetaStore),
#        never campaign state -- same two-store boundary as robco_immersion.
Check (
    $stateSrc151 -match "robco_input_mode:\s*\{\s*type:\s*'string',\s*default:\s*'overseer',\s*owner:\s*'state\.js'\s*\}"
) "151.1: robco_input_mode is registered in META_MANIFEST as a device pref (default 'overseer')"

# 151.2  get/set/other accessors defined in state.js, mirroring the
#        Immersion-dial pattern exactly (Protocol 22)
Check (
    ($stateSrc151 -match "function getInputMode\(\)") -and
    ($stateSrc151 -match "function setInputMode\(mode\)") -and
    ($stateSrc151 -match "function otherInputMode\(mode\)") -and
    ($stateSrc151 -match "MetaStore\.get\(INPUT_MODE_KEY\)") -and
    ($stateSrc151 -match "MetaStore\.set\(INPUT_MODE_KEY, m\)")
) "151.2: getInputMode/setInputMode/otherInputMode defined in state.js and round-trip through MetaStore only"

# 151.3  the pill is a real <button> (Protocol UI-5) with a diegetic
#        aria-label, and the hint reveal element exists
Check (
    ($htmlSrc151 -match '<button\s[^>]*id="modePill"[^>]*class="action-btn btn-sm mode-pill mode-pill--overseer"[^>]*onclick="toggleInputMode\(\)"[^>]*aria-label="[^"]+"') -and
    ($htmlSrc151 -match '<div id="modeHintPopup" class="mode-hint"')
) '151.3: #modePill is a real <button> (action-btn btn-sm mode-pill) with onclick + aria-label; #modeHintPopup exists'

# 151.4  the pill and the Ctrl+Enter/[TRANSMIT] paths route through the ONE
#        new choke point, submitCommandInput() -- the direct transmitMessage()
#        call sites are gone from index.html (moved behind the resolver)
Check (
    ($htmlSrc151 -match 'onclick="submitCommandInput\(\)"') -and
    ($htmlSrc151 -match "(?s)submitCommandInput\(\);\s*\n\s*\}") -and
    (-not ($htmlSrc151 -match 'onclick="transmitMessage\(\)"'))
) '151.4: [TRANSMIT PROTOCOL] and Ctrl+Enter both call submitCommandInput(); no direct transmitMessage() call site remains in index.html'

# 151.5  transmitMessage() gained an OPTIONAL overrideText param -- additive,
#        no-arg behavior (every existing call site) is unchanged
Check (
    ($apiSrc151 -match "async function transmitMessage\(overrideText\)") -and
    ($apiSrc151 -match "const userText = \(typeof overrideText === 'string' \? overrideText : inputEl\.value\)\.trim\(\);")
) "151.5: transmitMessage(overrideText) -- an optional param; called with no args it reads #chatInput exactly as before"

# 151.6  transmitTerminal(): native commands first on the WHOLE unsplit line
#        (muscle memory -- a [TOKEN]'s own args are never comma-split), then
#        comma-separated quick-log routing, else a hint -- and it NEVER calls
#        the AI (no fetch, no Director-Link payload assembly)
$transmitTerminalBody151 = Get-FunctionBody $apiSrc151 'transmitTerminal'
Check (
    ($transmitTerminalBody151 -match "_routeNativeCommand\(userText\)") -and
    ($transmitTerminalBody151 -match "_routeQuickLogMulti\(userText\)") -and
    ($transmitTerminalBody151 -match "UNRECOGNIZED") -and
    (-not ($transmitTerminalBody151 -match "fetch\(|generateSyncPayload|getSystemDirective"))
) '151.6: transmitTerminal() tries _routeNativeCommand() on the whole line then _routeQuickLogMulti(), else shows an UNRECOGNIZED hint; never calls fetch/generateSyncPayload/getSystemDirective (no AI)'

# 151.7  submitCommandInput(): an attached image always forces the AI path
#        (transmitMessage()) regardless of the resolved mode -- TERMINAL has
#        no visual-analysis equivalent
$submitBody151 = Get-FunctionBody $apiSrc151 'submitCommandInput'
Check (
    ($submitBody151 -match "(?s)if \(attachedImageData\) \{\s*\n\s*transmitMessage\(\);\s*\n\s*return;\s*\n\s*\}") -and
    ($submitBody151 -match "resolved\.mode === 'terminal'")
) "151.7: submitCommandInput() routes an attached image straight to transmitMessage() (AI), before checking the resolved mode"

# 151.8  _resolveCommandInput(): leading `/` (first-char-only, whole line ->
#        terminal) takes precedence over an INLINE `@` (anywhere in the line
#        -> overseer, text after the first `@` only), both tolerate one
#        optional leading space, and neither is otherInputMode(persisted)
#        (the upgrade retiring the old first-char-only relative `@`).
$resolveBody151 = Get-FunctionBody $apiSrc151 '_resolveCommandInput'
Check (
    ($resolveBody151 -match "raw\.charAt\(0\) === '/'") -and
    ($resolveBody151 -match "rest\.charAt\(0\) === ' '") -and
    ($resolveBody151 -match "mode: 'terminal'") -and
    ($resolveBody151 -match "const atIdx = raw\.indexOf\('@'\);") -and
    ($resolveBody151 -match "text\.charAt\(0\) === ' '") -and
    ($resolveBody151 -match "mode: 'overseer'") -and
    (-not ($resolveBody151 -match "otherInputMode\(persisted\)"))
) "151.8: _resolveCommandInput() checks a leading ``/`` first (whole line -> terminal), then an INLINE ``@`` anywhere (raw.indexOf('@'), everything after -> overseer), both stripping one optional leading space -- never otherInputMode(persisted)"

# 151.9  QUICK_LOG_PATTERNS: all four quick-log verbs present with the
#        expected regex anchors
Check (
    ($apiSrc151 -match "(?s)id:\s*'kill',\s*\n\s*re:\s*/\^killed\?\\s\+") -and
    ($apiSrc151 -match "(?s)id:\s*'caps',\s*\n\s*re:\s*/\^\(\[\+-\]\)") -and
    ($apiSrc151 -match "(?s)id:\s*'location',\s*\n\s*re:\s*/\^\(\?:arrived") -and
    ($apiSrc151 -match "(?s)id:\s*'faction',\s*\n\s*re:\s*/\^rep\\s\+")
) "151.9: QUICK_LOG_PATTERNS defines kill/caps/location/faction with the documented regex shapes"

# 151.10  quick-log handlers REUSE existing native setters -- none are forked
#         (Protocol 22): kill writes through _logEvent, caps mirrors #c_caps
#         before saveState (the WU-N2 idiom), location calls the shared
#         onLocationChange() (owner report fix: sets CURRENT location, not just
#         markLocationVisited's discovered-but-not-current mark), faction calls the
#         shared adjustFaction() gated on getFactionRegistry()
$quickLogCapsBody151 = Get-FunctionBody $apiSrc151 '_quickLogCaps'
$quickLogFactionBody151 = Get-FunctionBody $apiSrc151 '_quickLogFaction'
Check (
    ($apiSrc151 -match "_logEvent\('kill', text\)") -and
    ($quickLogCapsBody151 -match "document\.getElementById\('c_caps'\)") -and
    ($apiSrc151 -match "onLocationChange\(loc\)") -and
    ($apiSrc151 -match "adjustFaction\(match\.key, field, 5\)") -and
    ($quickLogFactionBody151 -match "getFactionRegistry\(\)")
) "151.10: quick-log handlers reuse _logEvent/onLocationChange/adjustFaction/getFactionRegistry -- no forked duplicate logic"

# 151.11  the faction quick-log falls through (returns false) on an unknown
#         key, rather than blindly creating one -- the caller then shows the
#         "unrecognized" hint instead of silently mutating an invented faction
Check (
    $quickLogFactionBody151 -match "if \(!match\) return false;"
) '151.11: _quickLogFaction returns false on an unknown faction key (falls through to the TERMINAL "unrecognized" hint, never invents a faction)'

# 151.12  COMMAND_REGISTRY documents the mode system so it is discoverable
#         via [FEATURES] -- the pill, both override prefixes (the inline `@`
#         anywhere upgrade), the comma multi-action syntax, and all four
#         quick-log verbs
Check (
    ($uiCoreSrc151 -match "group:\s*'COMMAND-LINE MODE'") -and
    ($uiCoreSrc151 -match "'/message'") -and
    ($uiCoreSrc151 -match "'text @message'") -and
    ($uiCoreSrc151 -match "'killed <target>'") -and
    ($uiCoreSrc151 -match "'\+N caps / -N caps'") -and
    ($uiCoreSrc151 -match "'arrived <location>'") -and
    ($uiCoreSrc151 -match "'rep <faction> up/down'") -and
    ($uiCoreSrc151 -match "'action, action, action'")
) "151.12: COMMAND_REGISTRY has a COMMAND-LINE MODE group documenting the pill, /message, the inline `"text @message`" ping, the comma multi-action syntax, and all four quick-log verbs"

# 151.13  wireInput() is generalized to accept a function resolver -- the
#         three existing registry-category call sites are UNCHANGED
#         (backward-compatible), and #chatInput is wired to _commandSuggestions
Check (
    ($uiSavesSrc151 -match "function wireInput\(inputId, categoryOrFn\)") -and
    ($uiSavesSrc151 -match "var isFn = typeof categoryOrFn === 'function';") -and
    ($uiSavesSrc151 -match "wireInput\('newQuestName', 'quests'\);") -and
    ($uiSavesSrc151 -match "wireInput\('newItemName', 'items'\);") -and
    ($uiSavesSrc151 -match "wireInput\('newPerkName', 'perks'\);") -and
    ($uiSavesSrc151 -match "wireInput\('chatInput', _commandSuggestions\);")
) "151.13: wireInput(inputId, categoryOrFn) accepts a function; the 3 existing registry-category calls are untouched; #chatInput is newly wired to _commandSuggestions"

# 151.14  _commandSuggestions() is suppressed entirely (returns []) unless
#         the message resolves to TERMINAL -- no AI-mode suggestion clutter
$commandSuggestionsBody151 = Get-FunctionBody $apiSrc151 '_commandSuggestions'
Check (
    $commandSuggestionsBody151 -match "if \(resolved\.mode !== 'terminal'\) return \[\];"
) "151.14: _commandSuggestions() returns [] whenever the message would resolve to OVERSEER"

# 151.15  CSS: the pill/hint classes exist, reuse .action-btn.btn-sm sizing
#         (>=28px tap target, Protocol 17) rather than a bespoke min-height,
#         and never wrap (Suite 92 anti-recurrence pattern)
$modePillBlock151 = [regex]::Match($cssSrc151, '\.mode-pill\s*\{[^}]*\}').Value
Check (
    ($modePillBlock151 -match "white-space:\s*nowrap;") -and
    ($cssSrc151 -match "\.mode-pill--terminal\s*\{") -and
    ($cssSrc151 -match "\.mode-pill--overseer\s*\{") -and
    ($cssSrc151 -match "(?s)\.mode-hint\s*\{[^}]*white-space:\s*nowrap;") -and
    (-not ($modePillBlock151 -match "min-height"))
) "151.15: .mode-pill/.mode-pill--terminal/.mode-pill--overseer/.mode-hint are defined, both nowrap; .mode-pill has no bespoke min-height (inherits the >=28px tap target from .action-btn.btn-sm)"

# 151.16  game-agnostic (Protocol 38): the new B1 code carries no hardcoded
#         game literals -- faction validation routes through the registry
$renderModePillBody151 = Get-FunctionBody $uiCoreSrc151 '_renderModePill'
$b1Combined151 = $transmitTerminalBody151 + $quickLogFactionBody151 + $resolveBody151 + $renderModePillBody151
Check (
    -not ($b1Combined151 -match "\bFNV\b|\bFO3\b|Fallout|New Vegas|Mojave|Capital Wasteland")
) "151.16: the Command-Line MODE system is game-agnostic -- no hardcoded game literals (faction quick-log validates via getFactionRegistry())"

# 151.17  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#         has no JS execution sandbox -- same convention as Suite 149.8/150.10):
#         the resolver's source SHAPE proves the upgraded precedence -- a
#         leading `/` (untrimmed raw.charAt(0), first-char-only) is checked
#         and returned FIRST, so it always wins over any later `@`; the `@`
#         scan (raw.indexOf) only runs when no leading `/` matched, and finds
#         `@` ANYWHERE (not just position 0); both strip exactly one leading
#         space (not all whitespace); neither branch is otherInputMode(persisted)
#         (which would make the target relative to the starting mode).
Check (
    ($resolveBody151 -match "raw\.charAt\(0\) === '/'") -and
    ($resolveBody151 -match "raw\.slice\(1\)") -and
    ($resolveBody151 -match "rest\.slice\(1\)") -and
    (-not ($resolveBody151 -match "raw\.trim\(\)\.charAt\(0\)")) -and
    (-not ($resolveBody151 -match "\.replace\(/\^\\s\*/")) -and
    ($resolveBody151 -match "mode: 'terminal'") -and
    ($resolveBody151 -match "const atIdx = raw\.indexOf\('@'\);") -and
    ($resolveBody151 -match "raw\.slice\(atIdx \+ 1\)") -and
    ($resolveBody151 -match "mode: 'overseer'") -and
    ($resolveBody151.IndexOf("raw.charAt(0) === '/'") -lt $resolveBody151.IndexOf("raw.indexOf('@')")) -and
    (-not ($resolveBody151 -match "otherInputMode\(persisted\)"))
) "151.17: structural mirror of the JS behavioral proof -- the leading-`/` branch (untrimmed raw.charAt(0), first-char-only) is checked and returned BEFORE the inline `@` scan (raw.indexOf, anywhere in the line), both strip exactly one leading space, and neither targets otherInputMode(persisted)"

# 151.18  Protocol 1 -- CACHE_NAME is a well-formed, current revision string.
#         (The exact -rN value is asserted once, in the LATEST suite to touch
#         a served file -- currently Suite 153.9 -- rather than duplicated/
#         hardcoded here too, which would go stale on every later commit.)
Check (
    (Read-Src "sw.js") -match "const CACHE_NAME = 'robco-terminal-v2\.7\.0-r\d+';"
) "151.18: CACHE_NAME is a well-formed robco-terminal-v2.7.0-rN revision string (Protocol 1)"

# ===========================================================
# Suite 152 -- Shutdown/OFF power-on affordance (Protocol 42 fix)
# (10 tests). Mirrors JS Suite 152. Owner bug: forcing SHUTDOWN/OFF
# (A3 shutdown-crt observer) left a fully black screen with no visible
# way back on. A diegetic #powerOnBtn, shown ONLY during SHUTDOWN/OFF
# via the SAME body classes the observer already toggles, recovers
# using legal transition() edges only (never forceState, the
# documented TEST-ONLY escape hatch -- Suite 146.15 still guards that).
# ===========================================================
Sep "Suite 152 -- Shutdown/OFF power-on affordance (Protocol 42 fix)"
$htmlSrc152 = Read-Src "index.html"
$cssSrc152 = Read-Src "css/terminal.css"
$uiCoreSrc152 = Read-Src "js/ui-core.js"
$powerOnBody152 = Get-FunctionBody $uiCoreSrc152 '_powerOnFromShutdown'

# 152.1  #powerOnBtn is a real <button> (Protocol UI-5) with a diegetic
#        aria-label, wired to the recovery handler
Check (
    ($htmlSrc152 -match 'id="powerOnBtn"') -and
    ($htmlSrc152 -match '<button[\s\S]{0,200}?>')
) '152.1: #powerOnBtn is a real <button> wired to _powerOnFromShutdown() with a diegetic aria-label'
Check (
    ($htmlSrc152 -match 'id="powerOnBtn"') -and
    ($htmlSrc152 -match 'onclick="_powerOnFromShutdown\(\)"') -and
    ($htmlSrc152 -match 'aria-label="Power on the terminal"')
) '152.1b: #powerOnBtn carries the onclick handler and a literal, descriptive aria-label'

# 152.2  CSS: hidden by default, shown ONLY via the SAME body classes the
#        shutdown-crt observer already toggles (Protocol 22 -- no separate
#        JS visibility bookkeeping that could drift), sits ABOVE the
#        shutdown cover's z-index (100001), and never wraps
$powerOnBlock152 = [regex]::Match($cssSrc152, '\.power-on-btn\s*\{[^}]*\}').Value
Check (
    ($powerOnBlock152 -match "display:\s*none;") -and
    ($powerOnBlock152 -match "z-index:\s*100002;") -and
    ($powerOnBlock152 -match "white-space:\s*nowrap;") -and
    ($cssSrc152 -match "(?s)body\.rt-shutdown \.power-on-btn,\s*\n\s*body\.rt-shutdown-plain \.power-on-btn\s*\{\s*\n\s*display:\s*block;")
) '152.2: .power-on-btn is hidden by default, z-index 100002 (above the 100001 shutdown cover), never wraps, and is shown ONLY via body.rt-shutdown/body.rt-shutdown-plain (the observer-owned classes)'

# 152.3  >=28px tap target (Protocol 17) -- min-height comfortably exceeds
#        the floor, and width:auto (not the global button{width:100%})
Check (
    ($powerOnBlock152 -match "min-height:\s*44px;") -and
    ($powerOnBlock152 -match "width:\s*auto;")
) '152.3: .power-on-btn has an explicit min-height (44px, exceeding the >=28px Protocol 17 floor) and width:auto (overrides the global button{width:100%})'

# 152.4  reduced-motion: the pulse glow is a plain `animation:` declaration,
#        caught by the existing global prefers-reduced-motion block -- no
#        bespoke override needed (same convention as every other CRT effect)
Check (
    ($cssSrc152 -match "@keyframes power-on-glow") -and
    ($powerOnBlock152 -match "animation:\s*power-on-glow")
) '152.4: the power-on-glow keyframe is applied via a plain `animation:` declaration, neutralised by the existing global prefers-reduced-motion block (animation-duration:0.01ms on *)'

# 152.5  _powerOnFromShutdown() recovers using ONLY legal transition()
#        edges -- SHUTDOWN's only legal edge is OFF, so a SHUTDOWN-only
#        force state is walked through OFF first, then to COLD_BOOT.
#        NEVER calls forceState() (the documented TEST-ONLY escape hatch).
Check (
    ($powerOnBody152 -match "if \(AmbientRuntime\.getState\(\) === 'SHUTDOWN'\) AmbientRuntime\.transition\('OFF'\);") -and
    ($powerOnBody152 -match "AmbientRuntime\.transition\('COLD_BOOT'\);") -and
    (-not ($powerOnBody152 -match "forceState"))
) "152.5: _powerOnFromShutdown() walks SHUTDOWN -> OFF -> COLD_BOOT using ONLY legal transition() calls, never forceState() (production code must never bypass the LEGAL adjacency map -- Suite 146.15)"

# 152.6  fail-safe: never throws if AmbientRuntime is unavailable
Check (
    $powerOnBody152 -match "typeof AmbientRuntime === 'undefined' \|\| !AmbientRuntime"
) '152.6: _powerOnFromShutdown() guards on AmbientRuntime being available before calling into it'

# 152.7  the click handler is exposed on window (index.html's inline
#        onclick calls it) and lives beside the shutdown-crt observer
#        (Protocol 22 -- co-located with the state it recovers from)
Check (
    ($uiCoreSrc152 -match "window\._powerOnFromShutdown = _powerOnFromShutdown;") -and
    ($uiCoreSrc152 -match "(?s)id: 'shutdown-crt'.*?function _powerOnFromShutdown\(\)")
) '152.7: _powerOnFromShutdown() is exposed on window and defined immediately after the shutdown-crt observer it recovers from'

# 152.8  game-agnostic (Protocol 38) + no durable campaign write -- pure
#        runtime-state/DOM recovery, same invariant as the rest of A3
Check (
    (-not ($powerOnBody152 -match "\bFNV\b|\bFO3\b|Fallout|New Vegas|Mojave|Capital Wasteland")) -and
    (-not ($powerOnBody152 -match "saveState|robco_v8|_logEvent|\beventLog\b|localStorage\.(set|get)Item"))
) '152.8: _powerOnFromShutdown() is game-agnostic and writes nothing durable to the campaign (runtime-state transition only)'

# 152.9  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#         has no JS execution sandbox -- same convention as Suite
#         149.8/150.10/151.17): the recovery sequence's source SHAPE proves
#         the properties the JS side actually EXECUTES -- exactly two
#         transition() call sites exist, and the SHUTDOWN-only branch's
#         transition('OFF') appears BEFORE the unconditional
#         transition('COLD_BOOT') (so a SHUTDOWN start walks OFF then
#         COLD_BOOT, in that order, while an OFF start reaches COLD_BOOT
#         directly).
Check (
    (([regex]::Matches($powerOnBody152, "AmbientRuntime\.transition\(")).Count -eq 2) -and
    ($powerOnBody152.IndexOf("AmbientRuntime.transition('OFF')") -ge 0) -and
    ($powerOnBody152.IndexOf("AmbientRuntime.transition('OFF')") -lt $powerOnBody152.IndexOf("AmbientRuntime.transition('COLD_BOOT')"))
) "152.9: structural mirror -- exactly two transition() call sites exist (the conditional OFF branch and the unconditional COLD_BOOT call), with transition('OFF') appearing BEFORE transition('COLD_BOOT'), matching the two-hop-from-SHUTDOWN / one-hop-from-OFF behavior the JS vm sandbox executes"

# ===========================================================
# Suite 153 -- Command-Line MODE upgrades: inline `@` ping, comma
# multi-action quick-log, content-aware autocomplete (9 tests).
# Mirrors JS Suite 153. Step 2 Phase 2 B1 follow-up.
# ===========================================================
Sep "Suite 153 -- Command-Line MODE upgrades: inline @, comma multi-action, content autocomplete"
$apiSrc153 = Read-Src "js/api.js"
$dbNvSrc153 = Read-Src "js/db_nv.js"
$dbFo3Src153 = Read-Src "js/db_fo3.js"

# 153.1  _routeQuickLogMulti(): splits on commas, trims + drops empty
#        segments, routes EACH through the unchanged single-segment
#        _routeQuickLog(), and returns {anyMatched, anyUnmatched}
$multiBody153 = Get-FunctionBody $apiSrc153 '_routeQuickLogMulti'
Check (
    ($multiBody153 -match "(?s)userText\s*\n\s*\.split\(','\)") -and
    ($multiBody153 -match "\.map\(s => s\.trim\(\)\)") -and
    ($multiBody153 -match "\.filter\(Boolean\)") -and
    ($multiBody153 -match "if \(_routeQuickLog\(seg\)\) anyMatched = true;") -and
    ($multiBody153 -match "else anyUnmatched = true;") -and
    ($multiBody153 -match "return \{ anyMatched, anyUnmatched \};")
) '153.1: _routeQuickLogMulti() splits on commas, trims and drops empty segments, routes each through _routeQuickLog(), and returns {anyMatched, anyUnmatched}'

# 153.2  transmitTerminal() collates ONE combined hint when some (but not
#        all) segments are unrecognized -- never one hint per segment
$transmitTerminalBody153 = Get-FunctionBody $apiSrc153 'transmitTerminal'
Check (
    ($transmitTerminalBody153 -match "const \{ anyMatched, anyUnmatched \} = _routeQuickLogMulti\(userText\);") -and
    ($transmitTerminalBody153 -match "if \(anyMatched\)") -and
    ($transmitTerminalBody153 -match "if \(anyUnmatched\)") -and
    ($transmitTerminalBody153 -match "wasn.{1,2}t recognized")
) "153.2: transmitTerminal() shows ONE collated `"part of that line wasn't recognized`" hint only when anyMatched && anyUnmatched -- never spammed per segment"

# 153.3  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#        has no JS execution sandbox): the split/trim/filter chain runs in
#        that exact ORDER (split -> map trim -> filter Boolean) before the
#        per-segment forEach, and _routeQuickLog is called with the SEGMENT
#        variable (never the whole unsplit userText) -- proving each of the
#        4 comma-separated actions is routed independently, in order.
Check (
    ($multiBody153.IndexOf(".split(',')") -lt $multiBody153.IndexOf(".map(s => s.trim())")) -and
    ($multiBody153.IndexOf(".map(s => s.trim())") -lt $multiBody153.IndexOf(".filter(Boolean)")) -and
    ($multiBody153 -match "segments\.forEach\(seg => \{") -and
    (-not ($multiBody153 -match "_routeQuickLog\(userText\)"))
) "153.3: structural mirror -- the split -> trim -> filter(Boolean) chain runs in that order, and segments.forEach() routes each SEGMENT (never the whole unsplit userText) through _routeQuickLog() independently, matching the 4-action-line behavior the JS vm sandbox executes"

# 153.4  getBestiaryNames() defined in BOTH db runners (Protocol 15 parity),
#        reuses the SAME lazy cache lookupBestiaryEntry() builds (Protocol
#        22 -- no second CSV parse)
Check (
    ($dbNvSrc153 -match "function _ensureBestiaryCache\(\)") -and
    ($dbNvSrc153 -match "function getBestiaryNames\(\)") -and
    ($dbNvSrc153 -match "(?s)_ensureBestiaryCache\(\);\s*\n\s*return Array\.from\(_bestiaryCache\.values\(\)\)\.map\(e => e\.name\);") -and
    ($dbFo3Src153 -match "function _ensureBestiaryCache\(\)") -and
    ($dbFo3Src153 -match "function getBestiaryNames\(\)")
) '153.4: getBestiaryNames() is defined in both db_nv.js and db_fo3.js, reusing the same lazy _bestiaryCache lookupBestiaryEntry() builds (no second CSV parse)'

# 153.5  lookupBestiaryEntry() itself is unchanged behaviorally -- still
#        routes through _ensureBestiaryCache() (Protocol 42: a refactor must
#        not alter the function it extracts from)
Check (
    ($dbNvSrc153 -match "(?s)function lookupBestiaryEntry\(name\) \{\s*\n\s*if \(!name\) return null;\s*\n\s*_ensureBestiaryCache\(\);")
) '153.5: lookupBestiaryEntry() still guards on !name then calls _ensureBestiaryCache() -- the extraction preserved its exact behavior'

# 153.6  _quickLogContentSuggestions(): recognizes all three verb lead-ins
#        (kill/location/faction) plus the faction-then-direction follow-up,
#        reading from the ACTIVE game's registries/DB (game-agnostic,
#        Protocol 38) -- never a hardcoded name list
$contentBody153 = Get-FunctionBody $apiSrc153 '_quickLogContentSuggestions'
Check (
    ($contentBody153 -match "rep\\s\+\(\\S\+\)\\s\+\(\\S\*\)\$") -and
    ($contentBody153 -match "rep\\s\+\(\\S\*\)\$") -and
    ($contentBody153 -match "arrived\(\?:\\s\+at\)\?\|at\)\\s\+\(\.\*\)\$") -and
    ($contentBody153 -match "killed\?\\s\+\(\?:\\d\+\\s\+\)\?\(\.\*\)\$") -and
    ($contentBody153 -match "getFactionRegistry\(\)") -and
    ($contentBody153 -match "FALLOUT_REGISTRY\.locations") -and
    ($contentBody153 -match "getBestiaryNames\(\)") -and
    (-not ($contentBody153 -cmatch "\bFNV\b|\bFO3\b|Fallout|New Vegas|Mojave|Capital Wasteland"))
) '153.6: _quickLogContentSuggestions() recognizes rep+direction, rep+key, arrived/at+location, and killed+creature lead-ins, reading names ONLY from getFactionRegistry()/FALLOUT_REGISTRY.locations/getBestiaryNames() -- game-agnostic, no hardcoded name list'

# 153.7  _commandSuggestions() tries content suggestions FIRST and, when
#        present, preserves whatever prefix _resolveCommandInput() stripped
#        (e.g. a `/` override) so picking a suggestion never drops it
$suggestBody153 = Get-FunctionBody $apiSrc153 '_commandSuggestions'
Check (
    ($suggestBody153 -match "const prefix = rawStr\.slice\(0, rawStr\.length - resolved\.text\.length\);") -and
    ($suggestBody153 -match "const contentSuggestions = _quickLogContentSuggestions\(text\);") -and
    ($suggestBody153 -match "return contentSuggestions\.map\(s => \(\{ name: prefix \+ s\.name, type: s\.type \}\)\);") -and
    ($suggestBody153 -match "out\.push\(\{ name: prefix \+ cmd \+ ' ', type: 'native command' \}\)") -and
    ($suggestBody153 -match "out\.push\(\{ name: prefix \+ p\.stub, type: p\.tag \}\)")
) "153.7: _commandSuggestions() tries content suggestions first, and every suggestion (content or verb/token) is prefixed with whatever the resolver stripped, so a ``/`` override survives picking a suggestion"

# 153.8  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof: each
#        lead-in's filter predicate matches on a lower-cased startsWith
#        against the partial token (the same shape the JS side actually
#        EXECUTES against fixture registries to prove "killed de" ->
#        deathclaw, "arrived no" -> Novac, "rep nc" -> ncr, "rep ncr u" -> up).
Check (
    ($contentBody153 -match "n\.toLowerCase\(\)\.startsWith\(partial\)") -and
    ($contentBody153 -match "f\.key\.toLowerCase\(\)\.startsWith\(partial\)") -and
    ($contentBody153 -match "\['up', 'down'\]") -and
    ($contentBody153 -match "\.filter\(d => d\.startsWith\(partial\)\)") -and
    ($contentBody153 -match "f\.key\.toLowerCase\(\) === m\[1\]\.toLowerCase\(\)")
) "153.8: structural mirror -- every content-suggestion lead-in filters on a lower-cased startsWith(partial) against the matching registry field (location/creature names, faction keys) or the up/down literal set, matching the fixture-driven behavior the JS vm sandbox executes"

# 153.9  Protocol 1 -- CACHE_NAME is a well-formed, current revision string.
#        (Superseded as "latest" by Suite 154 -- the exact -rN pin moved there
#        per the rotation pattern documented at 151.18; kept generic here so a
#        later served-file bump can't make this suite stale.)
Check (
    (Read-Src "sw.js") -match "const CACHE_NAME = 'robco-terminal-v2\.7\.0-r\d+';"
) "153.9: CACHE_NAME is a well-formed robco-terminal-v2.7.0-rN revision string (Protocol 1)"

# ===========================================================
# Suite 154 -- Step 2 (v2.8.0) Phase 2 B2a: MODULE BAY core reframe (37 tests --
# 154.24-154.33 add the WU-optics-picker GREEN FAMILY phosphor-tube-picker redesign;
# 154.34-154.37 add the owner post-ship audit's anode-nib/ghost-peek/compact-tag fixes,
# including the (DEFAULT) marker's own matching corner-chip treatment)
# The Security & Configuration panel reframed as installable hardware
# (owner-approved mockup, Protocol 25 sanctioned exception). ONE-TRUTH MODEL:
# the bay + the permanent Schematic View are both projections of the SAME
# stored device prefs; every control still calls the setter it always called
# (Protocol 22/23) -- zero new campaign state, zero AI involvement. The 13
# SLOT-02 audio channels stay in their CURRENT (un-flipped) polarity this
# unit -- B2b converts them to DIP chips. Mirrors JS Suite 154.
# ===========================================================
Sep "Suite 154 -- Step 2 Phase 2 B2a: Module Bay core reframe"
$html154   = Read-Src "index.html"
$core154   = Read-Src "js/ui-core.js"
$audio154  = Read-Src "js/ui-audio.js"
$state154  = Read-Src "js/state.js"
$css154    = Read-Src "css/terminal.css"
$claude154 = Read-Src "CLAUDE.md"

# 154.1  the bay chrome + all 6 SLOT sub-panels are present, each a real
#        sub-panel (data-sub-id) defaulting OPEN on first boot (owner decision)
$slotIds154 = @('slot_01_optics','audio_systems','power_systems','slot_04_immersion','slot_05_uplink','slot_svc_tray')
$allSlotsOpen154 = $true
foreach ($id in $slotIds154) {
    if ($html154 -notmatch "(?s)data-sub-id=`"$id`".{0,40}open") { $allSlotsOpen154 = $false }
}
Check (
    ($html154 -match 'id="moduleBay" class="module-bay">') -and
    ($html154 -match 'id="bayHatch" class="bay-hatch" hidden>') -and
    ($html154 -match 'id="bayContent" class="bay-content">') -and
    $allSlotsOpen154
) "154.1: #moduleBay + #bayHatch + #bayContent exist; all 6 SLOT sub-panels default open="""" on first boot"

# 154.2  Protocol UI-1 clarification honored -- every SLOT/tray heading is an
#        <h3> (not a bare/plain summary), the panel's own <h2> stays untouched
$slotH3Count154 = [regex]::Matches($html154, '(?s)<h3[^>]*>.{0,40}&gt; SLOT 0[1-5]').Count
Check (
    ($html154 -match '(?s)<h2 style="border-color: var\(--robco-alert\); color: var\(--robco-alert\)">\s*> SECURITY & CONFIGURATION') -and
    ($slotH3Count154 -eq 5) -and
    ($html154 -match '<h3>&gt; SVC TRAY')
) "154.2: the panel keeps its single <h2>; every SLOT + the SVC tray use the sub-panel <h3> convention (Protocol UI-1 clarification)"

# 154.3  every pre-existing setter/id survives verbatim -- no functionality lost
#        (checkbox-driven boolean modules keep their EXACT id + onchange contract).
#        Owner report (SVC tray export consolidation): #ejectHolotapeBtn's
#        onclick intentionally changed from ejectHolotape() to
#        _svcEjectHolotape() as part of that authorized redesign -- every
#        OTHER id/onchange/onclick pair below is still required verbatim.
$needles154 = @(
    'id="apiKeyInput"', 'id="geminiKeySyncToggle"', 'id="btnFetchModels"', 'id="apiModelInput"',
    'id="highLumenToggle"', 'onchange="toggleHighLumen(this.checked)"',
    'id="immersionSelect"', 'onchange="onImmersionChange(this.value)"',
    'id="masterMuteToggle"', 'onchange="toggleMasterMute(this.checked)"',
    'id="radioToggle"', 'onchange="toggleRadio(this.checked)"',
    'id="wakeLockToggle"', 'onchange="toggleWakeLock(this.checked)"',
    'id="hapticToggle"', 'onchange="toggleHaptic(this.checked)"',
    'id="typerSpeedSlider"', 'id="ejectHolotapeBtn"',
    'id="btnViewChangelog"', 'id="btnInstallPwa"'
)
$allNeedles154 = $true
foreach ($n in $needles154) { if (-not $html154.Contains($n)) { $allNeedles154 = $false } }
Check ($allNeedles154) "154.3: every existing control id + its EXACT onchange/onclick setter call survives the reframe unmodified"

# 154.4  all 13 channel-mute checkboxes are UNTOUCHED this unit (ids + onchange
#        keys identical -- B2b, not B2a, converts them to DIP chips)
$muteKeys154 = @(
    'robco_sfx_muted','robco_hum_muted','robco_geiger_muted','robco_tinnitus_muted',
    'robco_ambient_muted','robco_wake_muted','robco_panelclick_muted','robco_bootdrone_muted',
    'robco_levelup_muted','robco_heartbeat_muted','robco_questcomplete_muted',
    'robco_questfail_muted','robco_factionthreshold_muted'
)
$allMutes154 = $true
foreach ($k in $muteKeys154) { if (-not $html154.Contains("toggleAudio('$k', this.checked)")) { $allMutes154 = $false } }
Check ($allMutes154) "154.4: all 13 SLOT-02 channel checkboxes keep their exact toggleAudio() call this unit (un-flipped -- B2b converts to chips)"

# 154.5  the phosphor tube rack replaces the OPTICS <select> -- 7 tubes, one per
#        THEMES key, each seating via the SAME changeOpticsColor() setter
$themeBlock154 = [regex]::Match($state154, '(?s)const THEMES = \{.*?\n\};').Value
$themeKeys154 = [regex]::Matches($themeBlock154, '(?m)^\s*(\w+):\s*\{') | ForEach-Object { $_.Groups[1].Value }
$allTubes154 = $true
foreach ($k in $themeKeys154) { if ($html154 -notmatch "data-optic=`"$k`"") { $allTubes154 = $false } }
$seatCount154 = [regex]::Matches($html154, 'onclick="_seatOpticsTube\(this\)"').Count
Check (($themeKeys154.Count -eq 7) -and $allTubes154 -and ($seatCount154 -eq 7)) `
    "154.5: the tube rack has exactly one button per THEMES key (7), each wired to _seatOpticsTube(this)"

# 154.6  _seatOpticsTube is a thin adapter -- it calls the SAME changeOpticsColor()
#        setter (Protocol 22), never a parallel persistence path
$seatFn154 = Get-FunctionBody $audio154 '_seatOpticsTube'
Check (
    ($seatFn154 -match 'changeOpticsColor\(key\)') -and
    (-not ($seatFn154 -match 'MetaStore\.set')) -and
    ($seatFn154 -match 'renderModuleBay')
) "154.6: _seatOpticsTube() calls changeOpticsColor() (the existing setter) and renderModuleBay() -- no new persistence path"

# 154.7  one-truth model: renderModuleBay() re-syncs status lines and, when the
#        Schematic View is open, regenerates it -- never a second wired control set
$renderBayFn154 = Get-FunctionBody $core154 'renderModuleBay'
Check (
    ($renderBayFn154 -match '_updateOpticsBoardStatus') -and
    ($renderBayFn154 -match '_updateSonicBoardStatus') -and
    ($renderBayFn154 -match 'renderBaySchematic')
) "154.7: renderModuleBay() re-syncs both combined status lines and regenerates an open Schematic View"

# 154.8  the Schematic View is REGENERATED from state on open (no persistent
#        parallel DOM) -- every row calls the SAME setter as its bay counterpart
$schemFn154 = Get-FunctionBody $core154 'renderBaySchematic'
$schemSetters154 = @('changeOpticsColor','toggleHighLumen','toggleMasterMute','toggleRadio','toggleWakeLock','toggleHaptic','onImmersionChange','_schemSetGeminiSync')
$allSchemSetters154 = $true
foreach ($fn in $schemSetters154) { if ($schemFn154 -notmatch [regex]::Escape($fn)) { $allSchemSetters154 = $false } }
Check ($allSchemSetters154 -and ($schemFn154 -match 'list\.innerHTML =')) `
    "154.8: renderBaySchematic() regenerates the flat list via innerHTML and every row calls the same real setter the bay uses"

# 154.9  toggleBaySchematic() swaps the bay grid for the schematic (never shows
#        both). B2b (Suite 155) factored the actual show/hide into a shared
#        _applyBayView(view) so the boot restore could reuse it -- this test now
#        checks that shared function (Suite 155.12 covers the delegation).
$toggleSchemFn154 = Get-FunctionBody $core154 '_applyBayView'
Check (
    ($toggleSchemFn154 -match 'schem\.hidden = !toSchematic') -and
    ($toggleSchemFn154 -match 'bay\.hidden = toSchematic')
) "154.9: _applyBayView() (called by both toggleBaySchematic() and initModuleBay()) shows exactly one of the bay grid / schematic list at a time"

# 154.10  first-visit-only hatch (LOCKED-1): a NEW device pref (not campaign state)
#         gates whether #bayHatch is shown; releasing it sets the pref permanently
Check (
    ($state154 -match "robco_bay_opened: \{ type: 'bool', default: false, owner: 'ui-core\.js' \}") -and
    ($core154 -match "MetaStore\.get\('robco_bay_opened'\) === 'true'") -and
    ($core154 -match "MetaStore\.set\('robco_bay_opened', 'true'\)")
) "154.10: robco_bay_opened is a registered MetaStore device pref; initModuleBay() reads it, releaseBayHatch() sets it permanently"

# 154.11  the hatch ceremony honors prefers-reduced-motion (instant reveal -- no
#         forced animation wait for a user who has reduced motion set)
$releaseFn154 = Get-FunctionBody $core154 'releaseBayHatch'
Check (
    ($releaseFn154 -match 'prefers-reduced-motion: reduce') -and
    ($releaseFn154 -match 'reduced \? 0 : 900')
) "154.11: releaseBayHatch() checks prefers-reduced-motion and skips the animation wait when set"

# 154.12  Protocol UI-5 -- every NEW interactive element is a real <button> or
#         native input; the key-sync control stays an accessible native checkbox
#         (no <span onclick> pattern introduced anywhere in the bay)
Check (
    (-not ($html154 -match '<span[^>]*onclick=')) -and
    ($html154 -match '(?s)<button.{0,40}type="button".{0,40}class="hatch-latch-btn"') -and
    ($html154 -match '(?s)<button.{0,40}type="button".{0,40}class="tube"')
) "154.12: no <span onclick> pattern anywhere; the hatch latch + tube-rack controls are real <button>s (Protocol UI-5)"

# 154.13  Protocol 17 -- tap targets: the boolean-module card and phosphor tube
#         both meet the >=28px floor (WU-optics-picker: button.tube's floor is the
#         shared --tube-h cell-geometry var, driven well past 28px so every rack
#         cell -- standalone tube, cartridge, fan-tray variant -- is the same size)
$tubeHVal154 = 0
if ($css154 -match '--tube-h:\s*(\d+)px') { $tubeHVal154 = [int]$matches[1] }
Check (
    ($css154 -match '(?s)\.bay-module-card \{.{0,300}min-height:\s*28px') -and
    ($css154 -match '(?s)button\.tube \{.{0,900}min-height:\s*var\(--tube-h\)') -and
    ($tubeHVal154 -ge 28)
) "154.13: .bay-module-card and button.tube both declare an explicit >=28px tap target (Protocol 17)"

# 154.14  Protocol 42 fix (found during this unit's manual DESKTOP render-check,
#         a check the automated 360/412px gate doesn't cover): the plan's mockup
#         two-column desktop bay assumed a full-viewport-width panel, but this
#         app's desktop shell fixes the settings panel's own column at a hard
#         380px (confirmed live: .module-bay measures ~338px wide at BOTH 1280px
#         and 1920px viewports -- the column never grows). A two-column @container
#         breakpoint can therefore never engage -- it would be dead, misleading
#         code -- so .bay-grid is single-column UNCONDITIONALLY, and no
#         viewport @media is used for this either (container-type infra is
#         kept, harmless, for if the shell ever widens). NOTE -- the sibling
#         .bay-channel-list check this test originally carried was retired in
#         B2b (Suite 155), which replaced that single-column checkbox list
#         with a deliberately MULTI-column .chip-grid (Suite 155 covers its
#         own bounded track).
Check (
    ($css154 -match 'container-type:\s*inline-size') -and
    ($css154 -match 'container-name:\s*bay') -and
    (-not ($css154 -match '@container bay')) -and
    (-not ($css154 -match '(?s)@media \(min-width:\s*1000px\).{0,120}\.bay-grid')) -and
    ($css154 -match '(?s)\.bay-grid \{.{0,900}grid-template-columns:\s*minmax\(0, 1fr\);')
) "154.14: .bay-grid is single-column unconditionally -- confirmed via live desktop measurement that the shell column never exceeds ~340px, so a two-column breakpoint would be unreachable dead code (Protocol 42 fix)"

# 154.15  SLOT 05 keeps the amber "external hardware" identity (LOCKED-4); SLOTs
#         01-04 + the SVC tray are NOT amber (green baseline / blue utility)
Check (
    ($css154 -match '(?s)details\.bay-board\.uplink \{.{0,80}border-color:\s*rgba\(243, 156, 18') -and
    ($html154 -match '(?s)<h3 style="color: var\(--robco-alert\)">.{0,40}&gt; SLOT 05') -and
    (-not ($html154 -match '(?s)<h3 style="color: var\(--robco-alert\)">.{0,40}&gt; SLOT 0[1-4]'))
) "154.15: SLOT 05 keeps its amber AI-uplink identity; SLOTs 01-04 do not (LOCKED-4)"

# 154.16  owner report fix: initModuleBay() is NO LONGER called unconditionally from
#         window.onload (that fired the first-visit hatch ceremony at page load,
#         before the Courier had touched anything) -- it's wired instead to
#         securityConfigPanel's own toggle listener inside _wirePanelPersistence(),
#         gated on _restoringPanels so a genuine user-initiated panel open still
#         reaches it (a boot-time state RESTORE never does -- Suite 172).
$onloadIdx154 = $core154.IndexOf('window.onload = async function ()')
$onloadEnd154 = $core154.IndexOf("`n};", $onloadIdx154)
$onloadBody154 = $core154.Substring($onloadIdx154, $onloadEnd154 - $onloadIdx154)
$panelPersistFn154 = Get-FunctionBody $core154 '_wirePanelPersistence'
Check (
    (-not ($onloadBody154 -match 'initModuleBay\(')) -and
    ($onloadBody154 -match '_wirePanelPersistence\(\);') -and
    ($panelPersistFn154 -match "d\.id === 'securityConfigPanel' && d\.open") -and
    ($panelPersistFn154 -match '_restoringPanels') -and
    ($panelPersistFn154 -match "typeof initModuleBay === 'function'") -and
    ($panelPersistFn154 -match 'initModuleBay\(\);')
) "154.16: initModuleBay() is wired to securityConfigPanel's own toggle event (inside _wirePanelPersistence()) instead of window.onload -- the hatch ceremony never fires at page load (Protocol 42 fix)"

# 154.17  game-agnostic (Protocol 38) -- no FNV/FO3/Fallout literals anywhere in
#         the Module Bay markup or its controller functions
$bayJsStart154 = $core154.IndexOf('const BAY_SVC_LOG_CAP')
$bayJsEnd154 = $core154.IndexOf('window._svcInstallPwa = _svcInstallPwa;') + 'window._svcInstallPwa = _svcInstallPwa;'.Length
$bayJs154 = $core154.Substring($bayJsStart154, $bayJsEnd154 - $bayJsStart154) + $seatFn154
$bayHtmlStart154 = $html154.IndexOf('id="moduleBay"')
$bayHtmlEnd154 = $html154.IndexOf('ALL SAVES')
$bayHtml154 = $html154.Substring($bayHtmlStart154, $bayHtmlEnd154 - $bayHtmlStart154)
Check (
    (-not ($bayJs154 -match '\bFNV\b|\bFO3\b|Fallout')) -and
    (-not ($bayHtml154 -match '\bFNV\b|\bFO3\b|Fallout'))
) "154.17: the Module Bay controller code and markup are game-agnostic -- no hardcoded game literals"

# 154.18  Protocol 25 sanctioned-exception clause + the UI-1 clarification are
#         both recorded in CLAUDE.md (this reframe's own authorization + guardrails)
Check (
    ($claude154 -match 'Sanctioned exception . owner-approved redesigns') -and
    ($claude154 -match 'internal headings use the sub-panel')
) "154.18: CLAUDE.md records the Protocol 25 sanctioned-exception clause and the Protocol UI-1 sub-panel-heading clarification"

# 154.19  Protocol 42 fix (found during this unit's gate render-check): the
#         decorative bus-strip wraps UNCONDITIONALLY (no container-query clip
#         variant -- see 154.14, the shell column never reaches a width where
#         clipping would matter) instead of nowrap+ellipsis, which left a
#         full-width scrollable node behind even though nothing was visibly
#         cut off (Protocol 17 -- content must actually fit).
Check (
    ($css154 -match '(?s)\.bay-bus-strip \{.{0,500}white-space:\s*normal') -and
    (-not ($css154 -match '(?s)@container bay.{0,120}\.bay-bus-strip'))
) "154.19: .bay-bus-strip wraps (white-space:normal) unconditionally -- no unreachable container-query clip variant (Protocol 42 render-check fix)"

# 154.20  Protocol 42 fix (found during this unit's gate render-check): .bay-grid's
#         track uses minmax(0, 1fr), never a bare 1fr -- a bare 1fr track's implicit
#         minimum is "auto" (content-based), which forced each SLOT board wider
#         than its track at narrow widths (a real Playwright-verified 360px
#         overflow, traced to this exact well-known CSS Grid pitfall, not a
#         harness artifact). The sibling .bay-channel-list check this test
#         originally carried was retired in B2b (Suite 155) -- see 154.14's note.
Check (
    (-not ($css154 -match '(?s)\.bay-grid \{.{0,900}grid-template-columns:\s*1fr;')) -and
    ($css154 -match '(?s)\.bay-grid \{.{0,900}grid-template-columns:\s*minmax\(0, 1fr\);')
) "154.20: .bay-grid uses a minmax(0, 1fr) track, never a bare 1fr, so a board can never be forced wider than its track (Protocol 42 fix -- confirmed REAL via Playwright at 360px, not harness-only)"

# 154.21  Protocol 42 fix (found during this unit's manual browser verification):
#         the bay's own checkboxes and the Schematic View's mirrored checkboxes
#         are two SEPARATE DOM elements bound to the same MetaStore key -- a change
#         made via the schematic silently failed to push its new .checked state
#         back to the bay's own control (verified REAL in a live browser, not
#         harness-only: toggle in schematic -> back to bay -> bay showed the stale
#         checked state until reload). renderModuleBay() now re-syncs every
#         boolean control's checked state from MetaStore on every call, closing
#         the gap in both directions; toggleBaySchematic() also re-syncs at the
#         exact moment it switches back to the bay view.
$renderBayFn154b = Get-FunctionBody $core154 'renderModuleBay'
$toggleSchemFn154b = Get-FunctionBody $core154 '_applyBayView'
$syncIds154 = @('highLumenToggle','masterMuteToggle','radioToggle','wakeLockToggle','hapticToggle','geminiKeySyncToggle')
$allSyncIds154 = $true
foreach ($id in $syncIds154) { if ($core154 -notmatch "$id`:\s*'robco_") { $allSyncIds154 = $false } }
Check (
    ($core154 -match 'const BAY_CHECKBOX_SYNC_MAP = \{') -and
    $allSyncIds154 -and
    ($renderBayFn154b -match 'Object\.keys\(BAY_CHECKBOX_SYNC_MAP\)\.forEach') -and
    ($renderBayFn154b -match "el\.checked = MetaStore\.get\(BAY_CHECKBOX_SYNC_MAP\[id\]\) === 'true'") -and
    ($toggleSchemFn154b -match 'else renderModuleBay\(\)')
) "154.21: renderModuleBay() re-syncs every boolean control's .checked from MetaStore (closing the bay<->schematic drift a live browser test found), and toggleBaySchematic() re-syncs on switching back to the bay (Protocol 42 fix)"

# 154.22  owner report fix: the Security & Configuration panel has its own stable id
#         and defaults CLOSED absent a saved user choice on EVERY viewport (excluded
#         from the generic desktop-auto-open branch), so the hatch never shows before
#         the Courier has actually clicked the panel open.
Check (
    ($html154 -match '<details\s+id="securityConfigPanel"\s+class="panel"') -and
    ($core154 -match "(?s)id !== 'securityConfigPanel' &&\s*\n\s*window\.matchMedia\('\(min-width: 1000px\)")
) "154.22: #securityConfigPanel defaults closed on every viewport (excluded from the desktop auto-open branch) so the Module Bay hatch never shows at page load (owner report fix)"

# 154.23  owner report fix: SLOT 05's status line reflects a REAL validated Gemini
#         key + engine, not a hardcoded NO CARRIER string -- reusing
#         robco_gemini_validated_key (set only inside fetchAuthorizedModels()'s live
#         200-response success path) rather than a bare "a key string exists" check,
#         wired live into renderModuleBay() and refreshed on every key edit.
$uplinkStatusFn154 = Get-FunctionBody $audio154 '_updateUplinkBoardStatus'
$apiSrc154 = Read-Src "js/api.js"
Check (
    ($html154 -match '<p class="board-status alert" id="uplinkStatus">') -and
    ($state154 -match 'robco_gemini_validated_key') -and
    ($uplinkStatusFn154 -match "getElementById\('uplinkStatus'\)") -and
    ($uplinkStatusFn154 -match 'validatedKey === key') -and
    ($uplinkStatusFn154 -match 'CARRIER ESTABLISHED') -and
    ($core154 -match "_updateUplinkBoardStatus === 'function'\) _updateUplinkBoardStatus\(\)") -and
    ($apiSrc154 -match "MetaStore\.set\('robco_gemini_validated_key', rawKey\)") -and
    ($apiSrc154 -match "_updateUplinkBoardStatus === 'function'\) _updateUplinkBoardStatus\(\)")
) "154.23: SLOT 05 reflects the REAL AI Uplink connection (validated key + model) via _updateUplinkBoardStatus(), live-wired into renderModuleBay(), fetchAuthorizedModels() success, and every key edit -- never a hardcoded NO CARRIER (owner report fix)"

# -- WU-optics-picker: SLOT 01 phosphor-tube picker redesign (154.24-154.33) --
# The 7 flat swatches become one GREEN FAMILY cartridge (ROBCO/PIP-BOY/GHOUL fan
# out of a shared socket) + 4 standalone tubes, every tube gets a seat lamp,
# every rack cell is the same size, and the expand/collapse motion is plain CSS
# animation (Protocol UI-9 auto-degrades under reduced-motion).

# 154.24  the family-socket markup: cartridge (data-family, aria-expanded) + fan-tray
#         (shell escape hatch + the 3 green variant tubes)
Check (
    ($html154 -match 'class="family-socket" id="opticsFamilySocket"') -and
    ($html154 -match '(?s)id="opticsFamilyTube".{0,200}data-family="green"') -and
    ($html154 -match 'aria-expanded="false"') -and
    ($html154 -match 'id="opticsFamilyTray"') -and
    ($html154 -match '(?s)class="shell".{0,200}_collapseOpticsFamily\(false\)')
) "154.24: the GREEN FAMILY cartridge (#opticsFamilyTube, data-family, aria-expanded) + its fan-tray (#opticsFamilyTray + a shell escape-hatch button) are present in the markup"

# 154.25  seat lamp: every single .tube (cartridge, fan-tray variants, and the 4
#         standalone tubes -- 8 total) carries a .t-led dot
$rackBlock154 = [regex]::Match($html154, '(?s)id="opticsColorInput"[\s\S]*?</div>\s*<div class="bay-module">').Value
$tubeButtonCount154 = ([regex]::Matches($rackBlock154, 'class="tube[ "]')).Count
$tLedCount154 = ([regex]::Matches($rackBlock154, 'class="t-led"')).Count
Check (
    ($tubeButtonCount154 -eq 8) -and ($tLedCount154 -eq 8) -and ($tubeButtonCount154 -eq $tLedCount154)
) "154.25: every .tube button (8 -- cartridge + 3 fan-tray variants + 4 standalone) carries a .t-led seat lamp (found $tubeButtonCount154 tubes, $tLedCount154 lamps)"

# 154.26  the expand/collapse adapters exist, are wired to the cartridge/shell onclick
#         handlers, and are window-exposed (inline-handler entry points)
Check (
    ($html154 -match 'onclick="_expandOpticsFamily\(this\)"') -and
    ($audio154 -match 'function _expandOpticsFamily\(btnEl\)') -and
    ($audio154 -match 'window\._expandOpticsFamily = _expandOpticsFamily') -and
    ($audio154 -match 'function _collapseOpticsFamily\(reseat\)') -and
    ($audio154 -match 'window\._collapseOpticsFamily = _collapseOpticsFamily')
) "154.26: _expandOpticsFamily()/_collapseOpticsFamily() exist, are window-exposed, and the cartridge is wired to _expandOpticsFamily(this)"

# 154.27  _seatOpticsTube() is extended (Protocol 22, same function) to repaint the
#         cartridge representative + collapse-with-reseat ONLY for a family member pick --
#         changeOpticsColor() stays the single persistence writer
$seatFn154b = Get-FunctionBody $audio154 '_seatOpticsTube'
Check (
    ($seatFn154b -match 'isFamilyMember = !!\(t && t\.family\)') -and
    ($seatFn154b -match '_updateOpticsFamilyRepresentative\(key\)') -and
    ($seatFn154b -match '_collapseOpticsFamily\(true\)') -and
    ($seatFn154b -match 'changeOpticsColor\(key\)')
) "154.27: _seatOpticsTube() detects a family-member pick, repaints the cartridge, and collapses with the reseat flourish -- changeOpticsColor(key) remains the single writer"

# 154.28  data-driven family membership (Protocol 38): _themeFamilyMembers() reads
#         THEMES[k].family -- no hardcoded ['green','green3','ghoul']-style colour-key
#         array anywhere in the optics picker code
Check (
    ($audio154 -match 'function _themeFamilyMembers\(familyKey\)') -and
    ($audio154 -match 'THEMES\[k\]\.family === familyKey') -and
    (-not ($audio154 -match "\[\s*'green'\s*,\s*'green3'\s*,\s*'ghoul'\s*\]"))
) "154.28: _themeFamilyMembers() derives family membership from THEMES[k].family -- no hardcoded ['green','green3','ghoul'] array in the picker code (Protocol 38)"

# 154.29  uniform cell geometry (owner directive: "the boxes should all be the same
#         size") -- one shared --tube-h/--tube-w/--cell driving BOTH button.tube and
#         button.shell to the identical floor
Check (
    ($css154 -match '--tube-w:\s*\d+px') -and
    ($css154 -match '--tube-h:\s*\d+px') -and
    ($css154 -match '--cell:\s*calc\(var\(--tube-w\) \+ var\(--rack-gap\)\)') -and
    ($css154 -match '(?s)button\.tube \{.{0,900}min-height:\s*var\(--tube-h\)') -and
    ($css154 -match '(?s)button\.shell \{.{0,400}min-height:\s*var\(--tube-h\)')
) "154.29: .tube-rack declares shared --tube-w/--tube-h/--cell geometry, and BOTH button.tube and button.shell floor to the same min-height: var(--tube-h) (uniform cell size)"

# 154.30  every new motion verb is a plain animation: declaration (never transition:
#         alone), so the app's global prefers-reduced-motion block neutralizes each to
#         its instant final frame with no bespoke carve-out (Protocol UI-9)
Check (
    ($css154 -match '@keyframes tubeEject') -and
    ($css154 -match '@keyframes shellOpen') -and
    ($css154 -match '@keyframes tubeSeat') -and
    ($css154 -match 'animation:\s*tubeEject') -and
    ($css154 -match 'animation:\s*shellOpen') -and
    ($css154 -match 'animation:\s*tubeSeat')
) "154.30: tubeEject/shellOpen/tubeSeat are all plain animation: declarations (Protocol UI-9 -- the global reduced-motion block degrades them for free)"

# 154.31  hover feedback is gated behind (hover:hover) and (pointer:fine) -- the mockup
#         verification found a stuck-hover-after-tap issue on the eject animation
#         (variants animate out from under the pointer)
Check (
    ($css154 -match '(?s)@media \(hover: hover\) and \(pointer: fine\) \{.{0,200}button\.tube:hover') -and
    ($css154 -match '(?s)@media \(hover: hover\) and \(pointer: fine\) \{.{0,200}button\.tube:hover.{0,200}button\.shell:hover')
) "154.31: button.tube:hover and button.shell:hover both sit inside a (hover:hover) and (pointer:fine) gate (no sticky touch hover)"

# 154.32  the family cartridge is excluded from the generic (DEFAULT) tagging loop (it
#         shows its own "N TYPES" tag instead) -- no tag collision
Check (
    ($audio154 -match "if \(btn\.classList\.contains\('family'\)\) return;") -and
    ($html154 -match 'class="multi-tag"')
) '154.32: _updateOpticsDefaultLabel() skips the family cartridge (it shows its own multi-tag "N TYPES" instead of a redundant (DEFAULT))'

# 154.33  boot-restore (_restoreOpticsPreference, ui-core.js) repaints the family
#         representative and force-collapses the socket on every boot/game-switch --
#         the tray never opens on a fresh page load
$restoreFn154 = Get-FunctionBody $core154 '_restoreOpticsPreference'
Check (
    ($restoreFn154 -match "_famSocket\.classList\.remove\('expanded'\)") -and
    ($restoreFn154 -match '_resolveOpticsFamilyRepresentative') -and
    ($restoreFn154 -match '_updateOpticsFamilyRepresentative')
) "154.33: _restoreOpticsPreference() force-collapses the family socket and repaints its representative on every boot/game-switch"

# 154.34  owner audit vs the mockup, FIX 1: the built tube read as a flat-topped
#         battery -- .tube .glass is missing the mockup's small rounded "anode nib"
#         cap above the border-radius'd top that reads as a vacuum-phosphor-tube
#         silhouette rather than a battery cell.
Check (
    $css154 -match '(?s)\.tube \.glass::after \{.{0,300}border-radius:\s*2px 2px 0 0'
) "154.34: .tube .glass::after adds the mockup's rounded anode-nib cap to every tube (owner FIX 1 -- no more flat-topped battery look)"

# 154.35  owner audit vs the mockup, FIX 2: the ghosts were sized/offset
#         independently of the glass they hide behind, so the "hint of 3 types"
#         never actually peeked out from behind the seated glass. The ghosts now
#         share the glass's own 20x38 footprint so the peek math is provable.
$ghostBlock154 = [regex]::Match($css154, '(?s)\.tube\.family \.ghost \{.*?\n\}').Value
Check (
    ($ghostBlock154 -match 'width:\s*20px') -and
    ($ghostBlock154 -match 'height:\s*38px') -and
    ($css154 -match '(?s)\.tube\.family \.ghost\.g1 \{.{0,80}margin-left:\s*-5px') -and
    ($css154 -match '(?s)\.tube\.family \.ghost\.g2 \{.{0,80}margin-left:\s*-15px')
) "154.35: .tube.family .ghost shares the glass's 20x38 footprint, with g1/g2 margin-left offsets recalculated so each peeks out from behind the seated glass (owner FIX 2)"

# 154.36  owner audit, FIX 3: "make the 3 types a tag ... so the squares can all
#         be the same size without being big af" -- the multi-tag used to sit in
#         flow as its own line, forcing --tube-h ~22px taller than every other
#         tube needed. It's now an absolute corner chip, and --tube-h shrank back
#         down now that every tube converges on the same natural height.
Check (
    ($css154 -match '(?s)\.tube\.family \.multi-tag \{.{0,300}position:\s*absolute') -and
    ($css154 -match '--tube-h:\s*112px')
) "154.36: .tube.family .multi-tag is an absolute corner chip (no longer forces its own flow line), and the shared --tube-h shrank accordingly -- all tubes stay the same, compact size (owner FIX 3)"

# 154.37  FIX 3 follow-up (owner: "make the default a tag too somehow? or a badge...
#         not tabs badges") -- (DEFAULT) gets the same absolute corner-chip treatment
#         as .multi-tag (opposite corner), and :empty hides the chip entirely on
#         every tube that isn't the active game's default -- _updateOpticsDefaultLabel()
#         itself is unchanged (Protocol 22).
$tDefaultBlock154 = [regex]::Match($css154, '(?s)\.tube \.t-default \{.*?\n\}').Value
Check (
    ($tDefaultBlock154 -match 'position:\s*absolute') -and
    ($tDefaultBlock154 -match 'display:\s*none') -and
    ($css154 -match '(?s)\.tube \.t-default:not\(:empty\) \{.{0,60}display:\s*inline-block') -and
    (-not ($tDefaultBlock154 -match 'min-height'))
) "154.37: .tube .t-default is an absolute corner chip hidden via :empty (no longer a reserved-min-height flow line), matching .multi-tag's treatment on the opposite corner"

# ===========================================================
# Suite 155 -- Step 2 (v2.7.0) Phase 2 B2b: Module Bay visual fidelity + fixes (16 tests)
# Rebuilds the B2a Module Bay to match the owner-approved Fable mockup's rich
# diegetic visuals (DIP-chip channel array, power-cell/solenoid graphics, a
# rotary immersion dial, the chassis subheader) plus four owner-reported fixes
# discovered live-rendering this unit (Protocol 42): unreadable tube labels,
# Schematic View text clipping, SVC-tray centering, and a new reload-
# persistence pref for the Bay/Schematic view choice. One-truth model
# preserved throughout. Mirrors JS Suite 155.
# ===========================================================
Sep "Suite 155 -- Step 2 Phase 2 B2b: Module Bay visual fidelity + fixes"
$html155   = Read-Src "index.html"
$core155   = Read-Src "js/ui-core.js"
$state155  = Read-Src "js/state.js"
$css155    = Read-Src "css/terminal.css"
$claude155 = Read-Src "CLAUDE.md"
$rules155  = Read-Src "RULES.md"

# 155.1  the chassis subheader from the mockup's bay-head row is present
Check (
    ($html155 -match '<div class="bay-chassis">') -and
    ($html155 -match 'CHASSIS RIT-V300') -and
    ($html155 -match 'BUS VOLTAGE NOMINAL')
) "155.1: the ""CHASSIS RIT-V300 . INTERNAL SERVICE VIEW . BUS VOLTAGE NOMINAL"" subheader is present in the bay header"

# 155.2  SLOT 02: the mute checkboxes are a DIP-chip grid -- exact
#        ids/onchange calls survive verbatim (Protocol 4/22), CH-01..CH-14
#        pin ids are present (CH-14 REACTOR HUM added by the CHASSIS LIVING
#        CORE behavior-batch unit), and the old plain-checkbox-list markup
#        is gone
$muteKeys155 = @(
    'robco_sfx_muted','robco_hum_muted','robco_geiger_muted','robco_tinnitus_muted',
    'robco_ambient_muted','robco_wake_muted','robco_panelclick_muted','robco_bootdrone_muted',
    'robco_levelup_muted','robco_heartbeat_muted','robco_questcomplete_muted',
    'robco_questfail_muted','robco_factionthreshold_muted','robco_reactorhum_muted'
)
$allMutes155 = $true
foreach ($k in $muteKeys155) { if (-not $html155.Contains("toggleAudio('$k', this.checked)")) { $allMutes155 = $false } }
$allChNums155 = $true
for ($i = 1; $i -le 14; $i++) { $ch = "CH-{0:D2}" -f $i; if (-not $html155.Contains($ch)) { $allChNums155 = $false } }
Check (
    ([regex]::Matches($html155, 'class="chip-wrap"').Count -eq 14) -and
    ([regex]::Matches($html155, 'class="chip-input"').Count -eq 14) -and
    ([regex]::Matches($html155, 'class="chip-card"').Count -eq 14) -and
    $allChNums155 -and $allMutes155 -and
    (-not ($html155 -match 'class="audio-row"')) -and
    (-not ($html155 -match 'class="bay-channel-list"'))
) "155.2: the 14 SLOT-02 channels render as a chip-grid of chip-wrap/chip-input/chip-card triples with CH-01..CH-14 pin ids, every toggleAudio() call unchanged, and the old audio-row/bay-channel-list markup is fully retired"

# 155.3  chip polarity is INVERTED in CSS only (Protocol 25 sanctioned
#        exception) -- the checkbox keeps writing the same `muted` boolean;
#        :checked (muted=true) reads as a PULLED chip, not a seated one
Check (
    ($css155 -match '(?s)\.chip-input:checked \+ \.chip-card \{.{0,200}(border-style:\s*dashed|opacity:\s*0\.5)') -and
    ($css155 -match "(?s)\.chip-input:checked \+ \.chip-card \.pin-id::after \{.{0,80}content:\s*' . SOCKET EMPTY'")
) "155.3: chip :checked (muted) styles as a PULLED/dashed chip and appends ""SOCKET EMPTY"" -- presentation-only inversion, storage format unchanged"

# 155.4  SLOT 03 hardware graphics: a battery-cell graphic wired to the
#        Sustained Power Cell module, a coil graphic wired to the Haptic
#        Solenoid module -- both keep their exact pre-existing setters
Check (
    ($html155 -match '(?s)id="wakeLockToggle".{0,60}class="bay-module-input".{0,300}onchange="toggleWakeLock\(this\.checked\)"') -and
    ($html155 -match '(?s)<span class="cell-graphic" aria-hidden="true".{0,60}FUSION MK-II') -and
    ($html155 -match '(?s)id="hapticToggle".{0,300}onchange="toggleHaptic\(this\.checked\)"') -and
    ($html155 -match '<span class="coil-graphic" aria-hidden="true">')
) "155.4: SLOT 03 shows a battery-cell graphic (Sustained Power Cell) and a coil graphic (Haptic Solenoid), both still driven by their unchanged toggleWakeLock()/toggleHaptic() setters"

# 155.5  SLOT 04: a real, functioning #immersionSelect survives VERBATIM
#        (Protocol 4) but is now visually hidden; a genuinely-custom rotary
#        dial button is the visible control, cycling the same 3 values
Check (
    ($html155 -match '(?s)id="immersionSelect".{0,60}class="bay-visually-hidden-input".{0,200}onchange="onImmersionChange\(this\.value\)"') -and
    ($html155 -match '(?s)<button.{0,100}class="dial".{0,120}onclick="_cycleImmersionDial\(\)"') -and
    ($html155 -match 'id="immersionDialKnob"') -and
    ($html155 -match 'id="immersionDialPos"') -and
    ($html155 -match 'id="immersionDialDesc"')
) "155.5: #immersionSelect keeps its exact id/onchange (now visually hidden, Protocol 17 a11y preserved) alongside a real .dial button + knob/pos/desc readout"

# 155.6  _cycleImmersionDial() calls the SAME onImmersionChange() setter
#        (Protocol 22) -- never a parallel persistence path
$cycleFn155 = Get-FunctionBody $core155 '_cycleImmersionDial'
Check (
    ($cycleFn155 -match 'onImmersionChange\(next\)') -and
    (-not ($cycleFn155 -match 'MetaStore\.set'))
) "155.6: _cycleImmersionDial() calls onImmersionChange() (the existing setter) directly -- no new persistence path"

# 155.7  _updateImmersionUI() is the single re-sync point keeping the hidden
#        select's value, the dial knob rotation, and the position/description
#        readout all agreeing with the one stored tier
$immersionUiFn155 = Get-FunctionBody $core155 '_updateImmersionUI'
Check (
    ($immersionUiFn155 -match 'sel\.value = tier') -and
    ($immersionUiFn155 -match 'IMMERSION_DIAL\[tier\]') -and
    ($immersionUiFn155 -match 'knob\.style\.transform') -and
    ($immersionUiFn155 -match 'posEl\.textContent = tier\.toUpperCase\(\)')
) "155.7: _updateImmersionUI() re-syncs the hidden select value + dial knob/position/description from the single stored tier on every call"

# 155.8  SLOT 05: the CIPHER KEY SLOT label is present, and #btnFetchModels
#        (moved inside .key-slot beside the input) appears EXACTLY ONCE --
#        the pre-existing standalone duplicate was removed, not left behind
Check (
    ($html155 -match '(?s)class="key-slot-label".{0,20}>\s*CIPHER KEY SLOT') -and
    ([regex]::Matches($html155, 'id="btnFetchModels"').Count -eq 1) -and
    ($html155 -match '(?s)class="key-slot">.{0,600}id="btnFetchModels"')
) "155.8: the ""CIPHER KEY SLOT"" label is present and #btnFetchModels (HANDSHAKE) now lives exactly once, inside .key-slot beside the cipher key input"

# 155.9  SVC tray: the tray still centers any partial last row via flex
#        (FIX 3) -- the EJECT HOLOTAPE consolidation (owner report, a later
#        unit) is covered by its own dedicated Suite 174; this guard only
#        locks the .bay-tools centering behavior it originally verified.
Check (
    ($css155 -match '(?s)\.bay-tools \{.{0,200}display:\s*flex.{0,200}justify-content:\s*center')
) "155.9: .bay-tools centers a partial last row via flex + justify-content:center (FIX 3)"

# 155.10  FIX 2 (owner report): the Schematic View's rows stack name/loc
#         above a full-width control so a select can never be squeezed
#         narrower than its own content ("ROBCO GR..." clipping regression)
$schemFn155 = Get-FunctionBody $core155 'renderBaySchematic'
Check (
    ($schemFn155 -match 'schem-row-head') -and
    ($schemFn155 -match 'schem-row-control') -and
    ($css155 -match "(?s)\.schem-row-control select,\s*`n\s*\.schem-row-control input\[type='range'\] \{.{0,60}width:\s*100%")
) "155.10: renderBaySchematic() stacks each row's name/loc above a full-width .schem-row-control, and the control CSS forces width:100% -- the select can never clip its selected-option text again (FIX 2)"

# 155.11  FIX 1 (owner report): button.tube declares an explicit color --
#         regression guard against the dark-on-dark bug (a plain <button>
#         inherits the global button{color:var(--robco-dark)} meant for a
#         bright fill; .tube overrides background but had never overridden
#         color, rendering near-black text on its own near-black card)
Check (
    ($css155 -match '(?s)button\.tube \{.{0,700}color:\s*var\(--robco-green\)')
) "155.11: button.tube declares an explicit color (not the inherited global button dark-text default) -- regression guard for the unreadable tube-label bug (FIX 1)"

# 155.12  FIX 4 (new standing rule -- "everything remembers on reload"): the
#         Bay/Schematic view choice is a registered MetaStore device pref,
#         shared by both the boot restore and the user toggle so they can
#         never drift (Protocol 22)
Check (
    ($state155 -match "robco_bay_view: \{ type: 'string', default: 'bay', owner: 'ui-core\.js' \}") -and
    ($core155 -match 'function _applyBayView\(view\)') -and
    ($core155 -match "_applyBayView\(MetaStore\.get\('robco_bay_view'\) === 'schematic' \? 'schematic' : 'bay'\)") -and
    ($core155 -match "MetaStore\.set\('robco_bay_view', view\)") -and
    ($core155 -match '(?s)function toggleBaySchematic\(\).{0,300}_applyBayView\(view\)')
) "155.12: robco_bay_view is a registered MetaStore pref; initModuleBay() and toggleBaySchematic() both route through the shared _applyBayView() so the Bay/Schematic choice survives a reload"

# 155.13  Protocol 17 -- every new interactive/graphic element meets the
#         >=28px tap-target floor
Check (
    ($css155 -match '(?s)\.chip-card \{.{0,400}min-height:\s*44px') -and
    ($css155 -match '(?s)button\.dial \{.{0,400}(width:\s*84px|height:\s*84px)') -and
    ($css155 -match '(?s)\.bay-tools button \{.{0,300}min-height:\s*28px')
) "155.13: the new chip cards, the rotary dial, and the SVC tray buttons all meet the >=28px tap-target floor (Protocol 17)"

# 155.14  Protocol UI-5 -- no <span onclick> pattern was introduced anywhere
#         in this unit's additions (re-verify after B2b's new markup)
Check (-not ($html155 -match '<span[^>]*onclick=')) "155.14: no <span onclick> pattern anywhere (Protocol UI-5) after the B2b visual rebuild"

# 155.15  Protocol 38 -- the new markup/JS is game-agnostic
$bayJsStart155 = $core155.IndexOf('const BAY_SVC_LOG_CAP')
$bayJsEnd155 = $core155.IndexOf('window._svcInstallPwa = _svcInstallPwa;') + 'window._svcInstallPwa = _svcInstallPwa;'.Length
$bayJs155 = $core155.Substring($bayJsStart155, $bayJsEnd155 - $bayJsStart155) + $cycleFn155 + $immersionUiFn155
$bayHtmlStart155 = $html155.IndexOf('id="moduleBay"')
$bayHtmlEnd155 = $html155.IndexOf('ALL SAVES')
$bayHtml155 = $html155.Substring($bayHtmlStart155, $bayHtmlEnd155 - $bayHtmlStart155)
Check (
    (-not ($bayJs155 -match '\bFNV\b|\bFO3\b|Fallout')) -and
    (-not ($bayHtml155 -match '\bFNV\b|\bFO3\b|Fallout'))
) "155.15: the B2b Module Bay additions stay game-agnostic -- no hardcoded game literals"

# 155.16  the reload-persistence standing rule + the Protocol 2a wording fix
#         are both recorded in the docs this unit touches
Check (
    ($claude155 -match '(?i)everything remembers on reload') -and
    (-not ($claude155 -match 'the files are kept identical for protocol sections')) -and
    (-not ($rules155 -match 'the files are kept identical for protocol sections'))
) "155.16: CLAUDE.md records the new reload-persistence standing rule, and the stale ""RULES.md and CLAUDE.md are kept identical"" sentence is corrected"

# ===========================================================
# Suite 156 -- Step 2 (v2.7.0) Phase 2 B2c: Module Bay refinements + hardware
# SFX (16 tests). Two owner bug/request fixes -- master-mute now shows every
# SLOT-02 chip as pulled/off (display-only, individual mute prefs preserved),
# a draggable/slideable Immersion dial layered on top of the existing tap-to-
# cycle -- plus the Module Bay's SFX unit: a SERVO CLICK RELAY channel gating
# a tactile chip-click and a heavier board-thunk on every install/eject
# action across chips, the Sonic Processor board, and the radio/power-cell/
# haptic bay-module toggles. Mirrors JS Suite 156.
# ===========================================================
Sep "Suite 156 -- Step 2 Phase 2 B2c: Module Bay refinements + hardware SFX"
$html156  = Read-Src "index.html"
$core156  = Read-Src "js/ui-core.js"
$audio156 = Read-Src "js/ui-audio.js"
$state156 = Read-Src "js/state.js"
$css156   = Read-Src "css/terminal.css"
$arch156  = Read-Src "ARCHITECTURE.md"

# 156.1  FIX 1: #chipGrid id is present on the 13-chip grid so JS can target
#        it, and the CSS ejected-board rule reads every chip as pulled
Check (
    ($html156 -match '<div class="chip-grid" id="chipGrid">') -and
    ($css156 -match '(?s)\.sonic-board--ejected \.chip-card \{.{0,120}(border-style:\s*dashed|opacity:\s*0\.5)') -and
    ($css156 -match "(?s)\.sonic-board--ejected \.chip-card \.pin-id::after \{.{0,60}content:\s*' . SOCKET EMPTY'")
) "156.1: #chipGrid exists and .sonic-board--ejected forces every .chip-card to read pulled/SOCKET EMPTY, independent of each chip's own :checked state"

# 156.2  FIX 1: _updateSonicBoardStatus() toggles the ejected class purely
#        from AudioSettings.masterMute and never writes to any robco_*_muted
#        key -- the individual chip mute prefs must survive untouched
$sonicStatusFn156 = Get-FunctionBody $audio156 '_updateSonicBoardStatus'
Check (
    ($sonicStatusFn156 -match "classList\.toggle\('sonic-board--ejected', !!AudioSettings\.masterMute\)") -and
    (-not ($sonicStatusFn156 -match 'MetaStore\.set'))
) "156.2: _updateSonicBoardStatus() drives .sonic-board--ejected purely off AudioSettings.masterMute and performs no MetaStore writes (visual-only, individual chip prefs preserved for reseat)"

# 156.3  FIX 1: toggleAudio() (the setter every one of the 13 chips + the
#        SERVO CLICK RELAY calls) still writes the per-key mute pref
#        unconditionally -- the ejected-board display never short-circuits it
$toggleAudioFn156 = Get-FunctionBody $audio156 'toggleAudio'
Check (
    $toggleAudioFn156 -match 'MetaStore\.set\(key, isMuted\)'
) "156.3: toggleAudio() still unconditionally persists the per-chip mute key regardless of master-mute state -- FIX 1 is display-only"

# 156.4  FIX 2: the dial's tap-to-cycle path and the new drag path share the
#        SAME 3-value order and the SAME onImmersionChange() setter, and a
#        genuine drag suppresses the trailing synthetic click so a drag can
#        never double-apply on release
$cycleFn156 = Get-FunctionBody $core156 '_cycleImmersionDial'
Check (
    ($core156 -match "const IMMERSION_ORDER = \['full', 'balanced', 'minimal'\];") -and
    ($core156 -match 'let _dialDragSuppressClick = false;') -and
    ($cycleFn156 -match "(?s)if \(_dialDragSuppressClick\) \{\s*_dialDragSuppressClick = false;\s*return;") -and
    ($cycleFn156 -match 'onImmersionChange\(next\)')
) "156.4: _cycleImmersionDial() consumes-and-resets the drag-suppress flag before falling through to its unchanged IMMERSION_ORDER cycle + onImmersionChange() call"

# 156.5  FIX 2: the drag handlers step through IMMERSION_ORDER via the SAME
#        onImmersionChange() setter (Protocol 22 -- never a forked
#        persistence path), and wiring degrades gracefully with no
#        PointerEvent support
$dialMoveFn156 = Get-FunctionBody $core156 '_dialPointerMove'
$wireDragFn156 = Get-FunctionBody $core156 '_wireImmersionDialDrag'
$initImmersionFn156 = Get-FunctionBody $core156 'initImmersion'
Check (
    ($dialMoveFn156 -match 'onImmersionChange\(IMMERSION_ORDER\[idx\]\)') -and
    ($wireDragFn156 -match "typeof window\.PointerEvent === 'undefined'") -and
    ($wireDragFn156 -match "addEventListener\('pointerdown', _dialPointerDown\)") -and
    ($initImmersionFn156 -match '_wireImmersionDialDrag\(\);')
) "156.5: pointer-drag steps IMMERSION_ORDER through the same onImmersionChange() setter, no-ops gracefully without PointerEvent support, and is wired from initImmersion() at boot"

# 156.6  FIX 2: the dial disables page-scroll gestures while a drag is in
#        progress, and the existing keyboard/tap path (button + onclick) is
#        untouched
Check (
    ($css156 -match '(?s)button\.dial \{.{0,700}touch-action:\s*none') -and
    ($html156 -match '(?s)class="dial".{0,60}onclick="_cycleImmersionDial\(\)"')
) "156.6: button.dial sets touch-action:none for clean drag gestures, and the original onclick=""_cycleImmersionDial()"" tap/keyboard path is unchanged"

# 156.7  B2c: the new hardwareSfx channel is a registered device pref (both
#        the META_MANIFEST boundary and the AudioSettings runtime cache)
Check (
    ($state156 -match "robco_hardwaresfx_muted: \{ type: 'bool', default: false, owner: 'ui-audio\.js' \}") -and
    ($core156 -match "hardwareSfx: MetaStore\.get\('robco_hardwaresfx_muted'\) === 'true'")
) "156.7: robco_hardwaresfx_muted is registered in META_MANIFEST and seeded into AudioSettings.hardwareSfx at startup"

# 156.8  B2c (Protocol 7 guard order): both new play functions check
#        AudioSettings.masterMute FIRST, then their own channel flag SECOND
$chipClickFn156 = Get-FunctionBody $audio156 'playChipClick'
$boardThunkFn156 = Get-FunctionBody $audio156 'playBoardThunk'
Check (
    ($chipClickFn156 -match "(?s)if \(AudioSettings\.masterMute\) return;\s*if \(AudioSettings\.hardwareSfx\) return;") -and
    ($boardThunkFn156 -match "(?s)if \(AudioSettings\.masterMute\) return;\s*if \(AudioSettings\.hardwareSfx\) return;")
) "156.8: playChipClick() and playBoardThunk() both guard on AudioSettings.masterMute first, then AudioSettings.hardwareSfx second (Protocol 7 order)"

# 156.9  B2c: toggleAudio()'s keyMap wires the new key to the AudioSettings
#        cache, and every chip pull/insert fires the click via that channel
Check (
    ($toggleAudioFn156 -match "robco_hardwaresfx_muted: 'hardwareSfx', // B2c") -and
    ($toggleAudioFn156 -match 'playChipClick\(!isMuted\);')
) "156.9: toggleAudio() maps robco_hardwaresfx_muted -> AudioSettings.hardwareSfx and fires playChipClick() on every chip toggle"

# 156.10  B2c: the Sonic Processor board's own eject/reseat plays the
#         heavier board-thunk at the correct moment relative to the
#         masterMute flag flip -- heard leaving on eject (before the flag
#         flips true), heard arriving on reseat (after it flips back false)
#         -- so the click itself never bypasses the master-mute guard
$masterMuteFn156 = Get-FunctionBody $audio156 'toggleMasterMute'
Check (
    $masterMuteFn156 -match "(?s)if \(isMuted\) playBoardThunk\(false\);\s*MetaStore\.set\('robco_master_muted', isMuted\);\s*AudioSettings\.masterMute = isMuted;\s*if \(!isMuted\) playBoardThunk\(true\);"
) "156.10: toggleMasterMute() plays the eject thunk before the flag flips true and the reseat thunk after it flips back false, so playBoardThunk()'s own masterMute guard is never the thing suppressing it"

# 156.11  B2c: the other bay-module install/eject toggles (radio, power
#         cell, haptic solenoid) all fire the same tactile click
$radioFn156 = Get-FunctionBody $audio156 'toggleRadio'
$wakeLockFn156 = Get-FunctionBody $core156 'toggleWakeLock'
$hapticFn156 = Get-FunctionBody $audio156 'toggleHaptic'
Check (
    ($radioFn156 -match 'playChipClick\(on\);') -and
    ($wakeLockFn156 -match 'playChipClick\(enabled\);') -and
    ($hapticFn156 -match 'playChipClick\(enabled\);')
) "156.11: toggleRadio()/toggleWakeLock()/toggleHaptic() each fire playChipClick() on install/eject, alongside their unchanged feature logic"

# 156.12  B2c: the SERVO CLICK RELAY control lives inside the SLOT-02 Audio
#         Systems sub-panel with INVERTED checkbox semantics (checked =
#         installed = audible) writing through the SAME toggleAudio() every
#         other channel chip uses (Protocol 25 sanctioned-exception rule)
$audioPanelStart156 = $html156.IndexOf('id="audioSystemsDetails"')
$audioPanelEnd156 = $html156.IndexOf('id="chipGrid"')
$audioPanel156 = $html156.Substring($audioPanelStart156, $audioPanelEnd156 - $audioPanelStart156)
Check (
    $audioPanel156.Contains('id="hardwareSfxToggle"') -and
    $audioPanel156.Contains('class="bay-module-input"') -and
    $audioPanel156.Contains('onchange="toggleAudio(''robco_hardwaresfx_muted'', !this.checked)"') -and
    $audioPanel156.Contains('SERVO CLICK RELAY') -and
    ($audioPanel156.IndexOf('id="hardwareSfxToggle"') -lt $audioPanel156.IndexOf('onchange="toggleAudio(''robco_hardwaresfx_muted'', !this.checked)"'))
) "156.12: #hardwareSfxToggle sits inside SLOT 02, defaults checked (installed), and writes the mute boolean through the unchanged toggleAudio() setter with inverted presentation only"

# 156.13  B2c: boot restore, the bay<->schematic resync, and the Schematic
#         View mirror all account for the INVERTED checkbox semantics -- the
#         same three-way sync discipline every other bay control follows
Check (
    ($core156 -match "(?s)if \(MetaStore\.get\('robco_hardwaresfx_muted'\) === 'true'\) \{\s*let el = document\.getElementById\('hardwareSfxToggle'\);\s*if \(el\) el\.checked = false;") -and
    ($core156 -match "hwSfxToggle\.checked = MetaStore\.get\('robco_hardwaresfx_muted'\) !== 'true'") -and
    ($core156 -match "(?s)function _schemSetHardwareSfx\(checked\) \{\s*toggleAudio\('robco_hardwaresfx_muted', !checked\);") -and
    ($core156 -match "checkboxRow\('_schemSetHardwareSfx', hwSfxOn, 'SERVO CLICK RELAY', 'SLOT 02'\)")
) "156.13: _restoreDevicePrefs()/renderModuleBay()/renderBaySchematic() all mirror the inverted SERVO CLICK RELAY state so the bay checkbox, the schematic checkbox, and a fresh boot can never drift"

# 156.14  B2c: the new device-preference key is documented in the canonical
#         Settings table (Protocol 7's ARCHITECTURE.md checklist item)
Check (
    $arch156 -match '`robco_hardwaresfx_muted`\s*\|\s*bool\s*\|\s*ui-audio\.js'
) "156.14: robco_hardwaresfx_muted is documented in the ARCHITECTURE.md Settings & localStorage Keys table"

# 156.15  Protocol 38 -- every B2c addition stays game-agnostic
$b2cJs156 = $chipClickFn156 + $boardThunkFn156 + $cycleFn156 + $dialMoveFn156 + $wireDragFn156 + $sonicStatusFn156
Check (
    (-not ($b2cJs156 -match '\bFNV\b|\bFO3\b|Fallout')) -and
    (-not ($audioPanel156 -match '\bFNV\b|\bFO3\b|Fallout'))
) "156.15: the B2c additions (dial drag, chip/board SFX, ejected-board display) stay game-agnostic -- no hardcoded game literals"

# 156.16  Protocol UI-5 -- no <span onclick> pattern was introduced anywhere
Check (-not ($html156 -match '<span[^>]*onclick=')) "156.16: no <span onclick> pattern anywhere (Protocol UI-5) after the B2c additions"

# ===========================================================
# Suite 157 -- DO-K: identity keystone -- GAME_DEFS[ctx].identity + data-game
# (Design Overhaul, build FIRST). Shells out to node (mirrors the Suite 133
# pattern) to behaviorally prove: every GAME_DEFS entry (FNV/FO3/FO4) carries
# a complete `identity` contract; `identity.theme` is the SAME object as the
# game's existing `theme` facet (Protocol 22 -- widened, never forked); and
# getIdentity() resolves the active game by default, an explicit ctx, and
# fails safe to FNV for an unknown ctx. FO4 is a complete-but-designOnly entry
# with the skill-less (FO4-class) contract (skillKeys/factions/combatSkills:
# []) locked by the Step 2 Phase 0 U11 audit. Static guards cover the three
# data-game write sites (index.html pre-paint, _restoreOpticsPreference(),
# onGameContextChange()), the designOnly guards in onGameContextChange() and
# wipeTerminal()'s context-list loop, and the save boundary (no
# saveState()/robco_v8 write anywhere in the DO-K additions). Mirrors JS
# Suite 157. 24 tests.
# ===========================================================
Sep "Suite 157 -- DO-K: identity keystone (GAME_DEFS.identity + data-game)"
$html157   = Read-Src "index.html"
$core157   = Read-Src "js/ui-core.js"
$state157  = Read-Src "js/state.js"
$eslint157 = Read-Src "eslint.config.mjs"

$labels157 = @(
    "js/state.js loads cleanly in a fresh VM sandbox",
    "157.1.FNV: GAME_DEFS.FNV.identity carries every contract field (machine/material/structuralMode/theme/persona/ceremony/motionTexture/cursor/audio/voice/ambient/overseer/databank)",
    "157.1.FO3: GAME_DEFS.FO3.identity carries every contract field (machine/material/structuralMode/theme/persona/ceremony/motionTexture/cursor/audio/voice/ambient/overseer/databank)",
    "157.1.FO4: GAME_DEFS.FO4.identity carries every contract field (machine/material/structuralMode/theme/persona/ceremony/motionTexture/cursor/audio/voice/ambient/overseer/databank)",
    "157.2.FNV: GAME_DEFS.FNV.identity.theme === GAME_DEFS.FNV.theme (same object, zero drift possible)",
    "157.2.FO3: GAME_DEFS.FO3.identity.theme === GAME_DEFS.FO3.theme (same object, zero drift possible)",
    "157.2.FO4: GAME_DEFS.FO4.identity.theme === GAME_DEFS.FO4.theme (same object, zero drift possible)",
    "157.3: getIdentity() is defined in js/state.js and exposed as window.getIdentity",
    "157.4: getIdentity() with no ctx resolves the active game (default FNV) identity block",
    "157.5: getIdentity(""FO3"") resolves GAME_DEFS.FO3.identity by explicit ctx",
    "157.6: getIdentity() fails safe to FNV identity for an unknown/invalid ctx -- never returns undefined",
    "157.7: GAME_DEFS.FO4.designOnly === true",
    "157.8: GAME_DEFS.FO4.skillKeys/factions/combatSkills are declared as empty arrays (never omitted -- the skill-less FO4-class contract)",
    "157.9: FO3.identity and FO4.identity are distinct objects with distinct machine/persona/cursor values",
    "157.10: GAME_DEFS.FNV.identity matches the approved NV mockup (salvaged-terminal, amber-block cursor, Mojave uplink handshake, populated blip bank)"
)
try {
    $nodeCheck157 = Get-Command node -ErrorAction SilentlyContinue
    if ($nodeCheck157) {
        $statePathNode157 = (Join-Path $Root "js/state.js").Replace('\', '/')
        $testScript157 = @"
const fs = require('fs');
const vm = require('vm');
const stateSource = fs.readFileSync('$statePathNode157', 'utf8');
const sandbox = { window: {}, document: { getElementById: () => null }, console: { error: () => {}, log: () => {}, warn: () => {} } };
vm.createContext(sandbox);
const results = [];
let GAME_DEFS, getIdentity;
try {
  vm.runInContext(stateSource, sandbox);
  GAME_DEFS = sandbox.window.GAME_DEFS;
  getIdentity = sandbox.window.getIdentity;
  results.push(!!GAME_DEFS && !!getIdentity);
} catch (e) {
  results.push(false);
}
const CONTRACT = ['machine','material','structuralMode','theme','persona','ceremony','motionTexture','cursor','audio','voice','ambient','overseer','databank'];
['FNV','FO3','FO4'].forEach(ctx => {
  try {
    const id = GAME_DEFS[ctx] && GAME_DEFS[ctx].identity;
    const missing = CONTRACT.filter(f => !id || id[f] === undefined || id[f] === null);
    results.push(!!id && missing.length === 0);
  } catch (e) { results.push(false); }
});
['FNV','FO3','FO4'].forEach(ctx => {
  try {
    const def = GAME_DEFS[ctx];
    results.push(!!def && !!def.identity && def.identity.theme === def.theme);
  } catch (e) { results.push(false); }
});
try { results.push(typeof getIdentity === 'function'); } catch (e) { results.push(false); }
try { results.push(getIdentity() === GAME_DEFS.FNV.identity); } catch (e) { results.push(false); }
try { results.push(getIdentity('FO3') === GAME_DEFS.FO3.identity); } catch (e) { results.push(false); }
try { results.push(getIdentity('NOT-A-REAL-GAME') === GAME_DEFS.FNV.identity); } catch (e) { results.push(false); }
try { results.push(GAME_DEFS.FO4.designOnly === true); } catch (e) { results.push(false); }
try {
  const fo4 = GAME_DEFS.FO4;
  results.push(Array.isArray(fo4.skillKeys) && fo4.skillKeys.length === 0 && Array.isArray(fo4.factions) && fo4.factions.length === 0 && Array.isArray(fo4.combatSkills) && fo4.combatSkills.length === 0);
} catch (e) { results.push(false); }
try {
  const fo3id = GAME_DEFS.FO3.identity, fo4id = GAME_DEFS.FO4.identity;
  results.push(fo3id !== fo4id && fo3id.machine !== fo4id.machine && fo3id.persona.texture !== fo4id.persona.texture && fo3id.cursor !== fo4id.cursor);
} catch (e) { results.push(false); }
try {
  const nv = GAME_DEFS.FNV.identity;
  results.push(nv.machine === 'salvaged-terminal' && nv.cursor === 'amber-block' && nv.ceremony.coldStart === 'mojave-uplink-handshake' && Array.isArray(nv.persona.blipBank) && nv.persona.blipBank.length > 0);
} catch (e) { results.push(false); }
console.log('RESULT:' + results.map(r => r ? '1' : '0').join(''));
"@
        $out157 = ($testScript157 | node 2>&1 | Out-String)
        $rm157 = [regex]::Match($out157, 'RESULT:([01]{15})')
        if ($rm157.Success) {
            $bits157 = $rm157.Groups[1].Value
            for ($bi = 0; $bi -lt 15; $bi++) { Check ($bits157.Substring($bi, 1) -eq '1') $labels157[$bi] }
        } else {
            $err157 = if ([string]::IsNullOrWhiteSpace($out157)) { "No output from node" } else { $out157.Trim() }
            foreach ($lbl in $labels157) { Fail "$lbl  (runtime error: $err157)" }
        }
    } else {
        foreach ($lbl in $labels157) { Fail "$lbl  (node not found)" }
    }
} catch {
    foreach ($lbl in $labels157) { Fail "$lbl  (harness error: $_)" }
}

# 157.11  data-game pre-paint (index.html head script, before state.js loads)
Check (
    $html157 -match 'document\.documentElement\.dataset\.game\s*=\s*_ctx0'
) "157.11: index.html sets a flash-free pre-paint data-game attribute from the same _ctx0 the optics head script already resolves"

# 157.12  data-game re-applied once state.js is live (_restoreOpticsPreference)
$restoreBody157 = Get-FunctionBody $core157 '_restoreOpticsPreference'
Check (
    $restoreBody157 -match 'document\.documentElement\.dataset\.game\s*=\s*getGameContext\(\)'
) "157.12: _restoreOpticsPreference() re-applies data-game from getGameContext() once state is live"

# 157.13  data-game flips before the reload in onGameContextChange()
$ctxChangeBody157 = Get-FunctionBody $core157 'onGameContextChange'
$setIdx157 = $ctxChangeBody157.IndexOf('document.documentElement.dataset.game = ctx')
$reloadIdx157 = $ctxChangeBody157.IndexOf('window.location.reload()')
Check (
    ($setIdx157 -ge 0) -and ($reloadIdx157 -ge 0) -and ($setIdx157 -lt $reloadIdx157)
) "157.13: onGameContextChange() sets data-game to the target ctx BEFORE window.location.reload()"

# 157.14  onGameContextChange() refuses a designOnly game context (the FO4 guard)
Check (
    $ctxChangeBody157 -match 'if \(!GAME_DEFS\[ctx\] \|\| GAME_DEFS\[ctx\]\.designOnly\) return;'
) "157.14: onGameContextChange() returns early for an unknown OR designOnly game context"

# 157.15  #gameContextSelect offers no FO4 <option> (FO4 stays unreachable in the live UI)
$selectStart157 = $html157.IndexOf('id="gameContextSelect"')
$selectEnd157 = $html157.IndexOf('</select>', $selectStart157)
$selectBlock157 = $html157.Substring($selectStart157, $selectEnd157 - $selectStart157)
Check (
    ($selectBlock157 -match 'value="FNV"') -and ($selectBlock157 -match 'value="FO3"') -and (-not ($selectBlock157 -match 'value="FO4"'))
) "157.15: #gameContextSelect lists FNV and FO3 only -- no FO4 <option> (FO4 stays unreachable this cycle)"

# 157.16  wipeTerminal()'s "SELECT GAME CONTEXT" chat list filters out designOnly entries
$wipeBody157 = Get-FunctionBody $core157 'wipeTerminal'
Check (
    $wipeBody157 -match "(?s)Object\.values\(GAME_DEFS\)\s*\.filter\(d => !d\.designOnly\)\s*\.forEach"
) "157.16: wipeTerminal() filters Object.values(GAME_DEFS) to !d.designOnly before listing selectable contexts"

# 157.17  eslint.config.mjs declares the new getIdentity() cross-file global (readonly)
Check (
    $eslint157 -match "getIdentity:\s*'readonly'"
) "157.17: eslint.config.mjs declares getIdentity as a readonly cross-file global"

# 157.18  save boundary -- the DO-K additions write nothing durable to the campaign
$identityBlockMatch157 = [regex]::Match($state157, '(?s)DO-K: identity keystone.*?window\.GAME_DEFS = GAME_DEFS;')
$identityBlock157 = if ($identityBlockMatch157.Success) { $identityBlockMatch157.Value } else { '' }
Check (
    ($identityBlock157.Length -gt 0) -and (-not ($identityBlock157 -match 'saveState\(')) -and (-not ($identityBlock157 -match "localStorage\.setItem\('robco_v8'"))
) "157.18: the DO-K identity/theme-alias block in state.js contains no saveState()/robco_v8 write (data-def only, Protocol 26)"

# 157.19  APP_VERSION stays 2.7.0 under [Unreleased] -- DO-K is cache-rev-only (Protocol 2)
Check (
    $state157 -match "APP_VERSION\s*=\s*'2\.7\.0'"
) "157.19: APP_VERSION remains 2.7.0 -- DO-K ships under [Unreleased] with a cache-rev bump only"

# ===========================================================
# Suite 158 -- DO-N: bezel chrome + subsystem nav
# Verifies the tab bar -> bezel keycap replacement preserves the router
# (switchTab, hotkeys, #go= deep-links, robco_active_tab), adds no campaign
# write, and honors the mobile/reduced-motion/centering-rule invariants.
# UPDATED (Step 2 v2.8.0 Settings-tab unit): extended with the 7th [6]
# SETTINGS keycap (158.19/158.20). UPDATED (bezel fidelity pass): extended
# with 158.21-158.27 (Gaps 1-7, desktop framed-casing fidelity). UPDATED
# (mobile immersion pass): extended with 158.28-158.30 (the mobile-scale
# complement -- rounded casing corners + a soft outer shadow on the fixed
# keycap dock too, plus a guard that the desktop gate stays untouched).
# Protocol 42 note: this header's declared count had drifted stale after
# the bezel fidelity pass added 7 tests without updating it -- corrected
# here alongside this unit's own +3 (harness-only drift, no functional
# impact; the actual assertions always ran, only the doc comment lagged).
# UPDATED (owner-report fix -- keycap label wrap + active pressed-state):
# extended with 158.31-158.32 (label nowrap + ellipsis safety net, and
# the pressed-in active-keycap look).
# UPDATED (owner-report fix -- uniform keycap width): extended with
# 158.33-158.34 (all 7 keycaps share one fixed width via --navkey-w,
# with the label font shrunk to fit the longest labels at that width;
# desktop scales both up inside the existing hover+fine gate).
# 39 tests.
# ===========================================================
Sep "Suite 158 -- DO-N: bezel chrome + subsystem nav"
$html158 = Read-Src "index.html"
$core158 = Read-Src "js/ui-core.js"
$state158 = Read-Src "js/state.js"
$sw158 = Read-Src "sw.js"
$css158 = Read-Src "css/terminal.css"

# 158.1  every navkey exists with its id + hotkey label
Check ($html158 -match 'id="navkey-operator"') "158.1a: navkey-operator keycap exists"
Check ($html158 -match 'id="navkey-operations"') "158.1b: navkey-operations keycap exists"
Check ($html158 -match 'id="navkey-databank"') "158.1c: navkey-databank keycap exists"
Check ($html158 -match 'id="navkey-uplink"') "158.1d: navkey-uplink keycap exists"
Check ($html158 -match 'id="navkey-chassis"') "158.1e: navkey-chassis keycap exists"
Check ($html158 -match 'id="navkey-directory"') "158.1f: navkey-directory (DIR fallback) keycap exists"

# 158.2  role=tablist ARIA is preserved on the new nav-cluster
Check (
    $html158 -match '<nav class="nav-cluster" role="tablist"'
) "158.2: the bezel nav-cluster preserves role=""tablist"" ARIA"

# 158.3  selectSubsystem() routes operator/operations/databank through the
# EXISTING switchTab() -- no forked routing (Protocol 22)
Check (
    ($core158 -match 'function selectSubsystem\(view\)') -and ($core158 -match 'switchTab\(tab\)')
) "158.3: selectSubsystem() is defined and routes tab-mapped subsystems through switchTab()"

# 158.4  hotkeys 1-5 + 0 are wired to selectSubsystem()/openBezelDirectory()
Check (
    ($core158 -match 'hotkeyMap\[e\.key\]') -and
    ($core158 -match 'selectSubsystem\(hotkeyMap\[e\.key\]\)') -and
    ($core158 -match 'openBezelDirectory\(\)')
) "158.4: hotkeys [1]-[5] call selectSubsystem() and [0] opens the DIRECTORY fallback"

# 158.5  switchTab() keeps merging 'data'+'campg' into DATABANK while STAT/INV
# stay mutually exclusive singletons (structural, behavior-preserving)
Check (
    ($core158 -match "_DATABANK_TABS\s*=\s*\['data',\s*'campg'\]") -and
    ($core158 -match 'const showTabs = _DATABANK_TABS\.includes\(tab\) \? _DATABANK_TABS : \[tab\]')
) "158.5: switchTab() merges data+campg into one DATABANK subsystem, stat/inv stay exclusive"

# 158.6  robco_bezel_subsystem is a registered MetaStore device pref (Protocol UI-6)
Check (
    $state158 -match "robco_bezel_subsystem:\s*\{\s*type:\s*'string',\s*default:\s*'operator'"
) "158.6: robco_bezel_subsystem is registered in META_MANIFEST, default 'operator'"

# 158.7  the DIRECTORY fallback reuses the shared openModal() driver -- no
# bespoke second dialog (Protocol 22); no new .modal-overlay markup added
$modalOverlayCount158 = [regex]::Matches($html158, 'class="modal-overlay"').Count
Check (
    ($core158 -match 'function openBezelDirectory\(\)') -and
    ($core158 -match "openModal\(\{ title: '> SUBSYSTEM DIRECTORY', body \}\)") -and
    ($modalOverlayCount158 -eq 2)
) "158.7: openBezelDirectory() reuses openModal()/#sysModal -- no new modal-overlay shell"

# 158.8  the DO-N nav layer writes nothing durable to the campaign -- every new
# function reads state (telemetry text) or MetaStore (view prefs) only, never
# saveState()/robco_v8/state.<field>=
$doNFns158 = @(
    'selectSubsystem', '_syncBezelNav', '_bezelTelemetryText', '_bezelSweep',
    'openBezelDirectory', 'initBezelSubsystem', '_initBezelChrome', '_updateFaultLamp'
)
$offenders158 = $doNFns158 | Where-Object {
    try { $body = Get-FunctionBody $core158 $_ } catch { return $true }
    return ($body -match 'saveState\(|robco_v8|state\.\w+\s*=')
}
Check (
    $offenders158.Count -eq 0
) ("158.8: the DO-N nav layer never writes campaign state (saveState/robco_v8/state.<field>=)" + $(if ($offenders158.Count) { " -- offenders: $($offenders158 -join ', ')" } else { "" }))

# 158.9  PWA deep-links/shortcuts are untouched -- same 4 SHORTCUT_ROUTES keys,
