# ===========================================================
# Suite 159 -- Owner bug-fix batch: eventLog live-render + centering rule (2 tests)
# Two cross-cutting fixes from a batch of owner-reported staging bugs that don't have a
# single natural home suite (the other three fixes in the same batch extend Suites
# 114/151/149/154 directly): (1) _logEvent() -- the ONE writer for the Terminal Record
# (state.eventLog) -- now re-paints CROSSROADS RECORD + INCIDENT LOG the instant ANY
# caller logs an event. (2) the centering rule: the 13-chip grid and 7-tube phosphor
# rack move to the reusable flex+wrap+justify-content:center pattern already
# established by .bay-tools, and the SAVE/cloud-sync button row gets the same
# treatment. Mirrors JS Suite 159.
# ===========================================================
Sep "Suite 159 -- Owner bug-fix batch: eventLog live-render + centering rule"
$stateSrc159 = Read-Src "js/state.js"
$htmlSrc159 = Read-Src "index.html"
$cssSrc159 = Read-Src "css/terminal.css"
$logEventFn159 = Get-FunctionBody $stateSrc159 '_logEvent'

# 159.1  _logEvent() is the single writer for state.eventLog (Protocol 22) -- patching
#        it once re-renders CROSSROADS RECORD + INCIDENT LOG for every current AND
#        future caller, closing the owner-reported "doesn't live update, I have to
#        refresh" gap without touching every individual call site.
Check (
    $logEventFn159 -match "typeof renderCampaignStatus === 'function'\) renderCampaignStatus\(\);"
) "159.1: _logEvent() re-renders renderCampaignStatus() (CROSSROADS RECORD + INCIDENT LOG) after every append -- the single choke point that fixes the live-update gap for every eventLog writer (owner report)"

# 159.2  the centering rule: .chip-grid + .tube-rack use the reusable
#        flex+wrap+justify-content:center pattern (never CSS Grid auto-fill, which
#        can't center a responsive incomplete last row), and the SAVE/cloud-sync
#        button row gets the same treatment.
$saveBtnIdx159 = $htmlSrc159.IndexOf('id="btnSaveToCloud"')
$saveBtnRowStart159 = [Math]::Max(0, $saveBtnIdx159 - 400)
$saveBtnRowSlice159 = $htmlSrc159.Substring($saveBtnRowStart159, $saveBtnIdx159 - $saveBtnRowStart159)
Check (
    ($cssSrc159 -match "(?s)\.chip-grid \{.{0,120}display:\s*flex;.{0,120}justify-content:\s*center;") -and
    (-not ($cssSrc159 -match "(?s)\.chip-grid \{.{0,120}display:\s*grid;")) -and
    ($cssSrc159 -match "(?s)\.tube-rack \{.{0,300}justify-content:\s*center;") -and
    ($saveBtnIdx159 -ge 0) -and
    ($saveBtnRowSlice159 -match 'justify-content:\s*center')
) "159.2: .chip-grid and .tube-rack use the reusable flex+wrap+justify-content:center pattern (not CSS Grid auto-fill) and the SAVE/cloud-sync button row is centered -- an incomplete last row never left-aligns (owner report, centering rule)"

# ===========================================================
# Suite 160 -- Owner audit: bezel bottom placement + stray-pin cleanup (6 tests)
# Two more owner-reported staging bugs from the same DO-N follow-up batch:
# (1) the bezel keycap nav rendered ABOVE the glass on mobile (a normal
# document-flow page, unlike desktop's fixed-height single-viewport shell) --
# reordering alone would just bury it after the very long single-column panel
# stack, so mobile docks it as a genuine position:fixed thumb-zone bar
# instead, reserving bottom padding so it never covers the last panel's
# content; desktop is untouched (it already put the bezel at the bottom via
# CSS `order`); (2) the nav-cluster's independent flex-wrap let CHASSIS wrap
# onto its own second line with DIR floating beside it -- fixed to a single
# non-wrapping strip; (3) the amber connector/vent-pin strips (Module Bay
# board dividers, SLOT-02 chip sockets) tiled with a repeating-linear-gradient
# whose cycle length rarely divides the strip's actual (responsive) width
# evenly, leaving a stray thin partial pin at the end --
# background-repeat:round rescales the tile so a whole number of pins always
# fits. Mirrors JS Suite 160.
# ===========================================================
Sep "Suite 160 -- Owner audit: bezel bottom placement + stray-pin cleanup"
$cssSrc160 = Read-Src "css/terminal.css"

# 160.1  the nav-cluster never wraps its own 5 tabs independently -- the whole
#        strip shrinks together instead of orphaning a key onto its own line
Check (
    $cssSrc160 -match "(?s)\.nav-cluster \{[^}]*flex-wrap:\s*nowrap"
) "160.1: .nav-cluster is flex-wrap:nowrap -- the 5 tabs always render as one strip (owner report: CHASSIS was wrapping onto its own second line with DIR floating beside it)"

# 160.2  mobile (<1000px) docks the bezel as a real position:fixed bottom bar,
#        not a reorder/sticky -- a reorder-only fix would bury the nav after the
#        very long single-column mobile page instead of keeping it reachable
Check (
    $cssSrc160 -match "(?s)@media \(max-width:\s*999\.98px\)\s*\{\s*\.bezel\s*\{[^}]*position:\s*fixed;[^}]*left:\s*0;[^}]*right:\s*0;[^}]*bottom:\s*0;"
) "160.2: the mobile bezel is position:fixed;left:0;right:0;bottom:0 -- a genuine thumb-zone dock, not just a reorder (owner report: `"it's at the top instead of the bottom`")"

# 160.3  the fixed mobile bezel reserves bottom space on .container so the dock
#        never covers the last panel's controls (Protocol 17)
Check (
    $cssSrc160 -match "(?s)@media \(max-width:\s*999\.98px\)\s*\{.*?\.container\.machine\s*\{[^}]*padding-bottom:"
) "160.3: the mobile media query reserves bottom padding on .container.machine so the fixed bezel never covers the last panel's content"

# 160.4  desktop's existing order-based bottom placement is untouched (it was
#        already correct -- this owner batch only ever needed to fix mobile)
Check (
    ($cssSrc160 -match "(?s)\.casing-top\s*\{\s*order:\s*1;") -and
    ($cssSrc160 -match "(?s)\.glass-frame\s*\{\s*order:\s*2;") -and
    ($cssSrc160 -match "(?s)\.bezel\s*\{\s*order:\s*3;")
) "160.4: the desktop casing-top/glass-frame/bezel order:1/2/3 flip is unchanged (desktop already rendered the bezel at the bottom)"

# 160.5  details.bay-board::after (Module Bay board divider pins) uses
#        background-repeat:round so a whole number of pins always fits -- no
#        truncated stub pin at the end
Check (
    $cssSrc160 -match "(?s)details\.bay-board::after \{[^}]*background-size:\s*12px 100%;[^}]*background-repeat:\s*round;"
) "160.5: details.bay-board::after uses background-repeat:round (owner report: a stray thin partial block trailed the last full pin)"

# 160.6  .chip-card::after (SLOT-02 channel chip socket pins) uses the same
#        background-repeat:round fix
Check (
    $cssSrc160 -match "(?s)\.chip-card::after \{[^}]*background-size:\s*8px 100%;[^}]*background-repeat:\s*round;"
) "160.6: .chip-card::after uses background-repeat:round -- same stray-pin fix as details.bay-board::after"

# ===========================================================
# Suite 161 -- Owner batch: saves OVERWRITE + live-update sweep + save-help +
# hatch replay (10 tests). Four owner reports fixed together: (1) no explicit
# "overwrite this save" affordance existed for a local slot OR a cloud save
# without a rename prompt -- confirmOverwriteSlot() (ui-saves.js) +
# window.overwriteCloudSave (cloud.js) add one, confirm-gated, keeping the
# existing name (cloud writes via updateDoc-by-id only, never setDoc --
# Protocol 34); (2) the SAVES LIST's VER badge "doesn't live update, I have to
# click LOAD before it updates" -- traced to saveToSlot() never calling
# renderSavesList() itself (only loadUI(), called by a LOAD, did) -- fixed at
# the one write path so both the pre-existing quicksave buttons AND the new
# OVERWRITE control refresh the list immediately (Protocol 22); (3) the save
# "?" field manual never described EXPORT FULL BACKUP -- SAVE_HELP gains it
# plus an OVERWRITE entry; (4) the Module Bay's view-once hatch ceremony had no
# way to replay for testing -- a REPLAY HATCH button in the (still gated/inert)
# Test Console resets the exact same robco_bay_opened MetaStore key
# releaseBayHatch() sets. Mirrors JS Suite 161.
# ===========================================================
Sep "Suite 161 -- Owner batch: saves OVERWRITE + live-update sweep + save-help + hatch replay"
$uiAcct161 = Read-Src "js/ui-account.js"
$uiSaves161 = Read-Src "js/ui-saves.js"
$cloud161 = Read-Src "js/cloud.js"
$uiCore161 = Read-Src "js/ui-core.js"
$html161 = Read-Src "index.html"
$testConsole161 = Read-Src "js/test-console.js"

# Assignment-form extractor (`window.X = async function (...) { ... }`) --
# Get-FunctionBody's `function <name>` search can't find these.
function Get-WindowFnBody161($source, $fnName) {
    $idx = $source.IndexOf("window.$fnName =")
    if ($idx -lt 0) { return "" }
    $start = $source.IndexOf('{', $idx)
    if ($start -lt 0) { return "" }
    $depth = 0
    $i     = $start
    while ($i -lt $source.Length) {
        $ch = $source[$i]
        if     ($ch -eq '{') { $depth++ }
        elseif ($ch -eq '}') { $depth--; if ($depth -eq 0) { return $source.Substring($start, $i - $start + 1) } }
        $i++
    }
    return ""
}

# 161.1  local slot rows: OVERWRITE sits between LOAD and the VER badge, with
#        a literal, descriptive aria-label (Protocol UI-3)
$loadIdx161 = $uiAcct161.IndexOf('loadFromSlot(')
$overwriteIdx161 = $uiAcct161.IndexOf('confirmOverwriteSlot(')
$verIdx161 = $uiAcct161.IndexOf('viewSlotVersions(')
Check (
    ($loadIdx161 -ge 0) -and ($overwriteIdx161 -ge 0) -and ($verIdx161 -ge 0) -and
    ($loadIdx161 -lt $overwriteIdx161) -and ($overwriteIdx161 -lt $verIdx161) -and
    ($uiAcct161 -match 'aria-label="Overwrite ')
) "161.1: renderSavesList() renders a confirm-gated OVERWRITE control on each local slot row, positioned between LOAD and the VER badge, with a descriptive aria-label"

# 161.2  cloud rows: OVERWRITE sits between LOAD and NAME/DEL, routed to
#        window.overwriteCloudSave, with the same aria-label convention
$cLoadIdx161 = $uiAcct161.IndexOf('window.loadCloudSave(')
$cOverwriteIdx161 = $uiAcct161.IndexOf('window.overwriteCloudSave(')
$cNameIdx161 = $uiAcct161.IndexOf('window.renameCloudSave(')
$ariaCount161 = ([regex]::Matches($uiAcct161, 'aria-label="Overwrite ')).Count
Check (
    ($cLoadIdx161 -ge 0) -and ($cOverwriteIdx161 -ge 0) -and ($cNameIdx161 -ge 0) -and
    ($cLoadIdx161 -lt $cOverwriteIdx161) -and ($cOverwriteIdx161 -lt $cNameIdx161) -and
    ($ariaCount161 -eq 2)
) "161.2: renderSavesList() renders a confirm-gated OVERWRITE control on each cloud save row, positioned between LOAD and NAME/DEL, routed to window.overwriteCloudSave"

# 161.3  confirmOverwriteSlot() (ui-saves.js): no rename prompt, diegetic
#        confirmAction() gate (not the blocking confirm()), delegates to the
#        SAME saveToSlot() write path (Protocol 22 -- one overwrite implementation)
$overwriteSlotBody161 = Get-FunctionBody $uiSaves161 "confirmOverwriteSlot"
Check (
    ($overwriteSlotBody161 -match "await confirmAction\(") -and
    ($overwriteSlotBody161 -notmatch "\bprompt\(") -and
    ($overwriteSlotBody161 -match "await saveToSlot\(slotNum\)")
) "161.3: confirmOverwriteSlot() awaits confirmAction() (not confirm()/prompt()) and overwrites via saveToSlot() with no rename prompt -- the slot keeps its existing name"

# 161.4  saveToSlot() calls renderSavesList() on a successful write -- the
#        confirmed root cause of "the version history doesn't live update, I
#        have to click LOAD before it updates" (loadUI(), called by LOAD, was
#        the only path that refreshed the list; a save itself never did)
$saveToSlotBody161 = Get-FunctionBody $uiSaves161 "saveToSlot"
$okIdx161 = $saveToSlotBody161.IndexOf("if (ok) {")
$renderIdx161 = $saveToSlotBody161.IndexOf("renderSavesList();")
Check (
    ($okIdx161 -ge 0) -and ($renderIdx161 -ge 0) -and ($renderIdx161 -gt $okIdx161)
) "161.4: saveToSlot() calls renderSavesList() on success, so the SAVES LIST (and its VER badge) refreshes live immediately -- no unrelated LOAD click required first"

# 161.5  window.overwriteCloudSave (cloud.js): gated exactly like every other
#        cloud write (cloudSync flag + signed-in non-anonymous), confirmAction-
#        gated, and writes via updateDoc ONLY -- never addDoc (would duplicate)
#        or setDoc (Protocol 34's banned blind-overwrite primitive)
$overwriteCloudBody161 = Get-WindowFnBody161 $cloud161 "overwriteCloudSave"
Check (
    ($overwriteCloudBody161 -match "isFeatureEnabled\('cloudSync'\)") -and
    ($overwriteCloudBody161 -match "_currentUser\.isAnonymous") -and
    ($overwriteCloudBody161 -match "await confirmAction\(") -and
    ($overwriteCloudBody161 -match "\bupdateDoc\(") -and
    ($overwriteCloudBody161 -notmatch "\baddDoc\(") -and
    ($overwriteCloudBody161 -notmatch "\bsetDoc\(")
) "161.5: window.overwriteCloudSave is cloudSync/signed-in gated, confirmAction-gated, and writes via updateDoc only (never addDoc/setDoc -- Protocol 34)"

# 161.6  overwriteCloudSave preserves the save's EXISTING label (read live
#        from the doc) rather than prompting for a new one, and refreshes
#        renderSavesList() on success
Check (
    ($overwriteCloudBody161 -notmatch "\bprompt\(") -and
    ($overwriteCloudBody161 -match "existingData = docSnap\.data\(\)") -and
    ($overwriteCloudBody161 -match "existingData\.label") -and
    ($overwriteCloudBody161 -match "window\.renderSavesList\(\)")
) "161.6: overwriteCloudSave keeps the save's existing label (no rename prompt) and calls window.renderSavesList() on success"

# 161.7  SAVE_HELP documents both OVERWRITE (new) and EXPORT FULL BACKUP
#        (pre-existing feature the "?" help menu never described)
$helpIdx161 = $uiCore161.IndexOf("const SAVE_HELP = [")
$helpEnd161 = $uiCore161.IndexOf("function showSaveHelpModal")
$helpSrc161 = if (($helpIdx161 -ge 0) -and ($helpEnd161 -ge 0)) { $uiCore161.Substring($helpIdx161, $helpEnd161 - $helpIdx161) } else { "" }
Check (
    ($helpSrc161 -match "cmd:\s*'OVERWRITE'") -and ($helpSrc161 -match "cmd:\s*'EXPORT FULL BACKUP'")
) "161.7: SAVE_HELP documents both OVERWRITE and EXPORT FULL BACKUP (owner report: the `"?`" save-help menu didn't describe EXPORT FULL BACKUP)"

# 161.8  the Test Console template (inert inside <template>, staging/dev-only
#        gate -- Suite 149) gains a REPLAY HATCH button
$tplIdx161 = $html161.IndexOf('<template id="testConsoleTemplate">')
$tplEnd161 = $html161.IndexOf('</template>', $tplIdx161)
$tplSrc161 = if ($tplIdx161 -ge 0) { $html161.Substring($tplIdx161, $tplEnd161 - $tplIdx161) } else { "" }
Check (
    ($tplIdx161 -ge 0) -and ($tplSrc161 -match 'id="testConsoleReplayHatch"')
) "161.8: the (inert, staging/dev-only) Test Console template contains a #testConsoleReplayHatch button"

# 161.9  _wireReplayHatch is wired from the SAME _devConsoleUnlocked()-gated
#        initTestConsole() as every other console control -- no new/parallel gate
$initConsoleBody161 = Get-FunctionBody $testConsole161 "initTestConsole"
Check (
    ($testConsole161 -match "function _wireReplayHatch\(panel\)") -and
    ($initConsoleBody161 -match "_wireReplayHatch\(panel\);")
) "161.9: _wireReplayHatch() is wired from initTestConsole() -- the same _devConsoleUnlocked()-gated entry point as every other Test Console control"

# 161.10 _replayHatch() resets the EXACT SAME MetaStore key releaseBayHatch()
#        (ui-core.js) sets -- Protocol 22, never a parallel flag -- reopens the
#        real #bayHatch overlay, and touches no campaign state or the cloud
#        (Phase-2 prime invariant every other console control also holds to)
$replayHatchBody161 = Get-FunctionBody $testConsole161 "_replayHatch"
Check (
    ($uiCore161 -match "robco_bay_opened") -and
    ($replayHatchBody161 -match "MetaStore\.remove\('robco_bay_opened'\)") -and
    ($replayHatchBody161 -match "hatch\.classList\.remove\('bay-hatch--open'\)") -and
    ($replayHatchBody161 -match "hatch\.hidden = false") -and
    ($replayHatchBody161 -notmatch "state\.") -and
    ($replayHatchBody161 -notmatch "saveState") -and
    ($replayHatchBody161 -notmatch "pushToCloud")
) "161.10: _replayHatch() resets the same robco_bay_opened key ui-core.js's releaseBayHatch() sets, reopens #bayHatch, and touches no campaign state or the cloud"

# ===========================================================
# Suite 162 -- DO-O: the living Overseer (DIRECTOR UPLINK)
# Reskins the Comm-Link into the mockup's Director Uplink: an oscilloscope
# canvas driven by the REAL AI lifecycle (thinking at the transmitMessage
# thermal-load window, speaking during the appendToChat typewriter,
# listening/disabled/offline from the key+flag+navigator.onLine signals), a
# per-game status strip/relay header sourced from a new identity.overseer
# block (Protocol 38, extends the DO-K Suite 157 completeness contract), a
# mobile carrier-strip + self-contained UPLINK view (fixes the .col-right
# "infinite scroll" problem), reduced-motion/dial/standby gating, and zero
# campaign-state writes. Never forks appendToChat()/transmitMessage()
# (Protocol 22). Extended (owner mobile-density fix): the D-PAD/native-
# command cluster is tucked into a collapsible sub-panel (default-open
# desktop / collapsed mobile), the oscilloscope shrinks to a tidy banner,
# the command input gets real height, and the whole cluster is restyled
# amber to match the Director Uplink. Extended again (owner composer-
# integration redesign): the chat input is one modern rounded composer
# INTEGRATED into the transcript box (.transcript-card wraps both
# #chatDisplay and .composer, messenger-style) with a [+ upload]/[mode
# pill]/[? help]/[send] toolbar docked at its bottom, plus a real desktop
# min-height fix for a crush bug found live during verification
# (Protocol 42). Extended again (owner small-UI-polish batch): the composer
# textarea auto-grows from a small placeholder-fit size up to a cap instead
# of a fixed-height box, resets to small after every send, and the mode
# pill's touch-sticky hover fill is neutralized (gated back in for real
# hover-capable pointers only) with a blur() second line of defense. 31 tests.
# ===========================================================
Sep "Suite 162 -- DO-O: the living Overseer (DIRECTOR UPLINK)"
$html162  = Read-Src "index.html"
$core162  = Read-Src "js/ui-core.js"
$api162   = Read-Src "js/api.js"
$css162   = Read-Src "css/terminal.css"
$state162 = Read-Src "js/state.js"

$ovsStart162 = $core162.IndexOf('DO-O START')
$ovsEnd162 = $core162.IndexOf('DO-O END')
$ovsBlock162 = if (($ovsStart162 -ge 0) -and ($ovsEnd162 -ge 0)) { $core162.Substring($ovsStart162, $ovsEnd162 - $ovsStart162) } else { "" }

# 162.1  the canvas + status strip exist and are decorative; #chatDisplay
#        keeps its pre-existing aria-live region (unregressed)
Check ($html162 -match '<canvas id="overseerScope" aria-hidden="true"></canvas>') "162.1a: #overseerScope canvas exists and is aria-hidden (decorative)"
Check ($html162 -match 'class="ovs-head"') "162.1b: .ovs-head (DIRECTOR UPLINK header) present"
Check ($html162 -match 'class="scope-meta" id="scopeStrip"') "162.1c: .scope-meta status-strip present"
Check ($html162 -match 'id="chatDisplay"[\s\S]{0,40}aria-live="polite"[\s\S]{0,40}aria-atomic="false"') "162.1d: #chatDisplay keeps aria-live=`"polite`"/aria-atomic=`"false`" (unregressed)"

# 162.2  the state-machine API is defined in ui-core.js
Check (
    ($ovsBlock162.Length -gt 0) -and
    ($ovsBlock162 -match 'function setOverseerState\(s\)') -and
    ($ovsBlock162 -match 'function getOverseerState\(\)') -and
    ($ovsBlock162 -match 'function _overseerRestState\(') -and
    ($ovsBlock162 -match 'function initOverseerScope\(\)')
) "162.2: setOverseerState/getOverseerState/_overseerRestState/initOverseerScope are all defined in the DO-O block of ui-core.js"

# 162.3  OVERSEER_STATES enumerates all 5 states
Check (
    $ovsBlock162 -match "OVERSEER_STATES = \[\s*'listening',\s*'thinking',\s*'speaking',\s*'disabled',\s*'offline',?\s*\];"
) "162.3: OVERSEER_STATES enumerates all 5 states (listening/thinking/speaking/disabled/offline)"

# 162.4/162.5  transmitMessage() sets 'thinking' at the thermal-load window, and
#        its finally block resets ONLY when the state is still 'thinking'
$tm162 = Get-FunctionBody $api162 "transmitMessage"
$thermalIdx162 = $tm162.IndexOf("document.body.classList.add('thermal-load')")
$thinkingIdx162 = $tm162.IndexOf("window.setOverseerState('thinking')")
Check (
    ($thermalIdx162 -ge 0) -and ($thinkingIdx162 -ge 0) -and ($thinkingIdx162 -gt $thermalIdx162)
) "162.4: transmitMessage() calls window.setOverseerState('thinking') at the thermal-load window"
# Protocol 27 fix (owner report: USE dims the screen forever) moved the
# finally block's reset logic into a shared _resetTransmitUI() helper --
# also called from a new setup-phase catch (Protocol 22, one reset path).
$resetFn162 = Get-FunctionBody $api162 "_resetTransmitUI"
Check (
    ($resetFn162 -match "getOverseerState\(\) === 'thinking'") -and ($tm162 -match 'finally')
) "162.5: transmitMessage()'s finally block calls _resetTransmitUI(), which only resets the scope when getOverseerState() === 'thinking'"

# 162.6  appendToChat() sets 'speaking' at the AI typewriter start and
#        'listening' at completion, guarded on !isHistoryLoad in both branches
$atc162 = Get-FunctionBody $core162 "appendToChat"
Check (
    ($atc162 -match "sender === 'ai' && !isHistoryLoad && !_prefersReduced") -and
    ($atc162 -match "setOverseerState\('speaking'\)") -and
    ($atc162 -match "setOverseerState\('listening'\)")
) "162.6: appendToChat() sets 'speaking' at the AI typewriter start and 'listening' at completion, guarded on !isHistoryLoad"

# 162.7  reduced-motion gates the rAF loop -- no unconditional requestAnimationFrame
Check (
    ($ovsBlock162 -match "_scopeShouldAnimate\(\)[\s\S]{0,300}matchMedia\('\(prefers-reduced-motion: reduce\)'\)") -and
    ($ovsBlock162 -match "if \(_scopeShouldAnimate\(\)\) \{\s*_scopeAnimHandle = requestAnimationFrame\(_scopeLoop\);")
) "162.7: _scopeShouldAnimate() reads matchMedia(prefers-reduced-motion) and gates every requestAnimationFrame call (no unconditional rAF)"

# 162.8  runtime observer pauses on STANDBY/SHUTDOWN/OFF; the immersion dial
#        gate lives in _scopeShouldAnimate() via immersionAllows('balanced')
Check (
    ($ovsBlock162 -match "id: 'overseer-scope'") -and
    ($ovsBlock162 -match "states: \['STANDBY', 'SHUTDOWN', 'OFF'\]") -and
    ($ovsBlock162 -match 'onEnter:') -and
    ($ovsBlock162 -match 'onExit:') -and
    ($ovsBlock162 -match "immersionAllows\('balanced'\)")
) "162.8: the overseer-scope runtime observer pauses on ['STANDBY','SHUTDOWN','OFF'] with onEnter/onExit, and the dial gate (immersionAllows('balanced')) lives in _scopeShouldAnimate()"

# 162.9  Protocol 38 -- no hardcoded NV literal in the DO-O block; strings are
#        sourced from getIdentity().overseer with a generic fallback object
Check (
    ($ovsBlock162.Length -gt 0) -and
    ($ovsBlock162 -notmatch 'Lucky 38') -and
    ($ovsBlock162 -notmatch '0\.417') -and
    ($ovsBlock162 -notmatch 'Mojave') -and
    ($ovsBlock162 -match '_overseerIdentity\(\)') -and
    ($ovsBlock162 -match 'getIdentity\(\)') -and
    ($ovsBlock162 -match 'const OVERSEER_GENERIC_FALLBACK = \{')
) "162.9: the DO-O block contains no hardcoded NV literal (Lucky 38/0.417/Mojave) -- every string is sourced from getIdentity().overseer, with a generic fallback object for a game that has not authored one"

# 162.10  identity.overseer validates on FNV, FO3, and FO4 -- the DO-K Suite 157
#         identity-completeness contract was extended to require it; spot-check
#         the field shape here
$overseerMatches162 = [regex]::Matches($state162, 'overseer: \{[\s\S]*?greeting:[\s\S]*?\},')
$overseerAllOk162 = $true
foreach ($m in $overseerMatches162) {
    $b = $m.Value
    if (-not (($b -match 'title:') -and ($b -match 'relay:') -and ($b -match 'signalStrip:') -and ($b -match 'states: \{'))) { $overseerAllOk162 = $false }
}
Check (
    ($overseerMatches162.Count -eq 3) -and $overseerAllOk162
) "162.10: identity.overseer is authored on all three GAME_DEFS entries (FNV/FO3/FO4) with title/relay/signalStrip/states -- Suite 157's identity contract now requires it (DO-K contract extension)"

# 162.11  mobile: _syncBezelNav() -- the single choke point every subsystem
#         change already routes through -- sets document.body.dataset.subsystem
$syncBody162 = Get-FunctionBody $core162 "_syncBezelNav"
Check (
    $syncBody162 -match 'document\.body\.dataset\.subsystem = subsystem;'
) "162.11: _syncBezelNav() sets document.body.dataset.subsystem -- the single choke point every subsystem change already routes through"

# 162.12  the CSS gates the mobile UPLINK self-contained view + carrier-strip
#         visibility off body[data-subsystem]
Check (
    ($css162 -match "body\[data-subsystem='uplink'\] \.col-right \{") -and
    ($css162 -match "body:not\(\[data-subsystem='uplink'\]\) \.col-right \{") -and
    ($css162 -match "body:not\(\[data-subsystem='uplink'\]\) \.carrier-strip \{")
) "162.12: terminal.css gates the mobile UPLINK self-contained view + carrier-strip visibility off body[data-subsystem]"

# 162.13  .carrier-strip is NOT position:fixed (Suite 160 containing-block
#         caveat -- it sits in normal flow at the top of the scrollable glass)
$carrierRuleMatch162 = [regex]::Match($css162, '(?m)^\.carrier-strip \{[\s\S]*?\n\}')
$carrierRule162 = if ($carrierRuleMatch162.Success) { $carrierRuleMatch162.Value } else { "" }
Check (
    ($carrierRule162.Length -gt 0) -and ($carrierRule162 -notmatch 'position:\s*fixed')
) "162.13: .carrier-strip is not position:fixed (Suite 160 containing-block caveat -- it sits in normal flow at the top of the scrollable glass)"

# 162.14  save boundary -- no campaign-state write anywhere in the DO-O block;
#         the idle-life blip path renders via appendToChat(..., true) (never
#         persisted to chatHistory/robco_chat)
Check (
    ($ovsBlock162.Length -gt 0) -and
    ($ovsBlock162 -notmatch 'saveState\(') -and
    ($ovsBlock162 -notmatch 'robco_v8') -and
    ($ovsBlock162 -notmatch '\bstate\.\w') -and
    ($ovsBlock162 -match "appendToChat\(line, 'sys', true\)")
) "162.14: the DO-O block writes nothing durable to the campaign (no saveState()/robco_v8/state.* write) and the idle-blip observer renders via appendToChat(line,'sys',true) -- never persisted"

# 162.15  behavioral (shells out to node, Suite 157 precedent -- no native JS eval
#         in PowerShell) -- the pure _overseerRestState({hasKey,aiEnabled,online})
#         truth table, ACTUALLY EXECUTED against the real ui-core.js source
try {
    $nodeCheck162 = Get-Command node -ErrorAction SilentlyContinue
    if ($nodeCheck162) {
        $corePathNode162 = (Join-Path $Root "js/ui-core.js").Replace('\', '/')
        $testScript162 = @"
const fs = require('fs');
const src = fs.readFileSync('$corePathNode162', 'utf8');
function extractFullFn(src, fnName) {
  const idx = src.indexOf('function ' + fnName + '(');
  if (idx === -1) return '';
  const openParen = src.indexOf('(', idx);
  let pd = 0, i = openParen;
  for (; i < src.length; i++) {
    if (src[i] === '(') pd++;
    else if (src[i] === ')' && --pd === 0) { i++; break; }
  }
  const braceIdx = src.indexOf('{', i);
  if (braceIdx === -1) return '';
  let depth = 0;
  for (let j = braceIdx; j < src.length; j++) {
    if (src[j] === '{') depth++;
    else if (src[j] === '}' && --depth === 0) return src.slice(idx, j + 1);
  }
  return '';
}
let ok = false;
try {
  const fn = new Function('return (' + extractFullFn(src, '_overseerRestState') + ')')();
  ok = typeof fn === 'function' &&
    fn({ hasKey: true, aiEnabled: true, online: true }) === 'listening' &&
    fn({ hasKey: false, aiEnabled: true, online: true }) === 'disabled' &&
    fn({ hasKey: true, aiEnabled: false, online: true }) === 'disabled' &&
    fn({ hasKey: true, aiEnabled: true, online: false }) === 'offline';
} catch (e) { ok = false; }
console.log('RESULT:' + (ok ? '1' : '0'));
"@
        $out162 = ($testScript162 | node 2>&1 | Out-String)
        $rm162 = [regex]::Match($out162, 'RESULT:([01])')
        if ($rm162.Success) {
            Check ($rm162.Groups[1].Value -eq '1') "162.15: _overseerRestState() truth table -- {key,flag-on,online}->listening, {no key}->disabled, {flag off}->disabled, {offline}->offline (behaviorally executed, not just statically asserted)"
        } else {
            $err162 = if ([string]::IsNullOrWhiteSpace($out162)) { "No output from node" } else { $out162.Trim() }
            Fail "162.15: _overseerRestState() truth table  (runtime error: $err162)"
        }
    } else {
        Fail "162.15: _overseerRestState() truth table  (node not found)"
    }
} catch {
    Fail "162.15: _overseerRestState() truth table  (harness error: $_)"
}

# 162.16  Tool Deck unit (TOOLDECK_PLAN.md): the old always-present/
#         collapsible D-PAD + native-command cluster (the uplink-tray
#         sub-panel, .tactical-dashboard, #macroTarget) is retired entirely --
#         replaced by the ◈ Tool Deck + Quick-Draw Holster (see Suite 164).
Check (
    ($html162 -notmatch 'data-sub-id="uplinkCommandTray"') -and
    ($html162 -notmatch 'class="tactical-dashboard"') -and
    ($html162 -notmatch 'class="d-pad"') -and
    ($html162 -notmatch 'id="macroTarget"') -and
    ($html162 -notmatch 'class="macro-buttons"')
) "162.16a: the old uplink-tray/tactical-dashboard/d-pad/#macroTarget/macro-buttons cluster is fully removed from index.html (superseded by the Tool Deck -- Suite 164)"

Check (
    ($html162 -notmatch "onclick=""macroCommand\('\[PAD: ")
) "162.16b: no on-screen control calls macroCommand('[PAD: ...]') anymore -- the Quick-Draw Holster sockets call _nativePadFire()/_nativePadBind() directly (Suite 164)"

# 162.17  _wirePanelPersistence() no longer carries the uplinkCommandTray
#         per-id exception -- the tray it special-cased no longer exists.
$wpp162 = Get-FunctionBody $core162 "_wirePanelPersistence"
Check (
    ($wpp162 -notmatch 'uplinkCommandTray')
) "162.17: _wirePanelPersistence() no longer references uplinkCommandTray (the tray it special-cased is retired)"

# 162.18  the Tool Deck + Quick-Draw Holster CSS is restyled amber
#         (--bezel-wire), not the old blue/green boxy controls; the retired
#         .tactical-dashboard/.d-pad rules are gone entirely (Protocol 42
#         cleanup -- dead CSS is a stale-safeguard risk of its own)
$toolDeckMatch162 = [regex]::Match($css162, '(?s)\.tool-deck \{.*?\n\}')
$toolDeckRule162 = if ($toolDeckMatch162.Success) { $toolDeckMatch162.Value } else { "" }
$socketMatch162 = [regex]::Match($css162, "(?s)`n\.socket \{.*?`n\}")
$socketRule162 = if ($socketMatch162.Success) { $socketMatch162.Value } else { "" }
Check (
    ($toolDeckRule162.Length -gt 0) -and ($toolDeckRule162 -match 'border: 1px solid var\(--bezel-wire\)') -and
    ($socketRule162.Length -gt 0) -and
    ($toolDeckRule162 -notmatch '--robco-blue') -and ($socketRule162 -notmatch '--robco-blue')
) "162.18a: .tool-deck and .socket use --bezel-wire, not --robco-blue"

Check (
    ($css162 -notmatch '\.tactical-dashboard \{') -and
    ($css162 -notmatch '\.d-pad \{') -and
    ($css162 -notmatch '\.d-pad button \{') -and
    ($css162 -notmatch '\.d-pad-row \{') -and
    ($css162 -notmatch '\.macro-buttons button \{') -and
    ($css162 -notmatch 'details\.uplink-tray \{')
) "162.18b: the retired .tactical-dashboard/.d-pad(+button/-row)/.macro-buttons button/.uplink-tray CSS rules are gone entirely -- no dead cluster CSS survives"

Check (
    ($css162 -match "(?s)\.composer-icon-btn,\s*\n\.composer-send-btn,\s*\n\.icon-btn-round \{[^}]*border: 1px solid var\(--icon-btn-color, var\(--bezel-wire\)\);") -and
    ($css162 -match "(?s)\.composer-icon-btn:hover,\s*\n\.composer-send-btn:hover,\s*\n\.icon-btn-round:hover \{[^}]*background: var\(--icon-btn-color, var\(--bezel-wire\)\);")
) "162.18c: the composer icon/send buttons (and the shared .icon-btn-round) are outlined amber by default (transparent background, --icon-btn-color falling back to --bezel-wire) and fill on hover -- no leftover .blue-btn solid-fill bug (superseded by the composer redesign)"

# 162.19  mobile density -- the oscilloscope shrinks to a tidy banner;
#         #chatInput's own fixed height was superseded by the small-UI-
#         polish batch's auto-grow (162.25+), scoped to the existing UPLINK
#         mobile block (max-width: 999.98px)
$mobileMatch162 = [regex]::Match($css162, "(?s)@media \(max-width: 999\.98px\) \{.*?\n\}\n(?=/\* Desktop needs no explicit override)")
$mobileBlock162 = if ($mobileMatch162.Success) { $mobileMatch162.Value } else { "" }
Check (
    ($mobileBlock162 -match "body\[data-subsystem='uplink'\] #overseerScope \{\s*height: 64px;") -and
    ($mobileBlock162 -match "body\[data-subsystem='uplink'\] #chatInput \{\s*flex-shrink: 0;\s*\}") -and
    (-not ($mobileBlock162 -match "body\[data-subsystem='uplink'\] #chatInput \{\s*height:"))
) "162.19: the mobile UPLINK block shrinks #overseerScope to a 64px banner (down from the unconditional 120px); #chatInput keeps flex-shrink:0 but no longer hardcodes a fixed height (superseded by auto-grow -- see 162.25)"

# 162.20  owner composer redesign -- the composer INTEGRATES into the
#         transcript box (.transcript-card wraps BOTH #chatDisplay and
#         .composer -- messenger-style, not a separate stack of controls
#         below it) and replaces the separate dashed VISUAL UPLOAD button +
#         the bottom-of-panel TRANSMIT PROTOCOL button; both old controls
#         are gone
$transcriptCardStart162 = $html162.IndexOf('<div class="transcript-card">')
$composerStart162 = $html162.IndexOf('<div class="composer" id="composer">')
$composerImgInputIdx162 = if ($composerStart162 -ge 0) { $html162.IndexOf('id="imageInput"', $composerStart162) } else { -1 }
$composerBlock162 = if (($composerStart162 -ge 0) -and ($composerImgInputIdx162 -ge 0)) { $html162.Substring($composerStart162, $composerImgInputIdx162 - $composerStart162) } else { "" }
$transcriptCardBlock162 = if (($transcriptCardStart162 -ge 0) -and ($composerImgInputIdx162 -ge 0)) { $html162.Substring($transcriptCardStart162, $composerImgInputIdx162 - $transcriptCardStart162) } else { "" }
Check (
    ($composerBlock162.Length -gt 0) -and
    ($composerBlock162 -match 'class="composer-input"') -and
    ($composerBlock162 -match 'class="composer-toolbar"') -and
    ($composerBlock162 -match 'id="tokenBudgetDisplay" class="composer-token-budget"') -and
    ($composerBlock162 -match 'id="deckKey"') -and
    ($html162 -notmatch [regex]::Escape('[ &gt; VISUAL UPLOAD ]')) -and
    ($html162 -notmatch '&gt; TRANSMIT PROTOCOL')
) "162.20: the composer contains the textarea (.composer-input), a bottom toolbar (.composer-toolbar) with the ◈ Tool Deck launcher (#deckKey); the old standalone dashed VISUAL UPLOAD button and bottom TRANSMIT PROTOCOL button are both gone"

# 162.20b  structural integration proof -- #chatDisplay and .composer are
#          BOTH inside the SAME .transcript-card wrapper (the composer pill
#          docks at the bottom of the transcript box, not below it as a
#          separate element)
$chatDisplayIdx162 = $html162.IndexOf('id="chatDisplay"')
Check (
    ($transcriptCardStart162 -ge 0) -and
    ($transcriptCardStart162 -lt $chatDisplayIdx162) -and
    ($chatDisplayIdx162 -lt $composerStart162) -and
    ($transcriptCardBlock162.Contains('id="chatDisplay"')) -and
    ($transcriptCardBlock162.Contains('<div class="composer" id="composer">'))
) "162.20b: .transcript-card wraps BOTH #chatDisplay and .composer in source order (transcript, then composer) -- one integrated card, not a separate control stack below the transcript"

# 162.21  every composer control keeps its exact pre-existing handler
#         (Protocol 22) -- only the container/position/styling changed
Check (
    ($composerBlock162 -match 'class="composer-icon-btn"\s+onclick="triggerImageUpload\(\)"') -and
    ($composerBlock162 -match '(?s)id="modePill".{0,200}?onclick="toggleInputMode\(\)"') -and
    ($composerBlock162 -match 'class="composer-icon-btn composer-help-btn"\s+onclick="showHelpModal\(\)"') -and
    ($composerBlock162 -match 'onclick="submitCommandInput\(\)"\s+class="composer-send-btn"\s+id="transmitBtn"')
) "162.21: the composer [+] still calls triggerImageUpload(), the mode pill still calls toggleInputMode(), the [?] still calls showHelpModal(), and the send button keeps id=`"transmitBtn`" + onclick=`"submitCommandInput()`" -- no rewiring"

# 162.22  transmitMessage()'s busy/cancel/reset states swap a short glyph +
#         aria-label instead of the old long button-text strings, and the
#         Protocol 42 fix closes the onclick-drift bug found while adapting
#         this button: the finally block used to rebind onclick straight to
#         transmitMessage(), permanently bypassing submitCommandInput()'s
#         TERMINAL-mode/quick-log routing for every click after the FIRST
#         round-trip
$tm162b = Get-FunctionBody $api162 "transmitMessage"
# Protocol 27 fix moved the '↑'/onclick reset into the shared
# _resetTransmitUI() helper the finally block now calls (Protocol 22).
$resetFn162b = Get-FunctionBody $api162 "_resetTransmitUI"
$combined162b = $tm162b + "`n" + $resetFn162b
Check (
    ($tm162b.Contains("btn.textContent = '⋯';")) -and
    ($tm162b.Contains("btn.textContent = '✕';")) -and
    ($resetFn162b.Contains("btn.textContent = '↑';")) -and
    ($resetFn162b.Contains("btn.onclick = () => submitCommandInput();")) -and
    (-not ($combined162b.Contains("btn.onclick = () => transmitMessage();"))) -and
    (-not ($combined162b.Contains("btn.innerText = '> TRANSMIT PROTOCOL'")))
) "162.22: transmitMessage()'s busy/cancel states use short glyphs, and the shared _resetTransmitUI() helper restores the up-arrow glyph + onclick to submitCommandInput() -- not transmitMessage() directly (Protocol 42 fix: the prior direct rebind silently skipped TERMINAL-mode routing on every click after the first round-trip)"

# 162.23  owner-report fix (real-terminal-screen batch): .transcript-card no
#         longer carries a box (border/radius/background) -- the transcript
#         flows free on the screen; .composer now carries its OWN full
#         border/radius/background (the one thing still meant to read as a
#         bordered "pill"); the composer buttons still meet the Protocol 17
#         >=28px tap-target floor
$cardRuleMatch162 = [regex]::Match($css162, '(?s)\.transcript-card \{.*?\n\}')
$cardRule162 = if ($cardRuleMatch162.Success) { $cardRuleMatch162.Value } else { "" }
$chatDisplayRuleMatch162 = [regex]::Match($css162, "(?s)`n#chatDisplay \{.*?`n\}")
$chatDisplayRule162 = if ($chatDisplayRuleMatch162.Success) { $chatDisplayRuleMatch162.Value } else { "" }
$composerRuleMatch162 = [regex]::Match($css162, "(?s)`n\.composer \{.*?`n\}")
$composerRule162 = if ($composerRuleMatch162.Success) { $composerRuleMatch162.Value } else { "" }
$chatPanelRuleMatch162 = [regex]::Match($css162, "(?s)`n\.panel\.chat-panel \{.*?`n\}")
$chatPanelRule162 = if ($chatPanelRuleMatch162.Success) { $chatPanelRuleMatch162.Value } else { "" }
$iconBtnRuleMatch162 = [regex]::Match($css162, "(?s)\.composer-icon-btn,\s*\n\.composer-send-btn,\s*\n\.icon-btn-round \{.*?\n\}")
$iconBtnRule162 = if ($iconBtnRuleMatch162.Success) { $iconBtnRuleMatch162.Value } else { "" }
Check (
    ($chatPanelRule162.Length -gt 0) -and
    ($chatPanelRule162 -match 'border: none;') -and
    ($chatPanelRule162 -match 'background: none;')
) "162.23a: .panel.chat-panel (the outer Director Uplink content-area frame) carries no border AND no background -- every other .panel keeps the base green frame, only the Uplink column loses its box entirely"
Check (
    ($cardRule162.Length -gt 0) -and
    ($cardRule162 -notmatch 'border:') -and
    ($cardRule162 -notmatch 'border-radius') -and
    ($cardRule162 -notmatch 'background:')
) "162.23b: .transcript-card carries no border/radius/background -- the transcript flows directly on the screen with no box around it, like a real terminal"
Check (
    ($chatDisplayRule162.Length -gt 0) -and
    ($chatDisplayRule162 -notmatch 'border:\s*1px solid') -and
    ($composerRule162.Length -gt 0) -and
    ($composerRule162 -match 'border: 1px solid var\(--bezel-wire\);') -and
    ($composerRule162 -match 'border-radius: 20px;') -and
    ($composerRule162 -match 'background: rgba\(0, 0, 0, 0\.35\);')
) "162.23c: #chatDisplay stays borderless (the transcript never boxes itself) while .composer carries its own full border/radius/background -- the input pill is the one thing in the Director Uplink column still meant to read as boxed"
Check (
    ($iconBtnRule162.Length -gt 0) -and
    ($iconBtnRule162 -match 'width: 32px') -and
    ($iconBtnRule162 -match 'height: 32px') -and
    ($iconBtnRule162 -match 'border-radius: 50%')
) "162.23d: the composer icon/send buttons are circular (border-radius:50%) at 32px -- comfortably above the 28px Protocol 17 tap-target floor"

# 162.24  Protocol 42 regression guard -- a real bug found live while
#         verifying the composer-integration redesign: on desktop the
#         command cluster tray defaults OPEN (no height cap) and could
#         starve .transcript-card's flex-grow toward zero with
#         min-height:0, silently clipping the transcript to a sliver inside
#         the card's own overflow:hidden with no scrollbar ever appearing.
#         Fixed with a real min-height floor on the desktop .transcript-card
#         plus overflow-y:auto on .chat-panel itself so any further squeeze
#         scrolls instead of clipping.
$desktopMatch162 = [regex]::Match($css162, "(?s)@media \(min-width: 1000px\) and \(hover: hover\) and \(pointer: fine\) \{.*?\n\}\n\n(?=/\* ── Skills Grid)")
$desktopBlock162 = if ($desktopMatch162.Success) { $desktopMatch162.Value } else { "" }
$desktopChatPanelMatch162 = [regex]::Match($desktopBlock162, '(?s)\.panel\.chat-panel \{.*?\n  \}')
$desktopChatPanelRule162 = if ($desktopChatPanelMatch162.Success) { $desktopChatPanelMatch162.Value } else { "" }
$desktopCardMatch162 = [regex]::Match($desktopBlock162, '(?s)\.transcript-card \{.*?\n  \}')
$desktopCardRule162 = if ($desktopCardMatch162.Success) { $desktopCardMatch162.Value } else { "" }
Check (
    ($desktopBlock162.Length -gt 0) -and
    ($desktopChatPanelRule162 -match 'overflow-y: auto;') -and
    ($desktopCardRule162.Length -gt 0) -and
    ($desktopCardRule162 -match 'min-height: 282px;') -and
    (-not ($desktopCardRule162 -match 'min-height: 0;'))
) "162.24: desktop .panel.chat-panel scrolls (overflow-y:auto) and desktop .transcript-card carries a real 282px min-height floor (not 0) -- with the open-by-default command tray, this is what stops the transcript from being crushed to a clipped sliver with no scrollbar (Protocol 42 -- found live during this unit's desktop verification)"

# 162.25  owner small-UI-polish batch -- .composer-input starts as small as
#         possible (a small floor + a cap that scrolls) instead of a big
#         fixed-height box, and neither #chatInput override (mobile or
#         desktop) hardcodes a fixed height anymore
$composerInputRuleMatch162 = [regex]::Match($css162, "(?s)`n\.composer-input \{.*?`n\}")
$composerInputRule162 = if ($composerInputRuleMatch162.Success) { $composerInputRuleMatch162.Value } else { "" }
Check (
    ($composerInputRule162.Length -gt 0) -and
    ($composerInputRule162 -match 'min-height: 40px;') -and
    ($composerInputRule162 -match 'max-height: 160px;') -and
    ($composerInputRule162 -match 'overflow-y: auto;') -and
    (-not ($composerInputRule162 -match 'min-height: 56px;'))
) "162.25a: .composer-input has a small min-height floor (40px) + a max-height cap (160px) that scrolls, replacing the old fixed 56px min-height"
Check (
    ($desktopBlock162 -match '#chatInput \{\s*flex-shrink: 0;\s*\}') -and
    ($mobileBlock162 -match "body\[data-subsystem='uplink'\] #chatInput \{\s*flex-shrink: 0;\s*\}")
) "162.25b: neither the desktop nor the mobile #chatInput override hardcodes a fixed height anymore -- both keep only flex-shrink:0 (auto-grow supersedes the old 80px/76px fixed heights)"

# 162.26  owner small-UI-polish batch -- _autoGrowComposer()/
#         _wireComposerAutoGrow() (ui-core.js) drive the auto-grow: wired at
#         boot alongside _wireModeHint(), and re-measured whenever the
#         placeholder itself changes (mode toggle)
$autoGrowBody162 = Get-FunctionBody $core162 '_autoGrowComposer'
$wireAutoGrowBody162 = Get-FunctionBody $core162 '_wireComposerAutoGrow'
$restoreDevicePrefsBody162 = Get-FunctionBody $core162 '_restoreDevicePrefs'
$renderModePillBody162 = Get-FunctionBody $core162 '_renderModePill'
Check (
    ($autoGrowBody162 -match "el\.style\.height = 'auto';") -and
    ($autoGrowBody162 -match 'el\.value = el\.placeholder;') -and
    ($autoGrowBody162 -match 'Math\.min\(el\.scrollHeight, COMPOSER_INPUT_MAX_HEIGHT_PX\)') -and
    ($autoGrowBody162 -match "el\.value = '';")
) "162.26a: _autoGrowComposer() measures scrollHeight (briefly filling the empty box with its own placeholder to size the default state), caps it at COMPOSER_INPUT_MAX_HEIGHT_PX, and never leaves a placeholder string behind in the real value"
Check (
    ($wireAutoGrowBody162 -match "addEventListener\('input', _autoGrowComposer\)") -and
    ($restoreDevicePrefsBody162 -match '_wireComposerAutoGrow\(\);') -and
    ($renderModePillBody162 -match '_autoGrowComposer\(\);')
) "162.26b: _wireComposerAutoGrow() wires #chatInput to re-measure on every keystroke and is called from boot (_restoreDevicePrefs, alongside _wireModeHint); _renderModePill() re-measures too so switching modes resizes to fit the new placeholder"

# 162.27  owner small-UI-polish batch -- the composer resets to its small
#         size after every send (both OVERSEER and TERMINAL mode), not just
#         while typing
$tmBody162c = Get-FunctionBody $api162 'transmitMessage'
$ttBody162c = Get-FunctionBody $api162 'transmitTerminal'
Check (
    ($tmBody162c -match "inputEl\.value = '';\s*if \(typeof _autoGrowComposer === 'function'\) _autoGrowComposer\(\);") -and
    ($ttBody162c -match "inputEl\.value = '';\s*if \(typeof _autoGrowComposer === 'function'\) _autoGrowComposer\(\);")
) "162.27: transmitMessage() and transmitTerminal() (api.js) both re-measure the composer immediately after clearing #chatInput, so it snaps back to its small placeholder-fit size after every send"

# 162.28  owner report fix -- the mode pill's touch-sticky hover fill (from
#         the general button.action-btn:hover rule persisting after a tap
#         with no pointerleave to clear it) is neutralized unconditionally,
#         with the real fill restored only for genuine hover-capable
#         pointers; toggleInputMode() also blurs the pill as a second line
#         of defense
$pillHoverResetIdx162 = $css162.IndexOf('button.mode-pill--terminal:hover')
$pillHoverGatedIdx162 = if ($pillHoverResetIdx162 -ge 0) { $css162.IndexOf('(hover: hover) and (pointer: fine)', $pillHoverResetIdx162) } else { -1 }
$pillHoverResetBlock162 = if ($pillHoverResetIdx162 -ge 0) { $css162.Substring($pillHoverResetIdx162, [Math]::Min(400, $css162.Length - $pillHoverResetIdx162)) } else { "" }
Check (
    ($pillHoverResetIdx162 -ge 0) -and
    ($pillHoverGatedIdx162 -ge 0) -and
    ($pillHoverGatedIdx162 -gt $pillHoverResetIdx162) -and
    ($pillHoverResetBlock162 -match '(?s)button\.mode-pill--terminal:hover \{[^}]*background: transparent;[^}]*filter: none;') -and
    ($pillHoverResetBlock162 -match '(?s)button\.mode-pill--overseer:hover \{[^}]*background: transparent;[^}]*filter: none;') -and
    ($css162 -match '(?s)button\.mode-pill:hover \{[^}]*background: var\(--robco-green\);')
) "162.28a: button.mode-pill--terminal:hover / --overseer:hover unconditionally reset background/filter (declared BEFORE the gated hover-capable-only restore) so a touch tap can never leave the pill looking stuck-highlighted"
$toggleInputModeBody162 = Get-FunctionBody $core162 'toggleInputMode'
Check (
    ($toggleInputModeBody162 -match "getElementById\('modePill'\)") -and
    ($toggleInputModeBody162 -match '\.blur\(\)')
) "162.28b: toggleInputMode() blurs the pill after a tap (belt-and-suspenders alongside the CSS hover-gate fix)"

# ===========================================================
# Suite 163 -- Owner batch: SAVES LIST overhaul -- local DELETE, cloud VERSION
# HISTORY, per-game filtering, row-layout fit (15 tests). Four owner reports
# fixed together: (1) local slots had no DELETE control (cloud rows already
# had DEL) -- confirmDeleteSlot()/_deleteSlotApply() (ui-saves.js) add one,
# confirm-gated, clearing the localStorage mirror + the IDB-primary slot +
# its P5 version ring; (2) cloud saves had no version history even though
# OVERWRITE could destroy prior contents -- an additive Firestore
# subcollection (users/{uid}/saves/{docId}/versions) mirrors the local P5
# ring, archived by _pushCloudSaveVersion() before every overwrite, capped
# and oldest-pruned, with a versionCount field on the parent doc so the SAVES
# LIST can show a VER button without an extra read per save; (3) the list
# showed every save regardless of which game was active -- renderSavesList()
# now filters both local slots and cloud saves to the active game context,
# degrading to SHOW (never hide) a save with no recorded gameContext; (4) the
# row's growing button set could clip at 360/412px -- rows moved from inline
# styles to .save-row/.save-row-actions CSS classes, with flex-wrap letting
# buttons wrap onto their own line instead of overflowing. Mirrors JS Suite 163.
# ===========================================================
Sep "Suite 163 -- Owner batch: SAVES LIST local DELETE + cloud VERSION HISTORY + per-game filter"
$uiSaves163 = Read-Src "js/ui-saves.js"
$uiAcct163 = Read-Src "js/ui-account.js"
$cloud163 = Read-Src "js/cloud.js"
$css163 = Read-Src "css/terminal.css"

# Assignment-form extractor (`window.X = async function (...) { ... }`) --
# re-declared locally per the Suite 137/161 precedent.
function Get-WindowFnBody163($source, $fnName) {
    $idx = $source.IndexOf("window.$fnName =")
    if ($idx -lt 0) { return "" }
    $start = $source.IndexOf('{', $idx)
    if ($start -lt 0) { return "" }
    $depth = 0
    $i     = $start
    while ($i -lt $source.Length) {
        $ch = $source[$i]
        if     ($ch -eq '{') { $depth++ }
        elseif ($ch -eq '}') { $depth--; if ($depth -eq 0) { return $source.Substring($start, $i - $start + 1) } }
        $i++
    }
    return ""
}

# 163.1  confirmDeleteSlot() (ui-saves.js): diegetic confirmAction() gate
#        (not the blocking confirm()), delegates to _deleteSlotApply()
$confirmDeleteSlotBody163 = Get-FunctionBody $uiSaves163 "confirmDeleteSlot"
Check (
    ($confirmDeleteSlotBody163 -match "await confirmAction\(") -and
    ($confirmDeleteSlotBody163 -notmatch "\bconfirm\(") -and
    ($confirmDeleteSlotBody163 -match "await _deleteSlotApply\(slotNum\)")
) "163.1: confirmDeleteSlot() awaits confirmAction() (not confirm()) and delegates the erase to _deleteSlotApply()"

# 163.2  _deleteSlotApply() clears BOTH the localStorage mirror and the
#        IDB-primary copy (P3), plus that slot's retained version ring (P5)
#        -- a deleted slot leaves no orphaned version history -- and
#        refreshes renderSavesList() on completion
$deleteSlotApplyBody163 = Get-FunctionBody $uiSaves163 "_deleteSlotApply"
Check (
    ($deleteSlotApplyBody163 -match "localStorage\.removeItem\(_slotKey\(slotNum\)\)") -and
    ($deleteSlotApplyBody163 -match "IdbStore\.remove\('campaign', 'slot_' \+ slotNum\)") -and
    ($deleteSlotApplyBody163 -match "IdbStore\.remove\('campaign', 'slot_' \+ slotNum \+ '_versions'\)") -and
    ($deleteSlotApplyBody163 -match "renderSavesList\(\)")
) "163.2: _deleteSlotApply() removes the slot's localStorage key, its IDB campaign entry, and its version-history ring, then refreshes renderSavesList()"

# 163.3  renderSavesList() renders a DELETE control on every local slot row,
#        routed to confirmDeleteSlot(), with a literal descriptive aria-label
#        (Protocol UI-3) and the shared .delete-btn styling cloud rows
#        already use (Protocol 22 -- one delete-button class)
Check (
    ($uiAcct163 -match 'onclick="confirmDeleteSlot\(') -and
    ($uiAcct163 -match 'class="btn-sm delete-btn" onclick="confirmDeleteSlot\(') -and
    ($uiAcct163 -match 'aria-label="Delete ')
) "163.3: renderSavesList() renders a confirm-gated DELETE control on each local slot row (btn-sm delete-btn, same class cloud DEL already uses) with a descriptive aria-label"

# 163.4  cloud save VERSION HISTORY lives in an ADDITIVE Firestore
#        subcollection (users/{uid}/saves/{docId}/versions) -- a structural
#        translation of the local P5 ring, never an embedded array field on
#        the parent doc (a single Firestore document is capped at 1MB;
#        stacking several full campaign+chat snapshots into one doc could
#        approach that ceiling). _pushCloudSaveVersion archives via addDoc
#        (Protocol 34) and prunes beyond CLOUD_SLOT_VERSION_CAP via deleteDoc
#        (system-retention of its own auto-created backups, not a
#        user-initiated destructive action -- mirrors the local ring's
#        silent `.slice(0, SLOT_VERSION_CAP)` cap)
$pushVersionBody163 = Get-FunctionBody $cloud163 "_pushCloudSaveVersion"
Check (
    ($cloud163 -match "const CLOUD_SLOT_VERSION_CAP = 5;") -and
    ($pushVersionBody163 -match "collection\(db, 'users', _currentUid, 'saves', docId, 'versions'\)") -and
    ($pushVersionBody163 -match "await addDoc\(col,") -and
    ($pushVersionBody163 -match "await deleteDoc\(doc\(db, 'users', _currentUid, 'saves', docId, 'versions', ex\.id\)\)")
) "163.4: _pushCloudSaveVersion() archives via addDoc into an additive users/{uid}/saves/{docId}/versions subcollection and prunes beyond CLOUD_SLOT_VERSION_CAP via deleteDoc"

# 163.5  window.listCloudSaveVersions: fail-safe (returns [] when signed out,
#        the feature is disabled, or on any error) -- mirrors
#        readSlotVersions()'s contract so a caller that gets [] simply offers
#        no version history
$listVersionsBody163 = Get-WindowFnBody163 $cloud163 "listCloudSaveVersions"
Check (
    ($listVersionsBody163 -match "if \(!window\.isFeatureEnabled\('cloudSync'\) \|\| !_currentUid\) return \[\];") -and
    ($listVersionsBody163 -match "catch \(e\) \{[\s\S]*?return \[\];")
) "163.5: window.listCloudSaveVersions() is fail-safe -- returns [] when cloudSync is disabled, signed out, or on any Firestore error"

# 163.6  window.restoreCloudSaveVersion: DESTRUCTIVE to the live campaign ->
#        confirm-gated (Protocol 34), sanitized + migrated before applying
#        (same integrity path as loadCloudSave), and takes a rolling backup
#        first -- restores into the LOCAL campaign only, never rewrites the
#        cloud doc itself (mirrors restoreSlotVersion's local-only apply)
$restoreVersionBody163 = Get-WindowFnBody163 $cloud163 "restoreCloudSaveVersion"
Check (
    ($restoreVersionBody163 -match "await confirmAction\(") -and
    ($restoreVersionBody163 -match "snapRollingBackup") -and
    ($restoreVersionBody163 -match "sanitizeImportedContainer") -and
    ($restoreVersionBody163 -match "migrateState") -and
    ($restoreVersionBody163 -notmatch "updateDoc\(doc\(db, 'users', _currentUid, 'saves', docId\)")
) "163.6: window.restoreCloudSaveVersion() is confirm-gated, sanitizes + migrates before applying, snapshots a rolling backup first, and only ever replaces the LOCAL campaign (never writes back to the cloud doc)"

# 163.7  overwriteCloudSave() archives the save's PRIOR contents via
#        _pushCloudSaveVersion() BEFORE the updateDoc call replaces them,
#        stamps the resulting versionCount onto the same updateDoc write (no
#        extra read needed to show the VER button later), and its
#        confirm-gate warning now points at VERSION HISTORY instead of
#        claiming the prior contents "cannot be recovered"
$overwriteCloudBody163 = Get-WindowFnBody163 $cloud163 "overwriteCloudSave"
$versionIdx163 = $overwriteCloudBody163.IndexOf("_pushCloudSaveVersion(docId, existingData)")
$updateIdx163 = $overwriteCloudBody163.IndexOf("await updateDoc(doc(db,")
Check (
    ($versionIdx163 -ge 0) -and ($updateIdx163 -ge 0) -and ($versionIdx163 -lt $updateIdx163) -and
    ($overwriteCloudBody163 -match "versionCount,") -and
    ($overwriteCloudBody163 -match "VERSION HISTORY \(VER\)") -and
    ($overwriteCloudBody163 -notmatch "cannot be recovered")
) "163.7: overwriteCloudSave() archives the prior contents (_pushCloudSaveVersion) BEFORE the updateDoc replaces them, stamps versionCount onto that same write, and its confirm warning now points at VERSION HISTORY rather than claiming data loss"

# 163.8  deleteCloudSave() purges the retained version subcollection before
#        deleting the parent doc -- Firestore does not cascade-delete
#        subcollections, so skipping this would leave orphaned version
#        documents behind forever
$deleteCloudBody163 = Get-WindowFnBody163 $cloud163 "deleteCloudSave"
$versionsIdx163 = $deleteCloudBody163.IndexOf("listCloudSaveVersions(docId)")
$mainDeleteIdx163 = $deleteCloudBody163.IndexOf("await deleteDoc(doc(db, 'users', _currentUid, 'saves', docId));")
Check (
    ($versionsIdx163 -ge 0) -and ($mainDeleteIdx163 -ge 0) -and ($versionsIdx163 -lt $mainDeleteIdx163)
) "163.8: deleteCloudSave() clears the retained version subcollection before deleting the parent save doc, so no version document is ever orphaned"

# 163.9  viewCloudSaveVersions() (ui-saves.js) mirrors viewSlotVersions()'s
#        shape exactly -- same openModal driver, same escapeHtml discipline,
#        RESTORE routed to window.restoreCloudSaveVersion (Protocol 22 -- no
#        parallel viewer implementation)
$viewCloudVersionsBody163 = Get-FunctionBody $uiSaves163 "viewCloudSaveVersions"
Check (
    ($viewCloudVersionsBody163 -match "window\.listCloudSaveVersions\(docId\)") -and
    ($viewCloudVersionsBody163 -match "openModal\(") -and
    ($viewCloudVersionsBody163 -match "escapeHtml\(") -and
    ($viewCloudVersionsBody163 -match "window\.restoreCloudSaveVersion\(\\'") -and
    ($viewCloudVersionsBody163 -match "NO PRIOR VERSIONS ON FILE")
) "163.9: viewCloudSaveVersions() mirrors viewSlotVersions() -- lists window.listCloudSaveVersions() in the shared modal, escaped, with RESTORE routed to window.restoreCloudSaveVersion()"

# 163.10  renderSavesList() offers the VER button on a cloud row ONLY when
#         that save's versionCount is truthy -- fail-safe, mirrors the local
#         ring's versionCounts gate so a pre-feature cloud save (no
#         versionCount field yet) shows no button until its first overwrite
Check (
    $uiAcct163 -match "d\.versionCount\s*\?[\s\S]{0,120}viewCloudSaveVersions\(\\'"
) "163.10: renderSavesList() renders the cloud VER button only when d.versionCount is truthy -- no button for a save with no retained versions yet"

# 163.11  listLocalSaves() tags each slot with its recorded gameContext
#         (unfiltered) so the filter step below can judge every source
#         (localStorage + the IDB-only supplement) exactly once
$listLocalSavesBody163 = Get-FunctionBody $uiSaves163 "listLocalSaves"
Check (
    $listLocalSavesBody163 -match "gameContext: slot\.gameContext \|\| null,"
) "163.11: listLocalSaves() tags each returned slot with its recorded gameContext (or null), unfiltered -- the per-game filter itself lives centrally in renderSavesList()"

# 163.12  renderSavesList() filters BOTH local slots and cloud saves to the
#         ACTIVE game (getGameContext()), degrading to SHOW -- never hide --
#         a save with no recorded gameContext (can't attribute it to a game,
#         so showing beats silently hiding data)
Check (
    ($uiAcct163 -match "const curCtx = typeof getGameContext === 'function' \? getGameContext\(\) : 'FNV';") -and
    ($uiAcct163 -match "s\.isSlot && s\.gameContext && s\.gameContext !== curCtx") -and
    ($uiAcct163 -match "!s\.isSlot \|\| !s\.gameContext \|\| s\.gameContext === curCtx") -and
    ($uiAcct163 -match "s\.data\.gameContext && s\.data\.gameContext !== curCtx") -and
    ($uiAcct163 -match "!s\.data\.gameContext \|\| s\.data\.gameContext === curCtx")
) "163.12: renderSavesList() filters both local slots and cloud saves to getGameContext(), showing (never hiding) any save with no recorded gameContext"

# 163.13  the empty state tells the user WHY the list is empty when saves
#         exist but are all hidden by the per-game filter, instead of reusing
