# ===========================================================
# Suite 169 -- Owner batch: transcript cleanup (Style A) + composer
# autocomplete drop-up + Overseer LISTENING pulse (12 tests)
# Three owner-reported UPLINK/Director-Uplink polish fixes: (1) the
# transcript's old bounce (right-aligned/border'd user lines, centered italic
# system lines, italic tight-leading AI lines) is replaced with the approved
# chat-overhaul mockup's shared cleanup -- every line left-anchored + full-
# width with a 14px hanging indent, voice carried by color/weight/size only --
# while keeping Style A's OVERSEER tag-above (now mirrored by a symmetric
# TERMINAL tag on user lines, per the mockup); (2) the composer's (#chatInput)
# registry-autocomplete singleton now drops UP instead of down for that one
# input, since dropping down covered the composer's own toolbar/send button;
# (3) tapping the Overseer scope's [ LISTENING ] tag (now enabled in that
# state, not just disabled/offline) triggers a transient one-shot amplitude
# pulse on the waveform -- gated by the exact same _scopeShouldAnimate()
# reduced-motion/dial/hidden/standby check every other scope motion already
# obeys, never a bespoke carve-out -- and never writes any campaign state.
# (PS mirror of JS Suite 169.)
# ===========================================================
Sep "Suite 169 -- transcript cleanup + composer autocomplete drop-up + scope pulse"
$uiCore169 = Read-Src "js/ui-core.js"
$uiSaves169 = Read-Src "js/ui-saves.js"
$css169 = Read-Src "css/terminal.css"
$appendBody169 = Get-FunctionBody $uiCore169 "appendToChat"

# 169.1  appendToChat() adds a symmetric 'msg-tag--terminal' tag reading
#        TERMINAL for sender === 'user'
Check (($appendBody169 -match "else if \(sender === 'user'\) \{[\s\S]{0,500}msg-tag--terminal") -and ($appendBody169 -match "tagEl\.textContent = 'TERMINAL'")) `
    "169.1: appendToChat() adds a 'msg-tag--terminal' tag element reading TERMINAL for sender === 'user'"

# 169.2  .msg-user/.msg-ai/.msg-sys are each left-anchored with the same
#        14px hanging indent
$msgUserRule169 = [regex]::Match($css169, '\.msg-user \{[^}]*\}').Value
$msgAiRule169   = [regex]::Match($css169, '\.msg-ai \{[^}]*\}').Value
$msgSysRule169  = [regex]::Match($css169, '\.msg-sys \{[^}]*\}').Value
$hangingIndentOk169 = $true
foreach ($rule in @($msgUserRule169, $msgAiRule169, $msgSysRule169)) {
    if (-not (($rule -match 'text-align: left;') -and ($rule -match 'padding-left: 14px;') -and ($rule -match 'text-indent: -14px;'))) {
        $hangingIndentOk169 = $false
    }
}
Check $hangingIndentOk169 `
    '169.2: .msg-user/.msg-ai/.msg-sys are each left-anchored with the same 14px hanging indent'

# 169.3  the old bounce is gone: no right/center alignment, no side
#        borders/margins eating mobile width, no AI italic/tight-leading
Check (
    (-not ($css169 -match '\.msg-user \{[^}]*text-align: right')) -and
    (-not ($css169 -match '\.msg-user \{[^}]*border-left')) -and
    (-not ($css169 -match '\.msg-user \{[^}]*margin-left: 40px')) -and
    (-not ($css169 -match '\.msg-sys \{[^}]*text-align: center')) -and
    (-not ($css169 -match '\.msg-sys \{[^}]*font-style: italic')) -and
    (-not ($css169 -match '\.msg-ai \{[^}]*font-style: italic')) -and
    (-not ($css169 -match '\.msg-ai \{[^}]*line-height: 1\.15')) -and
    (-not ($css169 -match '\.msg-ai \{[^}]*border-right')) -and
    (-not ($css169 -match '\.chat-panel \.msg-ai \{[^}]*border-right'))
) '169.3: the old transcript bounce (right/center alignment, side borders/margins, AI italic + tight leading) is fully removed'

# 169.4  .msg-tag--terminal is defined via --robco-green; .msg-tag resets
#        text-indent for the tag row
Check (($css169 -match '\.msg-tag--terminal \{[^}]*var\(--robco-green\)') -and ($css169 -match '\.msg-tag \{[^}]*text-indent: 0;')) `
    '169.4: .msg-tag--terminal is defined via --robco-green (phosphor), and .msg-tag resets text-indent:0 for the tag row'

# 169.5  acPosition() drops the panel UP for #chatInput, DOWN for others
$acStart169 = $uiSaves169.IndexOf('function acDropsUp')
$acEnd169   = $uiSaves169.IndexOf('function acRender')
$acFnBody169 = $uiSaves169.Substring($acStart169, $acEnd169 - $acStart169)
Check (
    ($acFnBody169 -match "function acDropsUp\(inputEl\) \{\s*return inputEl && inputEl\.id === 'chatInput';") -and
    ($acFnBody169 -match 'if \(acDropsUp\(inputEl\)\)') -and
    ($acFnBody169 -match 'rect\.top - panelH - 2') -and
    ($acFnBody169 -match "panel\.style\.top = rect\.bottom \+ 2 \+ 'px';")
) "169.5: acPosition() drops the panel UP for #chatInput (acDropsUp gate, rect.top-based) and DOWN for every other input (rect.bottom-based, unchanged)"

# 169.6  acRender() adds 'ac-visible' BEFORE calling acPosition()
$acRenderBody169 = Get-FunctionBody $uiSaves169 "acRender"
$visibleIdx169 = $acRenderBody169.IndexOf("classList.add('ac-visible')")
$positionIdx169 = $acRenderBody169.IndexOf('acPosition(inputEl)')
Check (($visibleIdx169 -ge 0) -and ($positionIdx169 -ge 0) -and ($visibleIdx169 -lt $positionIdx169)) `
    "169.6: acRender() adds 'ac-visible' BEFORE calling acPosition(), so the composer's drop-up height measurement is never taken against a display:none panel"

# 169.7  _scopePulse() is gated on 'listening' AND _scopeShouldAnimate()
$pulseBody169 = Get-FunctionBody $uiCore169 "_scopePulse"
Check (
    ($pulseBody169 -match "if \(_scopeState !== 'listening'\) return;") -and
    ($pulseBody169 -match 'if \(!_scopeShouldAnimate\(\)\) return;') -and
    ($pulseBody169 -match '_scopePulseUntil = performance\.now\(\) \+ _scopePulseDurationMs;')
) "169.7: _scopePulse() only pulses in the 'listening' state and reuses _scopeShouldAnimate() as its reduced-motion/dial/hidden/standby gate -- no separate carve-out"

# 169.8  drawScope()'s listening branch amplifies from a decaying pulseEnv
$drawScopeBody169 = Get-FunctionBody $uiCore169 "drawScope"
Check (
    ($drawScopeBody169 -match 'pulseEnv = pulseRemain > 0 \? pulseRemain / _scopePulseDurationMs : 0') -and
    ($drawScopeBody169 -match '\* \(1 \+ pulseEnv \* 2\.5\)')
) '169.8: drawScope() derives a decaying pulseEnv from _scopePulseUntil and amplifies the listening-state carrier wave with it'

# 169.9  _scopeTagClick() routes 'listening' to the pulse while keeping the
#        disabled/offline routing intact
$tagClickBody169 = Get-FunctionBody $uiCore169 "_scopeTagClick"
Check (
    ($tagClickBody169 -match "_scopeState === 'disabled' \|\| _scopeState === 'offline'") -and
    ($tagClickBody169 -match '_openAiUplinkSlot') -and
    ($tagClickBody169 -match "else if \(_scopeState === 'listening'\) \{\s*_scopePulse\(\);")
) "169.9: _scopeTagClick() routes 'listening' to _scopePulse() while keeping the disabled/offline -> _openAiUplinkSlot() routing intact"

# 169.10  setOverseerState() disables #scopeTag only for thinking/speaking
$setStateBody169 = Get-FunctionBody $uiCore169 "setOverseerState"
Check ($setStateBody169 -match "tagEl\.disabled = s === 'thinking' \|\| s === 'speaking';") `
    "169.10: setOverseerState() disables #scopeTag only for 'thinking'/'speaking' -- listening/disabled/offline stay clickable"

# 169.11  zero campaign-state write -- transient module var only
Check (
    (-not ($uiCore169 -match '_scopePulse[\s\S]{0,10}state\.')) -and
    (-not ($uiCore169 -match 'let _scopePulseUntil[\s\S]{0,400}saveState\('))
) '169.11: the scope pulse writes nothing durable -- _scopePulseUntil is a transient module var, never persisted to state/robco_v8'

# 169.12  #scopeTag's aria-label reflects both new actionable states
Check (($setStateBody169 -match 'tap to pulse the scope') -and ($setStateBody169 -match 'tap to open the AI Uplink settings')) `
    "169.12: setOverseerState() updates #scopeTag's aria-label for both the LISTENING pulse action and the disabled/offline NO CARRIER routing"

# ===========================================================
# Suite 170 -- Owner batch: CRT hum follows power state + scanline
# contained in screen (9 tests)
# Two owner-reported casing/CRT fixes: (1) the CRT hum kept playing while the
# terminal was powered off -- a new 'crt-hum-power' AmbientRuntime observer,
# scoped to the same SHUTDOWN/OFF states the PWR lamp/shutdown-crt flourish
# already key off, stops the hum's audio graph on power-off (stopCrtHum(), a
# full stop+disconnect+null teardown mirroring stopTinnitus()) and restarts +
# re-derives its correct radiation/crippled-based intensity on power-on; not
# tier-gated (a functional power link, not a decorative ambient flourish),
# and still only ever audible per the existing masterMute/hum-mute guards
# inside startCrtHum() itself. (2) the CRT scanline/vignette overlay used to
# be position:fixed against the whole viewport, bleeding out over the
# casing-top/bezel chrome -- it now lives inside .glass-frame (the device
# chrome's "screen" layer, already position:relative;overflow:hidden) as
# position:absolute, and .glass-frame gained its own explicit z-index so the
# overlay's z-index:9999 is trapped inside that stacking context instead of
# being compared directly against sibling .bezel's z-index:60 (mobile,
# position:fixed) -- otherwise the scanline could still paint over the fixed
# bezel at some scroll depths even though overflow:hidden already clipped
# its box. (PS mirror of JS Suite 170.)
# ===========================================================
Sep "Suite 170 -- Owner batch: CRT hum follows power state + scanline contained in screen"
$uiAudio170 = Read-Src "js/ui-audio.js"
$uiCore170 = Read-Src "js/ui-core.js"
$css170 = Read-Src "css/terminal.css"
$html170 = Read-Src "index.html"

# 170.1  stopCrtHum() fully tears down the hum's audio graph
$stopCrtHumBody170 = Get-FunctionBody $uiAudio170 "stopCrtHum"
Check (
    ($stopCrtHumBody170 -match 'crtHumNode = null') -and
    ($stopCrtHumBody170 -match 'crtHumGain = null') -and
    ($stopCrtHumBody170 -match 'crtHumLfo = null') -and
    ($stopCrtHumBody170 -match 'crtHumLfoGain = null') -and
    ($stopCrtHumBody170 -match 'crtHumNode\.stop\(\)') -and
    ($stopCrtHumBody170 -match 'crtHumLfo\.stop\(\)')
) '170.1: stopCrtHum() stops+disconnects+nulls crtHumNode/crtHumGain/crtHumLfo/crtHumLfoGain (full teardown, not just a gain ramp)'

# 170.2  a 'crt-hum-power' observer is registered, scoped to SHUTDOWN/OFF
$wireAmbient170 = Get-FunctionBody $uiCore170 "_wireAmbientExperiences"
$humObsIdx170 = $wireAmbient170.IndexOf("id: 'crt-hum-power'")
$humObsLen170 = [Math]::Min(700, $wireAmbient170.Length - $humObsIdx170)
$humObsBlock170 = if ($humObsIdx170 -ge 0) { $wireAmbient170.Substring($humObsIdx170, $humObsLen170) } else { '' }
Check (($humObsIdx170 -ge 0) -and ($humObsBlock170 -match "states: \['SHUTDOWN', 'OFF'\]")) `
    "170.2: a 'crt-hum-power' observer is registered inside _wireAmbientExperiences(), scoped to states ['SHUTDOWN', 'OFF']"

# 170.3  onEnter stops the hum; onExit restarts + re-derives its intensity
Check (
    ($humObsBlock170 -match 'onEnter: \(\) => \{[\s\S]{0,80}stopCrtHum\(\)') -and
    ($humObsBlock170 -match 'onExit: \(\) => \{[\s\S]{0,400}startCrtHum\(\)[\s\S]{0,400}setCrtHumIntensity\(rads, hasCrippled\)')
) '170.3: the crt-hum-power observer stops the hum on power-off (onEnter) and restarts + re-derives its intensity on power-on (onExit)'

# 170.4  the observer is not tier-gated (a functional power link, not an
#        Immersion-gated decorative flourish)
Check (-not ($humObsBlock170 -match 'tier:')) `
    '170.4: the crt-hum-power observer has no `tier` property -- it stops/resumes at every Immersion level, matching the PWR lamp'

# 170.5  volume is still gated only by startCrtHum()'s existing guard
$startCrtHumBody170 = Get-FunctionBody $uiAudio170 "startCrtHum"
Check ($startCrtHumBody170 -match 'if \(crtHumNode \|\| AudioSettings\.masterMute \|\| AudioSettings\.hum\) return;') `
    "170.5: startCrtHum()'s existing masterMute/hum-mute guard is untouched -- a muted hum stays silent through a power cycle"

# 170.6  .crt-overlay now lives inside .glass-frame in index.html
$glassFrameIdx170 = $html170.IndexOf('<div class="glass-frame">')
$glassFrameLen170 = [Math]::Min(600, $html170.Length - $glassFrameIdx170)
$glassFrameWindow170 = if ($glassFrameIdx170 -ge 0) { $html170.Substring($glassFrameIdx170, $glassFrameLen170) } else { '' }
Check (($glassFrameIdx170 -ge 0) -and ($glassFrameWindow170 -match '<div class="crt-overlay"></div>')) `
    '170.6: <div class="crt-overlay"> is nested inside <div class="glass-frame"> in index.html (not a page-level sibling before .container)'

# 170.7  .crt-overlay is position:absolute, not position:fixed
$crtOverlayRule170 = [regex]::Match($css170, '\.crt-overlay \{[^}]*\}').Value
Check (($crtOverlayRule170 -match 'position: absolute;') -and (-not ($crtOverlayRule170 -match 'position: fixed;'))) `
    '170.7: .crt-overlay is position:absolute (was position:fixed against the viewport)'

# 170.8  .glass-frame declares its own z-index (stacking-context containment)
$glassFrameRuleMatches170 = [regex]::Matches($css170, '\.glass-frame \{[^}]*\}')
$glassFrameHasZIndex170 = $false
foreach ($m in $glassFrameRuleMatches170) {
    if ($m.Value -match 'z-index:\s*\d') { $glassFrameHasZIndex170 = $true }
}
Check $glassFrameHasZIndex170 `
    "170.8: .glass-frame declares its own z-index (traps .crt-overlay's stacking inside it, never above sibling .casing-top/.bezel)"

# 170.9  reduced-motion / high-lumen behavior for .crt-overlay is untouched
Check (
    ($css170 -match 'prefers-reduced-motion\s*:\s*reduce\b[\s\S]*?\.crt-overlay') -and
    ($css170 -match 'html\.high-lumen \.crt-overlay')
) '170.9: .crt-overlay keeps its prefers-reduced-motion + html.high-lumen behavior after the containment fix'

# ===========================================================
# Suite 171 -- WIPE TERMINAL dialog: one cancel + Complete RNG lock
# warning (9 tests)
# Two owner-reported wipe-dialog fixes: (1) confirmAction() (the ONE shared
# driver behind WIPE TERMINAL and every other destructive confirm --
# craft/scrap, save delete/overwrite, cloud save/version restore, etc.) used
# to render its own labeled CONTINUE + CANCEL pair INSIDE a modal that also
# carries an always-present static "[ CLOSE INTERFACE ]" button outside the
# injected content -- both did the exact same dismiss-without-confirming
# thing, reading as two cancels. openModal() gained a `hideCloseBtn` option
# (the same class-toggle idiom its pre-existing `wide` option already uses)
# that confirmAction() now always passes, toggling a new .confirm-mode class
# that hides the redundant static button via CSS; closeModal() always resets
# the class so no OTHER modal (help/error log/changelog/save help) is ever
# affected. (2) Complete RNG's permanent-lock mechanism was verified: once a
# wipe is performed while armed (state.campaignMode === 'rng'), the resulting
# 'rng-locked' state is enforced by onCampaignModeChange() refusing to
# uncheck/re-enable the control ever again for that save (pre-existing,
# previously untested -- now locked by 171.6) -- but the wipe dialog itself
# said nothing about this irreversible commitment. wipeTerminal() now appends
# a warning line to the first confirm gate, gated on the exact same
# state.campaignMode === 'rng' signal wasRngArmed reads a few lines later to
# actually commit the lock, so the warning and the lock can never disagree.
# (PS mirror of JS Suite 171.)
# ===========================================================
Sep "Suite 171 -- WIPE TERMINAL dialog: one cancel + Complete RNG lock warning"
$uiCore171 = Read-Src "js/ui-core.js"
$css171 = Read-Src "css/terminal.css"

# 171.1  openModal() supports hideCloseBtn -> .confirm-mode class toggle
$openModalBody171 = Get-FunctionBody $uiCore171 "openModal"
Check (
    ($openModalBody171 -match 'opts\.hideCloseBtn !== undefined') -and
    ($openModalBody171 -match "classList\.toggle\('confirm-mode', !!opts\.hideCloseBtn\)")
) "171.1: openModal({hideCloseBtn}) toggles .modal-box's confirm-mode class"

# 171.2  closeModal() always resets confirm-mode
$closeModalBody171 = Get-FunctionBody $uiCore171 "closeModal"
Check ($closeModalBody171 -match "classList\.remove\('confirm-mode'\)") `
    "171.2: closeModal() resets the confirm-mode class for the next modal open"

# 171.3  confirmAction() passes hideCloseBtn: true
$confirmActionBody171 = Get-FunctionBody $uiCore171 "confirmAction"
Check ($confirmActionBody171 -match 'hideCloseBtn: true,') `
    '171.3: confirmAction() opens its modal with hideCloseBtn:true, suppressing the redundant static CLOSE INTERFACE button'

# 171.4  the CSS rule that hides the button exists, scoped to .confirm-mode
Check ($css171 -match '\.modal-box\.confirm-mode \.close-btn \{\s*display: none;') `
    '171.4: .modal-box.confirm-mode .close-btn { display: none } is defined in terminal.css'

# 171.5  the surviving CANCEL button still calls closeModal()
Check ($confirmActionBody171 -match "noBtn\.addEventListener\('click', \(\) => \{\s*closeModal\(\);") `
    '171.5: the CANCEL button (#modalConfirmNo) still calls closeModal() -- dismiss behavior is unchanged'

# 171.6  onCampaignModeChange() refuses to un-lock once rng-locked
$campaignModeBody171 = Get-FunctionBody $uiCore171 "onCampaignModeChange"
Check (
    ($campaignModeBody171 -match "if \(state\.campaignMode === 'rng-locked'\) \{") -and
    ($campaignModeBody171 -match 'cb\.checked = true;') -and
    ($campaignModeBody171 -match 'cb\.disabled = true;') -and
    ($campaignModeBody171 -match 'return;')
) "171.6: onCampaignModeChange() forces the checkbox back to checked+disabled and no-ops once campaignMode is 'rng-locked' (permanent, matches the save)"

# 171.7  wipeTerminal() appends the RNG warning gated on the same signal
#        wasRngArmed reads later
$wipeTerminalBody171 = Get-FunctionBody $uiCore171 "wipeTerminal"
$rngWarnIdx171 = $wipeTerminalBody171.IndexOf("if (state.campaignMode === 'rng')")
$wasRngArmedIdx171 = $wipeTerminalBody171.IndexOf('wasRngArmed = state.campaignMode')
Check (
    ($rngWarnIdx171 -ge 0) -and
    ($wasRngArmedIdx171 -ge 0) -and
    ($rngWarnIdx171 -lt $wasRngArmedIdx171) -and
    ($wipeTerminalBody171 -match 'wipeWarning \+=')
) "171.7: wipeTerminal() appends an RNG-armed warning to gate1's text, gated on the same state.campaignMode === 'rng' check wasRngArmed reads later"

# 171.8  the warning states the lock is permanent and irreversible
Check (
    ($wipeTerminalBody171 -match 'PERMANENTLY enable it for this save') -and
    ($wipeTerminalBody171 -match 'cannot be changed or disabled afterward')
) '171.8: the RNG warning states the lock will be PERMANENT and cannot be changed/disabled afterward'

# 171.9  the original wipe warning text is preserved verbatim (additive only)
Check (
    ($wipeTerminalBody171 -match 'This will erase ALL Courier data') -and
    ($wipeTerminalBody171 -match 'This CANNOT be undone\. Continue\?')
) '171.9: the original wipe warning text (Courier data erasure list) is preserved verbatim; the RNG line is additive'

# ===========================================================
# Suite 172 -- Owner-report fix: boot-time panel-state RESTORE must never
# re-trigger the Module Bay hatch ceremony (Protocol 13 regression)
# 2 tests
# ===========================================================
Sep "Suite 172 -- Boot-restore must never re-trigger the Module Bay hatch"
$core172 = Read-Src "js/ui-core.js"
$wirePanelBody172 = Get-FunctionBody $core172 '_wirePanelPersistence'

# 172.1  Structural guard: the flag is declared before the restore loop,
#        checked in the securityConfigPanel toggle branch, and reset via a
#        setTimeout AFTER the loop (so every restore-triggered toggle --
#        queued as a task by the loop's own setAttribute/removeAttribute
#        calls -- is still caught before the flag flips back to false).
$declIdx172 = $wirePanelBody172.IndexOf('let _restoringPanels = true;')
$forEachIdx172 = $wirePanelBody172.IndexOf('panelEls.forEach(')
$checkIdx172 = $wirePanelBody172.IndexOf('if (_restoringPanels)')
$resetIdx172 = $wirePanelBody172.IndexOf('_restoringPanels = false;')
Check (
    ($declIdx172 -ge 0) -and ($forEachIdx172 -ge 0) -and ($declIdx172 -lt $forEachIdx172) -and
    ($checkIdx172 -ge 0) -and ($checkIdx172 -gt $forEachIdx172) -and
    ($resetIdx172 -ge 0) -and ($resetIdx172 -gt $checkIdx172) -and
    ($wirePanelBody172 -match "(?s)setTimeout\(\(\) => \{\s*_restoringPanels = false;") -and
    ($wirePanelBody172 -match "MetaStore\.set\('robco_bay_opened', 'true'\)") -and
    ($wirePanelBody172 -match "if \(typeof renderModuleBay === 'function'\) renderModuleBay\(\);")
) "172.1: _restoringPanels is declared before the restore loop, checked in the securityConfigPanel toggle branch, and reset via a deferred setTimeout after the loop -- marking robco_bay_opened + syncing content via renderModuleBay() while restoring"

# 172.2  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#        has no JS execution sandbox -- same convention as Suite 150.10): the
#        two scenarios the JS side actually EXECUTES are locked here as
#        source-shape guards instead -- (a) the _restoringPanels branch
#        (boot-time restore) marks robco_bay_opened + calls renderModuleBay()
#        and NEVER calls initModuleBay() from that branch; (b) the else
#        branch (a genuine post-boot toggle, _restoringPanels already false)
#        is the ONLY place initModuleBay() is called from this listener.
$restoringBranchIdx172 = $wirePanelBody172.IndexOf('if (_restoringPanels) {')
$elseBranchIdx172 = $wirePanelBody172.IndexOf('} else if (typeof initModuleBay', $restoringBranchIdx172)
$restoringBranchBody172 = if ($restoringBranchIdx172 -ge 0 -and $elseBranchIdx172 -gt $restoringBranchIdx172) {
    $wirePanelBody172.Substring($restoringBranchIdx172, $elseBranchIdx172 - $restoringBranchIdx172)
} else { '' }
Check (
    ($restoringBranchIdx172 -ge 0) -and ($elseBranchIdx172 -gt $restoringBranchIdx172) -and
    ($restoringBranchBody172 -match "MetaStore\.set\('robco_bay_opened', 'true'\)") -and
    ($restoringBranchBody172 -match 'renderModuleBay\(\);') -and
    (-not ($restoringBranchBody172 -match 'initModuleBay\(\);')) -and
    (([regex]::Matches($wirePanelBody172, 'initModuleBay\(\);')).Count -eq 1)
) "172.2: structural mirror of the JS behavioral proof -- the _restoringPanels (boot-time restore) branch marks robco_bay_opened released and calls renderModuleBay(), never initModuleBay(); the single initModuleBay() call site in this listener sits only in the else branch (a genuine post-boot user open)"

# ===========================================================
# Suite 173 -- Owner batch: native LEVEL UP control + readable event-log
# timestamps
# 8 tests
# ===========================================================
Sep "Suite 173 -- Owner batch: native LEVEL UP control + readable event-log timestamps"
$uiCore173 = Read-Src "js/ui-core.js"
$uiRender173 = Read-Src "js/ui-render.js"
$idxSrc173 = Read-Src "index.html"

# 173.1  index.html: #btnLevelUp is a real <button> (Protocol UI-5), starts
#        disabled, and carries a descriptive aria-label.
$btnMatch173 = [regex]::Match($idxSrc173, '(?s)<button[^>]*id="btnLevelUp"[\s\S]{0,500}?</button>')
$btnTag173 = if ($btnMatch173.Success) { $btnMatch173.Value } else { '' }
Check (
    ($btnTag173 -match '<button') -and
    ($btnTag173 -match 'onclick="nativeLevelUp\(\)"') -and
    ($btnTag173 -match '\bdisabled\b') -and
    ($btnTag173 -match 'aria-label="[^"]+"')
) "173.1: index.html #btnLevelUp is a real <button> wired to nativeLevelUp(), starts disabled, and has a descriptive aria-label (Protocol UI-5)"

# 173.2  nativeLevelUp() is defined in ui-core.js
Check ([bool]($uiCore173 -match 'function nativeLevelUp\s*\(')) "173.2: nativeLevelUp() is defined in ui-core.js"

# 173.3  owner report: leveling up is deterministic and ungated by XP --
#        MAX_PLAYER_LEVEL is a single named constant (Protocol 22), read by
#        BOTH nativeLevelUp() and updateMath(), never a re-derived/forked
#        magic number in either place.
$nativeLevelUpBody173 = Get-FunctionBody $uiCore173 'nativeLevelUp'
$updateMathBody173 = Get-FunctionBody $uiCore173 'updateMath'
Check (
    ($uiCore173 -match 'const MAX_PLAYER_LEVEL = 50;') -and
    $nativeLevelUpBody173.Contains('MAX_PLAYER_LEVEL') -and
    $updateMathBody173.Contains('MAX_PLAYER_LEVEL') -and
    (-not ($nativeLevelUpBody173 -match '\bxp\b'))
) "173.3: MAX_PLAYER_LEVEL is a single named constant read by both nativeLevelUp() and updateMath() (Protocol 22); nativeLevelUp() never reads XP at all -- leveling is fully ungated by XP"

# 173.4  nativeLevelUp() increments state.lvl by exactly +1 per press,
#        clamped at MAX_PLAYER_LEVEL, and emits the SAME 'level.up'
#        RobcoEvents the AI-driven autoImportState() path uses.
$autoImportBody173 = Get-FunctionBody $apiSrc 'autoImportState'
Check (
    ($nativeLevelUpBody173 -match 'if \(lvl >= MAX_PLAYER_LEVEL\) return;') -and
    ($nativeLevelUpBody173 -match 'const newLvl = Math\.min\(MAX_PLAYER_LEVEL, lvl \+ 1\);') -and
    ($nativeLevelUpBody173 -match 'state\.lvl = newLvl;') -and
    ($nativeLevelUpBody173 -match "RobcoEvents\.emit\('level\.up', \{ oldLvl: lvl, newLvl \}\)") -and
    ($autoImportBody173 -match "RobcoEvents\.emit\('level\.up',")
) "173.4: nativeLevelUp() no-ops at MAX_PLAYER_LEVEL, otherwise always increments state.lvl by exactly +1, and emits RobcoEvents 'level.up' -- the same event autoImportState()'s AI-driven level-up path emits (Protocol 22)"

# 173.5  updateMath() toggles #btnLevelUp.disabled ONLY at MAX_PLAYER_LEVEL --
#        never from an XP comparison (owner report: the button must work on
#        every press regardless of XP).
Check (
    ($updateMathBody173 -match "getElementById\('btnLevelUp'\)") -and
    ($updateMathBody173 -match 'levelUpBtn\.disabled = lvl >= MAX_PLAYER_LEVEL;')
) "173.5: updateMath() keeps #btnLevelUp's disabled state in sync with lvl >= MAX_PLAYER_LEVEL only -- never gated on XP"

# 173.6  _recordLine() no longer emits the raw "[T<ticks>]" prefix -- it
#        formats the same stored tick value with formatGameTime() instead.
$recordLineBody173 = Get-FunctionBody $uiRender173 '_recordLine'
Check (
    ($recordLineBody173 -match 'formatGameTime\(ev\.t \|\| 0\)') -and
    (-not ($recordLineBody173 -match '\[T\$\{ev\.t'))
) "173.6: _recordLine() formats ev.t through formatGameTime() instead of the raw ""[T<ticks>]"" prefix"

# 173.7  Both Crossroads Record and Incident Log still route through the
#        single _recordLine() choke point.
$rcStart173 = $uiRender173.IndexOf('function renderCampaignStatus')
$rcEnd173 = $uiRender173.IndexOf("`nfunction ", $rcStart173 + 1)
$rcBody173 = if ($rcStart173 -ge 0) { $uiRender173.Substring($rcStart173, $rcEnd173 - $rcStart173) } else { '' }
$recordLineCalls173 = ([regex]::Matches($rcBody173, '_recordLine\(ev\)')).Count
Check (
    $recordLineCalls173 -eq 2
) "173.7: both the Crossroads Record and Incident Log renderers call _recordLine(ev) (single formatter, no drift) -- found $recordLineCalls173"

# 173.8  STRUCTURAL MIRROR of the JS behavioral vm-sandbox proof (PowerShell
#        has no JS execution sandbox -- same convention as Suite 150.10/172.2):
#        formatGameTime() itself (the function _recordLine() now delegates
#        to) still builds the exact 'Weekday, MM.DD.YY, H:MM AM/PM' template
#        the JS side actually EXECUTES and regex-asserts against -- the same
#        shape guarantee, checked at its one source instead of by running it.
$formatGameTimeBody173 = Get-FunctionBody $uiRender173 'formatGameTime'
Check (
    ($formatGameTimeBody173 -match '\$\{WEEKDAYS\[dt\.weekday\]\}, \$\{dateStr\}, \$\{timeStr\}') -and
    ($formatGameTimeBody173 -match "dateStr = `\`\$\{mm\}\.`\$\{dd\}\.`\$\{yy\}`;" -or $formatGameTimeBody173 -match '\$\{mm\}\.\$\{dd\}\.\$\{yy\}') -and
    ($formatGameTimeBody173 -match '\$\{h12\}:\$\{String\(dt\.minute\)\.padStart\(2, .0.\)\} \$\{ampm\}')
) "173.8: structural mirror of the JS behavioral proof -- formatGameTime() (which _recordLine() now delegates to) still builds the 'Weekday, MM.DD.YY, H:MM AM/PM' template the JS side executes and regex-asserts against"

# 173.9  Owner-report regression (Protocol 13): STRUCTURAL MIRROR of the JS
#        behavioral vm-sandbox proof (PowerShell has no JS execution sandbox
#        -- same convention as Suite 150.10/172.2/173.8): nativeLevelUp()'s
#        body shape locks in the exact "always +1, no-op at max, XP never
#        read" contract the JS side actually EXECUTES and asserts --
#        (a) the level-cap guard is the FIRST statement (checked before any
#        state mutation or event emit), (b) the increment is unconditionally
#        +1 (Math.min(MAX_PLAYER_LEVEL, lvl + 1), never lvl + N or a
#        threshold-gated branch), and (c) RobcoEvents.emit('level.up', ...)
#        always follows the state write when the guard doesn't return early.
$guardIdx173 = $nativeLevelUpBody173.IndexOf('if (lvl >= MAX_PLAYER_LEVEL) return;')
$newLvlIdx173 = $nativeLevelUpBody173.IndexOf('const newLvl = Math.min(MAX_PLAYER_LEVEL, lvl + 1);')
$stateWriteIdx173 = $nativeLevelUpBody173.IndexOf('state.lvl = newLvl;')
$emitIdx173 = $nativeLevelUpBody173.IndexOf("RobcoEvents.emit('level.up',")
Check (
    ($guardIdx173 -ge 0) -and ($newLvlIdx173 -gt $guardIdx173) -and
    ($stateWriteIdx173 -gt $newLvlIdx173) -and ($emitIdx173 -gt $stateWriteIdx173) -and
    (-not ($nativeLevelUpBody173 -match '\bxp\b'))
) "173.9: structural mirror of the JS behavioral proof -- nativeLevelUp()'s MAX_PLAYER_LEVEL guard runs first, the +1 clamp/state write/level.up emit follow in that exact order, and XP is never read anywhere in the path (always +1 per press, no-op only at the cap)"

