    (-not ($html176 -match 'data-tab="data"\s+id="accountPanel"')) -and
    (-not ($html176 -match '(?s)data-tab="campg"\s+id="campgPanel" open>\s*<summary>\s*<h2>>\s*CAMPAIGN CONFIGURATION'))
) '176.1: #accountPanel, #securityConfigPanel, #savesPanel, #campaignConfigPanel are all data-tab="settings" -- Account/Module-Bay/Saves/Campaign-configs removed from their old tabs'

# 176.2  #campgPanel keeps only the campaign RECORD sub-panels + data-tab="campg",
#        renamed CAMPAIGN RECORD; the config controls (GAME/PLAYSTYLE/PLAYTHROUGH/
#        COMPLETE-RNG/DANGER-ZONE) live only in the new #campaignConfigPanel
$campgStart176 = $html176.IndexOf('id="campgPanel"')
$campgBlock176 = $html176.Substring($campgStart176, $html176.IndexOf('id="accountPanel"') - $campgStart176)
$configStart176 = $html176.IndexOf('id="campaignConfigPanel"')
$configBlock176 = $html176.Substring($configStart176, $html176.IndexOf('<div class="col-right">') - $configStart176)
Check (
    ($campgBlock176 -match '(?s)<h2>&gt;[\s\S]*?CAMPAIGN CHRONICLE</h2>') -and
    ($campgBlock176.Contains('data-sub-id="campaign_status"')) -and
    ($campgBlock176.Contains('data-sub-id="crossroads_record"')) -and
    ($campgBlock176.Contains('data-sub-id="incident_log"')) -and
    (-not ($campgBlock176.Contains('id="gameContextSelect"'))) -and
    (-not ($campgBlock176.Contains('id="wipeTerminalBtn"'))) -and
    ($configBlock176.Contains('id="gameContextSelect"')) -and
    ($configBlock176.Contains('id="playstyleInput"')) -and
    ($configBlock176.Contains('id="playthroughTypeSelect"')) -and
    ($configBlock176.Contains('id="completeRngToggle"')) -and
    ($configBlock176.Contains('id="wipeTerminalBtn"'))
) '176.2: #campgPanel (renamed CAMPAIGN CHRONICLE at Phase 3 . Piece 3) keeps only the record sub-panels; every config control + the DANGER ZONE moved verbatim into #campaignConfigPanel'

# 176.3  #systemStatusPanel exists on CHASSIS with device telemetry; the
#        firmware-log + error-log buttons are gone from the SVC tray.
#        UPDATED (Design Overhaul CHASSIS unit): the firmware-log/error-log
#        buttons moved again, from #systemStatusPanel into their own BUS-24
#        #serviceFaultConsolePanel board (see Suite 192) -- #systemStatusPanel
#        itself is now BUS-23 IDENTITY PLATE & BREAKERS (#systemStatusDisplay
#        only, no buttons).
$svcTrayMatch176 = [regex]::Match($html176, '(?s)data-sub-id="slot_svc_tray"[\s\S]*?</details>')
$svcTrayBlock176 = if ($svcTrayMatch176.Success) { $svcTrayMatch176.Value } else { '' }
Check (
    ($html176 -match '<details class="panel bay-board" data-tab="chassis" id="systemStatusPanel">') -and
    ($html176 -match 'id="systemStatusDisplay"') -and
    ($html176 -match '<details class="panel bay-board" data-tab="chassis" id="serviceFaultConsolePanel">') -and
    ($html176 -match 'id="btnSystemStatusErrorLog"[^>]*onclick="showErrorLog\(\)"') -and
    ($html176 -match 'id="btnViewChangelog"[^>]*onclick="_svcViewChangelog\(\)"') -and
    (-not ($svcTrayBlock176.Contains('id="btnViewChangelog"')))
) '176.3: #systemStatusPanel (CHASSIS, BUS-23) hosts #systemStatusDisplay; #serviceFaultConsolePanel (BUS-24) hosts the firmware-log button (moved out of the SVC tray) + the error-log button'

# 176.4  #campaignLogPanel exists on DATABANK with the campaign stats + reset
#        button (reskinned as BUS-21 SERVICE TALLY at Phase 3 . Piece 3)
Check (
    ($html176 -match '<details class="panel[^"]*"[^>]*data-tab="data"[^>]*id="campaignLogPanel">') -and
    ($html176 -match 'id="sessionStatsList"') -and
    ($html176 -match 'onclick="resetSessionStats\(\)"')
) '176.4: #campaignLogPanel (DATABANK) hosts #sessionStatsList + the ZERO CAMPAIGN COUNTERS reset button'

# 176.5  renderSystemStatus() is defined, reads real carrier/feature-flag/version
#        signals (no game literal), and is wired into both loadUI() and
#        refreshOverseerCarrier() (the single connection-status choke point)
$renderBody176 = Get-FunctionBody $core176 'renderSystemStatus'
$carrierBody176 = Get-FunctionBody $core176 'refreshOverseerCarrier'
Check (
    ($renderBody176 -match "getElementById\('systemStatusDisplay'\)") -and
    ($renderBody176 -match '_isUplinkConnected') -and
    ($renderBody176 -match 'isFeatureEnabled') -and
    ($renderBody176 -match 'APP_VERSION') -and
    ($carrierBody176 -match 'renderSystemStatus\(\);') -and
    ($core176 -match "if \(typeof renderSystemStatus === 'function'\) renderSystemStatus\(\);")
) '176.5: renderSystemStatus() reads carrier/feature-flag/version state and is called from both loadUI() and refreshOverseerCarrier()'

# 176.6  TAB_NAMES/TAB_TO_SUBSYSTEM include 'settings' and 'chassis' as real tabs
Check (
    ($core176 -match "const TAB_NAMES = \['stat', 'inv', 'data', 'campg', 'chassis', 'settings'\];") -and
    ($core176 -match "(?s)TAB_TO_SUBSYSTEM = \{.*?chassis:\s*'chassis',.*?settings:\s*'settings',")
) "176.6: TAB_NAMES and TAB_TO_SUBSYSTEM both include 'settings' and 'chassis' as real, independently tab-gated subsystems"

# 176.7  the first-visit Module Bay hatch fires on a genuine user [6]/SETTINGS
#        visit (via selectSubsystem) but NEVER on the boot-time initTabs() restore.
#        Owner batch item 5 (Protocol 27 root cause) tightened this further --
#        selectSubsystem('settings') only force-opens the panel on a genuine
#        FIRST-EVER visit (robco_bay_opened not yet 'true'); see Suite 190.7.
$initTabsBody176 = Get-FunctionBody $core176 'initTabs'
$selectSubsystemBody176 = Get-FunctionBody $core176 'selectSubsystem'
Check (
    ($selectSubsystemBody176 -match "(?s)if \(view === 'settings'\) \{.{0,700}securityConfigPanel.{0,200}setAttribute\('open', ''\)") -and
    ($selectSubsystemBody176 -match "MetaStore\.get\('robco_bay_opened'\) !== 'true'") -and
    (-not ($initTabsBody176 -match 'selectSubsystem'))
) "176.7: selectSubsystem('settings') re-opens #securityConfigPanel only on a genuine first-ever visit (robco_bay_opened not yet 'true'), firing its own once-only hatch toggle listener; initTabs() never calls selectSubsystem(), so a boot-time restore can't re-trigger the hatch (Protocol 42)"

# 176.8  expandPanelForCategory's 'config'/'log' categories were re-routed to
#        their new homes (settings/chassis) rather than left pointing at the
#        panels they used to live in. UPDATED (Design Overhaul CHASSIS unit):
#        'log' now targets the BUS-22 UNIT POWER PLANT board title, since the
#        former single SYSTEM STATUS panel split into three (Suite 192).
$expandBody176 = Get-FunctionBody $core176 'expandPanelForCategory'
Check (
    ($expandBody176 -match "config:\s*'settings'") -and
    ($expandBody176 -match "config:\s*'>\s*CAMPAIGN CONFIGS'") -and
    ($expandBody176 -match "log:\s*'chassis'") -and
    ($expandBody176 -match "log:\s*'>\s*UNIT POWER PLANT'")
) "176.8: expandPanelForCategory routes 'config' to the settings tab / CAMPAIGN CONFIGS panel and 'log' to the chassis tab / UNIT POWER PLANT panel"

# 176.9  the nav/render layer added by this unit writes nothing durable to the
#        campaign -- renderSystemStatus() and the settings-hatch trigger inside
#        selectSubsystem() only read state/MetaStore, never saveState()/robco_v8
$fns176 = @('renderSystemStatus', 'selectSubsystem')
$offenders176 = $fns176 | Where-Object {
    try { $body = Get-FunctionBody $core176 $_ } catch { return $true }
    return ($body -match 'saveState\(|robco_v8|state\.\w+\s*=')
}
Check (
    $offenders176.Count -eq 0
) ("176.9: renderSystemStatus()/selectSubsystem() never write campaign state (saveState/robco_v8/state.<field>=)" + $(if ($offenders176.Count) { " -- offenders: $($offenders176 -join ', ')" } else { "" }))

# ===========================================================
# Suite 177 -- Step 2 v2.8.0 SU-4: dynamic ACCOUNT (REG PORT) status words
# The REG PORT / Operator Registry board's diegetic status text is driven
# entirely by real auth + connection state (getAccountState()/
# isFeatureEnabled('googleSignIn')/_isUplinkConnected()) -- never a hardcoded
# story -- and live-updates through the SAME refreshOverseerCarrier() choke
# point that already drives the UPLINK lamp, bezel telemetry, and SYSTEM
# STATUS carrier line. Shells out to node (mirrors the Suite 133/135 pattern,
# temp-file transport per the Protocol 42 stdin-corruption fix) to actually
# EXECUTE the real renderAccount() body across all four conditions.
# 9 tests (PS mirror of JS Suite 177.)
# ===========================================================
Sep "Suite 177 -- SU-4: dynamic ACCOUNT (REG PORT) status words"
$html177 = Read-Src "index.html"
$acctSrc177 = Read-Src "js/ui-account.js"
$core177 = Read-Src "js/ui-core.js"
$css177 = Read-Src "css/terminal.css"

# 177.1  index.html: #acctSummaryStatus lives in the ACCOUNT panel's <summary>,
#        styled via .panel-substatus
Check (
    ($html177 -match '(?s)<h2>>\s*ACCOUNT</h2>\s*<span id="acctSummaryStatus" class="panel-substatus">') -and
    ($css177 -match '\.panel-substatus\s*\{')
) "177.1: #acctSummaryStatus sits inside the ACCOUNT panel summary, styled via .panel-substatus"

# 177.2  renderAccount() reads the real signals -- never navigator.onLine or a
#        second, parallel connection check (Protocol 22)
$acctBody177 = Get-FunctionBody $acctSrc177 "renderAccount"
Check (
    ($acctBody177 -match 'window\.getAccountState') -and
    ($acctBody177 -match "isFeatureEnabled\('googleSignIn'\)") -and
    ($acctBody177 -match '_isUplinkConnected\(\)') -and
    (-not ($acctBody177 -match 'navigator\.onLine'))
) "177.2: renderAccount() reads getAccountState()/isFeatureEnabled('googleSignIn')/_isUplinkConnected() -- no navigator.onLine, no parallel connection check"

# 177.3  refreshOverseerCarrier() calls renderAccount() -- the single choke point
Check (
    $core177 -match "(?s)_updateUplinkLamp\(\);.{0,200}_refreshBezelTelemetry\(\);.{0,200}renderSystemStatus\(\);.{0,300}if \(typeof renderAccount === 'function'\) renderAccount\(\);"
) "177.3: refreshOverseerCarrier() calls renderAccount() alongside _updateUplinkLamp()/_refreshBezelTelemetry()/renderSystemStatus() -- one choke point, cannot drift"

# 177.4-177.7  behavioral -- shell out to node and actually execute the real
# renderAccount() body against all four conditions.
$labels177 = @(
    "signed-out + googleSignIn ON -> NO OPERATOR ON RECORD, REG PORT VACANT, CLOUD ARCHIVE SYNC OFFLINE, sign-in button, summary UPLINK OFFLINE",
    "signed-out + googleSignIn OFF -> LOCAL ARCHIVES ACTIVE, no sign-in button, summary UPLINK TEMPORARILY UNAVAILABLE",
    "signed-in + carrier connected -> OPERATOR VERIFIED, CLOUD ARCHIVES + CIPHER-KEY SYNC AVAILABLE, sever-uplink button, name/email shown (real middot not &middot; entity), summary UPLINK ACTIVE",
    "signed-in + carrier disconnected -> OPERATOR VERIFIED, CLOUD ARCHIVE SYNC OFFLINE (NO CARRIER), sever-uplink button still present, summary CLOUD UNREACHABLE"
)
try {
    $nodeCheck177 = Get-Command node -ErrorAction SilentlyContinue
    if ($nodeCheck177) {
        $acctPathNode177 = (Join-Path $Root "js/ui-account.js").Replace('\', '/')
        $testScript177 = @"
const fs = require('fs');
const vm = require('vm');
const acctSource = fs.readFileSync('$acctPathNode177', 'utf8');
function extractFunctionBody(source, fnName) {
  const idx = source.indexOf('function ' + fnName);
  const braceStart = source.indexOf('{', source.indexOf('(', idx));
  let depth = 0, i = braceStart;
  for (; i < source.length; i++) {
    if (source[i] === '{') depth++;
    else if (source[i] === '}' && --depth === 0) break;
  }
  return source.slice(braceStart, i + 1);
}
function decl(name) {
  const s = acctSource.indexOf('function ' + name);
  const p = acctSource.slice(acctSource.indexOf('(', s), acctSource.indexOf('{', acctSource.indexOf('(', s)));
  return 'function ' + name + p + extractFunctionBody(acctSource, name);
}
function runAccount(acct, googleSignInOn, connected) {
  const els = { accountBody: { innerHTML: '' }, acctSummaryStatus: { textContent: '' } };
  const sandbox = {
    console,
    escapeHtml: s => String(s),
    _isUplinkConnected: () => connected,
    document: { getElementById: id => els[id] || null },
    window: {
      getAccountState: () => acct,
      isFeatureEnabled: key => (key === 'googleSignIn' ? googleSignInOn : true),
    },
  };
  vm.createContext(sandbox);
  vm.runInContext(decl('renderAccount') + '\nrenderAccount();', sandbox);
  return els;
}
const results = [];
try {
  const e = runAccount({ uid: null, isAnonymous: true, email: null, displayName: null }, true, false);
  results.push(/NO OPERATOR ON RECORD/.test(e.accountBody.innerHTML) && /REG PORT VACANT/.test(e.accountBody.innerHTML) && /CLOUD ARCHIVE SYNC OFFLINE/.test(e.accountBody.innerHTML) && /signInWithGoogle/.test(e.accountBody.innerHTML) && /UPLINK OFFLINE/.test(e.acctSummaryStatus.textContent));
} catch (err) { results.push(false); }
try {
  const e = runAccount({ uid: null, isAnonymous: true, email: null, displayName: null }, false, false);
  results.push(/LOCAL ARCHIVES ACTIVE/.test(e.accountBody.innerHTML) && !/signInWithGoogle/.test(e.accountBody.innerHTML) && /UPLINK TEMPORARILY UNAVAILABLE/.test(e.acctSummaryStatus.textContent));
} catch (err) { results.push(false); }
try {
  const e = runAccount({ uid: 'abc', isAnonymous: false, email: 'courier@six.test', displayName: 'Six' }, true, true);
  results.push(/OPERATOR VERIFIED/.test(e.accountBody.innerHTML) && /CLOUD ARCHIVES \+ CIPHER-KEY SYNC AVAILABLE/.test(e.accountBody.innerHTML) && /signOutAccount/.test(e.accountBody.innerHTML) && /Six/.test(e.accountBody.innerHTML) && /courier@six\.test/.test(e.accountBody.innerHTML) && /UPLINK ACTIVE/.test(e.acctSummaryStatus.textContent) && e.acctSummaryStatus.textContent.includes('Six · courier@six.test') && !/&middot;/.test(e.acctSummaryStatus.textContent));
} catch (err) { results.push(false); }
try {
  const e = runAccount({ uid: 'abc', isAnonymous: false, email: 'courier@six.test', displayName: 'Six' }, true, false);
  results.push(/OPERATOR VERIFIED/.test(e.accountBody.innerHTML) && /CLOUD ARCHIVE SYNC OFFLINE \(NO CARRIER\)/.test(e.accountBody.innerHTML) && /signOutAccount/.test(e.accountBody.innerHTML) && /CLOUD UNREACHABLE/.test(e.acctSummaryStatus.textContent));
} catch (err) { results.push(false); }
console.log('RESULT:' + results.map(r => r ? '1' : '0').join(''));
"@
        # Write to a temp file rather than piping through stdin (Protocol 42 fix --
        # see the Suite 135 precedent above).
        $tmpScript177 = [System.IO.Path]::GetTempFileName() + '.js'
        [System.IO.File]::WriteAllText($tmpScript177, $testScript177, [System.Text.Encoding]::UTF8)
        try {
            $out177 = (node $tmpScript177 2>&1 | Out-String)
        } finally {
            Remove-Item -Path $tmpScript177 -Force -ErrorAction SilentlyContinue
        }
        $rm177 = [regex]::Match($out177, 'RESULT:([01]{4})')
        if ($rm177.Success) {
            $bits177 = $rm177.Groups[1].Value
            for ($bi = 0; $bi -lt 4; $bi++) { Check ($bits177.Substring($bi, 1) -eq '1') "177.$(4+$bi): [behavioral] $($labels177[$bi])" }
        } else {
            $err177 = if ([string]::IsNullOrWhiteSpace($out177)) { "No output from node" } else { $out177.Trim() }
            foreach ($lbl in $labels177) { Fail "$lbl  (runtime error: $err177)" }
        }
    } else {
        foreach ($lbl in $labels177) { Fail "$lbl  (node not available in PATH)" }
    }
} catch {
    foreach ($lbl in $labels177) { Fail "$lbl  (exception: $($_.Exception.Message))" }
}

# 177.8  live-update trigger points: boot (loadUI) + sign-in/out/collision (cloud.js,
#        3 sites) + connectivity (refreshOverseerCarrier, asserted at 177.3)
$cloud177 = Read-Src "js/cloud.js"
$loadUIBody177 = Get-FunctionBody $core177 "loadUI"
$renderAcctCount177 = ([regex]::Matches($cloud177, [regex]::Escape('window.renderAccount();'))).Count
Check (
    ($loadUIBody177 -match 'renderAccount\(\);') -and ($renderAcctCount177 -ge 3)
) "177.8: renderAccount() is called from loadUI() (boot) and at least 3 sites in cloud.js (sign-in/out/collision)"

# 177.9  the account-word layer writes nothing durable to the campaign
Check (
    -not ($acctBody177 -match 'saveState\(|robco_v8|state\.\w+\s*=')
) "177.9: renderAccount() never writes campaign state (saveState/robco_v8/state.<field>=)"

# ===========================================================
# Suite 178 -- Step 2 v2.8.0 SU-3: CAMPAIGN CONFIGS modernized (P-DECK +
# RANDOMIZER INTERLOCK * PURGE)
# The #campaignConfigPanel config controls (GAME/PLAYSTYLE/PLAYTHROUGH TYPE/
# COMPLETE RNG/WIPE TERMINAL) are reskinned into the two-board Module-Bay
# hardware language -- RESKIN ONLY (Protocol 22/25): every control keeps its
# exact id/onchange/onclick, reachable both via the hidden real control (the
# Immersion Dial technique, Protocol 17) and the new visible cartridge/
# rocker/detent/breaker widgets, which drive the SAME setters. New in this
# unit: a confirm gate in front of a game-cartridge swap (owner decision).
# 15 tests (PS mirror of JS Suite 178.)
# ===========================================================
Sep "Suite 178 -- SU-3: CAMPAIGN CONFIGS modernized (P-DECK + INTERLOCK)"
$html178 = Read-Src "index.html"
$core178 = Read-Src "js/ui-core.js"
$css178 = Read-Src "css/terminal.css"
$cfgStart178 = $html178.IndexOf('id="campaignConfigPanel"')
$cfgEnd178 = $html178.IndexOf('<div class="col-right">', $cfgStart178)
$configBlock178 = $html178.Substring($cfgStart178, $cfgEnd178 - $cfgStart178)

# 178.1  both boards exist, nested inside #campaignConfigPanel with their own
#        data-sub-id persistence (Protocol UI-2) and collapsed-summary status lines
Check (
    ($configBlock178 -match 'data-sub-id="settings_campaign_profile"') -and
    ($configBlock178 -match 'data-sub-id="settings_campaign_interlock"') -and
    ($configBlock178 -match 'id="sum-profile"') -and
    ($configBlock178 -match 'id="sum-ilk"') -and
    ($configBlock178 -match 'class="sub-panel bay-board dangerboard"')
) "178.1: CAMPAIGN PROFILE and RANDOMIZER INTERLOCK * PURGE are both sub-panel boards (data-sub-id persistence) with one-line collapsed summary status"

# 178.2  every real control keeps its exact id + is visually hidden via the
#        SAME .bay-visually-hidden-input technique already shipped for
#        #immersionSelect (Protocol 17/22) -- never removed, never renamed
$hiddenIds178 = @('gameContextSelect', 'playstyleInput', 'playthroughTypeSelect', 'completeRngToggle')
$hiddenOk178 = $true
foreach ($id178 in $hiddenIds178) {
    if (-not [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'id="' + $id178 + '"[^>]*class="bay-visually-hidden-input"')) {
        $hiddenOk178 = $false
    }
}
Check ($hiddenOk178) "178.2: #gameContextSelect/#playstyleInput/#playthroughTypeSelect/#completeRngToggle all keep their exact ids and are visually hidden via .bay-visually-hidden-input"

# 178.3  the hidden real controls route through the new wrapper functions --
#        which themselves delegate to the UNCHANGED onGameContextChange/
#        changePlaystyle/onPlaythroughTypeChange/onCampaignModeChange
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'id="gameContextSelect"[^>]*onchange="_confirmGameContextChange\(this\.value\)"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'id="playstyleInput"[^>]*onchange="_setDoctrine\(this\.value\)"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'id="playthroughTypeSelect"[^>]*onchange="_setTempo\(this\.value\)"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'id="completeRngToggle"[^>]*onchange="onCampaignModeChange\(this\.checked\)"')
) "178.3: the hidden real controls route through _confirmGameContextChange/_setDoctrine/_setTempo (new wrappers) and the unchanged onCampaignModeChange"

# 178.4  the new wrapper functions delegate to the EXACT pre-existing setters
#        (Protocol 22 -- one truth, two entry points, no forked persistence path)
$setDoctrineBody178 = Get-FunctionBody $core178 "_setDoctrine"
$setTempoBody178 = Get-FunctionBody $core178 "_setTempo"
$seatCartBody178 = Get-FunctionBody $core178 "_seatGameCartridge"
Check (
    ($setDoctrineBody178 -match 'changePlaystyle\(style\)') -and
    ($setTempoBody178 -match 'onPlaythroughTypeChange\(type\)') -and
    ($seatCartBody178 -match '_confirmGameContextChange\(ctx\)')
) "178.4: _setDoctrine()/_setTempo()/_seatGameCartridge() delegate to the unchanged changePlaystyle()/onPlaythroughTypeChange()/_confirmGameContextChange() -- no forked setter logic"

# 178.5  PROGRAM CARTRIDGE deck: a real radiogroup container, populated at
#        render time by renderCartDeck() (Suite 179 owns the deep generation +
#        stacking checks -- the stack restyle moved the cartridge buttons from
#        static markup to a data-driven render, Protocol 38).
Check (
    ($html178 -match 'id="cartDeck"[^>]*role="radiogroup"') -and
    (-not ($html178 -match 'id="cart-fnv"'))
) "178.5: #cartDeck is a real radiogroup container, populated by renderCartDeck() rather than hand-authored static buttons"

# 178.6  ENGAGEMENT DOCTRINE rocker: 2-position, wired to _setDoctrine with the
#        exact any/melee values #playstyleInput used
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, "id=`"rk-any`"[^>]*onclick=`"_setDoctrine\('any'\)`"") -and
    [System.Text.RegularExpressions.Regex]::IsMatch($html178, "id=`"rk-melee`"[^>]*onclick=`"_setDoctrine\('melee'\)`"") -and
    ($html178 -match 'class="rocker" role="radiogroup"')
) "178.6: the ENGAGEMENT DOCTRINE rocker has 2 buttons (#rk-any/#rk-melee) wired to _setDoctrine('any'/'melee') inside a role=radiogroup"

# 178.7  OPERATIONAL TEMPO: 5 direct-pick detents (1 tap per pick, no cycling),
#        wired to _setTempo with the exact 5 values #playthroughTypeSelect used.
#        SU-3 rotary-dial rework (see Suite 180): .detent renamed .detent2 --
#        [\s\S]*? spans Prettier's multi-line attribute wrapping.
$tempoValues178 = @('standard', 'minmaxed', 'completionist', 'casual', 'speedrun')
$tempoOk178 = $true
foreach ($tv178 in $tempoValues178) {
    if (-not [System.Text.RegularExpressions.Regex]::IsMatch($html178, 'data-tempo="' + $tv178 + '"[\s\S]*?onclick="_setTempo\(''' + $tv178 + '''\)"')) {
        $tempoOk178 = $false
    }
}
$detentCount178 = ([System.Text.RegularExpressions.Regex]::Matches($html178, 'class="detent2(?: on)?"')).Count
Check ($tempoOk178 -and ($detentCount178 -eq 5)) "178.7: exactly 5 direct-pick detent buttons exist, one per playthroughType value (standard/minmaxed/completionist/casual/speedrun), each wired to _setTempo(value)"

# 178.8  RANDOMIZER INTERLOCK breaker: well/cover/seal/handle all present, wired
#        to _interlockLiftCover/_interlockThrowBreaker; the seal is CSS-gated on
#        data-rng="locked" (never a separate JS-toggled class)
Check (
    ($configBlock178 -match 'id="ilkWell"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($configBlock178, 'id="ilkCover"[^>]*onclick="_interlockLiftCover\(event\)"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($configBlock178, 'class="ilk-breaker"[^>]*onclick="_interlockThrowBreaker\(\)"') -and
    ($configBlock178 -match 'class="ilk-seal"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($css178, "\.interlock\[data-rng='locked'\] \.ilk-seal\s*\{")
) "178.8: the interlock well/cover/breaker/seal all exist, wired to _interlockLiftCover()/_interlockThrowBreaker(), with the seal CSS-gated on data-rng=locked"

# 178.9  #rngModeBanner/#rngLockedBanner keep their exact ids (only the
#        presentation moved from inline styles to .rng-banner classes)
$onCampaignModeBody178 = Get-FunctionBody $core178 "onCampaignModeChange"
Check (
    ($configBlock178 -match 'id="rngModeBanner" class="rng-banner armed"') -and
    ($configBlock178 -match 'id="rngLockedBanner" class="rng-banner locked"') -and
    ($onCampaignModeBody178 -match "rngModeBanner'\)")
) "178.9: #rngModeBanner/#rngLockedBanner keep their exact ids (reskinned via .rng-banner classes, not inline styles) -- onCampaignModeChange() still targets #rngModeBanner unchanged"

# 178.10  #wipeTerminalBtn keeps its exact id + onclick -- the danger-zone
#         double-confirm gate (wipeTerminal()) is completely untouched
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($configBlock178, '(?s)id="wipeTerminalBtn".*?class="purge-btn".*?onclick="wipeTerminal\(\)"')
) "178.10: #wipeTerminalBtn keeps its exact id + onclick=wipeTerminal() -- only reskinned to .purge-btn"

# 178.11  _syncCampaignProfileUI()/_syncInterlockUI() are wired into both the
#         boot-time restore block and loadUI()
$loadUIBody178 = Get-FunctionBody $core178 "loadUI"
$restoreDevicePrefsBody178 = Get-FunctionBody $core178 "_restoreDevicePrefs"
Check (
    ($loadUIBody178 -match '_syncCampaignProfileUI\(\)') -and
    ($loadUIBody178 -match '_syncInterlockUI\(\)') -and
    ($restoreDevicePrefsBody178 -match '_syncCampaignProfileUI\(\)') -and
    ($restoreDevicePrefsBody178 -match '_syncInterlockUI\(\)')
) "178.11: _syncCampaignProfileUI()/_syncInterlockUI() are called from both _restoreDevicePrefs() (boot) and loadUI()"

# 178.12  _confirmGameContextChange(): structural proof it's an async gate that
#         only calls the real onGameContextChange() AFTER an awaited
#         confirmAction() resolves truthy, and explicitly reverts the hidden
#         select + re-syncs the profile UI on a falsy (cancel) result.
$confirmSwapBody178 = Get-FunctionBody $core178 "_confirmGameContextChange"
$okBranchIdx178 = $confirmSwapBody178.IndexOf('if (!ok)')
$cancelBranch178 = if ($okBranchIdx178 -ge 0) {
    $ogccIdx178 = $confirmSwapBody178.IndexOf('onGameContextChange(ctx)')
    $confirmSwapBody178.Substring($okBranchIdx178, [Math]::Max(0, $ogccIdx178 - $okBranchIdx178))
} else { '' }
Check (
    ($core178 -match 'async function _confirmGameContextChange') -and
    ($confirmSwapBody178 -match 'await confirmAction\(\{') -and
    ($okBranchIdx178 -ge 0) -and
    ($cancelBranch178 -match 'sel\.value = current') -and
    ($cancelBranch178 -match '_syncCampaignProfileUI\(\)') -and
    ($cancelBranch178 -match 'return;') -and
    ($confirmSwapBody178 -match 'onGameContextChange\(ctx\);')
) "178.12: _confirmGameContextChange() is async, awaits confirmAction(), and on cancel (!ok) reverts the hidden select to the current game + re-syncs the profile UI + returns BEFORE reaching onGameContextChange(ctx) -- a cancelled swap never reloads"

# 178.13  the new custom-control layer writes nothing durable to the campaign
#         beyond the exact pre-existing setters it delegates to
$wrapperFns178 = @('_seatGameCartridge', '_setDoctrine', '_setTempo', '_interlockLiftCover', '_interlockThrowBreaker', '_syncCampaignProfileUI', '_syncInterlockUI')
$offenders178 = $wrapperFns178 | Where-Object {
    try { $body = Get-FunctionBody $core178 $_ } catch { return $true }
    # Protocol 42 fix (found while writing the JS mirror): exclude ==/=== reads
    # (e.g. state.campaignMode === 'rng-locked') from the assignment check.
    return ($body -match 'saveState\(|robco_v8|state\.\w+\s*=(?!=)')
}
Check (
    $offenders178.Count -eq 0
) ("178.13: the new cartridge/rocker/detent/breaker wrapper + sync functions never write campaign state directly (saveState/robco_v8/state.<field>=)" + $(if ($offenders178.Count) { " -- offenders: $($offenders178 -join ', ')" } else { "" }))

# 178.14  game-agnostic construction (Protocol 38): the tempo detent
#         labels/descriptions and doctrine rocker carry no game literal
$tempoRockerStart178 = $configBlock178.IndexOf('rack-note" style="margin-top: 14px">ENGAGEMENT')
$detentRackIdx178 = $configBlock178.IndexOf('dial-hint')
$detailsEndIdx178 = $configBlock178.IndexOf('</details>', $detentRackIdx178)
$tempoAndRockerSlice178 = if ($tempoRockerStart178 -ge 0 -and $detailsEndIdx178 -gt $tempoRockerStart178) {
    $configBlock178.Substring($tempoRockerStart178, $detailsEndIdx178 - $tempoRockerStart178)
} else { '' }
Check (
    -not [System.Text.RegularExpressions.Regex]::IsMatch($tempoAndRockerSlice178, '\bFNV\b|\bFO3\b|Capital Wasteland|Vault 101', 'IgnoreCase')
) "178.14: the doctrine rocker and tempo detent rack are game-agnostic -- no FNV/FO3/location literals (the GAME cartridge itself is exempt -- it IS the per-game picker)"

# 178.15  Protocol 42 fix (found live during render-verify): #completeRngToggle
#         is a real, keyboard/AT-reachable control (.bay-visually-hidden-input)
#         -- toggling it DIRECTLY (never touching the fancy breaker button) must
#         still repaint the whole interlock board. onCampaignModeChange() now
#         calls _syncInterlockUI() itself so BOTH entry points stay in sync.
$onCampaignModeBody178 = Get-FunctionBody $core178 "onCampaignModeChange"
Check (
    $onCampaignModeBody178 -match '_syncInterlockUI\(\)'
) "178.15: onCampaignModeChange() calls _syncInterlockUI() -- a direct toggle of the hidden #completeRngToggle repaints the whole interlock board, not just the armed banner"

# ══════════════════════════════════════════════════════════════
# Suite 179 -- Owner-requested restyle: PROGRAM CARTRIDGE stack (physical pile)
# The cartridges no longer render side-by-side -- the active game's cartridge
# sits on top (full legibility), every other seatable game piles beneath it
# with only a >=28px edge peeking out (tappable, no pointer-events trick).
# Generated by renderCartDeck() from GAME_DEFS (Protocol 38 -- a future
# seatable game needs only a new GAME_DEFS entry, never a markup rewrite),
# reusing the EXACT pre-existing _seatGameCartridge(ctx) confirm-gated swap
# (Protocol 22) -- visual/layout only, no behavior change.
# Owner-reported urgent addition: the whole Campaign Configs section (both
# boards) rendered near-illegible -- dim/dark text on a near-black
# background. Root cause: the global `button { color: var(--robco-dark) }`
# reset (meant for a solid bright-background button) leaked into every
# custom board control that overrides `background` away from that bright
# default (.cart, .rocker button, .detent, .ilk-breaker) without ever
# resetting `color` back to the legible phosphor tone -- so their text
# inherited a near-black color meant to sit on a bright background, not the
# dark one these controls actually have. Each now explicitly resets `color`
# to the same `--robco-green` phosphor tone the rest of the panel already
# reads correctly in (matching the approved mockup's legible palette).
# Follow-up owner report: the ARMED "DISARM -- RETURN TO SAFE" button (and,
# diligence-checked, WIPE TERMINAL + the safety-cover label) -- .ilk-actions
# button explicitly overrode the label to a FIXED amber (var(--robco-alert))
# while its background stayed the THEME-DEPENDENT var(--robco-green) inherited
# from the base button rule (bright green by default, but whatever hue the
# active optics theme resolves it to -- e.g. bright red under LEGION RED). A
# fixed amber label doesn't adapt per theme, so it read as low-contrast
# red-on-red under a warm-toned optic, exactly matching the owner's report.
# Removing the override lets the label fall back to var(--robco-dark) -- the
# SAME theme-matched dark partner the base button rule already reuses
# everywhere else (Protocol 22), verified by real WCAG contrast math below.
# 18 tests
# ══════════════════════════════════════════════════════════════
Sep "Suite 179 -- Owner-requested restyle: PROGRAM CARTRIDGE stack (physical pile)"
$html179 = Read-Src "index.html"
$core179 = Read-Src "js/ui-core.js"
$state179 = Read-Src "js/state.js"
$css179 = Read-Src "css/terminal.css"

# 179.1  every GAME_DEFS entry (FNV/FO3/FO4) declares theme.cartridgeTape --
#        the data seam renderCartDeck() reads instead of a hardcoded per-game
#        tape-name literal (Protocol 38).
$cart179AllGames = @('FNV', 'FO3', 'FO4') | ForEach-Object {
    $g = $_
    $themeMatch = [regex]::Match($state179, "(?s)$g`:.*?theme:\s*\{(.*?)\}")
    $themeMatch.Success -and ($themeMatch.Groups[1].Value -match "cartridgeTape:\s*'[^']+'")
}
Check (
    ($cart179AllGames | Where-Object { -not $_ }).Count -eq 0
) "179.1: GAME_DEFS.FNV/FO3/FO4 each declare a non-empty theme.cartridgeTape (the cartridge stack subtitle data seam)"

# 179.2  _seatableGames() filters out design-only entries -- the same guard
#        onGameContextChange() already uses, not re-derived differently.
$seatableBody179 = Get-FunctionBody $core179 '_seatableGames'
Check (
    $seatableBody179 -match 'Object\.keys\(GAME_DEFS\)\.filter\(k => !GAME_DEFS\[k\]\.designOnly\)'
) "179.2: _seatableGames() derives the stack from Object.keys(GAME_DEFS) filtered on !designOnly -- no hardcoded FNV/FO3 array"

# 179.3  renderCartDeck(): the active game sorts first (stack-index 0), the
#        stack depth is stamped as a CSS custom property, and the whole
#        button list is built via ONE map().join('') assignment -- never
#        innerHTML += inside a loop (Prohibited Patterns table).
$renderBody179 = Get-FunctionBody $core179 'renderCartDeck'
Check (
    ($renderBody179 -match [regex]::Escape('const ordered = games.includes(ctx) ? [ctx, ...games.filter(g => g !== ctx)] : games;')) -and
    ($renderBody179 -match [regex]::Escape("deck.style.setProperty('--cart-stack-depth', String(ordered.length))")) -and
    ($renderBody179 -match '(?s)deck\.innerHTML = ordered\s*\.map\(') -and
    (-not ($renderBody179 -match '\+='))
) "179.3: renderCartDeck() sorts the active game first, stamps --cart-stack-depth, and assigns deck.innerHTML exactly once via map().join() (no innerHTML += in a loop)"

# 179.4  every generated cartridge button carries a --stack-index custom
#        property, keeps the UNCHANGED _seatGameCartridge(ctx) onclick wiring
#        (Protocol 22 -- tapping a peeking cartridge still swaps games), real
#        radio ARIA, and escapes the game label/tape text (XSS safety).
Check (
    ($renderBody179 -match [regex]::Escape('style="--stack-index:${i}"')) -and
    ($renderBody179 -match [regex]::Escape('onclick="_seatGameCartridge(''${escapeHtml(g)}'')"')) -and
    ($renderBody179 -match 'role="radio"') -and
    ($renderBody179 -match [regex]::Escape('aria-checked="${seated}"')) -and
    ($renderBody179 -match [regex]::Escape('escapeHtml(label.toUpperCase())')) -and
    ($renderBody179 -match [regex]::Escape('escapeHtml(sub)'))
) "179.4: renderCartDeck() stamps --stack-index per button, keeps the unchanged _seatGameCartridge(ctx) onclick + role=radio/aria-checked, and escapes the rendered label/tape text"

# 179.5  _syncCampaignProfileUI() calls renderCartDeck() as its ONE cartridge
#        repaint step -- the old two-hardcoded-id (#cart-fnv/#cart-fo3) toggle
#        logic is gone from this function (regression guard against it
#        reappearing now that generation lives in renderCartDeck()).
$syncBody179 = Get-FunctionBody $core179 '_syncCampaignProfileUI'
Check (
    ($syncBody179 -match 'renderCartDeck\(\);') -and
    (-not ($syncBody179 -match "getElementById\('cart-fnv'\)")) -and
    (-not ($syncBody179 -match "getElementById\('cart-fo3'\)"))
) "179.5: _syncCampaignProfileUI() repaints the cartridges via renderCartDeck() only -- no leftover hand-toggling of #cart-fnv/#cart-fo3 by literal id"

# 179.6  index.html: #cartDeck starts empty -- a regression guard against a
#        static+dynamic split drifting back in (the stack is ALWAYS fully
#        generated by renderCartDeck(), never partially hand-authored).
Check (
    $html179 -match '<div\s+class="cart-deck"\s+id="cartDeck"\s+role="radiogroup"\s+aria-label="Program cartridge"\s*></div>'
) "179.6: #cartDeck is an empty container in index.html -- the cartridge stack is entirely generated by renderCartDeck(), never partially hand-authored"

# 179.7  CSS: .cart-deck stacks its children in ONE grid cell and reserves
#        exactly enough room (via --cart-stack-depth) for however many
#        cartridges are piled beneath the top one.
Check (
    ($css179 -match '(?s)\.cart-deck\s*\{[^}]*display:\s*grid[^}]*\}') -and
    ($css179 -match 'padding-bottom:\s*calc\(\(var\(--cart-stack-depth,\s*2\)\s*-\s*1\)\s*\*\s*30px\)') -and
    ($css179 -match 'padding-right:\s*calc\(\(var\(--cart-stack-depth,\s*2\)\s*-\s*1\)\s*\*\s*30px\)')
) "179.7: .cart-deck is a display:grid stacking container whose padding-bottom/padding-right reserve scales with --cart-stack-depth (not hardcoded to exactly 2 cartridges)"

# 179.8  CSS: .cart shares the same grid cell (grid-area: 1 / 1) and its
#        depth-driven transform/z-index are both keyed off --stack-index --
#        the actual pile mechanic (0 = on top, no offset; 1+ = behind + offset).
Check (
    ($css179 -match 'grid-area:\s*1\s*/\s*1') -and
    ($css179 -match 'transform:\s*translate\(\s*calc\(var\(--stack-index,\s*0\)\s*\*\s*30px\)') -and
    ($css179 -match 'z-index:\s*calc\(50\s*-\s*var\(--stack-index,\s*0\)\)')
) "179.8: .cart uses grid-area: 1 / 1 (genuine overlap, not a side-by-side row) with --stack-index driving both the diagonal peek transform and the z-index"

# 179.9  Protocol 17: the peeking sliver a background cartridge exposes is
#        >=28px thick in both axes (the per-layer offset literal, 30px,
#        clears the tap-target floor) -- regression guard against shrinking
#        it below the accessible minimum for a tighter-looking pile.
$offsetMatch179 = [regex]::Match($css179, 'transform:\s*translate\(\s*calc\(var\(--stack-index,\s*0\)\s*\*\s*(\d+)px\)')
$offsetPx179 = if ($offsetMatch179.Success) { [int]$offsetMatch179.Groups[1].Value } else { 0 }
Check (
    $offsetPx179 -ge 28
) "179.9: the per-stack-layer peek offset (${offsetPx179}px) is >=28px on both axes -- Protocol 17's tap-target floor, applied to the exposed sliver itself"

# 179.10  the hover/focus "lift toward front" preview reuses .cart's own
#         transition (no bespoke @keyframes for this feature), so the
#         existing global prefers-reduced-motion block neutralises the
#         shuffle with no carve-out (Protocol UI-9 convention).
$cartRuleMatch179 = [regex]::Match($css179, '(?s)\.cart\s*\{.*?\n\}')
$cartRule179 = if ($cartRuleMatch179.Success) { $cartRuleMatch179.Value } else { '' }
$hoverRuleMatch179 = [regex]::Match($css179, "(?s)\.cart:not\(\.seated\):hover,\s*\n\.cart:not\(\.seated\):focus-visible\s*\{(.*?)\}")
$hoverRule179 = if ($hoverRuleMatch179.Success) { $hoverRuleMatch179.Groups[1].Value } else { '' }
Check (
    ($cartRule179 -match 'transition:\s*transform [\d.]+s,') -and
    (-not ($cartRule179 -match 'animation:')) -and
    $hoverRuleMatch179.Success -and
    (-not ($hoverRule179 -match 'transition|animation'))
) "179.10: the peeking-cartridge hover/focus lift is a plain transform change riding .cart's own existing transition (no separate @keyframes/animation or bespoke transition-duration) -- reduced-motion neutralises it automatically"

# 179.11  writes nothing durable -- renderCartDeck()/_seatableGames() only
#         read GAME_DEFS/state.gameContext and touch the DOM; no
#         saveState()/robco_v8/state.<field>= anywhere in either function.
Check (
    (-not ($renderBody179 -match 'saveState\(|robco_v8|state\.\w+\s*=(?!=)')) -and
    (-not ($seatableBody179 -match 'saveState\(|robco_v8|state\.\w+\s*=(?!=)'))
) "179.11: renderCartDeck()/_seatableGames() write nothing durable to the campaign (read-only DOM/GAME_DEFS render helpers)"

# 179.12  Owner-reported urgent legibility fix: .cart explicitly resets
#         color to the legible phosphor tone -- never left to inherit the
#         global button rule's dark-on-bright text color.
Check (
    $cartRule179 -match 'color:\s*var\(--robco-green\)'
) "179.12: .cart explicitly sets color: var(--robco-green) -- never inherits the global button dark-on-bright text color"

# 179.13  ENGAGEMENT DOCTRINE rocker (.rocker button) and OPERATIONAL TEMPO
#         detents (.detent2 -- renamed from .detent by the SU-3 rotary-dial
#         rework, Suite 180) -- same legibility fix, same reason.
Check (
    ($css179 -match '(?s)\.rocker button\s*\{[^}]*color:\s*var\(--robco-green\)') -and
    ($css179 -match '(?s)\.detent2\s*\{[^}]*color:\s*var\(--robco-green\)')
) "179.13: .rocker button and .detent2 both explicitly reset color to var(--robco-green) (the global button dark-text reset no longer leaks into either control)"

# 179.14  RANDOMIZER INTERLOCK * PURGE board's breaker (.ilk-breaker) gets
#         the same fix -- the board's danger-red/amber ACCENTS (border,
#         hazard stripes, the WIPE TERMINAL button, the safety-cover text)
#         are untouched; only the previously-illegible body text is fixed.
Check (
    ($css179 -match '(?s)\.ilk-breaker\s*\{[^}]*color:\s*var\(--robco-green\)') -and
    ($css179 -match '(?s)\.ilk-cover\s*\{.*?color:\s*var\(--robco-alert\)') -and
    ($css179 -match '(?s)\.purge-btn\s*\{[^}]*color:\s*var\(--robco-danger\)')
) "179.14: .ilk-breaker resets its body text to var(--robco-green) (the same leaked dark-button-text bug), while .ilk-cover (amber) and .purge-btn (red) keep their own already-correct accent colors untouched"

# 179.15  the global button reset itself (color: var(--robco-dark)) is left
#         completely unchanged -- this fix resets CALLERS that override
#         background away from the bright default, not the shared base rule
#         every normal solid-background action button still relies on.
$buttonRuleMatch179 = [regex]::Match($css179, '(?:^|\n)button\s*\{([\s\S]*?)\n\}')
$buttonRule179 = if ($buttonRuleMatch179.Success) { $buttonRuleMatch179.Groups[1].Value } else { '' }
Check (
    ($buttonRule179 -match 'color:\s*var\(--robco-dark\)') -and
    ($buttonRule179 -match 'background:\s*var\(--robco-green\)')
) "179.15: the global button { background: var(--robco-green); color: var(--robco-dark) } reset is untouched -- only the custom board controls that override background away from it also now reset color"

# 179.16  Owner follow-up: .ilk-actions button (the ARMED "DISARM" button) no
#         longer overrides color/text-shadow with a fixed amber -- it falls
#         back to the base button rule's theme-matched var(--robco-dark),
#         the same pairing that already works everywhere else.
$ilkActionsRuleMatch179 = [regex]::Match($css179, '\.ilk-actions button\s*\{([\s\S]*?)\n\}')
$ilkActionsRule179 = if ($ilkActionsRuleMatch179.Success) { $ilkActionsRuleMatch179.Groups[1].Value } else { '' }
Check (
    ($ilkActionsRule179 -match 'border-color:\s*var\(--robco-alert\)') -and
    (-not ($ilkActionsRule179 -match '(?:^|\n)\s*color:\s*var\(--robco-alert\)')) -and
    (-not ($ilkActionsRule179 -match 'text-shadow'))
) "179.16: .ilk-actions button keeps its amber border accent but no longer overrides color/text-shadow -- falls back to the base button rule's theme-matched var(--robco-dark) label instead of a fixed amber that clashed under a warm-toned optic"

# 179.17  .ilk-actions button:hover no longer replaces the button's solid fill
#         with a near-transparent amber tint (which, combined with the
#         no-longer-amber label, would have created a NEW dark-on-near-black
#         contrast bug on hover) -- it falls back to the global
#         button:hover { filter: brightness(1.35) } every ordinary button uses.
Check (
    -not ($css179 -match '\.ilk-actions button:hover')
) "179.17: .ilk-actions button:hover no longer overrides background -- falls back to the global button:hover brightness-filter behavior (avoids reintroducing a hover-state contrast bug)"

# 179.18  real WCAG 2.x contrast math: the var(--robco-green)/var(--robco-dark)
#         pairing .ilk-actions button now relies on (via the base button rule)
#         clears AA (>=4.5:1) for every contrastSafe:true THEMES entry -- not
#         just asserted by convention, actually computed.
function Get-Luminance179($hexColor) {
    $m = $hexColor.Replace('#', '')
    $chan = {
        param($i)
        $c = [Convert]::ToInt32($m.Substring($i, 2), 16) / 255.0
        if ($c -le 0.03928) { return $c / 12.92 }
        return [Math]::Pow((($c + 0.055) / 1.055), 2.4)
    }
    return 0.2126 * (& $chan 0) + 0.7152 * (& $chan 2) + 0.0722 * (& $chan 4)
}
function Get-Contrast179($h1, $h2) {
    $a = Get-Luminance179 $h1
    $b = Get-Luminance179 $h2
    return ([Math]::Max($a, $b) + 0.05) / ([Math]::Min($a, $b) + 0.05)
}
$themesBlock179 = [regex]::Match($state179, '(?s)const THEMES = \{(.*?)\n\};').Groups[1].Value
$themeMatches179 = [regex]::Matches(
    $themesBlock179,
    "(?s)(\w+):\s*\{\s*rgb:\s*'([^']+)',\s*hex:\s*'(#[0-9a-fA-F]{6})',\s*dark:\s*'(#[0-9a-fA-F]{6})',\s*label:\s*'[^']+',\s*contrastSafe:\s*(true|false),?\s*(?:family:\s*'\w+',?\s*)?\}"
)
$themeEntries179 = $themeMatches179 | ForEach-Object {
    [PSCustomObject]@{
        Key  = $_.Groups[1].Value
        Hex  = $_.Groups[3].Value
        Dark = $_.Groups[4].Value
        Safe = $_.Groups[5].Value -eq 'true'
    }
}
$safeThemes179 = $themeEntries179 | Where-Object { $_.Safe }
$failing179 = $safeThemes179 | Where-Object { (Get-Contrast179 $_.Hex $_.Dark) -lt 4.5 }
Check (
    $themeEntries179.Count -ge 7 -and $safeThemes179.Count -ge 4 -and $failing179.Count -eq 0
) "179.18: every contrastSafe:true THEMES entry's hex/dark pairing clears real WCAG AA (>=4.5:1) -- the exact pairing .ilk-actions button (DISARM) now relies on via the base button rule"

# ===========================================================
# Suite 180 -- OPERATIONAL TEMPO centered rotary dial (SU-3 rework)
# Owner-approved mockup: planning/mockups/tempo-dial.html. Replaces the
# decorative-dial-plus-vertical-list from Suite 178/179 with a true rotary
# dial: the 5 playthroughType positions ring the knob on a gauge arc and the
# needle (the knob's own rotation) always points at the active one. Owner
# directive: the knob performs NO action on tap -- only a drag, a direct
# position tap, or the arrow keys change #playthroughTypeSelect.
# 13 tests (PS mirror of JS Suite 180.)
# ===========================================================
Sep "Suite 180 -- OPERATIONAL TEMPO centered rotary dial (SU-3 rework)"
$html180 = Read-Src "index.html"
$core180 = Read-Src "js/ui-core.js"
$css180 = Read-Src "css/terminal.css"
$cfgStart180 = $html180.IndexOf('id="campaignConfigPanel"')
$cfgEnd180 = $html180.IndexOf('<div class="col-right">', $cfgStart180)
$configBlock180 = $html180.Substring($cfgStart180, $cfgEnd180 - $cfgStart180)

# 180.1  the dial assembly: a tick-ring, 5 ticks on the exact gauge-arc
#        angles (-84...+84 deg, 42 apart, 0 = up), and the knob itself is a
#        real role=slider control spanning the 5 positions.
$tickAngles180 = @('-84deg', '-42deg', '0deg', '42deg', '84deg')
$ticksOk180 = ($tickAngles180 | Where-Object {
    -not [System.Text.RegularExpressions.Regex]::IsMatch($configBlock180, 'class="tempo-tick[^"]*"[\s\S]*?--a:\s*' + $_)
}).Count -eq 0
Check (
    ($configBlock180 -match 'id="tempoDialAssembly"') -and
    ($configBlock180 -match 'class="tick-ring"') -and
    $ticksOk180 -and
    [System.Text.RegularExpressions.Regex]::IsMatch($configBlock180, 'id="tempoKnob"[\s\S]*?role="slider"[\s\S]*?aria-valuemin="0"[\s\S]*?aria-valuemax="4"')
) "180.1: #tempoDialAssembly has a tick-ring + 5 ticks at the exact -84/-42/0/42/84 deg gauge-arc angles, and #tempoKnob is a real role=slider spanning 0..4"

# 180.2  5 direct-pick .detent2 position buttons ring the knob, each wired to
#        _setTempo with the exact playthroughType value, each carrying a
#        data-i index matching its tick (never orphaned from the arc).
$tempos180 = @(
    @{v = 'standard'; i = 0 }, @{v = 'minmaxed'; i = 1 }, @{v = 'completionist'; i = 2 },
    @{v = 'casual'; i = 3 }, @{v = 'speedrun'; i = 4 }
)
$detentOk180 = ($tempos180 | Where-Object {
    -not [System.Text.RegularExpressions.Regex]::IsMatch(
        $configBlock180,
        'class="detent2[^"]*"[\s\S]*?data-tempo="' + $_.v + '"[\s\S]*?data-i="' + $_.i + '"[\s\S]*?onclick="_setTempo\(''' + $_.v + '''\)"'
    )
}).Count -eq 0
$detent2Count180 = ([System.Text.RegularExpressions.Regex]::Matches($configBlock180, 'class="detent2(?: on)?"')).Count
Check (
    $detentOk180 -and ($detent2Count180 -eq 5)
) "180.2: exactly 5 .detent2 position buttons ring the knob, each wired to _setTempo(value) and carrying the data-i index matching its tick -- one tap per pick, never a cycle"

# 180.3  owner directive: the knob performs NO action on tap -- no onclick
#        attribute in the markup, and no .addEventListener('click', ...)
#        targeting the knob anywhere in ui-core.js.
$knobTagMatch180 = [regex]::Match($configBlock180, '<button[^>]*id="tempoKnob"[^>]*>')
$knobTag180 = if ($knobTagMatch180.Success) { $knobTagMatch180.Value } else { '' }
Check (
    ($knobTag180 -ne '') -and
    (-not ($knobTag180 -match 'onclick=')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($core180, "tempoKnob'\)[\s\S]{0,60}addEventListener\(\s*'click'")) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($core180, "addEventListener\(\s*'click'[\s\S]{0,120}tempoKnob"))
) "180.3: the knob has no onclick attribute and no click listener anywhere -- tapping the knob body does nothing (owner decision), only drag/position-tap/arrow-keys change the value"

# 180.4  _wireTempoDialDrag(): keydown attached unconditionally, pointerdown
#        gated on window.PointerEvent (graceful fallback) -- same shape as
#        the Immersion dial's own _wireImmersionDialDrag(), a parallel
#        pattern rather than a shared/forked implementation.
$wireBody180 = Get-FunctionBody $core180 '_wireTempoDialDrag'
Check (
    ($wireBody180 -match "addEventListener\('keydown', _tempoKeyDown\)") -and
    ($wireBody180 -match "typeof window\.PointerEvent === 'undefined'") -and
    ($wireBody180 -match "addEventListener\('pointerdown', _tempoPointerDown\)")
) "180.4: _wireTempoDialDrag() attaches keydown unconditionally and pointerdown only when window.PointerEvent exists (graceful fallback: tap-position + arrows still work)"

# 180.5  the needle-angle formula: _TEMPO_ROT is derived from the same
#        _TEMPO_ARC_MIN/_TEMPO_ARC_STEP the drag math uses -- the needle
#        always points at one of the 5 real positions, never empty space.
$arcMinMatch180 = [regex]::Match($core180, 'const _TEMPO_ARC_MIN = (-?\d+);')
$arcStepMatch180 = [regex]::Match($core180, 'const _TEMPO_ARC_STEP = (-?\d+);')
$rotMatch180 = [regex]::Match($core180, 'const _TEMPO_ROT = \[([^\]]+)\];')
$arcMin180 = if ($arcMinMatch180.Success) { [int]$arcMinMatch180.Groups[1].Value } else { 0 }
$arcStep180 = if ($arcStepMatch180.Success) { [int]$arcStepMatch180.Groups[1].Value } else { 0 }
$rotValues180 = if ($rotMatch180.Success) { $rotMatch180.Groups[1].Value -split ',' | ForEach-Object { [int]$_.Trim() } } else { @() }
$expected180 = 0..4 | ForEach-Object { $arcMin180 + $arcStep180 * $_ }
$rotMatchesExpected180 = $true
for ($i = 0; $i -lt 5; $i++) {
    if ($expected180[$i] -ne $rotValues180[$i]) { $rotMatchesExpected180 = $false }
}
$syncBody180ForRot = Get-FunctionBody $core180 '_syncCampaignProfileUI'
Check (
    ($rotValues180.Count -eq 5) -and $rotMatchesExpected180 -and
    ($syncBody180ForRot -match "knob\.style\.transform = 'rotate\(' \+ _TEMPO_ROT\[tIdx\] \+ 'deg\)'")
) ("180.5: _TEMPO_ROT === [_TEMPO_ARC_MIN + _TEMPO_ARC_STEP*i for i in 0..4] (" + ($expected180 -join ',') + ") and _syncCampaignProfileUI() rotates the knob to exactly that angle -- the needle always points at the active position")

# 180.6  all three input paths (drag release, direct position tap, arrow
#        keys) converge on the one real setter -- _setTempo(), which itself
#        still delegates to the unchanged onPlaythroughTypeChange().
$pointerUpBody180 = Get-FunctionBody $core180 '_tempoPointerUp'
$keyDownBody180 = Get-FunctionBody $core180 '_tempoKeyDown'
$setTempoBody180 = Get-FunctionBody $core180 '_setTempo'
$keyDownSetTempoCount180 = ([regex]::Matches($keyDownBody180, '_setTempo\(_TEMPO_ORDER\[')).Count
Check (
    ($pointerUpBody180 -match '_setTempo\(_TEMPO_ORDER\[idx\]\)') -and
    ($keyDownSetTempoCount180 -eq 4) -and
    ($setTempoBody180 -match 'onPlaythroughTypeChange\(type\)')
) "180.6: drag-release, arrow-key stepping (all 4 key branches), and the direct .detent2 tap (Suite 180.2) all call _setTempo(), which still delegates to the unchanged onPlaythroughTypeChange()"

# 180.7  _syncCampaignProfileUI() is the one repaint function that keeps the
#        knob/ticks/detents/readout/status line all in sync with
#        state.playthroughType.
$syncBody180 = Get-FunctionBody $core180 '_syncCampaignProfileUI'
Check (
    ($syncBody180 -match 'tempo-tick') -and
    ($syncBody180 -match 'detent2') -and
    ($syncBody180 -match 'aria-valuenow') -and
    ($syncBody180 -match 'aria-valuetext') -and
    ($syncBody180 -match 'tempoReadoutName') -and
    ($syncBody180 -match 'tempoReadoutDesc') -and
    ($syncBody180 -match 'st-tempo')
) "180.7: _syncCampaignProfileUI() repaints the ticks, detents, knob (transform + ARIA), readout (name + description), and status line together -- one function, no partial repaints"

# 180.8  game-agnostic (Protocol 38): the dial markup and every new
#        drag/keyboard function carry no FNV/FO3 literal.
$dragFnNames180 = @('_tempoPointerAngle', '_tempoPointerMove', '_tempoPointerUp', '_tempoPointerCancel', '_tempoPointerDown', '_tempoKeyDown', '_wireTempoDialDrag')
$dragFns180 = ($dragFnNames180 | ForEach-Object { Get-FunctionBody $core180 $_ }) -join "`n"
$tempoSliceStart180 = $configBlock180.IndexOf('rack-note" style="margin-top: 16px">OPERATIONAL')
$tempoSliceDialHint180 = $configBlock180.IndexOf('dial-hint')
$tempoSliceEnd180 = $configBlock180.IndexOf('</details>', $tempoSliceDialHint180)
$tempoSlice180 = if ($tempoSliceStart180 -ge 0 -and $tempoSliceEnd180 -gt $tempoSliceStart180) {
    $configBlock180.Substring($tempoSliceStart180, $tempoSliceEnd180 - $tempoSliceStart180)
} else { '' }
Check (
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($tempoSlice180, '\bFNV\b|\bFO3\b|Capital Wasteland|Vault 101', 'IgnoreCase')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($dragFns180, '\bFNV\b|\bFO3\b', 'IgnoreCase'))
) "180.8: the dial markup and every new drag/keyboard function are game-agnostic -- no FNV/FO3 literal (the 5 tempo names/descriptions are read from the existing shared maps)"

# 180.9  the new drag/keyboard functions write nothing durable to the
#        campaign directly -- only _setTempo()/onPlaythroughTypeChange()
#        (out of this guard's scope, already covered by 178.4/178.13)
#        actually persist a value.
$dragOffenderNames180 = @('_tempoPointerAngle', '_tempoPointerMove', '_tempoPointerCleanup', '_tempoPointerUp', '_tempoPointerCancel', '_tempoPointerDown', '_tempoKeyDown', '_wireTempoDialDrag')
$offenders180 = $dragOffenderNames180 | Where-Object {
    $body = Get-FunctionBody $core180 $_
    return ($body -match 'saveState\(|robco_v8|state\.\w+\s*=(?!=)')
}
Check (
    $offenders180.Count -eq 0
) ("180.9: the new drag/keyboard handler functions never write campaign state directly (saveState/robco_v8/state.<field>=) -- only the unchanged _setTempo()/onPlaythroughTypeChange() persist a value" + $(if ($offenders180.Count) { " -- offenders: $($offenders180 -join ', ')" } else { "" }))

# 180.10  the old decorative-dial-plus-vertical-list widget is fully
#         retired -- no orphaned .tempo-wrap/.tempo-dial/.detent-rack/
#         old-.detent markup or CSS remains.
Check (
    (-not ($html180 -match 'tempo-wrap')) -and
    (-not ($css180 -match 'tempo-wrap')) -and
    (-not ($html180 -match '"tempo-dial"')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($css180, '\.tempo-dial\b')) -and
    (-not ($html180 -match 'detent-rack')) -and
    (-not ($css180 -match 'detent-rack')) -and
    (-not ($html180 -match 'class="detent"')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($css180, '\.detent\s*\{'))
) "180.10: the old .tempo-wrap/.tempo-dial/.detent-rack/.detent widget is fully retired (not left as orphaned dead markup/CSS) -- superseded by .dial-assembly/.detent2"

# 180.11  Protocol 17: every .detent2 keeps a >=28px tap target; touch-
#         action:none is scoped to .knob2 ONLY (not the whole assembly or
#         the readout), so the surrounding page still scrolls normally.
$detent2RuleMatch180 = [regex]::Match($css180, '(?s)\.detent2\s*\{([\s\S]*?)\n\}')
$detent2Rule180 = if ($detent2RuleMatch180.Success) { $detent2RuleMatch180.Groups[1].Value } else { '' }
$minH180 = ([regex]::Match($detent2Rule180, 'min-height:\s*(\d+)px')).Groups[1].Value
$minW180 = ([regex]::Match($detent2Rule180, 'min-width:\s*(\d+)px')).Groups[1].Value
$touchActionMatches180 = [regex]::Matches($css180, '([.\w-]+)\s*\{[^}]*touch-action:\s*none')
$touchActionSites180 = $touchActionMatches180 | ForEach-Object { $_.Groups[1].Value }
Check (
    ([int]$minH180 -ge 28) -and ([int]$minW180 -ge 28) -and
    ($touchActionSites180 -contains '.knob2') -and
    (-not ($touchActionSites180 -contains '.dial-assembly')) -and
    (-not ($touchActionSites180 -contains '.tempo-readout'))
) "180.11: .detent2 keeps a >=28px tap target (Protocol 17), and touch-action:none is scoped to .knob2 only -- the assembly/readout never block page scroll"

# 180.12  reduced-motion: the knob's rotation is a plain CSS transition
#         (never animation:), so the existing global prefers-reduced-motion
#         block neutralises it to an instant snap with no bespoke carve-out.
$knob2RuleMatch180 = [regex]::Match($css180, '(?s)\.knob2\s*\{([\s\S]*?)\n\}')
$knob2Rule180 = if ($knob2RuleMatch180.Success) { $knob2RuleMatch180.Groups[1].Value } else { '' }
Check (
    ($knob2Rule180 -match 'transition:\s*transform') -and
    (-not ($knob2Rule180 -match 'animation:')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($css180, '(?s)\.knob2[\s\S]{0,40}prefers-reduced-motion'))
) "180.12: .knob2 rotates via a plain transition (no animation:) and declares no bespoke reduced-motion carve-out -- the existing global block neutralises it automatically"

# 180.13  Owner report: the readout ("> TEMPO SELECTED / <NAME> / <desc>")
#         used to only refresh on release (_setTempo -> _syncCampaignProfileUI),
#         so the needle could point at a new position mid-drag while the
#         readout still showed the last COMMITTED one. _tempoPointerMove()
#         must live-preview the readout (+ the knob's own ARIA) to the
#         NEAREST drag position on every frame, while still never
#         committing the value itself (_setTempo/onPlaythroughTypeChange)
#         until pointerup (180.6/180.9 -- commit-on-release unchanged).
$moveBody180 = Get-FunctionBody $core180 '_tempoPointerMove'
Check (
    ($moveBody180 -match 'tempoReadoutName') -and
    ($moveBody180 -match 'tempoReadoutDesc') -and
    ($moveBody180 -match '_TEMPO_LABELS\[nearKey\]') -and
    ($moveBody180 -match '_TEMPO_DESC\[nearKey\]') -and
    ($moveBody180 -match 'aria-valuenow') -and
    ($moveBody180 -match 'aria-valuetext') -and
    (-not ($moveBody180 -match '_setTempo\(')) -and
    (-not ($moveBody180 -match 'onPlaythroughTypeChange\('))
) "180.13: _tempoPointerMove() live-previews the readout name+description and the knob's ARIA to the nearest drag position on every frame, without ever committing (_setTempo/onPlaythroughTypeChange) until pointerup"

# ===========================================================
# Suite 181 -- PHASE 3 OPERATOR hero-three reskin (id-preservation
# contract) (20 tests)
# The Phase-3 hero-three OPERATOR/STAT dressing (planning/PHASE3_OPERATOR_
# PLAN.md, matching the owner-approved planning/mockups/operator-combined.html
# mix of Option-C CRT vitals monitor + Option-B fader bank + Option-B zone
# plate). A pure Protocol 22/25 RESKIN -- every id/handler the plan's
# id-preservation contract lists is preserved verbatim; BIO-METRICS is split
# into its 3 real boards (BUS-01 VITAL TELEMETRY, BUS-02 S.P.E.C.I.A.L.
# TUNING, BUS-04 CHRONO/POSITION) and BIO-SCAN & LIMB STATUS is re-dressed as
# BUS-03 SKELETAL HARNESS; the other 5 OPERATOR boards (SKILL MATRIX/PERKS/
# STATUS EFFECTS/FACTION STANDING/KARMA CENTER) are light-framed only (BUS
# tag + 0i status row, no internal redesign, renderSkills()/renderFactionRep()/
# renderKarmaCenter() untouched). All new instrument CSS (CRT trace, fader
# ladder, zone plate) reuses the existing .bay-board/.bay-slot-tag/.bay-part-
# no/.panel-substatus machine-language classes (Module Bay / ACCOUNT
# precedent) rather than a parallel class family. stat_rads stays a single
# unique id on BUS-01 (the owner-picked CRT-monitor placement) -- BUS-03
# mirrors the same value read-only rather than duplicating the id, a
# documented resolution of a mockup fidelity gap (the mockup fakes two
# rad readouts via a shared, non-unique data attribute). Fixing this same
# rename also caught a REAL regression during testing (Protocol 42):
# expandPanelForCategory() looked up the SPECIAL/BIO-SCAN boards by their old
# h2 text, which this rename broke silently -- fixed in the same commit
# (Suites 123.7/168.7 updated). (PS mirror of JS Suite 181.)
# ===========================================================
Sep "Suite 181 -- PHASE 3 OPERATOR hero-three reskin (id-preservation contract)"
$html181 = Read-Src "index.html"
$uiCore181 = Read-Src "js/ui-core.js"
$uiRender181 = Read-Src "js/ui-render.js"
$css181 = Read-Src "css/terminal.css"

# 181.1  the full fixed-id set from planning/PHASE3_OPERATOR_PLAN.md sec3
$FIXED_IDS_181 = @(
    's_s','s_p','s_e','s_c','s_i','s_a','s_l','stat_hp_cur','stat_hp_max','hp_bar_fill','hp_bar_container',
    'stat_lvl','stat_xp','xp_bar_fill','xp_bar_container','btnLevelUp','c_caps','stat_karma','karma_label',
    'stat_loc','locationOptions','cal_month','cal_day','cal_year','time_hour','time_min','time_day','stat_ticks',
    'gameDateDisplay','gameTimeDisplay','display_weight','display_ap','equippedDisplay','radAwayAlert','stat_rads',
    'btn_l_hd','btn_l_la','btn_l_ra','btn_l_ll','btn_l_rl','skillsGrid','skillBooksPanel','skillBooksDisplay',
    'magazinesPanel','magazinesDisplay','perksList','newPerkName','newPerkRank','newPerkLevel','traitsSection',
    'traitFilter','traitsDisplay','statusList','newStatusName','newStatusTicks','newStatusType','factionContainer',
    'factionPanel','karmaPanel','karmaCenterDisplay'
)
$missingIds181 = @($FIXED_IDS_181 | Where-Object { $html181 -notmatch ('id="' + $_ + '"') })
Check ($missingIds181.Count -eq 0) `
    ('181.1: every id in the PHASE3_OPERATOR_PLAN.md id-preservation contract (60 ids) still exists in index.html -- missing: ' + ($missingIds181 -join ', '))

# 181.2  every shipped handler the plan names is still referenced unchanged
$HANDLERS_181 = @('commitStat','capStatMax','toggleLimb','nativeLevelUp','onLvlInputChanged','onTimeInputChanged','onLocationChange','updateKarmaUI','renderBioScan')
$missingHandlers181 = @($HANDLERS_181 | Where-Object { $html181 -notmatch ($_ + '\(') })
Check ($missingHandlers181.Count -eq 0) `
    ('181.2: every shipped handler (commitStat/capStatMax/toggleLimb/nativeLevelUp/onLvlInputChanged/onTimeInputChanged/onLocationChange/updateKarmaUI/renderBioScan) is still called from index.html -- missing: ' + ($missingHandlers181 -join ', '))

# 181.3  renderSkills()/renderFactionRep()/renderKarmaCenter() still defined
# Phase 3 OPERATOR batch 2 (Suite 185b) ground-up-reskinned renderSkills()
# and renderFactionRep()'s OWN templates (VU meters / reputation console)
# while keeping this same function name + the id-preservation contract
# (Suite 181.1/181.2) intact -- renderKarmaCenter() is untouched, still
# light-frame-only, since BUS-09 was out of scope for that unit.
Check (($uiCore181 -match 'function renderSkills\(\)') -and ($uiRender181 -match 'function renderFactionRep\(\)') -and ($uiRender181 -match 'function renderKarmaCenter\(\)')) `
    '181.3: renderSkills()/renderFactionRep()/renderKarmaCenter() are all still defined under their original names -- renderKarmaCenter() stays light-frame-only, while renderSkills()/renderFactionRep() were ground-up reskinned at Suite 185b (their own templates changed, but every id/handler the plan requires is still emitted -- see Suite 185b)'

# 181.4  all 11 OPERATOR boards are <details class="panel bay-board"> with a BUS-0N tag
# Phase 3 OPERATOR batch 3 renamed 3 board titles (CHRONO/POSITION FIX ->
# POSITION & MISSION CLOCK, PERKS -> PERK LOADOUT, KARMA CENTER -> KARMA
# ALIGNMENT) and promoted SKILL BOOKS/SKILL MAGAZINES to their own top-level
# boards (BUS-05a/BUS-05b) -- 9 boards became 11.
$boardTitles181 = @('VITAL TELEMETRY','S.P.E.C.I.A.L. TUNING','POSITION &amp; MISSION CLOCK','SKELETAL HARNESS','SKILL MATRIX','SKILL BOOKS — REFERENCE SHELF','SKILL MAGAZINES — PERIODICAL RACK','PERK LOADOUT','STATUS EFFECTS','FACTION STANDING','KARMA ALIGNMENT')
$busTags181 = @('BUS-01','BUS-02','BUS-04','BUS-03','BUS-05','BUS-05a','BUS-05b','BUS-06','BUS-07','BUS-08','BUS-09')
# Prettier is free to wrap a long <h2> (id attribute + multi-word title) onto several
# indented lines, so a multi-word title matches with \s+ between words instead of a
# literal space (Protocol 42 -- caught live by npm run format wrapping the 4 hero boards).
$boardsOk181 = $true
foreach ($t in $boardTitles181) {
    # .NET Regex.Escape also escapes plain whitespace (e.g. "VITAL TELEMETRY" -> "VITAL\ TELEMETRY"),
    # so a blind space->\s+ replace afterward corrupts that backslash into a literal-backslash match
    # instead of a whitespace class. Escape each word separately, then join with \s+ instead.
    $escaped = (($t -split ' ') | ForEach-Object { [regex]::Escape($_) }) -join '\s+'
    if (-not [System.Text.RegularExpressions.Regex]::IsMatch($html181, '(?s)class="panel bay-board"[\s\S]{0,400}' + $escaped)) { $boardsOk181 = $false }
}
foreach ($b in $busTags181) {
    if ($html181 -notmatch ('class="bay-slot-tag">' + $b + '<')) { $boardsOk181 = $false }
}
Check $boardsOk181 `
    '181.4: all 11 OPERATOR boards are <details class="panel bay-board"> and carry their BUS-0N slot tag (reuses the existing Module Bay board-frame class, Protocol 22)'

# 181.5  Protocol UI-1 -- all 11 OPERATOR board h2 headings keep the ">" glyph
$opH2Ok181 = $true
foreach ($t in $boardTitles181) {
    # .NET Regex.Escape also escapes plain whitespace (e.g. "VITAL TELEMETRY" -> "VITAL\ TELEMETRY"),
    # so a blind space->\s+ replace afterward corrupts that backslash into a literal-backslash match
    # instead of a whitespace class. Escape each word separately, then join with \s+ instead.
    $escaped = (($t -split ' ') | ForEach-Object { [regex]::Escape($_) }) -join '\s+'
    $m = [System.Text.RegularExpressions.Regex]::Match($html181, '(?s)<h2>[\s\S]{0,200}?' + $escaped + '[\s\S]{0,20}?</h2>')
    if (-not $m.Success) { $opH2Ok181 = $false; continue }
    $text = ($m.Value -replace '<[^>]+>', '') -replace '&gt;', '>'
    if (-not $text.Trim().StartsWith('>')) { $opH2Ok181 = $false }
}
Check $opH2Ok181 `
    '181.5: all 11 OPERATOR board <h2> headings still start with the mandatory "> " glyph (Protocol UI-1) despite the new <span class="board-led">'

# 181.6  the SPECIAL fader steppers route through the existing commitStat(el)
$bumpBody181 = Get-FunctionBody $uiCore181 '_bumpSpecialStat'
Check (($bumpBody181 -match 'el\.value = String\(next\)') -and ($bumpBody181 -match 'commitStat\(el\)')) `
    '181.6: _bumpSpecialStat() sets el.value then calls the existing commitStat(el) -- one clamp/state-write/save path for both the typed field and the steppers'

# 181.7  updateMath() calls _syncOperatorTelemetry() exactly once
$updateMathBody181 = Get-FunctionBody $uiCore181 'updateMath'
Check ($updateMathBody181 -match '_syncOperatorTelemetry\(\);') `
    '181.7: updateMath() calls _syncOperatorTelemetry() exactly once, at the end of its existing body'

# 181.8  _syncOperatorTelemetry() drives HP cond-word, RAD trace/mirror, ladders, statuses
$syncBody181 = Get-FunctionBody $uiCore181 '_syncOperatorTelemetry'
Check (
    ($syncBody181 -match "getElementById\('opCondWord'\)") -and
    ($syncBody181 -match "getElementById\('opRadLine'\)") -and
    ($syncBody181 -match "getElementById\('opHarnessRadBar'\)") -and
    ($syncBody181 -match "getElementById\('opHarnessRadMirror'\)") -and
    ($syncBody181 -match 'data-fd-ladder') -and
    ($syncBody181 -match "setStatus\(\s*'opVitalStatus'") -and
    ($syncBody181 -match "setStatus\(\s*'opHarnessStatus'")
) '181.8: _syncOperatorTelemetry() drives the HP cond-word, the RAD trace + BUS-03 mirror, the SPECIAL fader ladders, and the board-status rows'

# 181.9  stat_rads stays a single unique id
$radIdOccurrences181 = ([regex]::Matches($html181, 'id="stat_rads"')).Count
Check ($radIdOccurrences181 -eq 1) `
    '181.9: id="stat_rads" appears exactly once (BUS-01) -- BUS-03 mirrors the same value read-only via #opHarnessRadMirror, never a duplicate input sharing the id'

# 181.10  the RadAway alert restructure is handled correctly by updateMath()
Check (($updateMathBody181 -match 'if \(alertTextEl\) alertTextEl\.textContent = msg;') -and ($updateMathBody181 -match "alertEl\.style\.display = 'flex'")) `
    "181.10: updateMath()'s RadAway block sets #radAwayAlertText's textContent on its primary path (a bare alertEl.textContent would erase the lamp icon) and flips display to 'flex'"

# 181.11  loadUI() calls _syncBioHarnessZones()
$loadUIBody181 = Get-FunctionBody $uiCore181 'loadUI'
Check ($loadUIBody181 -match '_syncBioHarnessZones\(\);') `
    '181.11: loadUI() calls _syncBioHarnessZones() -- the SVG zone crippled-state can never drift from the limb-button re-render in the same function'

# 181.12  zone taps route through the existing toggleLimb()
$wireZonesBody181 = Get-FunctionBody $uiCore181 '_wireBioHarnessZones'
Check (($wireZonesBody181 -match 'toggleLimb\(zone\.dataset\.limb\)') -and ($wireZonesBody181 -match "addEventListener\('click'") -and ($wireZonesBody181 -match "addEventListener\('keydown'")) `
    '181.12: _wireBioHarnessZones() routes both click and Enter/Space keyboard activation through the existing toggleLimb() -- one handler, two input surfaces'

# 181.13  the SVG zone plate has all 5 data-limb zones
$zonesOk181 = $true
foreach ($l in @('hd','la','ra','ll','rl')) {
    if ($html181 -notmatch ('data-limb="' + $l + '"')) { $zonesOk181 = $false }
}
Check $zonesOk181 '181.13: the SVG zone plate has all 5 data-limb zones (hd/la/ra/ll/rl)'

# 181.14  the level-up key flash is a NEW 'level.up' bus subscriber
$wireEventBusBody181 = Get-FunctionBody $uiCore181 '_wireCoreEventBusSubscribers'
Check (
    ($wireEventBusBody181 -match "RobcoEvents\.on\('level\.up', p => \{") -and
    ($wireEventBusBody181 -match 'opLevelUpKeyText') -and
    ($wireEventBusBody181 -match "LEVEL ' \+ newLvl \+ ' COMMITTED")
) "181.14: _wireCoreEventBusSubscribers() adds a NEW 'level.up' subscriber that flashes #opLevelUpKeyText -- nativeLevelUp()'s existing emit call and onclick wiring are untouched"

# 181.15  #btnLevelUp still calls onclick="nativeLevelUp()" directly
Check ($html181 -match 'onclick="nativeLevelUp\(\)"') `
    '181.15: #btnLevelUp still calls onclick="nativeLevelUp()" directly -- the flash is a bus subscriber, never a wrapper around the click handler'

# 181.16  centering rule on every new incomplete-row flex container
$centeredClasses181 = @('.fader-row','.zone-flex','.zone-chips','.readback-strip','.bio-actions')
$centeringOk181 = $true
foreach ($cls in $centeredClasses181) {
    $escaped = [regex]::Escape($cls)
    $m = [System.Text.RegularExpressions.Regex]::Match($css181, $escaped + ' \{[^}]*\}')
    if (-not ($m.Success -and ($m.Value -match 'justify-content:\s*center'))) { $centeringOk181 = $false }
}
Check $centeringOk181 `
    '181.16: .fader-row/.zone-flex/.zone-chips/.readback-strip/.bio-actions all center an incomplete last row (justify-content:center)'

# 181.17  reduced-motion -- new discrete effects are plain animation: (no bespoke carve-out)
$ledRuleMatch181 = [regex]::Match($css181, '\.board-led \{[^}]*\}')
$ledRule181 = if ($ledRuleMatch181.Success) { $ledRuleMatch181.Value } else { '' }
Check (
    ($ledRule181 -match 'animation:\s*rad-pulse') -and
    ($css181 -match '@keyframes zoneCriBlink') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($css181, '(?s)\.zone\.crippled path,[\s\S]{0,120}animation:\s*zoneCriBlink')
) '181.17: .board-led and .zone.crippled both use plain `animation:` keyframes (rad-pulse / zoneCriBlink) -- no bespoke reduced-motion carve-out needed'

# 181.18  game-agnostic status computation (no hardcoded skill/faction counts)
Check (($syncBody181 -match 'getSkillKeys\(\)\.length') -and ($syncBody181 -match 'getFactionRegistry\(\)\.length')) `
    '181.18: the SKILL MATRIX / FACTION STANDING 0i status lines are computed via getSkillKeys().length / getFactionRegistry().length (Protocol 38 -- never a hardcoded per-game count)'

# 181.19  no stray game-literal skill count in the decorative part number
Check (-not ($html181 -match 'PN RBC-SKL-13')) `
