# ===========================================================
Write-Host "`n-- Suite 182 -- OPERATOR follow-up: drag controls + RAD max clamp $('-' * 5)"
$uiCore182 = Read-Src "js/ui-core.js"
$stateSrc182 = Read-Src "js/state.js"
$apiSrc182 = Read-Src "js/api.js"
