# 184.18  _syncCampaignConfigTopSummary() aggregates both boards' summaries.
$profileBody184 = Get-FunctionBody $core184 '_syncCampaignProfileUI'
$interlockBody184 = Get-FunctionBody $core184 '_syncInterlockUI'
