# 185.9  last-open drawer remembered via a registered MetaStore pref (UI-6).
$setInvFilterBody185 = Get-FunctionBody $render185 'setInvFilter'
$restoreDevicePrefsBody185 = Get-FunctionBody $core185 '_restoreDevicePrefs'
