$summaryIds185 = @('opsBridgeStatus', 'opsManifestStatus', 'opsFabStatus', 'opsBarterStatus', 'opsSquadStatus', 'opsCurioStatus')
$missingSummaries185 = $summaryIds185 | Where-Object {
