# 186.4  _skillVuSet()/_onSkillVuInput() both clamp 0-100 and call saveState().
$skillVuSetBody186 = Get-FunctionBody $core186 '_skillVuSet'
$onSkillVuInputBody186 = Get-FunctionBody $core186 '_onSkillVuInput'
Check (
