# 186.16  centering rule: the lamp grid uses flex-wrap + justify-content:center.
$cssStripped186 = $css186 -replace '(?s)/\*.*?\*/', ''
$stlampGridRule186 = ([regex]::Match($cssStripped186, '\.stlamp-grid\s*\{[^}]*\}')).Value
