) '190.13b: #radDragTrack.dragging .bar-fill.rad sets transition:none -- the SKELETAL HARNESS RAD bar never lags a real-time drag either'

# ===========================================================
# Suite 191 -- BUS-15 CURIO ARCHIVE themed-object redesign: collectibles
# as their recognizable Fallout object (snow globe / bobblehead / typed
# Lincoln relic), category-driven (Protocol 38), on plank shelves mounted
# INSIDE one sealed glass display case (owner clarification: a display
# case naturally has shelves inside it -- merged into ONE unified vitrine,
# never a switchable view; the CASE/SHELF toggle from the first pass was
# removed entirely, including its MetaStore pref). Owner batch: each
# object now carries its own shelf plank (immune to scroll desync and to
# Lincoln's row-height variance) and the Lincoln disposition <select>
# sizes to its own content (no more mid-glyph clipping) with native
# form-control chrome stripped via appearance:none so the box stays
# compact and consistent across devices (Protocol 17 floors preserved).
# Mirrors JS Suite 191. 25 tests.
# ===========================================================
Sep "Suite 191 -- CURIO ARCHIVE: shelves-inside-a-sealed-case themed objects"
$state191 = Read-Src "js/state.js"
$render191 = Read-Src "js/ui-render.js"
$reg191 = Read-Src "js/reg_fo3.js"
$html191 = Read-Src "index.html"
$css191 = Read-Src "css/terminal.css"

# 191.1  The pre-existing tracker-toggle contract is fully preserved --
#        every function the mockup notes promise stays unchanged is
#        still present, plus the new curio icon helper.
Check (
    ($render191 -match 'function renderCollectibles\(') -and
    ($render191 -match 'function toggleCollectible\(') -and
    ($render191 -match 'function renderLincolnMemorabilia\(') -and
    ($render191 -match 'function toggleLincolnItem\(') -and
    ($render191 -match 'function setLincolnDisposition\(') -and
    ($render191 -match 'function _curioObjectIconHtml\(')
) '191.1: renderCollectibles/toggleCollectible/renderLincolnMemorabilia/toggleLincolnItem/setLincolnDisposition contract kept unchanged, plus the new _curioObjectIconHtml helper'

# 191.2  The CASE/SHELF view toggle was fully retired, not just orphaned --
#        no setCurioView/_applyCurioView functions remain anywhere.
Check (
    (-not ($render191 -match 'function setCurioView\(')) -and (-not ($render191 -match 'function _applyCurioView\('))
) '191.2: setCurioView/_applyCurioView no longer exist -- the view toggle was removed entirely, not left as dead code (owner clarification: one unified vitrine, not a switchable view)'

# 191.3  robco_curio_view is NOT a registered MetaStore key -- the toggle
#        preference was removed along with the toggle itself.
Check (
    -not ($state191 -match 'robco_curio_view')
) '191.3: robco_curio_view no longer appears anywhere in state.js -- the retired view-toggle preference left no trace'

# 191.4  collectibleCategory is a data-driven Protocol-38 token on every
#        GAME_DEFS entry (never a JS ctx branch in the consuming code).
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($state191, "FNV:\s*\{[\s\S]*?collectibleCategory:\s*'snowglobe'") -and
    [System.Text.RegularExpressions.Regex]::IsMatch($state191, "FO3:\s*\{[\s\S]*?collectibleCategory:\s*'bobblehead'") -and
    [System.Text.RegularExpressions.Regex]::IsMatch($state191, "FO4:\s*\{[\s\S]*?collectibleCategory:\s*'bobblehead'")
) "191.4: GAME_DEFS.FNV/FO3/FO4 each declare collectibleCategory ('snowglobe'/'bobblehead'/'bobblehead') -- the Curio Archive object class is data, not a per-game code branch"

# 191.5  _curioObjectIconHtml() itself carries no hardcoded game literal
#        (Protocol 38) -- it dispatches purely on the `kind` string.
$iconBody191 = Get-FunctionBody $render191 '_curioObjectIconHtml'
Check (
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($iconBody191, "'FNV'|'FO3'|`"FNV`"|`"FO3`"")) -and
    ($iconBody191 -match "kind === 'bobblehead'") -and
    ($iconBody191 -match "kind\.indexOf\('lincoln-'\)")
) '191.5: _curioObjectIconHtml() dispatches on the collectibleCategory/shape token only -- no hardcoded FNV/FO3 literal anywhere in the function body'

# 191.6  reg_fo3.js: every one of the 9 Lincoln relics carries a `shape`
#        field from the typed-artifact vocabulary, and the two literal
#        sentinels the mockup names resolve correctly.
$lincStart191 = $reg191.IndexOf('lincolnMemorabilia: [')
$lincEnd191 = $reg191.IndexOf('// -- ZONES')
if ($lincEnd191 -lt 0) { $lincEnd191 = $reg191.IndexOf('zones: [') }
$lincBlock191 = $reg191.Substring($lincStart191, $lincEnd191 - $lincStart191)
$shapeMatches191 = [System.Text.RegularExpressions.Regex]::Matches($lincBlock191, "shape:\s*'(\w+)'")
$validShapes191 = @('rifle', 'hat', 'cylinder', 'figure', 'poster', 'book', 'coin')
$allShapesValid191 = $true
foreach ($m in $shapeMatches191) { if ($validShapes191 -notcontains $m.Groups[1].Value) { $allShapesValid191 = $false } }
Check (
    ($shapeMatches191.Count -eq 9) -and $allShapesValid191
) '191.6: all 9 FO3 lincolnMemorabilia entries carry a shape field drawn from the typed-artifact vocabulary (rifle/hat/cylinder/figure/poster/book/coin)'

$hatEntry191 = [System.Text.RegularExpressions.Regex]::Match($lincBlock191, "name:\s*`"Lincoln's Hat`"[\s\S]*?\n\s*\},").Value
$repeaterEntry191 = [System.Text.RegularExpressions.Regex]::Match($lincBlock191, "name:\s*`"Lincoln's Repeater`"[\s\S]*?\n\s*\},").Value
Check (
    ($hatEntry191 -match "shape:\s*'hat'") -and ($repeaterEntry191 -match "shape:\s*'rifle'")
) "191.7: `"Lincoln's Hat`" resolves to shape 'hat' and `"Lincoln's Repeater`" resolves to shape 'rifle'"

# 191.8  index.html: the CASE/SHELF view-toggle buttons and attribute are
#        gone -- #curioPanel is a plain board with no data-curio-view.
Check (
    (-not ($html191 -match 'id="curioViewCaseBtn"')) -and
    (-not ($html191 -match 'id="curioViewShelfBtn"')) -and
    (-not ($html191 -match 'data-curio-view'))
) '191.8: index.html no longer has CASE/SHELF view-toggle buttons or a data-curio-view attribute -- one unified board, no switchable view'

# 191.9  #collectiblesDisplay and #lincolnMemorabiliaDisplay are both
#        nested inside the shared curio-display/scrollwrap/caselist/
#        row-flex chrome (bounded scroll, Protocol 10/17).
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($html191, 'curio-display[\s\S]{0,40}id="curioDisplayWrap"[\s\S]{0,120}curio-scrollwrap[\s\S]{0,80}curio-caselist[\s\S]{0,80}curio-row-flex"\s+id="collectiblesDisplay"') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($html191, 'curio-display[\s\S]{0,40}id="lincolnDisplayWrap"[\s\S]{0,150}curio-caselist[\s\S]{0,80}curio-row-flex"\s+id="lincolnMemorabiliaDisplay"')
) '191.9: #collectiblesDisplay and #lincolnMemorabiliaDisplay are both nested inside the shared .curio-display/.curio-scrollwrap/.curio-caselist/.curio-row-flex chrome'

# 191.10  #curioMainPlaque / #lincolnTally / #lincolnPlaque mount points
#         exist for the live count-plaque/tally text.
Check (
    ($html191 -match 'id="curioMainPlaque"') -and
    ($html191 -match 'id="lincolnTally"') -and
    ($html191 -match 'id="lincolnPlaque"')
) '191.10: #curioMainPlaque, #lincolnTally, and #lincolnPlaque mount points exist for the live plaque/tally readouts'

# 191.11  button.curio-obj carries the same specificity fix as
#         button.spine/button.mag (Protocol 42) and the mockup's 88x112
#         button footprint.
$cssStripped191 = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$curioObjRule191 = [regex]::Match($cssStripped191, 'button\.curio-obj\s*\{[^\}]*\}').Value
Check (
    ($curioObjRule191 -match 'width:\s*88px') -and
    ($curioObjRule191 -match 'min-height:\s*112px') -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($cssStripped191, '(?m)^\s*\.curio-obj\s*\{'))
) '191.11: button.curio-obj (element+class specificity, not plain .curio-obj) sets the 88x112px button footprint so it beats button.tracker-toggle'

# 191.12  .curio-display carries the sealed-case vitrine chrome
#         UNCONDITIONALLY (no longer gated behind a [data-curio-view]
#         attribute) -- border, dark backlit interior, box-shadow.
$cssStripped191d = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$displayRule191 = [regex]::Match($cssStripped191d, '\.curio-display\s*\{[^\}]*\}').Value
Check (
    (-not ($css191 -match 'data-curio-view')) -and
    ($displayRule191 -match 'border:\s*2px solid') -and
    ($displayRule191 -match 'box-shadow:\s*inset')
) '191.12: .curio-display carries the sealed-vitrine border/box-shadow unconditionally -- no [data-curio-view] gate remains anywhere in the CSS'

# 191.13  .curio-caselist is the bounded scroll VIEWPORT (max-height,
#         overflow-y) with the 24px top clearance for the latch plate --
#         the shelf itself is NOT painted here (see 191.18/191.19: it
#         moved to a per-object plank so it can never desync from the
#         objects while scrolling, Protocol 27 owner report).
$cssStripped191e = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$caselistRule191 = [regex]::Match($cssStripped191e, '\.curio-caselist\s*\{[^\}]*\}').Value
Check (
    ($caselistRule191 -match 'max-height:\s*430px') -and
    ($caselistRule191 -match 'overflow-y:\s*auto') -and
    ($caselistRule191 -match 'padding:\s*24px')
) '191.13: .curio-caselist provides the bounded scroll (max-height:430px, overflow-y:auto) AND the 24px latch-plate clearance'

# 191.14  The glass sheen and the sealed latch plate exist unconditionally
#         on .curio-display, each above the shelves in paint order
#         (positive z-index), so the shelves/objects read as sitting
#         BEHIND the glass rather than as flat page content. The latch
#         plate text keeps its space intact -- a CSS \XXXX escape
#         immediately followed by a literal space consumes that space as
#         the escape's own delimiter, which is why the literal character
#         is used instead (Protocol 39).
$cssStripped191f = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$sheenRule191 = [regex]::Match($cssStripped191f, '\.curio-display::before\s*\{[^\}]*\}').Value
$latchRule191 = [regex]::Match($cssStripped191f, '\.curio-display::after\s*\{[^\}]*\}').Value
Check (
    ($sheenRule191 -match 'z-index:\s*2') -and ($latchRule191 -match 'z-index:\s*3')
) '191.14a: the glass sheen (::before, z-index 2) and the sealed latch plate (::after, z-index 3) both paint above the plank shelves/objects (which set no z-index), reading as behind the glass'
Check (
    ($css191.Contains("content: '$([char]0x25C8) SEALED EXHIBIT';")) -and (-not ($css191.Contains('\25C8')))
) '191.14b: the sealed latch plate content is the literal diamond character (not a \25C8 CSS escape, which would swallow the following space and render the words run together)'

# 191.15  .curio-scrollwrap declares no z-index of its own, so it can
#         never be raised above the glass sheen/latch plate by the
#         cascade -- the shelves stay behind the glass regardless of
#         future edits to this rule.
$cssStripped191g = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$scrollwrapRule191 = [regex]::Match($cssStripped191g, '\.curio-scrollwrap\s*\{[^\}]*\}').Value
Check (
    ($scrollwrapRule191.Length -gt 0) -and (-not ($scrollwrapRule191 -match 'z-index'))
) '191.15: .curio-scrollwrap sets no z-index (stays at the auto/base paint level), so the glass sheen/latch plate above it can never end up rendering underneath the shelves'
Check (
    $css191 -match '\.curio-scrollwrap::after'
) '191.15b: .curio-scrollwrap::after still supplies the bottom edge-fade over the bounded scroll region'

# 191.16  .curio-row-flex follows the centering rule (flex-wrap +
#         justify-content:center), matching every other wrapped-row
#         board in the app.
$cssStripped191c = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$rowFlexRule191 = [regex]::Match($cssStripped191c, '\.curio-row-flex\s*\{[^\}]*\}').Value
Check (
    ($rowFlexRule191 -match 'flex-wrap:\s*wrap') -and ($rowFlexRule191 -match 'justify-content:\s*center')
) '191.16: .curio-row-flex wraps with justify-content:center (the centering rule) so a partial last row is never left-stranded'

# 191.17  The bobblehead bobble is a plain @keyframes animation (never a
#         bare transition), so the existing global prefers-reduced-motion
#         block neutralises it automatically -- and the uncollected state
#         stops the animation entirely (dashed silhouette, no bobble).
Check (
    ($css191 -match '@keyframes\s+curioBob\s*\{') -and
    ($css191 -match 'animation:\s*curioBob\s') -and
    [System.Text.RegularExpressions.Regex]::IsMatch($css191, 'tracker-toggle--inactive\s+\.cb-head\s*\{[^\}]*animation:\s*none')
) '191.17: the bobblehead bobble is a plain @keyframes curioBob animation (auto-neutralised by the global reduced-motion block) and is turned off (animation:none) on the uncollected/dashed state'

# 191.18  Owner report (Protocol 27 root cause): the shelf used to be a
#         single repeating-gradient background painted on .curio-caselist
#         (the scroll VIEWPORT) -- background-attachment:scroll anchors a
#         background to the element it's declared on, not to that
#         element's own overflow content, so the shelf stayed fixed while
#         the objects scrolled past it. .curio-caselist must carry no
#         such background any more.
$cssStripped191h = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$caselistRule191b = [regex]::Match($cssStripped191h, '\.curio-caselist\s*\{[^\}]*\}').Value
Check (
    (-not ($caselistRule191b -match 'repeating-linear-gradient')) -and (-not ($caselistRule191b -match 'background:'))
) '191.18: .curio-caselist (the scroll viewport) no longer carries the shelf background -- the old fixed-in-place shelf bug can no longer recur there'

# 191.19  Each object now carries its OWN shelf plank as a
#         button.curio-obj::after pseudo-element, attached to the object
#         itself rather than a shared row/container background -- immune
#         to scroll position (it moves with its own button by
#         construction) AND to row-height variance from the Lincoln
#         sub-case's taller "found" rows (a shared fixed-cycle background
#         would drift out of alignment there; a per-object pseudo cannot).
#         Also confirms neither .curio-row-flex nor .curio-cell picked up
#         a repeating-gradient shelf background as an alternate fix.
$cssStripped191i = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$plankRule191 = [regex]::Match($cssStripped191i, 'button\.curio-obj::after\s*\{[^\}]*\}').Value
$rowFlexRule191b = [regex]::Match($cssStripped191i, '\.curio-row-flex\s*\{[^\}]*\}').Value
$cellRule191b = [regex]::Match($cssStripped191i, '\.curio-cell\s*\{[^\}]*\}').Value
Check (
    ($plankRule191 -match 'position:\s*absolute') -and
    ($plankRule191 -match 'background:\s*linear-gradient') -and
    (-not ($rowFlexRule191b -match 'repeating-linear-gradient')) -and
    (-not ($cellRule191b -match 'repeating-linear-gradient'))
) '191.19: button.curio-obj::after renders each object''s own shelf plank (position:absolute, attached to the button) -- neither .curio-row-flex nor .curio-cell carries a shared repeating-gradient shelf background instead'

# 191.20  .curio-cell's gap is wide enough to clear the plank's own
#         protrusion below the button (bottom offset + height), so the
#         plank can never visually overlap the Lincoln disposition
#         <select> that can follow the button in the same cell.
$cssStripped191j = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$cellRule191 = [regex]::Match($cssStripped191j, '\.curio-cell\s*\{[^\}]*\}').Value
$plankRule191b = [regex]::Match($cssStripped191j, 'button\.curio-obj::after\s*\{[^\}]*\}').Value
$gapMatch191 = [regex]::Match($cellRule191, 'gap:\s*(\d+)px')
$bottomMatch191 = [regex]::Match($plankRule191b, 'bottom:\s*-(\d+)px')
$heightMatch191 = [regex]::Match($plankRule191b, 'height:\s*(\d+)px')
$gapPx191 = 0
if ($gapMatch191.Success) { $gapPx191 = [int]$gapMatch191.Groups[1].Value }
$bottomPx191 = 0
if ($bottomMatch191.Success) { $bottomPx191 = [int]$bottomMatch191.Groups[1].Value }
$heightPx191 = 0
if ($heightMatch191.Success) { $heightPx191 = [int]$heightMatch191.Groups[1].Value }
$protrusionPx191 = $bottomPx191 + $heightPx191
Check (
    ($gapPx191 -gt 0) -and ($protrusionPx191 -gt 0) -and ($gapPx191 -gt $protrusionPx191)
) "191.20: .curio-cell's gap (${gapPx191}px) clears button.curio-obj::after's total protrusion below the button (${protrusionPx191}px), so the plank can never overlap the Lincoln disposition <select> that follows it"

# 191.21  Owner report round 1: the Lincoln disposition <select> was a
#         fixed width: 88px (matching the object button above it),
#         clipping the longer labels ("HANNIBAL (FREE SLAVES)", "LEROY
#         WALKER (SLAVERS)") mid-glyph. SUPERSEDED (owner polish batch, see
#         Suite 193): sizing to its own widest-option content
#         (width:auto/min-width:64px/max-width:~234px) turned out to be the
#         Protocol 27 root cause of a LATER owner report -- it forced every
#         "found" Lincoln cell wide enough to strand it one-per-row instead
#         of sitting side by side with its siblings. The select now sizes
#         to its (fixed-width) grid CELL instead, with ellipsis for any
#         label too long for that compact width -- see Suite 193.5/193.6
#         for the current contract; this guard now only confirms the old
#         content-sizing contract is truly gone.
$cssStripped191k = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$dispositionRule191 = [regex]::Match($cssStripped191k, '\.curio-linc-disposition\s*\{[^\}]*\}').Value
Check (
    (-not ($dispositionRule191 -match 'width:\s*auto')) -and
    (-not ($dispositionRule191 -match 'min-width:\s*64px'))
) '191.21: .curio-linc-disposition no longer sizes to its own widest-option content (width:auto/min-width:64px) -- that contract was the Protocol 27 root cause of the later one-per-row stacking bug fixed in Suite 193'

# 191.22  Owner report round 2 (Protocol 27 root cause, live-measured): a
#         native <select> with only width: auto renders using the
#         browser/OS's own default form-control chrome (padding, minimum
#         touch height, arrow gutter), which varies across engines and can
#         render far bigger than this rule's own box model -- measured
#         live, even Chromium alone rendered ~8px wider than an
#         appearance:none version at identical content. appearance: none
#         (+ vendor prefixes) strips that native chrome so the box is
#         driven purely by this rule's own compact padding, consistent on
#         every device. font-size stays >=16px (Protocol 17 -- prevents
#         iOS/Android focus auto-zoom) and min-height stays >=28px
#         (Protocol 17 tap-target floor) -- neither mobile-baseline floor
#         is reduced to chase compactness; the fix is entirely in removing
#         native chrome variance, not in violating either rule.
$cssStripped191l = [regex]::Replace($css191, '/\*[\s\S]*?\*/', '')
$dispositionRule191b = [regex]::Match($cssStripped191l, '\.curio-linc-disposition\s*\{[^\}]*\}').Value
$fontSizeMatch191 = [regex]::Match($dispositionRule191b, 'font-size:\s*(\d+)px')
$fontSizePx191 = if ($fontSizeMatch191.Success) { [int]$fontSizeMatch191.Groups[1].Value } else { 0 }
$minHeightMatch191 = [regex]::Match($dispositionRule191b, 'min-height:\s*(\d+)px')
$minHeightPx191 = if ($minHeightMatch191.Success) { [int]$minHeightMatch191.Groups[1].Value } else { 0 }
Check (
    ($dispositionRule191b -match 'appearance:\s*none') -and
    ($dispositionRule191b -match '-webkit-appearance:\s*none') -and
    ($fontSizePx191 -ge 16) -and ($minHeightPx191 -ge 28)
) "191.22: .curio-linc-disposition uses appearance:none (+ -webkit-appearance) to strip native form-control chrome variance, while keeping font-size (${fontSizePx191}px) >=16 and min-height (${minHeightPx191}px) >=28 -- the Protocol 17 mobile-baseline floors are never reduced to chase compactness"

# ===========================================================
# Suite 192 -- Design Overhaul CHASSIS unit: the self-diagnostic maintenance
# bay + THE LIVING CORE (Protocol UI-10). The former single SYSTEM STATUS
# panel is rebuilt as three boards (BUS-22 UNIT POWER PLANT / BUS-23 IDENTITY
# PLATE & BREAKERS / BUS-24 SERVICE & FAULT CONSOLE, reskin only). The core is
# a decorative layer over REAL machine signals (setOverseerState/
# _isUplinkConnected/AmbientRuntime/RobcoEvents -- reused, never forked),
# gate-stacked to a single static frame, zero campaign-state write, and
# mirrored verbatim (single shared _coreRefresh() choke point) into a mini
# glyph. UPDATED (owner follow-up): the mini glyph moved from the Overseer
# Uplink header into its own dedicated readout window in the always-visible
# casing-top header (#chassisScreenMini). (PS mirror of JS Suite 192.)
# 26 tests
# ===========================================================
Sep "Suite 192 -- Design Overhaul CHASSIS unit: THE LIVING CORE"
$html192 = Read-Src "index.html"
$core192 = Read-Src "js/ui-core.js"
$audio192 = Read-Src "js/ui-audio.js"
$saves192 = Read-Src "js/ui-saves.js"
$cloud192 = Read-Src "js/cloud.js"
$css192 = Read-Src "css/terminal.css"

# 192.1  the three BUS-22/23/24 boards exist on the CHASSIS tab, each a real
#        .panel.bay-board with its own BUS slot tag
Check (
    ($html192 -match '<details class="panel bay-board" data-tab="chassis" id="unitPowerPlantPanel"') -and
    ($html192 -match '<details class="panel bay-board" data-tab="chassis" id="systemStatusPanel">') -and
    ($html192 -match '<details class="panel bay-board" data-tab="chassis" id="serviceFaultConsolePanel">') -and
    ($html192 -match 'BUS-22') -and ($html192 -match 'BUS-23') -and ($html192 -match 'BUS-24')
) '192.1: BUS-22 UNIT POWER PLANT / BUS-23 IDENTITY PLATE & BREAKERS / BUS-24 SERVICE & FAULT CONSOLE are three real .panel.bay-board boards on the CHASSIS tab'

# 192.2  #chassisCore is a real <button> (Protocol UI-5) wired to
#        _coreTapPoke() with a descriptive aria-label; #chassisCoreMini is a
#        decorative aria-hidden mirror -- both share .chassis-core-shape
$coreBtnTag192 = [regex]::Match($html192, '(?s)<button[^>]*id="chassisCore"[^>]*>').Value
$miniTag192 = [regex]::Match($html192, '(?s)<span[^>]*id="chassisCoreMini"[^>]*>').Value
Check (
    ($coreBtnTag192 -match 'class="chassis-core-shape"') -and
    ($coreBtnTag192 -match 'onclick="_coreTapPoke\(\)"') -and
    ($coreBtnTag192 -match 'aria-label="[^"]+"') -and
    ($miniTag192 -match 'chassis-core-shape') -and
    ($miniTag192 -match 'aria-hidden="true"')
) '192.2: #chassisCore is a real <button> (onclick="_coreTapPoke()", descriptive aria-label) and #chassisCoreMini is a decorative aria-hidden mirror -- both carry .chassis-core-shape'

# 192.3  the "?" explainer opens showCoreHelpModal(), which is defined and
#        drives the shared openModal() (Suite 103 showSaveHelpModal pattern)
Check (
    ($html192 -match '(?s)onclick="showCoreHelpModal\(\)".{0,120}aria-label="[^"]+"') -and
    ($core192 -match 'function showCoreHelpModal\(\)') -and
    ((Get-FunctionBody $core192 'showCoreHelpModal') -match 'openModal\(\{')
) '192.3: a "?" button opens showCoreHelpModal(), which renders through the shared openModal() driver'

# 192.4  _coreRefresh() is the ONE choke point -- queries the shared
#        .chassis-core-shape class (never two separate getElementById calls,
#        which would let the two views drift) and reads every real signal
$coreRefreshBody192 = Get-FunctionBody $core192 '_coreRefresh'
Check (
    ((Get-FunctionBody $core192 '_coreShells') -match "querySelectorAll\('\.chassis-core-shape'\)") -and
    ($coreRefreshBody192 -match 'getOverseerState') -and
    ($coreRefreshBody192 -match '_readErrorLog') -and
    ($coreRefreshBody192 -match '_radioPlaying') -and
    ($coreRefreshBody192 -match '_corePowerClass') -and
    (-not ($coreRefreshBody192 -match "getElementById\('chassisCore'\)")) -and
    (-not ($coreRefreshBody192 -match "getElementById\('chassisCoreMini'\)"))
) '192.4: _coreRefresh() is the single choke point -- reads getOverseerState()/_readErrorLog()/_radioPlaying()/_corePowerClass() and paints both shells via ONE shared .chassis-core-shape query, never two separate ids'

# 192.5  _coreShouldAnimate() gates on all four documented signals --
#        reduced-motion, the Immersion dial below Balanced, document.hidden,
#        and the Ambient Runtime in STANDBY/SHUTDOWN/OFF
$shouldAnimateBody192 = Get-FunctionBody $core192 '_coreShouldAnimate'
Check (
    ($shouldAnimateBody192 -match 'prefers-reduced-motion') -and
    ($shouldAnimateBody192 -match "immersionAllows\('balanced'\)") -and
    ($shouldAnimateBody192 -match 'document\.hidden') -and
    ($shouldAnimateBody192 -match 'STANDBY') -and
    ($shouldAnimateBody192 -match 'SHUTDOWN') -and
    ($shouldAnimateBody192 -match "'OFF'")
) "192.5: _coreShouldAnimate() suppresses the continuous loop on reduced-motion OR Immersion<Balanced OR document.hidden OR runtime STANDBY/SHUTDOWN/OFF -- no bespoke per-behaviour carve-out"

# 192.6  the gate is a single .core-still CSS rule pausing every continuous
#        animation as a group -- the state classes themselves are untouched
#        by it, so a state CHANGE still paints instantly even while paused
$cssStripped192 = [regex]::Replace($css192, '/\*[\s\S]*?\*/', '')
$coreStillRule192 = [regex]::Match($cssStripped192, '(?s)\.core-still[\s\S]*?\{[^\}]*\}').Value
Check (
    ($coreStillRule192 -match 'animation-play-state:\s*paused\s*!important') -and
    ($cssStripped192 -match '(?s)\.core-still,[\s\S]*\.c-ring,[\s\S]*\.c-heart')
) '192.6: .core-still pauses .c-ring/.c-heart/the fault overlay via animation-play-state:paused as one group (Protocol UI-10 gate-stacking)'

# 192.7  the AI-revs (#2) and connection (#3) behaviors reuse the Overseer's
#        OWN choke points rather than re-instrumenting transmitMessage()/
#        appendToChat() -- one new line each in setOverseerState()/onImmersionChange()
Check (
    ((Get-FunctionBody $core192 'setOverseerState') -match '_coreRefresh') -and
    ((Get-FunctionBody $core192 'onImmersionChange') -match '_coreRefresh')
) '192.7: setOverseerState() and onImmersionChange() both call _coreRefresh() (Protocol 22 -- reused, not re-instrumented)'

# 192.8  fault strain (#6) reuses ONE shared _readErrorLog() reader across
#        _updateFaultLamp()/renderServiceFaultConsole()/_coreRefresh() --
#        never a second source of truth for "how many faults are buffered"
$faultLampBody192 = Get-FunctionBody $core192 '_updateFaultLamp'
Check (
    ($core192 -match 'function _readErrorLog\(\)') -and
    ($faultLampBody192 -match 'renderServiceFaultConsole') -and
    ($faultLampBody192 -match '_coreRefresh') -and
    ((Get-FunctionBody $core192 'renderServiceFaultConsole') -match '_readErrorLog')
) '192.8: _updateFaultLamp() calls both renderServiceFaultConsole() and _coreRefresh(), and renderServiceFaultConsole() reads the SAME _readErrorLog() the core also reads'

# 192.9  radio-reactive (#10) hooks the ONE existing choke point
#        (_updateRadioUI, called by both startRadio()/stopRadio()) rather than
#        a second call site or a poll loop
Check ((Get-FunctionBody $audio192 '_updateRadioUI') -match '_coreRefresh') `
    '192.9: _updateRadioUI() (called by both startRadio()/stopRadio()) calls _coreRefresh() -- one choke point covers the whole radio lifecycle'

# 192.10  the OS Event Bus wiring (deferred to window.onload, the Suite 135
#         U7 boot-order lesson) subscribes runtime.state/level.up/data.write
$wireBody192 = Get-FunctionBody $core192 '_wireChassisCoreEventBusSubscribers'
Check (
    ($wireBody192 -match "RobcoEvents\.on\('runtime\.state', \(\) => _coreRefresh\(\)\)") -and
    ($wireBody192 -match "RobcoEvents\.on\('level\.up', \(\) => _coreFlare\(\)\)") -and
    ($wireBody192 -match "RobcoEvents\.on\('data\.write', \(\) => _coreDataPulse\(\)\)") -and
    ($core192 -match '_wireChassisCoreEventBusSubscribers\(\);')
) '192.10: _wireChassisCoreEventBusSubscribers() subscribes runtime.state->_coreRefresh, level.up->_coreFlare, data.write->_coreDataPulse, and is called from window.onload'

# 192.11  initChassisCore() paints the boot frame after the Ambient Runtime is
#         live (called AFTER initAmbientRuntime() in window.onload)
Check ($core192 -match '(?s)initAmbientRuntime\(\);.{0,200}initChassisCore\(\);') `
    '192.11: initChassisCore() is called from window.onload, after initAmbientRuntime() so the first paint reads a live runtime state'

# 192.12  save/sync write-pulse (#9) -- data.write is emitted from every write
#         path: the local slot save, and the three cloud paths (push, pull, overwrite)
$dataWriteCount192 = ([regex]::Matches($cloud192, "RobcoEvents\.emit\('data\.write'")).Count
Check (
    ($saves192 -match "RobcoEvents\.emit\('data\.write', \{ kind: 'local-save' \}\)") -and
    ($dataWriteCount192 -eq 3) -and
    ($cloud192 -match "kind: 'cloud-push'") -and
    ($cloud192 -match "kind: 'cloud-pull'")
) "192.12: 'data.write' is emitted from saveToSlot() (local-save) and from saveCurrentToCloud()/loadCloudSave()/overwriteCloudSave() (cloud-push x2 + cloud-pull) in cloud.js"

# 192.13  the one-shot flourishes (#8/#9/#13) all gate on _coreShouldAnimate()
#         and use the reflow-restart pattern so a repeated trigger restarts
#         cleanly (the Suite 135/162 precedent)
$oneShotBody192 = Get-FunctionBody $core192 '_coreOneShot'
Check (
    ($oneShotBody192 -match 'if \(!_coreShouldAnimate\(\)\) return;') -and
    ($oneShotBody192 -match 'void el\.offsetWidth') -and
    ($core192 -match 'function _coreFlare\(\)') -and
    ($core192 -match 'function _coreDataPulse\(\)') -and
    ($core192 -match 'function _coreTapPoke\(\)')
) '192.13: _coreFlare()/_coreDataPulse()/_coreTapPoke() all route through _coreOneShot(), which gates on _coreShouldAnimate() and force-reflows before re-adding the class (repeated triggers restart cleanly)'

# 192.14  tap-to-poke (#13) reuses the EXISTING hardware-SFX channel
#         (Protocol 7 -- playChipClick() already guards masterMute + the
#         hardwareSfx pref) rather than a new audio function
$tapPokeBody192 = Get-FunctionBody $core192 '_coreTapPoke'
Check (
    ($tapPokeBody192 -match 'playChipClick\(true\)') -and
    (-not ($tapPokeBody192 -match 'function playChipClick'))
) '192.14: _coreTapPoke() reuses the existing playChipClick() hardware-SFX function (Protocol 7), never a forked audio path'

# 192.15  zero campaign-state write -- none of the CHASSIS core functions
#         ever touch saveState()/robco_v8/state.<field>=
$coreFns192 = @('_coreRefresh', '_coreShouldAnimate', '_corePowerClass', '_coreOneShot', '_coreFlare', '_coreDataPulse', '_coreTapPoke', 'initChassisCore', 'showCoreHelpModal', 'renderServiceFaultConsole')
$offenders192 = @()
foreach ($n in $coreFns192) {
    try {
        $body = Get-FunctionBody $core192 $n
        if ($body -match 'saveState\(|robco_v8|state\.\w+\s*=') { $offenders192 += $n }
    } catch {
        $offenders192 += $n
    }
}
Check ($offenders192.Count -eq 0) `
    ('192.15: every LIVING CORE function is free of saveState()/robco_v8/state.<field>= writes' + $(if ($offenders192.Count) { ' -- offenders: ' + ($offenders192 -join ', ') } else { '' }))

# 192.16  mobile baseline (Protocol 17) -- the core button is well over the
#         28px tap-target floor, and the "?" explainer reuses the shared
#         >=28px .icon-btn-round (never a bespoke small target)
$coreShapeRule192 = [regex]::Match($cssStripped192, '\.chassis-core-shape\s*\{[^\}]*\}').Value
$coreShapeWMatch192 = [regex]::Match($coreShapeRule192, 'width:\s*(\d+)px')
$coreShapeW192 = if ($coreShapeWMatch192.Success) { [int]$coreShapeWMatch192.Groups[1].Value } else { 0 }
Check (
    ($coreShapeW192 -ge 28) -and
    ($html192 -match 'class="icon-btn-round core-help-btn"')
) "192.16: #chassisCore is ${coreShapeW192}px (>=28px Protocol 17 floor) and the ""?"" reuses the shared .icon-btn-round (>=28px)"

# 192.17  game-agnostic (Protocol 38) -- no FNV/FO3/Fallout literals in the
#         CHASSIS boards or the core's field-manual copy
$chassisIdx192 = $html192.IndexOf('id="unitPowerPlantPanel"')
$chassisEndIdx192 = $html192.IndexOf('</details>', $html192.IndexOf('id="serviceFaultConsolePanel"'))
$chassisBlock192 = $html192.Substring($chassisIdx192, $chassisEndIdx192 - $chassisIdx192)
Check (
    (-not ($chassisBlock192 -match '(?i)\bFNV\b|\bFO3\b|Fallout|New Vegas|Capital Wasteland')) -and
    (-not ((Get-FunctionBody $core192 'showCoreHelpModal') -match '(?i)\bFNV\b|\bFO3\b|Fallout|New Vegas|Capital Wasteland'))
) '192.17: the CHASSIS boards and the core help modal carry zero game literals -- device/OS fiction only'

# 192.18  BUS-22 UNIT POWER PLANT reuses the BUS-21 SERVICE TALLY's _odoTile()
#         digit-wheel helper verbatim (Protocol 22, no parallel drum-tile
#         implementation) and stamps the collapsed summary line
$overseerBody192 = Get-FunctionBody $core192 'renderOverseerLog'
Check (
    ($overseerBody192 -match '_odoTile') -and
    ($overseerBody192 -match "getElementById\('chassisPlantStatus'\)")
) '192.18: renderOverseerLog() renders BUS-22 hour meters via the shared _odoTile() helper and stamps #chassisPlantStatus'

# 192.19  BUS-23 IDENTITY PLATE & BREAKERS renders the serial plate + breaker
#         rack (CARRIER + every _SYSTEM_STATUS_FLAGS entry) and stamps the
#         collapsed summary line
$statusBody192 = Get-FunctionBody $core192 'renderSystemStatus'
Check (
    ($statusBody192 -match 'id-plate') -and
    ($statusBody192 -match 'breaker-rack') -and
    ($statusBody192 -match "_chassisBreaker\('CARRIER'") -and
    ($statusBody192 -match "getElementById\('chassisIdentityStatus'\)")
) '192.19: renderSystemStatus() renders the BUS-23 id-plate + a breaker-rack (CARRIER + every feature flag) and stamps #chassisIdentityStatus'

# 192.20  BUS-24 SERVICE & FAULT CONSOLE -- renderServiceFaultConsole() is
#         defined, updates every fault-annunciator element, and is called
#         from initChassisCore() (initial paint) as well as _updateFaultLamp()
$svcConsoleBody192 = Get-FunctionBody $core192 'renderServiceFaultConsole'
Check (
    ($svcConsoleBody192 -match "getElementById\('svcFaultCounter'\)") -and
    ($svcConsoleBody192 -match "getElementById\('svcFaultNum'\)") -and
    ($svcConsoleBody192 -match "getElementById\('svcFaultLast'\)") -and
    ($svcConsoleBody192 -match "getElementById\('chassisSvcStatus'\)") -and
    ((Get-FunctionBody $core192 'initChassisCore') -match 'renderServiceFaultConsole\(\)')
) '192.20: renderServiceFaultConsole() paints the fault counter/last-fault line/summary, and initChassisCore() calls it for the initial frame'

# 192.21  every CHASSIS board follows the Protocol UI-1 heading standard
#         (summary > h2 starting with ">") -- already covered generically by
#         Suite 88, reconfirmed directly here scoped to the three new boards
$plantSlice192 = [regex]::Match($html192, '(?s)id="unitPowerPlantPanel".{0,200}').Value
$idpSlice192 = [regex]::Match($html192, '(?s)id="systemStatusPanel">.{0,200}').Value
$svcSlice192 = [regex]::Match($html192, '(?s)id="serviceFaultConsolePanel">.{0,200}').Value
Check (
    ($plantSlice192 -match '(?s)<summary>\s*<h2>\s*&gt;') -and
    ($idpSlice192 -match '(?s)<summary>\s*<h2>\s*&gt;') -and
    ($svcSlice192 -match '(?s)<summary>\s*<h2>\s*&gt;')
) '192.21: BUS-22/23/24 each carry <summary><h2>> (Protocol UI-1 panel heading standard)'

# 192.22  UPDATED (owner follow-up): the mini core mirror was moved out of
#         the Overseer Uplink header into its own dedicated readout window
#         built into the casing-top header (#chassisScreenMini), which is
#         always visible -- WITHOUT altering the Overseer waveform
#         (#overseerScope) markup, and no longer present in .ovs-head
$casingTopBlock192 = [regex]::Match($html192, '(?s)<div class="casing-top">[\s\S]*?<div class="bezel">').Value
$ovsHeadBlock192 = [regex]::Match($html192, '(?s)<div class="ovs-head">[\s\S]*?</div>').Value
Check (
    ($casingTopBlock192 -match '(?s)<div\s+class="chassis-screen-mini"\s+id="chassisScreenMini"') -and
    ($casingTopBlock192.Contains('id="chassisCoreMini"')) -and
    (-not ($ovsHeadBlock192.Contains('id="chassisCoreMini"'))) -and
    ($html192 -match '<canvas id="overseerScope" aria-hidden="true"></canvas>')
) '192.22: #chassisCoreMini sits in its own #chassisScreenMini readout window inside the always-visible casing-top header (not the Overseer Uplink header), and the #overseerScope waveform canvas is untouched'

# 192.23  the casing-top screen is pushed to the right of the header (the
#         owner's requested placement) via margin-left:auto, and is sized to
#         actually be visible/legible rather than a near-invisible sliver
$screenRule192 = [regex]::Match($cssStripped192, '\.chassis-screen-mini\s*\{[^\}]*\}').Value
$screenWMatch192 = [regex]::Match($screenRule192, 'width:\s*(\d+)px')
$screenHMatch192 = [regex]::Match($screenRule192, 'height:\s*(\d+)px')
$screenW192 = if ($screenWMatch192.Success) { [int]$screenWMatch192.Groups[1].Value } else { 0 }
$screenH192 = if ($screenHMatch192.Success) { [int]$screenHMatch192.Groups[1].Value } else { 0 }
Check (
    ($screenRule192 -match 'margin-left:\s*auto') -and ($screenW192 -ge 30) -and ($screenH192 -ge 20)
) "192.23: .chassis-screen-mini is pushed to the right of the casing-top header (margin-left:auto) and sized to be legible (${screenW192}x${screenH192}px, not a near-invisible sliver)"

# 192.24  Protocol 42 regression guard -- a real overflow found live by the
#         gate's populated-save render-check: at the new 26px mini size, the
#         ring/heart children's percentage-inset + border positioning rounds
#         to a couple of stray px past the shape's own box. Two parts:
#         .chassis-core-shape visually clips its own bleed (overflow:hidden --
#         never visible, it's already a circle; .core-help-btn is a SIBLING
#         inside .chassis-core-shell, never a descendant, so it is unaffected)
#         AND the render-check's populated-save scrollWidth scan allowlists
#         the class (overflow:hidden alone does not change scrollWidth -- the
#         actual gate-passing fix).
$renderCheckSrc192 = Read-Src "tests/render-check.mjs"
Check (
    ($coreShapeRule192 -match 'overflow:\s*hidden') -and
    ($renderCheckSrc192 -match "cls\.includes\('chassis-core-shape'\)")
) "192.24: .chassis-core-shape clips its own ring/heart bleed (overflow:hidden) AND is allowlisted in render-check.mjs's populated-save scrollWidth scan (the harmless decorative-bleed category, matching the .facon-mini/.facon-scale precedent) -- fixes a real render-check-caught overflow at the small mini-core size, never affecting the sibling .core-help-btn"

# 192.25  Protocol 42 regression guard -- a real a11y regression found live by
#         the gate's axe scan: #chassisScreenMini is a plain, non-interactive
#         <div> whose implicit ARIA role is "generic", which does not support
#         aria-label (axe's aria-prohibited-attr rule) -- it must stay
#         aria-hidden with no naming attribute (a mouse-only title tooltip is
#         fine; that is not an ARIA attr).
$screenTag192 = [regex]::Match($html192, '(?s)<div[^>]*id="chassisScreenMini"[^>]*>').Value
Check (
    ($screenTag192 -match 'aria-hidden="true"') -and (-not ($screenTag192 -match 'aria-label='))
) '192.25: #chassisScreenMini is aria-hidden with no aria-label (a generic-role <div> cannot carry one -- axe aria-prohibited-attr)'

# 192.26  Protocol 42 regression guard -- a real live-render bug found during
#         render-verify: #chassisCoreMini carries BOTH .chassis-core-shape
#         (the shared 96px base) and .chassis-core-mini (its own size). A bare
#         `.chassis-core-mini { ... }` rule has the SAME specificity as
#         `.chassis-core-shape { ... }`, so whichever one sits LATER in the
#         file silently wins, regardless of which is "supposed to" override
#         the other -- this bit twice (the 26px base size, then the 20px
#         @media(max-width:480px) mobile shrink) before landing on the fix:
#         every mini-core SIZING rule must use the compound
#         .chassis-core-shape.chassis-core-mini selector (0,2,0), which always
#         beats the shared base (0,1,0) regardless of source order. The
#         .c-ring/.c-cap descendant overrides are unaffected (no competing
#         equal-specificity rule exists for them).
$compoundMiniCount192 = ([regex]::Matches($cssStripped192, '\.chassis-core-shape\.chassis-core-mini\s*\{')).Count
Check (
    ($compoundMiniCount192 -ge 2) -and
    (-not ($cssStripped192 -match '(?<!\.chassis-core-shape)\.chassis-core-mini\s*\{'))
) '192.26: every #chassisCoreMini sizing rule (base + the @media(max-width:480px) mobile shrink) uses the compound .chassis-core-shape.chassis-core-mini selector, never a bare .chassis-core-mini that would tie in specificity with .chassis-core-shape and silently lose by source order'

# 192.27  owner re-verification (Option A confirmed) -- #chassisScreenMini
#         sits inside the always-visible .casing-top header, which is
#         structurally OUTSIDE every tab-gated panel (no [data-tab] attribute
#         reaches it), so the mini core renders on every page, not just
#         SETTINGS/CHASSIS. Reuses the 192.22 $casingTopBlock192 slice
#         (casing-top through the bezel) and asserts it carries no
#         data-tab/panel gating of its own.
Check (
    ($casingTopBlock192 -match 'class="casing-top"') -and
    ($casingTopBlock192 -match 'id="chassisScreenMini"') -and
    ($casingTopBlock192 -match 'id="chassisCoreMini"') -and
    (-not ($casingTopBlock192 -match 'data-tab=')) -and
    (-not ($casingTopBlock192 -match 'class="panel'))
) '192.27: #chassisScreenMini/#chassisCoreMini sit inside .casing-top, which carries no data-tab gating and no panel wrapper -- the mini core is visible on every subsystem/page, not settings-only'

# 192.28  the Director Uplink header no longer hosts a second mini-core mirror
#         -- placement is singular (the casing-top screen only), so the two
#         views can never drift or double-render. Reuses the 192.22
#         $ovsHeadBlock192 slice.
Check (
    -not ($ovsHeadBlock192.Contains('id="chassisCoreMini"'))
) '192.28: the Director Uplink/Overseer header does not carry a second chassisCoreMini mirror -- the mini core lives ONLY in the casing-top screen'

# 192.29  #14 3D ring burst -- _coreStatBurst()/_emitStatChangeIfDiffers()
#         exist, the burst routes through the SAME gated _coreOneShot() every
#         other flourish uses (no bespoke reduced-motion carve-out), and the
#         RobcoEvents bus fires it on both level.up and a real stat.change.
$statBurstBody192 = Get-FunctionBody $core192 '_coreStatBurst'
Check (
    ($statBurstBody192 -match "_coreOneShot\('core-stat-burst'") -and
    ($wireBody192 -match "RobcoEvents\.on\('level\.up',\s*\(\)\s*=>\s*_coreStatBurst\(\)\)") -and
    ($wireBody192 -match "RobcoEvents\.on\('stat\.change',\s*\(\)\s*=>\s*_coreStatBurst\(\)\)")
) '192.29: _coreStatBurst() routes through the shared, gated _coreOneShot() and RobcoEvents wires BOTH level.up and stat.change to trigger it'

# 192.30  _emitStatChangeIfDiffers() only emits stat.change on a REAL value
#         change (not on every call/every render) -- a static shape check (old
#         !== undefined guard so the first-ever call per key never fires, and
#         old !== newVal so a same-value re-set never fires), plus every
#         drag-style stat setter (HP/XP/RAD bars, the skill VU meter) and the
#         onchange commitStat() path call it/emit directly.
$emitDiffersBody192 = Get-FunctionBody $core192 '_emitStatChangeIfDiffers'
$applyHpBody192 = Get-FunctionBody $core192 'setupHpBarInteraction'
$applyXpBody192 = Get-FunctionBody $core192 'setupXpBarInteraction'
$wireRadBody192 = Get-FunctionBody $core192 '_wireRadDragSurface'
$skillVuSetBody192 = Get-FunctionBody $core192 '_skillVuSet'
# commitStat() now delegates its clamp/emit to _nativeSetSpecial() (Native USE +
# TERMINAL stat-edits plan, Protocol 22) -- the 'stat.change' emit lives in the
# shared setter, reached from every commitStat() call.
$commitStatBody192 = Get-FunctionBody $core192 'commitStat'
$nativeSetSpecialBody192 = Get-FunctionBody $core192 '_nativeSetSpecial'
Check (
    ($emitDiffersBody192 -match 'old !== undefined') -and
    ($emitDiffersBody192 -match 'old !== newVal') -and
    ($emitDiffersBody192 -match "RobcoEvents\.emit\('stat\.change'") -and
    ($applyHpBody192 -match "_emitStatChangeIfDiffers\('hp',\s*newHp\)") -and
    ($applyXpBody192 -match "_emitStatChangeIfDiffers\('xp',\s*newXp\)") -and
    ($wireRadBody192 -match "_emitStatChangeIfDiffers\('rads',\s*newRads\)") -and
    ($skillVuSetBody192 -match "_emitStatChangeIfDiffers\('skill:'\s*\+\s*key,\s*v\)") -and
    ($commitStatBody192 -match '_nativeSetSpecial\(') -and
    ($nativeSetSpecialBody192 -match "RobcoEvents\.emit\('stat\.change'")
) '192.30: _emitStatChangeIfDiffers() only fires stat.change on a genuine value change (never the first-seen baseline, never a same-value re-set), and every drag-style stat setter plus commitStat() (via _nativeSetSpecial) feeds it/emits directly'

# 192.31  the 3D orbital burst is real CSS (rotateX/rotateY/rotateZ keyframes,
#         a distinct per-ring tumble via .core-stat-burst on the SAME
#         .chassis-core-shape shared by both the full core and the
#         casing-top mini core), and it is caught by the SAME .core-still gate
#         that already pauses every other .c-ring animation -- no second gate
#         was written for it.
Check (
    ($cssStripped192 -match 'rotateX') -and
    ($cssStripped192 -match 'rotateY') -and
    ($cssStripped192 -match 'rotateZ') -and
    ($cssStripped192 -match '\.chassis-core-shape\.core-stat-burst \.c-ring\.r1') -and
    ($cssStripped192 -match '\.chassis-core-shape\.core-stat-burst \.c-ring\.r3') -and
    ($cssStripped192 -match '(?s)\.core-still,[\s\S]*\.c-ring,[\s\S]*\.c-heart')
) '192.31: the 3D orbital burst (rotateX/rotateY/rotateZ per-ring keyframes on .core-stat-burst) applies to the same .chassis-core-shape used by both cores, and is stilled by the existing generic .core-still .c-ring gate -- no bespoke reduced-motion carve-out'

# 192.32  zero campaign-state write -- the new #14 functions never touch
#         saveState()/robco_v8/state.<field>= (extends the existing 192.15
#         guard to the new code).
Check (
    (-not ($statBurstBody192 -match 'saveState\(\)')) -and
    (-not ($statBurstBody192 -match 'robco_v8')) -and
    (-not ($emitDiffersBody192 -match 'saveState\(\)')) -and
    (-not ($emitDiffersBody192 -match 'robco_v8'))
) '192.32: _coreStatBurst()/_emitStatChangeIfDiffers() are free of saveState()/robco_v8 writes -- purely a transient in-memory/DOM flourish, extending the 192.15 zero-write guard'

# 192.33  owner prominence-pass follow-up -- the casing-top screen/mini-core
#         now scales across THREE size tiers (desktop base > the
#         >400-480px tier > the <=400px tier), each strictly bigger than the
#         last, and every tier is bigger than the pre-prominence-pass
#         baseline (44x34 screen / 26x26 core desktop, 36x28 / 20x20 old
#         mobile) -- locking the regression so a future edit can't quietly
#         shrink it back down.
$tier480Rule192 = [regex]::Match($cssStripped192, '(?s)@media \(max-width:\s*480px\)\s*\{[\s\S]*?\.chassis-screen-mini\s*\{([^\}]*)\}[\s\S]*?\.chassis-core-shape\.chassis-core-mini\s*\{([^\}]*)\}')
$tier480ScreenBody192 = $tier480Rule192.Groups[1].Value
$tier480CoreBody192 = $tier480Rule192.Groups[2].Value
$tier400Block192 = [regex]::Match($cssStripped192, '(?s)@media \(max-width:\s*400px\)\s*\{([\s\S]*?)\n\}').Groups[1].Value
$tier400ScreenBody192 = [regex]::Match($tier400Block192, '(?s)\.chassis-screen-mini\s*\{([^\}]*)\}').Groups[1].Value
$tier400CoreBody192 = [regex]::Match($tier400Block192, '(?s)\.chassis-core-shape\.chassis-core-mini\s*\{([^\}]*)\}').Groups[1].Value
$coreShapeMiniBaseBody192 = [regex]::Match($cssStripped192, '(?s)\.chassis-core-shape\.chassis-core-mini\s*\{([^\}]*)\}').Groups[1].Value
function Get-NumPx192($body, $prop) {
    $m = [regex]::Match($body, "$prop`:\s*(\d+)px")
    if ($m.Success) { return [int]$m.Groups[1].Value }
    return 0
}
$desktopScreenW192 = Get-NumPx192 $screenRule192 'width'
$desktopCoreW192 = Get-NumPx192 $coreShapeMiniBaseBody192 'width'
$tier480ScreenW192 = Get-NumPx192 $tier480ScreenBody192 'width'
$tier480CoreW192 = Get-NumPx192 $tier480CoreBody192 'width'
$tier400ScreenW192 = Get-NumPx192 $tier400ScreenBody192 'width'
$tier400CoreW192 = Get-NumPx192 $tier400CoreBody192 'width'
Check (
    ($desktopScreenW192 -gt $tier480ScreenW192) -and
    ($tier480ScreenW192 -gt $tier400ScreenW192) -and
    ($desktopCoreW192 -gt $tier480CoreW192) -and
    ($tier480CoreW192 -gt $tier400CoreW192) -and
    ($tier400ScreenW192 -gt 46) -and
    ($tier400CoreW192 -gt 27) -and
    ($desktopScreenW192 -ge 80) -and
    ($desktopCoreW192 -ge 44)
) "192.33: the casing-top screen/mini-core scale across three strictly-decreasing size tiers (desktop $desktopScreenW192/${desktopCoreW192}px > 401-480px tier $tier480ScreenW192/${tier480CoreW192}px > <=400px tier $tier400ScreenW192/${tier400CoreW192}px), and every tier is bigger than the pre-second-bump baseline (72/44px desktop, 46/27px old narrowest mobile)"

# 192.34  owner prominence-pass follow-up -- the 3D ring burst is now
#         substantially bigger and longer: every axis completes a full
#         720deg double rotation (not the old 360deg single swing), the CSS
#         animation-duration and the JS _coreOneShot() removal timeout both
#         move together (owner follow-up: 1.4s/1400 -> 1.8s/1800, "a bit
#         slower" for a more graceful tumble), and the burst also flares the
#         heart (paired with the ring tumble so the whole event reads as one
#         unmistakable flourish, not just the rings) via the same
#         box-shadow/transform mechanism every other one-shot flourish
#         already uses (Protocol 22).
$burstCssBlock192 = [regex]::Match($cssStripped192, '(?s)@keyframes chassisCoreOrbitBurst1[\s\S]*?\.chassis-core-shape\.core-stat-burst \.c-heart[\s\S]*?\}').Value
Check (
    ($burstCssBlock192 -match 'rotateX\(720deg\)') -and
    ($burstCssBlock192 -match 'rotateY\(720deg\)') -and
    ($burstCssBlock192 -match 'rotateZ\(720deg\)') -and
    ($burstCssBlock192 -match 'chassisCoreOrbitBurst1 1\.8s') -and
    ($burstCssBlock192 -match 'chassisCoreOrbitBurst3 1\.8s') -and
    ($statBurstBody192 -match "_coreOneShot\('core-stat-burst',\s*1800\)") -and
    ($burstCssBlock192 -match '(?s)\.core-stat-burst \.c-heart\s*\{[^\}]*box-shadow')
) '192.34: the 3D ring burst now completes a full 720deg double rotation on every axis over a matching 1.8s CSS/JS duration, and flares the heart alongside the ring tumble -- a substantially more prominent and graceful event than the old 360deg/900ms swing'

# 192.35  owner fluidity pass -- the previous 0/40/70/100 keyframes with an
#         overshoot "back" bezier bounced at every segment boundary, reading
#         as three chained snaps rather than one continuous tumble. Now
#         every burst keyframe is evenly spaced (0/25/50/75/100%) with each
#         axis value held EXACTLY proportional to its keyframe percent
#         (constant angular velocity, no per-segment speed changes), the
#         overshoot bezier is gone in favor of a smooth non-overshooting
#         ease-in-out applied to the whole span, and the always-animating
#         .c-ring gets will-change:transform so neither the burst nor the
#         continuous idle spin stutters off the GPU compositor.
$orbitBurst1KF192 = [regex]::Match($cssStripped192, '(?s)@keyframes chassisCoreOrbitBurst1\s*\{[\s\S]*?\n\}').Value
$evenlySpaced192 = (
    ($orbitBurst1KF192 -match '0%\s*\{') -and
    ($orbitBurst1KF192 -match '25%\s*\{') -and
    ($orbitBurst1KF192 -match '50%\s*\{') -and
    ($orbitBurst1KF192 -match '75%\s*\{') -and
    ($orbitBurst1KF192 -match '100%\s*\{')
)
$proportional192 = (
    ($orbitBurst1KF192 -match '(?s)25%\s*\{\s*transform:\s*rotateX\(180deg\)\s*rotateY\(180deg\)\s*rotateZ\(180deg\)') -and
    ($orbitBurst1KF192 -match '(?s)50%\s*\{\s*transform:\s*rotateX\(360deg\)\s*rotateY\(360deg\)\s*rotateZ\(360deg\)') -and
    ($orbitBurst1KF192 -match '(?s)75%\s*\{\s*transform:\s*rotateX\(540deg\)\s*rotateY\(540deg\)\s*rotateZ\(540deg\)')
)
$ringRule192 = [regex]::Match($cssStripped192, '\.chassis-core-shape \.c-ring\s*\{[^\}]*\}').Value
Check (
    $evenlySpaced192 -and
    $proportional192 -and
    ($burstCssBlock192 -match 'chassisCoreOrbitBurst1 1\.8s ease-in-out') -and
    ($burstCssBlock192 -match 'chassisCoreOrbitBurst3 1\.8s ease-in-out') -and
    (-not ($burstCssBlock192 -match 'cubic-bezier\(0\.34,\s*1\.56')) -and
    ($ringRule192 -match 'will-change:\s*transform')
) '192.35: the 3D ring burst keyframes are now evenly spaced with each axis held exactly proportional to its keyframe percent (constant angular velocity), driven by a smooth ease-in-out instead of the old overshoot "back" bezier, and the always-animating .c-ring carries will-change:transform for GPU compositing -- fixing the owner-reported choppy/jerky tumble'

# 192.36  owner follow-up -- always-on perpendicular 3D ring, CORRECTED to a
#         diagonal-axis tumble: a 4th ring, built as a ::before
#         pseudo-element (no HTML markup change, so both the full core AND
#         the casing-top mini core share it automatically via the same
#         .chassis-core-shape class, Protocol 22). The first attempt
#         (rotateX(90deg)+rotateY) was a flat ring spinning around the
#         vertical axis, not what the owner asked for; corrected to
#         rotate3d(1, 1, 0, deg), which spins around a DIAGONAL 3D axis so
#         the ring's two diagonal corner-pairs swap through depth as it
#         turns (upper-left/bottom-right <-> bottom-left/upper-right) -- a
#         genuine always-on diagonal 3D tumble, not just during the #14
#         stat-change burst. transform-only + linear infinite (matching the
#         r1/r3 idle-spin convention) + will-change keeps it GPU-composited.
#         preserve-3d on the shape lets it compose in the same 3D space as
#         the burst rings. The SAME .core-still gate (Protocol UI-10) stills
#         it -- no bespoke carve-out for this new continuous loop.
$beforeRule192 = [regex]::Match($cssStripped192, '\.chassis-core-shape::before\s*\{[^\}]*\}').Value
$orbitPerpKF192 = [regex]::Match($cssStripped192, '(?s)@keyframes chassisCoreOrbitPerp\s*\{[\s\S]*?\n\}').Value
$shapeBaseRule192 = [regex]::Match($cssStripped192, '\.chassis-core-shape\s*\{[^\}]*\}').Value
$coreStillGateRule192 = [regex]::Match($cssStripped192, '(?s)\.core-still,[\s\S]*?animation-play-state:\s*paused\s*!important;\s*\}').Value
Check (
    ($beforeRule192 -match 'content:\s*''''') -and
    ($beforeRule192 -match 'animation:\s*chassisCoreOrbitPerp') -and
    ($beforeRule192 -match 'infinite') -and
    ($beforeRule192 -match 'will-change:\s*transform') -and
    ($orbitPerpKF192 -match 'rotate3d\(1,\s*1,\s*0,\s*0deg\)') -and
    ($orbitPerpKF192 -match 'rotate3d\(1,\s*1,\s*0,\s*360deg\)') -and
    (-not ($orbitPerpKF192 -match 'rotateX\(90deg\)')) -and
    ($shapeBaseRule192 -match 'transform-style:\s*preserve-3d') -and
    ($coreStillGateRule192 -match '\.core-still::before')
) "192.36: an always-on perpendicular ring (.chassis-core-shape::before) now tumbles around a DIAGONAL 3D axis via rotate3d(1,1,0,deg) -- the corrected owner ask, swapping the ring's diagonal corner-pairs through depth rather than flatly spinning around the vertical axis -- is shared by both cores via the same base class, and is stilled by the SAME .core-still gate as everything else -- no bespoke carve-out"

# 192.37  SUPERSEDED by the big/mini visual-parity fix (see the updated
#         assertion below): a flat 130px mini perspective, never adjusted
#         per responsive tier, drifted the perspective-to-size RATIO far
#         narrower than the full core's constant 200/96 ratio as the mini
#         shrank on phones -- the actual reason the two cores never looked
#         alike. This now locks the CORRECTED contract: the mini core's
#         desktop-tier perspective (54px) holds the SAME ~2.08x ratio to
#         its own size that the full core (200px/96px) does.
# Negative lookbehind excludes the "body "-prefixed responsive-tier
# overrides (Suite 195 unit) so this grabs the desktop-tier base rule.
$miniPerspRule192 = [regex]::Match($cssStripped192, '(?<!body )\.chassis-core-shape\.chassis-core-mini\s*\{\s*perspective:\s*(\d+)px').Groups[1].Value
if (-not $miniPerspRule192) { $miniPerspRule192 = '0' }
$fullPerspRule192 = [regex]::Match($cssStripped192, '\.chassis-core-shape\s*\{\s*perspective:\s*(\d+)px').Groups[1].Value
if (-not $fullPerspRule192) { $fullPerspRule192 = '0' }
# Three .chassis-core-shape.chassis-core-mini::before rules now exist -- the
# two responsive-tier overrides (480px/400px media blocks, EARLIER in file
# order) plus the base desktop-tier (54px) rule LAST in file order -- so
# take the LAST match, which is always the base rule.
$miniBeforeBoostMatches192 = [regex]::Matches($cssStripped192, '\.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*\}')
$miniBeforeBoostRule192 = ''
if ($miniBeforeBoostMatches192.Count -gt 0) { $miniBeforeBoostRule192 = $miniBeforeBoostMatches192[$miniBeforeBoostMatches192.Count - 1].Value }
$miniBoostBorderW192 = [int]([regex]::Match($miniBeforeBoostRule192, 'border-width:\s*(\d+)px').Groups[1].Value)
$fullPerpBorderWMatch192 = [regex]::Match($beforeRule192, 'border(?:-width)?:\s*(\d+)px')
$fullPerpBorderW192 = 0
if ($fullPerpBorderWMatch192.Success) { $fullPerpBorderW192 = [int]$fullPerpBorderWMatch192.Groups[1].Value }
$fullRatio192 = [double]$fullPerspRule192 / 96
$miniRatio192 = [double]$miniPerspRule192 / 54
Check (
    ([int]$miniPerspRule192 -ge 100) -and
    ([Math]::Abs($miniRatio192 - $fullRatio192) -lt 0.15) -and
    ($miniBeforeBoostRule192 -match 'border-color:\s*rgba\(var\(--robco-green-rgb\),\s*0\.8\)')
) "192.37: the mini core's desktop-tier perspective (${miniPerspRule192}px / 54px = $([Math]::Round($miniRatio192,2))x) now holds the SAME ratio as the full core's (${fullPerspRule192}px / 96px = $([Math]::Round($fullRatio192,2))x) -- a flat, per-tier-unadjusted 130px previously drifted the ratio far narrower on phones, which was the real reason the two cores never visually matched -- and the mini ring keeps its own higher-contrast border color"

# 192.38  Owner correction: "wider" was misread as bigger diameter -- the
#         actual ask was a THICKER, genuinely 3D band (a torus/sphere-shell
#         with volume), and the previous inset:6% (an 88%-diameter ellipse)
#         was reported as oversized, especially in the cramped mini screen.
#         The ring's diameter is now SMALLER (inset raised to 20%, nesting
#         between r1 at 100% and r3 at 44%), its border is a genuinely
#         thick band, and a box-shadow pair shades it like a lit, rounded
#         tube. The mini core's border-width is now deliberately SMALLER
#         than the full core's (not bigger) -- matching the SAME ~15-17%
#         border-to-diameter ratio at every size is the actual parity fix.
$fullPerpInsetMatch192 = [regex]::Match($beforeRule192, 'inset:\s*(\d+)%')
$fullPerpInset192 = 100
if ($fullPerpInsetMatch192.Success) { $fullPerpInset192 = [int]$fullPerpInsetMatch192.Groups[1].Value }
$hasVolumeShadow192 = [System.Text.RegularExpressions.Regex]::IsMatch($beforeRule192, "(?s)box-shadow:\s*\n?\s*inset[^;]*,\s*\n?\s*inset[^;]*,\s*\n?\s*0 0[^;]*rgba\(var\(--robco-green-rgb\)")
Check (
    ($fullPerpInset192 -ge 15) -and ($fullPerpInset192 -lt 44) -and
    ($fullPerpBorderW192 -ge 7) -and
    ($miniBoostBorderW192 -ge 3) -and
    ($miniBoostBorderW192 -lt $fullPerpBorderW192) -and
    $hasVolumeShadow192
) "192.38: the always-on perpendicular ring's DIAMETER shrank (inset raised to ${fullPerpInset192}%, nesting between r1/r3 rather than nearly filling the shape) while its border became a genuinely thick band (${fullPerpBorderW192}px full / ${miniBoostBorderW192}px mini, proportionally matched -- mini deliberately thinner in absolute px, not thicker) shaded by an inset+outer box-shadow trio so it reads as a lit 3D tube, not a flat wide ellipse -- the owner's thicker-not-wider correction"

# 192.39  owner follow-up -- the full core had one more ring (r2) than the
#         mini core ever carried, reading as cluttered and making the two
#         cores visually mismatched. r2 was removed from the full core's
#         markup entirely (never added to the mini, since the mini never
#         had it) so BOTH cores now render the exact same ring set: r1, r3,
#         and the shared .chassis-core-shape::before perpendicular ring.
#         Sync is structural, not per-core: both #chassisCore and
#         #chassisCoreMini elements carry the SAME class-based rules
#         (chassisCoreSpin durations, the ::before diagonal tumble), with no
#         ID-scoped override anywhere that could desync one core's rotation
#         from the other's -- and _coreShells()/_coreRefresh()/
#         _coreOneShot() (checked earlier in this suite) always update
#         every .chassis-core-shape element in the same synchronous pass, so
#         a state change always lands on both cores at once.
$coreBtnBlock192 = [regex]::Match($html192, '(?s)<button[^>]*id="chassisCore"[^>]*>[\s\S]*?</button>').Value
$miniSpanBlock192 = [regex]::Match($html192, '(?s)<span[^>]*id="chassisCoreMini"[^>]*>[\s\S]*?</span>\s*</span>').Value
$fullRingIds192 = ([regex]::Matches($coreBtnBlock192, 'c-ring r\d') | ForEach-Object { $_.Value -replace 'c-ring ', '' } | Sort-Object)
$miniRingIds192 = ([regex]::Matches($miniSpanBlock192, 'c-ring r\d') | ForEach-Object { $_.Value -replace 'c-ring ', '' } | Sort-Object)
Check (
    ($fullRingIds192.Count -eq 2) -and
    (($fullRingIds192 -join ',') -eq ($miniRingIds192 -join ',')) -and
    (-not ($html192 -match 'c-ring r2')) -and
    (-not ($cssStripped192 -match '\.c-ring\.r2\b')) -and
    (-not ($cssStripped192 -match '#chassisCore\s*\.c-ring|#chassisCoreMini\s*\.c-ring'))
) "192.39: the full core and mini core now render the IDENTICAL ring set ($($fullRingIds192 -join ',') on both -- the redundant r2 removed entirely, not just from one core), with zero ID-scoped per-core animation override anywhere that could desync their rotation"

# ===========================================================
# Suite 193 -- Owner polish batch: tap-highlight kill + CURIO ARCHIVE
# Lincoln side-by-side grid (the OPERATIONAL TEMPO live-readout-while-
# dragging fix from this same batch is covered by Suite 180.13). Item 1:
# the browser's own default tap/active highlight box flashed on the real
# <button> underneath every dressed control (worst on the CHASSIS living
# core) -- fixed via -webkit-tap-highlight-color:transparent on a broad
# selector, :focus-visible left fully intact. Item 2: the FO3 Lincoln
# relics stacked one-per-row instead of side by side -- root cause: the
# disposition <select> sized itself to its widest OPTION content
# (width:auto, ~234px), forcing every "found" cell far wider than the 88px
# object button. Fixed by pinning the Lincoln cell to a fixed compact
# width (min-width:0 to escape the flexbox min-width:auto trap). (PS
# mirror of JS Suite 193.)
# 8 tests
# ===========================================================
Sep "Suite 193 -- Owner polish batch: tap-highlight kill + Lincoln side-by-side grid"
$html193 = Read-Src "index.html"
$css193 = Read-Src "css/terminal.css"
$cssStripped193 = [regex]::Replace($css193, '/\*[\s\S]*?\*/', '')

# 193.1  -webkit-tap-highlight-color:transparent is declared on a broad
#        base selector (html) so the native tap/active highlight overlay
#        never shows.
$htmlRuleMatch193 = [regex]::Match($cssStripped193, '(?m)^html\s*\{[^\}]*\}')
$htmlRule193 = if ($htmlRuleMatch193.Success) { $htmlRuleMatch193.Value } else { '' }
Check (
    $htmlRule193 -match '-webkit-tap-highlight-color:\s*transparent'
) '193.1: html { -webkit-tap-highlight-color: transparent } suppresses the browser default tap/active highlight box app-wide'

# 193.2  the same suppression is repeated directly on every interactive
#        element type (button/a/summary/select/[role=button]/[role=tab])
#        as belt-and-suspenders for engines that key off the element
#        itself rather than the inherited/root value.
$broadRuleMatch193 = [regex]::Match($cssStripped193, "button,\s*a,\s*summary,\s*select,\s*\[role='button'\],\s*\[role='tab'\]\s*\{([^\}]*)\}")
$broadRule193 = if ($broadRuleMatch193.Success) { $broadRuleMatch193.Groups[1].Value } else { '' }
Check (
    $broadRule193 -match '-webkit-tap-highlight-color:\s*transparent'
) '193.2: button/a/summary/select/[role=button]/[role=tab] each get -webkit-tap-highlight-color:transparent directly, not just via html inheritance'

# 193.3  the CHASSIS living core's own tap-to-poke button explicitly
#        neutralises the tap highlight too -- the owner's specifically
#        named worst-offender, where the highlight washed out the core's
#        own pulse.
$coreShapeRuleMatch193 = [regex]::Match($cssStripped193, '(?s)button\.chassis-core-shape\s*\{([^\}]*)\}')
$coreShapeRule193 = if ($coreShapeRuleMatch193.Success) { $coreShapeRuleMatch193.Groups[1].Value } else { '' }
Check (
    $coreShapeRule193 -match '-webkit-tap-highlight-color:\s*transparent'
) '193.3: button.chassis-core-shape (the CHASSIS living core tap-to-poke control) declares its own -webkit-tap-highlight-color:transparent'

# 193.4  regression guard: :focus-visible keyboard focus rings (Protocol
#        17) are untouched -- the tap-highlight fix must never also
#        suppress KEYBOARD focus visibility.
Check (
    ($css193 -match 'button:focus-visible,') -and
    ($css193 -match 'outline:\s*2px solid var\(--robco-green\)')
) '193.4: the button:focus-visible keyboard-focus ring rule still exists -- the tap-highlight fix only removes the mouse/touch active overlay, never keyboard focus visibility'

# 193.5  CURIO ARCHIVE: the Lincoln cell is pinned to a fixed, compact
#        width (with min-width:0 to escape the flexbox min-width:auto
#        trap) so it can never be forced wide by its disposition
#        <select>'s own content-based sizing -- the Protocol 27 root
#        cause of the one-per-row stacking bug.
$lincCellRuleMatch193 = [regex]::Match($cssStripped193, '(?s)\.curio-caselist--linc \.curio-cell\s*\{([^\}]*)\}')
$lincCellRule193 = if ($lincCellRuleMatch193.Success) { $lincCellRuleMatch193.Groups[1].Value } else { '' }
$widthMatch193 = [regex]::Match($lincCellRule193, '(?:^|\s)width:\s*(\d+)px')
$widthPx193 = if ($widthMatch193.Success) { [int]$widthMatch193.Groups[1].Value } else { 0 }
Check (
    ($widthPx193 -ge 100) -and ($widthPx193 -le 160) -and
    ($lincCellRule193 -match 'min-width:\s*0\b') -and
    ($lincCellRule193 -match 'flex:\s*0 0 \d+px')
) "193.5: .curio-caselist--linc .curio-cell is pinned to a fixed compact width (${widthPx193}px, in the 100-160px range two fit side by side at 360px) with min-width:0 so it never grows to fit its select's own content"

# 193.6  the disposition <select> now sizes to its CELL (width:100%,
#        min-width:0) instead of its own widest-option content, with
#        ellipsis handling any label too long for that compact width --
#        the old width:auto/min-width:64px content-sizing contract (which
#        forced the one-per-row bug) is gone.
$dispRuleMatch193 = [regex]::Match($cssStripped193, '(?s)\.curio-linc-disposition\s*\{([^\}]*)\}')
$dispRule193 = if ($dispRuleMatch193.Success) { $dispRuleMatch193.Groups[1].Value } else { '' }
Check (
    ($dispRule193 -match 'width:\s*100%') -and
    ($dispRule193 -match 'min-width:\s*0\b') -and
    ($dispRule193 -match 'overflow:\s*hidden') -and
    ($dispRule193 -match 'text-overflow:\s*ellipsis') -and
    ($dispRule193 -match 'white-space:\s*nowrap') -and
    (-not ($dispRule193 -match 'width:\s*auto')) -and
    (-not ($dispRule193 -match 'min-width:\s*64px'))
) '193.6: .curio-linc-disposition sizes to its cell (width:100%, min-width:0) with overflow/text-overflow/white-space ellipsis handling -- no longer auto-sizes to its widest option content'

# 193.7  Protocol 17 mobile-baseline floors are not sacrificed to chase
#        the new compact width: font-size still >=16px (prevents iOS/
#        Android focus auto-zoom), min-height still >=28px (tap target).
$fontSizeMatch193 = [regex]::Match($dispRule193, 'font-size:\s*(\d+)px')
$minHeightMatch193 = [regex]::Match($dispRule193, 'min-height:\s*(\d+)px')
$fontSizePx193 = if ($fontSizeMatch193.Success) { [int]$fontSizeMatch193.Groups[1].Value } else { 0 }
$minHeightPx193 = if ($minHeightMatch193.Success) { [int]$minHeightMatch193.Groups[1].Value } else { 0 }
Check (
    ($fontSizePx193 -ge 16) -and ($minHeightPx193 -ge 28)
) '193.7: .curio-linc-disposition keeps font-size >=16px and min-height >=28px (Protocol 17) even after the compact-width fix'

# 193.8  structural guard: #lincolnMemorabiliaDisplay still sits inside
#        .curio-caselist.curio-caselist--linc (the exact selector the
#        193.5 grid fix scopes to) -- if this wrapper class were ever
#        renamed/removed, the compact-width rule would silently stop
#        applying and the one-per-row bug could recur unnoticed.
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($html193, '(?s)class="curio-caselist curio-caselist--linc"[\s\S]{0,150}id="lincolnMemorabiliaDisplay"')
) '193.8: #lincolnMemorabiliaDisplay is still wrapped by .curio-caselist.curio-caselist--linc, the exact scope the Lincoln-only compact-cell/select rules (193.5/193.6) target'

# ===========================================================
# Suite 194 -- CHASSIS LIVING CORE: 10 owner-approved new behaviors
# (batch 2). #1 thermal glow, #2 energy sparks, #3 spin inertia, #4
# power-surge ripple, #5 idle flares, #6 reactor hum (a second
# synthesized WebAudio channel), #7 recovery animation, #8 uptime-
# milestone pulse, #9 tap-and-hold overcharge. #10 (a center readout
# glyph) was evaluated and DROPPED -- it could not be made legible on the
# small casing-top mini core (33-54px, already sharing its circle with 3
# rings + the heart) without hurting the design; guarded here by a
# negative check that no half-shipped readout markup exists. (PS mirror
# of JS Suite 194.)
# 21 tests
# ===========================================================
Sep "Suite 194 -- CHASSIS LIVING CORE: 10 owner-approved new behaviors (batch 2)"
$html194 = Read-Src "index.html"
$css194 = Read-Src "css/terminal.css"
$cssStripped194 = [regex]::Replace($css194, '/\*[\s\S]*?\*/', '')
$core194 = Read-Src "js/ui-core.js"
$audio194 = Read-Src "js/ui-audio.js"
$state194 = Read-Src "js/state.js"

# 194.1  #1 thermal glow: a real activity-derived accumulator (_coreTemp),
#        mutated ONLY by _coreThermalTick() (never by _coreRefresh(),
#        which just paints it), registered as a dial-gated AmbientRuntime
#        observer on the awake states -- never a bare setInterval.
Check (
    ($core194 -match 'let _coreTemp = 0;') -and
    ($core194 -match 'function _coreThermalTick\(\)') -and
    ($core194 -match [regex]::Escape('_coreTemp = busy ? Math.min(100, _coreTemp + 8) : Math.max(0, _coreTemp - 5)')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "id: 'core-thermal',\s*`n\s*states: \['ACTIVE', 'IDLE'\],\s*`n\s*tier: 'balanced',\s*`n\s*cadenceMs: 4000,\s*`n\s*onTick: _coreThermalTick,"))
) "194.1: _coreTemp is a real activity-derived accumulator, mutated only by _coreThermalTick() (thinking/radio/fault -> warm, otherwise cool), registered as a dial-gated 'core-thermal' AmbientRuntime observer on ACTIVE/IDLE -- never a bare polling timer"

# 194.2  #1 thermal tint rides filter:hue-rotate() on .c-heart (optic-
#        agnostic), and _coreRefresh() only READS _coreTemp to paint
#        core-temp-warm/-hot, never mutates it.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-temp-warm \.c-heart\s*\{\s*filter:\s*hue-rotate\(-?\d+deg\)')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-temp-hot \.c-heart\s*\{\s*filter:\s*hue-rotate\(-?\d+deg\)')) -and
    ($cssStripped194 -match 'filter 1\.2s ease') -and
    ($core194 -match [regex]::Escape('const tempWarm = _coreTemp >= 34 && _coreTemp < 67;')) -and
    ($core194 -match [regex]::Escape('const tempHot = _coreTemp >= 67;'))
) '194.2: the warm/hot thermal tiers tint .c-heart via filter:hue-rotate() (rides whatever optic colour is active, Protocol 38/optic-agnostic) eased by a 1.2s transition, and _coreRefresh() only reads _coreTemp to choose the tier'

# 194.3  #2 energy sparks: the SAME two-span markup (s1 always-on, s2
#        busy-only) exists on BOTH #chassisCore and #chassisCoreMini
#        (Protocol 22 -- one shared child set, never a per-core fork).
$s1Count194 = ([regex]::Matches($html194, 'class="c-spark s1"')).Count
$s2Count194 = ([regex]::Matches($html194, 'class="c-spark s2"')).Count
Check (
    ($s1Count194 -eq 2) -and ($s2Count194 -eq 2)
) '194.3: both #chassisCore and #chassisCoreMini carry the identical c-spark s1/s2 markup (Protocol 22 -- one shared child set, never a per-core fork)'

# 194.4  #2 sparks orbit via the classic rotate()+translateX() technique
#        (no wrapper element), scaled down for the mini core so the orbit
#        stays inside its own smaller box, and s2 is hidden at rest --
#        only busy states reveal it.
Check (
    ($cssStripped194 -match '@keyframes chassisCoreOrbitDot') -and
    ($cssStripped194 -match [regex]::Escape('translateX(var(--spark-r, 40px))')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-mini \.c-spark\s*\{[^\}]*--spark-r:\s*15px')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape \.c-spark\.s2\s*\{[^\}]*opacity:\s*0;')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($css194, "\.core-thinking \.c-spark\.s2,\s*`n\.chassis-core-shape\.core-overclock \.c-spark\.s2,\s*`n\.chassis-core-shape\.core-temp-hot \.c-spark\.s2\s*\{"))
) '194.4: sparks orbit via rotate()+translateX(--spark-r) (no wrapper element needed), --spark-r is scaled down for the mini core so the orbit stays inside its smaller box, and the second spark is hidden at rest -- only thinking/overclock/hot-thermal reveal it (density tracks real activity)'

# 194.5  #2 gate: .c-spark is added to the SAME .core-still pause list
#        every other continuous LIVING CORE element already uses.
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch($css194, "\.core-still,\s*`n\.core-still \.c-ring,\s*`n\.core-still \.c-heart,\s*`n\.core-still \.c-spark,")
) '194.5: .c-spark is paused by the SAME .core-still gate group as .c-ring/.c-heart -- no bespoke reduced-motion/low-immersion/hidden-tab/standby carve-out'

# 194.6  #3 spin inertia: --core-spin-mul-r1/-r3 are registered as
#        INTERPOLATABLE @property custom properties (numeric, initial 1),
#        and the base .chassis-core-shape rule transitions them.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, "@property --core-spin-mul-r1\s*\{\s*syntax:\s*'<number>';\s*inherits:\s*true;\s*initial-value:\s*1;\s*\}")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, "@property --core-spin-mul-r3\s*\{\s*syntax:\s*'<number>';\s*inherits:\s*true;\s*initial-value:\s*1;\s*\}")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($css194, "--core-spin-mul-r1 1\.6s ease,\s*`n\s*--core-spin-mul-r3 1\.6s ease;"))
) "194.6: --core-spin-mul-r1/-r3 are registered via @property as interpolatable numbers (initial-value 1), and .chassis-core-shape transitions both over 1.6s -- the multiplier easing IS the spin-inertia effect (progressive enhancement: unsupported browsers just keep the old instant snap)"

# 194.7  #3 the r1/r3 ring animation-duration is computed from the
#        multiplier via calc(), replacing the old hardcoded per-state
#        animation-duration snaps -- core-boot/standby/thinking/overclock
#        now set ONLY the multiplier for r1/r3, never a raw
#        animation-duration.
Check (
    ($cssStripped194 -match [regex]::Escape('animation: chassisCoreSpin calc(14s / var(--core-spin-mul-r1)) linear infinite;')) -and
    ($cssStripped194 -match [regex]::Escape('animation: chassisCoreSpin calc(9s / var(--core-spin-mul-r3)) linear infinite reverse;')) -and
    (-not ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-boot \.c-ring\.r1\s*\{\s*animation-duration'))) -and
    (-not ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-thinking \.c-ring\.r1\s*\{\s*animation-duration'))) -and
    (-not ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-overclock \.c-ring\.r1\s*\{\s*animation-duration')))
) '194.7: r1/r3 animation-duration is calc()-driven from --core-spin-mul-r1/-r3 (re-read live), and core-boot/thinking/overclock no longer set a raw animation-duration on r1 directly -- the multiplier is the one source of truth'

# 194.8  #3 regression-safety: every per-state multiplier reproduces the
#        EXACT original target duration (14s/9s base) that shipped before
#        this unit -- the ramp is new, the destination speeds are not.
function Get-Mul194([string]$stateClass, [string]$prop) {
    $m = [regex]::Match($cssStripped194, "\.${stateClass}\s*\{[^\}]*${prop}:\s*([\d.]+)")
    if ($m.Success) { return [double]$m.Groups[1].Value } else { return $null }
}
$allClose194 = $true
$wantR1_194 = @{ 'core-boot' = 2.2; 'core-standby' = 40; 'core-thinking' = 3; 'core-overclock' = 1.6 }
$wantR3_194 = @{ 'core-boot' = 1.4; 'core-standby' = 26; 'core-thinking' = 2; 'core-overclock' = 1 }
foreach ($k in $wantR1_194.Keys) {
    $mr1 = Get-Mul194 $k '--core-spin-mul-r1'
    $mr3 = Get-Mul194 $k '--core-spin-mul-r3'
    if (($null -eq $mr1) -or ([Math]::Abs((14 / $mr1) - $wantR1_194[$k]) -gt 0.01)) { $allClose194 = $false }
    if (($null -eq $mr3) -or ([Math]::Abs((9 / $mr3) - $wantR3_194[$k]) -gt 0.01)) { $allClose194 = $false }
}
Check (
    $allClose194
) '194.8: every core-boot/standby/thinking/overclock multiplier reproduces the exact pre-existing r1 (14s base) and r3 (9s base) target durations to within 0.01s -- regression-safe, only the ramp BETWEEN targets is new'

# 194.9  #4 power-surge ripple: a dedicated .c-ripple child (not ::after)
#        exists identically on both cores, with its own expanding-then-
#        fading keyframes.
$rippleCount194 = ([regex]::Matches($html194, 'class="c-ripple"')).Count
Check (
    ($rippleCount194 -eq 2) -and
    ($cssStripped194 -match '@keyframes chassisCoreRipple') -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-ripple \.c-ripple\s*\{\s*animation:\s*chassisCoreRipple'))
) "194.9: both cores carry an identical .c-ripple child (Protocol 22, never sharing the fault ring's ::after) driven by a dedicated expanding/fading chassisCoreRipple keyframe"

# 194.10  #4 the ripple fires on the SAME data.write/level.up signals the
#         core already reacts to, PLUS a reconnect edge computed inside
#         _coreRefresh() itself -- never a new/invented trigger.
Check (
    ($core194 -match [regex]::Escape("RobcoEvents.on('level.up', () => _coreRipple());")) -and
    ($core194 -match [regex]::Escape("RobcoEvents.on('data.write', () => _coreRipple());")) -and
    ($core194 -match [regex]::Escape('const justReconnected = _lastCoreDisconnected && !disconnected;')) -and
    ($core194 -match [regex]::Escape("if (justReconnected) _coreOneShot('core-ripple', 900);"))
) "194.10: the ripple is wired to the EXISTING level.up/data.write RobcoEvents signals plus a reconnect edge (_lastCoreDisconnected -> !disconnected) computed inside _coreRefresh() itself -- Protocol 22, no invented trigger"

# 194.11  #5 idle flares: a dial-gated, non-persisted AmbientRuntime
#         observer mirroring the DO-O Overseer idle-blip timer exactly.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "id: 'core-idle-flare',\s*`n\s*states: \['IDLE'\],\s*`n\s*tier: 'balanced',\s*`n\s*cadenceMs: 42000,")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "if \(Math\.random\(\) > 0\.5\) return;\s*`n\s*_coreOneShot\('core-idle-flare', 1100\);")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-idle-flare \.c-heart\s*\{'))
) "194.11: 'core-idle-flare' is a dial-gated ('balanced' tier), non-persisted AmbientRuntime observer that only runs during genuine IDLE, firing a faint faded flare roughly half the time -- mirrors the DO-O Overseer idle-blip timer pattern exactly (Protocol 22)"

# 194.12  #6 reactor hum: its own Protocol-7 audio channel -- masterMute
#         guarded first, then its own mute pref -- tuned to a
#         perfect-fifth (90Hz) above the CRT hum's 60Hz fundamental.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($audio194, "function startReactorHum\(\) \{\s*`n\s*if \(reactorHumNode \|\| AudioSettings\.masterMute \|\| AudioSettings\.reactorHum\) return;")) -and
    ($audio194 -match [regex]::Escape("reactorHumNode.frequency.value = 90; // perfect fifth above the CRT hum's 60Hz fundamental")) -and
    ($state194 -match [regex]::Escape("robco_reactorhum_muted: { type: 'bool', default: false, owner: 'ui-audio.js' }")) -and
    ($core194 -match [regex]::Escape("reactorHum: MetaStore.get('robco_reactorhum_muted') === 'true'"))
) "194.12: startReactorHum() guards masterMute THEN its own AudioSettings.reactorHum pref (Protocol 7, same order as every sibling channel), is tuned to 90Hz -- a perfect fifth (3:2 ratio) above the CRT hum's 60Hz fundamental so the two blend harmonically -- and robco_reactorhum_muted is a registered META_MANIFEST device pref seeded into AudioSettings"

# 194.13  #6 reactor hum has its own CH-14 chip in the SLOT 02 SONIC
#         PROCESSOR board, wired through the SAME toggleAudio() choke
#         point every sibling channel already uses.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($html194, '(?s)id="muteReactorHumToggle"[\s\S]{0,80}onchange="toggleAudio\(''robco_reactorhum_muted'', this\.checked\)"')) -and
    ($html194 -match 'CH-14') -and
    ($audio194 -match [regex]::Escape("robco_reactorhum_muted: 'reactorHum', // LIVING CORE #6: reactor hum"))
) "194.13: the CH-14 REACTOR HUM chip routes through the SAME toggleAudio() choke point (Protocol 22), and robco_reactorhum_muted is in toggleAudio's mute-flag keyMap"

# 194.14  #6 toggleMasterMute() silences/resumes the reactor hum exactly
#         like it already does for the CRT hum and radio.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($audio194, "if \(reactorHumGain\) \{\s*`n\s*reactorHumGain\.gain\.linearRampToValueAtTime\(0, audioCtx\.currentTime \+ 0\.3\);\s*`n\s*\}")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($audio194, "if \(!reactorHumNode && !AudioSettings\.reactorHum\) \{\s*`n\s*startReactorHum\(\);"))
) '194.14: toggleMasterMute() ramps the reactor hum to silence on mute and resumes it (only if its own channel pref is still on) on unmute -- mirrors the existing CRT hum/radio master-mute handling exactly'

# 194.15  #6 the hum's live intensity is driven from _coreRefresh()'s own
#         already-computed activity signals, and reads the
#         CHASSIS-subsystem-active signal for the louder-on-CHASSIS
#         requirement.
Check (
    ($audio194 -match [regex]::Escape('function _updateReactorHumLevel(thinking, radioOn, hasFault)')) -and
    ($audio194 -match [regex]::Escape("document.body.dataset.subsystem === 'chassis'")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "if \(typeof _updateReactorHumLevel === 'function'\) \{\s*`n\s*_updateReactorHumLevel\(thinking, radioOn, faultCount > 0\);"))
) "194.15: _updateReactorHumLevel() is called from _coreRefresh() with the SAME thinking/radioOn/faultCount signals already computed there (never a second polling loop), and reads document.body.dataset.subsystem === 'chassis' to go louder while CHASSIS is the active view"

# 194.16  #7 recovery animation: a one-shot stabilize transition fires
#         exactly when a buffered fault count transitions from >0 to 0.
Check (
    ($core194 -match [regex]::Escape('const justRecovered = _lastCoreFaultCount > 0 && faultCount === 0;')) -and
    ($core194 -match [regex]::Escape("if (justRecovered) _coreOneShot('core-recovering', 1200);")) -and
    ($cssStripped194 -match '@keyframes chassisCoreRecover') -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-recovering::after\s*\{'))
) '194.16: core-recovering fires as a one-shot exactly on the fault-count >0 -> 0 edge (never every repaint), safely reusing ::after because core-fault is already removed in the same _coreRefresh() pass before core-recovering is applied'

# 194.17  #8 uptime-milestone pulse: fires exactly once per crossed hour.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "if \(h > _lastCoreUptimeMilestone\) \{\s*`n\s*_lastCoreUptimeMilestone = h;\s*`n\s*if \(typeof _coreMilestonePulse === 'function'\) _coreMilestonePulse\(\);")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "function _coreMilestonePulse\(\) \{\s*`n\s*_coreOneShot\('core-milestone', 1000\);")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-milestone \.c-heart\s*\{'))
) '194.17: _coreMilestonePulse() fires exactly once per crossed hour of session uptime (a strictly-increasing _lastCoreUptimeMilestone guard inside the EXISTING _tickUptimeClock(), never a separate timer)'

# 194.18  #9 tap-and-hold overcharge: a real hold-threshold state machine
#         wired to #chassisCore's pointer events, reusing the #14
#         stat-burst tumble keyframes for the release flourish.
Check (
    ($core194 -match [regex]::Escape("coreBtn.addEventListener('pointerdown', _coreHoldStart);")) -and
    ($core194 -match [regex]::Escape("coreBtn.addEventListener('pointerup', _coreHoldEnd);")) -and
    ($core194 -match [regex]::Escape("coreBtn.addEventListener('pointercancel', _coreHoldEnd);")) -and
    ($core194 -match [regex]::Escape("coreBtn.addEventListener('pointerleave', _coreHoldEnd);")) -and
    ($core194 -match [regex]::Escape('_coreSuppressNextTap = wasCharged;')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($core194, "if \(_coreSuppressNextTap\) \{\s*`n\s*_coreSuppressNextTap = false;\s*`n\s*return;")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, '\.chassis-core-shape\.core-overcharge \.c-ring\.r1\s*\{\s*animation:\s*chassisCoreOrbitBurst1'))
) '194.18: #chassisCore wires pointerdown/up/cancel/leave to _coreHoldStart/_coreHoldEnd, a charged release reuses the #14 stat-burst tumble keyframes (Protocol 22), and _coreSuppressNextTap consumes the trailing click so a charged release never ALSO fires a plain tap-poke'

# 194.19  #9 the charging visual is GATED and reuses the #3 inertia
#         multiplier mechanism.
Check (
    ($core194 -match [regex]::Escape('if (!_coreShouldAnimate()) return; // gate closed — no charge visual, plain tap still works')) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped194, "\.chassis-core-shape\.core-charging\s*\{\s*`n\s*--core-spin-mul-r1:\s*3;\s*`n\s*--core-spin-mul-r3:\s*3;"))
) '194.19: _coreHoldStart() is gated by _coreShouldAnimate() before adding any charging class (a closed gate degrades to a plain no-flourish hold, never a broken half-state), and .core-charging reuses the #3 --core-spin-mul-r1/-r3 inertia mechanism (Protocol 22)'

# 194.20  #10 (center readout) was evaluated and correctly DROPPED -- no
#         half-shipped readout markup/class exists anywhere.
Check (
    (-not ($html194 -match 'c-readout')) -and
    (-not ($css194 -match 'c-readout')) -and
    (-not ($core194 -match 'c-readout')) -and
    (-not ($core194 -match 'coreReadout'))
) '194.20: #10 (a center readout glyph) was correctly dropped rather than half-shipped -- no c-readout/coreReadout markup, CSS, or JS exists anywhere'

# 194.21  zero campaign-state write across every new function this batch
#         added -- brace-counting extractor bounds each function body
#         precisely; excludes ===/!== from the assignment check.
function Get-FnBody194([string]$src, [string]$name) {
    $startTok = "function $name("
    $start = $src.IndexOf($startTok)
    if ($start -lt 0) { return $null }
    $braceStart = $src.IndexOf('{', $start)
    if ($braceStart -lt 0) { return $null }
    $depth = 0
    for ($i = $braceStart; $i -lt $src.Length; $i++) {
        if ($src[$i] -eq '{') { $depth++ }
        elseif ($src[$i] -eq '}') {
            $depth--
            if ($depth -eq 0) { return $src.Substring($braceStart + 1, $i - $braceStart - 1) }
        }
    }
    return $null
}
$writeRe194 = 'saveState\(|robco_v8|state\.\w+\s*=(?!=)'
$clean194 = $true
$foundAll194 = $true
foreach ($name in @('_coreThermalTick','_coreRipple','_coreMilestonePulse','_coreHoldStart','_coreHoldEnd')) {
    $body = Get-FnBody194 $core194 $name
    if ($null -eq $body) { $foundAll194 = $false; continue }
    if ($body -match $writeRe194) { $clean194 = $false }
}
foreach ($name in @('startReactorHum','stopReactorHum','_updateReactorHumLevel')) {
    $body = Get-FnBody194 $audio194 $name
    if ($null -eq $body) { $foundAll194 = $false; continue }
    if ($body -match $writeRe194) { $clean194 = $false }
}
Check (
    $clean194 -and $foundAll194
) '194.21: every new LIVING CORE function this batch added (_coreThermalTick/_coreRipple/_coreMilestonePulse/_coreHoldStart/_coreHoldEnd, plus the reactor-hum audio functions) is free of saveState()/robco_v8/state.<field>= writes -- transient/MetaStore only'

# ===========================================================
# Suite 195 -- LIVING CORE ring visual-parity fix (owner audit): the full
# core and mini core still looked different despite the earlier "sync
# confirmed" claim; root cause was a flat, per-tier-unadjusted mini
# perspective (130px regardless of the mini's own 54/40/33px responsive
# sizes) drifting the perspective-to-size ratio away from the full core's
# constant 200/96 ratio, compounded by a flat mini border-width. Also:
# "wider" was the wrong read of an earlier ask -- the owner meant
# THICKER/volumetric, not bigger in diameter (which was actually too
# large, especially in the mini) -- and the core "?" button sat close
# enough to the shape's corner that the r1 ring crossed through it. (PS
# mirror of JS Suite 195.)
# 8 tests
# ===========================================================
Sep "Suite 195 -- LIVING CORE ring visual-parity fix (owner audit)"
$css195 = Read-Src "css/terminal.css"
$cssStripped195 = [regex]::Replace($css195, '/\*[\s\S]*?\*/', '')

# 195.1  perspective holds the SAME ratio-to-own-size at EVERY mini tier
#        (54px desktop, 40px @480px, 33px @400px) that the full core
#        holds at 96px -- not just "big enough," true parity at every
#        breakpoint, which is what the earlier flat-130px fix missed.
$fullPersp195 = [int]([regex]::Match($cssStripped195, '\.chassis-core-shape\s*\{\s*perspective:\s*(\d+)px').Groups[1].Value)
# Negative lookbehind excludes the "body "-prefixed tier overrides below --
# a plain substring match would otherwise happily match this selector even
# when it's actually preceded by "body ", grabbing the WRONG (tier) value.
$baseMiniPersp195 = [int]([System.Text.RegularExpressions.Regex]::Match($cssStripped195, '(?<!body )\.chassis-core-shape\.chassis-core-mini\s*\{\s*perspective:\s*(\d+)px').Groups[1].Value)
$tier480Match195 = [System.Text.RegularExpressions.Regex]::Match($cssStripped195, "(?s)@media \(max-width:\s*480px\)\s*\{.*?\n\}\n")
$tier480Block195 = ''
if ($tier480Match195.Success) { $tier480Block195 = $tier480Match195.Value }
$tier400Match195 = [System.Text.RegularExpressions.Regex]::Match($cssStripped195, "(?s)@media \(max-width:\s*400px\)\s*\{.*?\n\}\n")
$tier400Block195 = ''
if ($tier400Match195.Success) { $tier400Block195 = $tier400Match195.Value }
# A bare (un-prefixed) perspective declaration inside these media blocks
# would be CASCADE-DEAD: an unconditional, equal-specificity rule for this
# exact property sits further down the file and -- media queries add no
# specificity of their own -- always wins regardless of viewport, since it
# comes LAST in source order. The fix requires a "body " specificity bump
# (0,2,0 -> 0,2,1); these regexes require it explicitly.
$tier480Persp195 = [int]([regex]::Match($tier480Block195, 'body \.chassis-core-shape\.chassis-core-mini\s*\{[^\}]*perspective:\s*(\d+)px').Groups[1].Value)
$tier400Persp195 = [int]([regex]::Match($tier400Block195, 'body \.chassis-core-shape\.chassis-core-mini\s*\{[^\}]*perspective:\s*(\d+)px').Groups[1].Value)
$fullRatio195 = [double]$fullPersp195 / 96
function RatioClose195([int]$persp, [int]$size) {
    return [Math]::Abs(([double]$persp / $size) - $fullRatio195) -lt 0.15
}
$bareTier480Persp195 = [System.Text.RegularExpressions.Regex]::IsMatch($tier480Block195, '(?<!body )\.chassis-core-shape\.chassis-core-mini\s*\{[^\}]*perspective:')
$bareTier400Persp195 = [System.Text.RegularExpressions.Regex]::IsMatch($tier400Block195, '(?<!body )\.chassis-core-shape\.chassis-core-mini\s*\{[^\}]*perspective:')
Check (
    ($fullPersp195 -eq 200) -and
    (RatioClose195 $baseMiniPersp195 54) -and
    (RatioClose195 $tier480Persp195 40) -and
    (RatioClose195 $tier400Persp195 33) -and
    (-not $bareTier480Persp195) -and (-not $bareTier400Persp195)
) "195.1: perspective holds the full core's own ~$([Math]::Round($fullRatio195,2))x ratio at EVERY mini tier -- 54px (${baseMiniPersp195}px), 40px @480px (${tier480Persp195}px), and 33px @400px (${tier400Persp195}px) -- not a flat value that drifts the ratio narrower as the mini shrinks, and each tier override uses the required body specificity bump (never a bare, cascade-dead duplicate) so it actually wins against the later unconditional base rule"

# 195.2  the diagonal ring's border-width is likewise proportionally
#        matched (not just "bolder") at every tier -- mini deliberately
#        thinner in absolute px than the full core, holding roughly the
#        SAME border-to-diameter ratio (~15-17%) at every size.
$fullBorderW195 = [int]([regex]::Match($cssStripped195, '\.chassis-core-shape::before\s*\{[^\}]*border:\s*(\d+)px').Groups[1].Value)
$fullInset195 = [int]([regex]::Match($cssStripped195, '\.chassis-core-shape::before\s*\{[^\}]*inset:\s*(\d+)%').Groups[1].Value)
$miniBeforeMatches195 = [regex]::Matches($cssStripped195, '\.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*\}')
$baseMiniBeforeRule195 = ''
if ($miniBeforeMatches195.Count -gt 0) { $baseMiniBeforeRule195 = $miniBeforeMatches195[$miniBeforeMatches195.Count - 1].Value }
$baseMiniBorderW195 = [int]([regex]::Match($baseMiniBeforeRule195, 'border-width:\s*(\d+)px').Groups[1].Value)
# Same cascade-dead trap as the perspective tiers above -- the "body "
# specificity bump is required here too.
$tier480BorderW195 = [int]([regex]::Match($tier480Block195, 'body \.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*border-width:\s*(\d+)px').Groups[1].Value)
$tier400BorderW195 = [int]([regex]::Match($tier400Block195, 'body \.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*border-width:\s*(\d+)px').Groups[1].Value)
$fullDiam195 = 96 * (1 - $fullInset195 / 50)
$fullBorderRatio195 = $fullBorderW195 / $fullDiam195
function RatioNear195([int]$border, [int]$size) {
    $diam = $size * (1 - $fullInset195 / 50)
    return [Math]::Abs(($border / $diam) - $fullBorderRatio195) -lt 0.06
}
$bareTier480Border195 = [System.Text.RegularExpressions.Regex]::IsMatch($tier480Block195, '(?<!body )\.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*border-width:')
$bareTier400Border195 = [System.Text.RegularExpressions.Regex]::IsMatch($tier400Block195, '(?<!body )\.chassis-core-shape\.chassis-core-mini::before\s*\{[^\}]*border-width:')
Check (
    ($fullBorderW195 -ge 7) -and
    ($baseMiniBorderW195 -lt $fullBorderW195) -and
    (RatioNear195 $baseMiniBorderW195 54) -and
    (RatioNear195 $tier480BorderW195 40) -and
    (RatioNear195 $tier400BorderW195 33) -and
    (-not $bareTier480Border195) -and (-not $bareTier400Border195)
) "195.2: the diagonal ring's border-width holds roughly the SAME border-to-diameter ratio (~$([Math]::Round($fullBorderRatio195*100,0))%) at every size -- full ${fullBorderW195}px, mini 54px=${baseMiniBorderW195}px, 40px=${tier480BorderW195}px, 33px=${tier400BorderW195}px -- deliberately thinner in absolute px on the mini, never just bolder, and each tier override uses the required body specificity bump (never a bare, cascade-dead duplicate)"

# 195.3  the ring's diameter genuinely shrank and now nests strictly
#        between r1 (inset 0%, 100% diameter) and r3 (inset 28%, 44%
#        diameter) -- smaller than before's near-full-shape ellipse.
$r3Inset195 = [int]([regex]::Match($cssStripped195, '\.chassis-core-shape \.c-ring\.r3\s*\{\s*inset:\s*(\d+)%').Groups[1].Value)
Check (
    ($fullInset195 -gt 0) -and ($fullInset195 -lt $r3Inset195)
) "195.3: the diagonal ring's inset (${fullInset195}%) sits strictly between r1's (0%, full diameter) and r3's (${r3Inset195}%, its own smaller diameter) -- a genuinely reduced ring, not the earlier near-full-shape ellipse"

# 195.4  the ring is shaded with a volumetric box-shadow trio (inset dark
#        "underside" + inset light "lip" + outer glow "reflected bloom")
#        so a THICK border reads as a lit, rounded 3D band rather than a
#        flat wide outline -- the owner's actual thicker/genuinely-3D ask,
#        achieved via box-shadow (never border-image, which fights
#        border-radius on a circle across browsers).
$beforeRule195 = [regex]::Match($cssStripped195, '\.chassis-core-shape::before\s*\{[^\}]*\}').Value
$insetCount195 = ([regex]::Matches($beforeRule195, 'inset 0 0')).Count
Check (
    ($beforeRule195 -match 'box-shadow:') -and
    ($insetCount195 -ge 2) -and
    ($beforeRule195 -match 'rgba\(var\(--robco-green-rgb\)') -and
    (-not ($beforeRule195 -match 'border-image'))
) '195.4: the diagonal ring is shaded with a box-shadow trio (two inset shadows + an outer glow) simulating a lit, rounded 3D band -- never border-image, which does not reliably compose with border-radius on a circular element across browsers'

# 195.5  the core "?" help button was nudged further up and right so the
#        r1 ring (inset:0, a circle of radius 48px centered on the 96x96
#        shape) no longer visibly crosses through it -- an owner-reported
#        live-render bug. This computes the ACTUAL geometry (not just a
#        "bigger than before" range) -- a live-measured first attempt
#        (-11px/-10px) still put the button's nearest corner at ~37.5px
#        from the shape's center, well INSIDE the 48px ring radius, so the
#        ring still crossed it despite reading as "moved further." The
#        button's bottom-left corner (nearest the circle) sits at
#        (64+right, 32-top) relative to the shape's own (0,0)-(96,96) box
#        (32 = the .icon-btn-round size); its distance from the center
#        (48,48) must clear the ring's ~48px radius with margin for the
#        ring's own ~2px stroke.
$helpBtnRule195 = [regex]::Match($cssStripped195, '\.core-help-btn\s*\{[^\}]*\}').Value
$helpTop195 = [int]([regex]::Match($helpBtnRule195, 'top:\s*-(\d+)px').Groups[1].Value)
$helpRight195 = [int]([regex]::Match($helpBtnRule195, 'right:\s*-(\d+)px').Groups[1].Value)
$cornerX195 = 64 + $helpRight195
$cornerY195 = 32 - $helpTop195
$cornerDist195 = [Math]::Sqrt([Math]::Pow($cornerX195 - 48, 2) + [Math]::Pow($cornerY195 - 48, 2))
Check (
    ($helpTop195 -gt 6) -and ($helpRight195 -gt 6) -and ($cornerDist195 -ge 49)
) "195.5: .core-help-btn moved from -6px/-6px to -${helpTop195}px top / -${helpRight195}px right -- its nearest corner to the shape's center is now $([Math]::Round($cornerDist195,1))px away, clearing the r1 ring's own 48px-radius edge (a first attempt at -11px/-10px only reached ~37.5px, still inside the ring -- this assertion catches that class of under-correction)"

# 195.6  no ID-scoped override of the ring's perspective/border-width/
#        inset exists anywhere for #chassisCore or #chassisCoreMini --
#        every value affecting the ring's visual parity still comes from
#        the ONE shared .chassis-core-shape/.chassis-core-mini class
#        selectors, never a per-id divergence that could desync them.
Check (
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($cssStripped195, '#chassisCore\s*\{[^\}]*(?:perspective|border-width|inset)')) -and
    (-not [System.Text.RegularExpressions.Regex]::IsMatch($cssStripped195, '#chassisCoreMini\s*\{[^\}]*(?:perspective|border-width|inset)'))
) '195.6: no #chassisCore/#chassisCoreMini ID-scoped rule overrides perspective/border-width/inset anywhere -- every ring-parity value still comes from the shared .chassis-core-shape/.chassis-core-mini class selectors (Protocol 22, one source)'

# 195.7  the gate-stacking mechanism (.core-still) still pauses the
#        perpendicular ring's continuous loop -- unaffected by this
#        visual-only pass.
Check (
    $cssStripped195 -match '\.core-still::before'
) '195.7: .core-still::before still pauses the diagonal ring -- the gate-stacking mechanism (reduced-motion/low-immersion/hidden-tab/standby) is untouched by this visual-only fix'

# 195.8  Protocol 17: the help button's own tap target (.icon-btn-round,
#        32px) is unaffected by the position nudge -- only top/right
#        moved, width/height/min-width/min-height are untouched.
$iconBtnRule195 = [System.Text.RegularExpressions.Regex]::Match($cssStripped195, "(?s)\.composer-icon-btn,\s*\n\.composer-send-btn,\s*\n\.icon-btn-round\s*\{[^\}]*\}").Value
Check (
    ($iconBtnRule195 -match 'width:\s*32px') -and ($iconBtnRule195 -match 'min-width:\s*32px')
) '195.8: .icon-btn-round keeps its 32px (>=28px Protocol 17) tap target -- the help button repositioning only changed top/right, never its size'

# ===========================================================
# Suite 196 -- FEEDBACK ANIMATION WAVE 1: the STATUS ANNUNCIATOR echo
# mechanism, 4 new additive RobcoEvents emits (rad.tier/limb.state/
# quest.status/location.visited + the collectible.acquired AI-path emit),
# and the 8 Tier-S flagship home-panel animations
# (planning/FEEDBACK_ANIMATION_BUILD_PLAN.md -- WAVE 1). Extended with two
# owner-reported bug fixes: the CASE-CLOSED/FAILED stamp overlapping the
# CYCLE button (196.28), and the CRITICAL USE-dims-the-screen lockup
# (196.29 -- a pre-existing transmitMessage() gap, not a Wave 1 regression).
# Further extended with 3 DATABANK CARTOGRAPHY TABLE fixes: the global CRT
# refresh-bar sweep crossing over the map's legend/hint text (196.30), the
# map scrolling away when backing out of a zoomed node (196.31), and the
# survey-ping route line drawing itself already-complete instead of being
# watchable (196.32/196.33).
# 50 tests
# ===========================================================
Sep "Suite 196 -- FEEDBACK ANIMATION WAVE 1: annunciator + new emits + 8 flagships"
$stateSrc196 = Read-Src "js/state.js"
$coreSrc196 = Read-Src "js/ui-core.js"
$renderSrc196 = Read-Src "js/ui-render.js"
$apiSrc196 = Read-Src "js/api.js"
$htmlSrc196 = Read-Src "index.html"
$css196 = Read-Src "css/terminal.css"
$cssStripped196 = [regex]::Replace($css196, '/\*[\s\S]*?\*/', '')

# 196.1  rad.tier emitted once at the existing radThreshold crossing
#        detector in updateMath() -- the hp.critical precedent, reusing
#        _bioScanCompute's own NONE/MINOR/ADVANCED/SEVERE breakpoints.
$updateMathBody196 = Get-FunctionBody $coreSrc196 'updateMath'
Check (
    ($updateMathBody196 -match "RobcoEvents\.emit\(\s*['`"]rad\.tier['`"]") -and
    ($updateMathBody196 -match '_lastRadThreshold\s*=\s*radThreshold')
) '196.1: updateMath() emits rad.tier exactly at the existing _lastRadThreshold crossing detector'

# 196.2  _radTierName() maps the threshold ladder onto _bioScanCompute's own
#        NONE/MINOR/ADVANCED/SEVERE tier names -- no new breakpoint table.
Check (
    ($coreSrc196 -match 'function _radTierName\(threshold\)') -and
    ($coreSrc196 -match "'SEVERE'") -and ($coreSrc196 -match "'ADVANCED'") -and
    ($coreSrc196 -match "'MINOR'") -and ($coreSrc196 -match "'NONE'")
) '196.2: _radTierName() reuses the NONE/MINOR/ADVANCED/SEVERE tier vocabulary (no second breakpoint table)'

# 196.3  limb.state emitted from the native toggleLimb() setter.
$toggleLimbBody196 = Get-FunctionBody $coreSrc196 'toggleLimb'
Check (
    $toggleLimbBody196 -match "RobcoEvents\.emit\(\s*['`"]limb\.state['`"]"
) '196.3: toggleLimb() emits limb.state on every native limb toggle'

# 196.4  limb.state ALSO emitted from the AI limb-set path in
#        autoImportState() (api.js) -- fired only on a genuine change.
Check (
    ($apiSrc196 -match "const wasOk = state\[limb\] === 'OK';") -and
    ($apiSrc196 -match "RobcoEvents\.emit\(\s*['`"]limb\.state['`"]") -and
    ($apiSrc196 -match 'if \(wasOk !== nowOk\)')
) '196.4: the AI limb-set path in autoImportState() also emits limb.state, gated on a genuine OK<->CRIPPLED change'

# 196.5  quest.status emitted from the native cycleQuestStatus() -- the ONE
#        native quest-status write path (Suite 189) -- AND from the AI
#        quest-status-diff in autoImportState() (Protocol 14 AI-contract:
#        both paths drive the SAME event, never a fork).
$cycleBody196 = Get-FunctionBody $renderSrc196 'cycleQuestStatus'
Check (
    $cycleBody196 -match "RobcoEvents\.emit\(\s*['`"]quest\.status['`"]"
) '196.5: cycleQuestStatus() emits quest.status on a genuine complete/failed transition'
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch(
        $apiSrc196,
        "if \(prev && prev\.status !== curr\.status\) \{[\s\S]{0,1200}RobcoEvents\.emit\(\s*['`"]quest\.status['`"]"
    )
) '196.6: the AI quest-status-diff in autoImportState() also emits quest.status (same event as the native cycle key)'

# 196.7  location.visited emitted from the SINGLE choke point
#        recordLocationVisit() (state.js) -- covers manual mark-visited,
#        arrival, and the AI autoImport path in one emit (Protocol 22).
$recordBody196 = Get-FunctionBody $stateSrc196 'recordLocationVisit'
Check (
    $recordBody196 -match "RobcoEvents\.emit\(\s*['`"]location\.visited['`"]"
) '196.7: recordLocationVisit() emits location.visited -- the single choke point for every discovery path'

# 196.8  collectible.acquired ALSO emitted on the AI collectible-add path
#        (previously only the native toggleCollectible() emitted it) --
#        fired only for genuinely NEW names (never an AI resend replay).
Check (
    ($apiSrc196 -match '_collectBefore\.has\(name\.toLowerCase\(\)\)') -and
    ($apiSrc196 -match "RobcoEvents\.emit\(\s*['`"]collectible\.acquired['`"]")
) '196.8: the AI collectible-add path in autoImportState() emits collectible.acquired for genuinely new items only'

# 196.9  the casing-top readout is a real <button> (Protocol UI-5), with
#        role=status + aria-live=polite (doubles as an SR notification) and
#        a static aria-label (so an empty button always has an accessible
#        name -- the a11y button-name rule).
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch(
        $htmlSrc196,
        '(?s)<button[\s\S]{0,300}id="statusAnnunciator"[\s\S]{0,200}role="status"[\s\S]{0,200}aria-live="polite"[\s\S]{0,300}aria-label="[^"]+"'
    ) -and ($htmlSrc196 -match 'onclick="_echoJump\(\)"')
) '196.9: #statusAnnunciator is a real <button> with role=status, aria-live=polite, a static aria-label, and tap-to-jump wired to _echoJump()'

# 196.10 the suppression rule (the viewability core): _echoPush() fires IFF
#        the event's home subsystem != the active one -- never both.
$echoPushBody196 = Get-FunctionBody $coreSrc196 '_echoPush'
Check (
    $echoPushBody196 -match '_echoActiveSubsystem\(\) === homeSubsystem\) return;'
) "196.10: _echoPush() suppresses the echo when the active subsystem already equals the event's home (no redundant echo)"

# 196.11 identical-consecutive collapse (xN) -- never floods with repeats.
Check (
    ($echoPushBody196 -match '_echoCurrent\.count\+\+') -and ($echoPushBody196 -match 'tail\.count\+\+')
) '196.11: _echoPush() collapses an identical consecutive event into a xN count bump instead of a new entry'
Check (
    $coreSrc196 -match "count > 1 \? ' ×' \+ c\.count"
) '196.11b: _echoRenderCurrent() actually renders the xN suffix when count > 1'

# 196.12 FIFO queue, cap 6, drop-oldest -- never floods.
Check (
