$wireBody196 = Get-FunctionBody $coreSrc196 '_wireFeedbackEchoSubscribers'
foreach ($evt196 in @('hp.critical', 'rad.tier', 'limb.state', 'level.up', 'faction.threshold', 'quest.status', 'location.visited', 'collectible.acquired')) {
