$mapBody196 = Get-FunctionBody $renderSrc196 'renderWorldMap'
$sectorSheetIdx196 = $mapBody196.IndexOf('if (_mapActiveZone)')
$pingConsumeIdx196 = $mapBody196.IndexOf('const pingZone = _pendingSurveyPing')
