) '196.28: .dir-stamp is a normal-flow flex child pinned above the row (order:-1, full flex-basis) -- never position:absolute, so it can never land on .dir-keys again'

# 196.29  BEHAVIORAL (shells out to node, temp-file transport -- Protocol 42)
#         owner-reported CRITICAL bug: clicking USE dimmed the whole screen
#         and locked out all interaction. Root-caused to transmitMessage()'s
#         own pre-existing uiPanel dim-in, applied well before the network
#         try/finally that undoes it -- a throw anywhere in the unguarded
#         setup zone (generateSyncPayload(), apiContents building) left the
#         dim stuck forever. Pre-existing (predates Wave 1) -- fixed by
#         wrapping that setup zone in its own try/catch reusing the SAME
#         _resetTransmitUI() the network path's finally already calls.
try {
    $nodeCheck196 = Get-Command node -ErrorAction SilentlyContinue
    if ($nodeCheck196) {
        $apiPathNode196 = (Join-Path $Root "js/api.js").Replace('\', '/')
        $testScript196 = @"
const fs = require('fs');
const vm = require('vm');
try {
  const src = fs.readFileSync('$apiPathNode196', 'utf8');
  function extractFunctionBody(source, fnName) {
    let idx = source.indexOf('function ' + fnName);
    let i = source.indexOf('{', idx);
    let depth = 0;
    const start = i;
    while (i < source.length) {
      if (source[i] === '{') depth++;
      else if (source[i] === '}' && --depth === 0) return source.slice(start, i + 1);
      i++;
    }
  }
  function declareFn(src, name) {
    const nameIdx = src.indexOf('function ' + name);
    const parenIdx = src.indexOf('(', nameIdx);
    const braceIdx = src.indexOf('{', parenIdx);
    const params = src.slice(parenIdx, braceIdx);
    const isAsync = src.slice(Math.max(0, nameIdx - 6), nameIdx) === 'async ';
    return (isAsync ? 'async ' : '') + 'function ' + name + params + extractFunctionBody(src, name);
  }
  const src196 = declareFn(src, '_resetTransmitUI') + '\n' + declareFn(src, 'transmitMessage');

  const mockEl = () => ({
    value: '', textContent: '', disabled: false, onclick: null, style: {},
    classList: {
      _set: new Set(),
      add(c) { this._set.add(c); },
      remove(c) { this._set.delete(c); },
      contains(c) { return this._set.has(c); },
    },
    setAttribute() {}, getAttribute() { return null; }, focus() {},
  });
  const els = {
    chatInput: mockEl(), transmitBtn: mockEl(), uiPanel: mockEl(),
    imagePreviewContainer: mockEl(), imagePreview: mockEl(), imageInput: mockEl(),
  };
  els.chatInput.value = '> [USE] Test Item';

  let chatMessages = [];
  const sandbox = {
    document: {
      getElementById: id => els[id] || mockEl(),
      body: { classList: {
        _set: new Set(),
        add(c) { this._set.add(c); },
        remove(c) { this._set.delete(c); },
        contains(c) { return this._set.has(c); },
      } },
    },
    window: {},
    chatHistory: [],
    attachedImageData: null,
    attachedImageMimeType: null,
    appendToChat: (text, sender) => chatMessages.push({ text, sender }),
    _routeNativeCommand: () => false,
    _isPrecisePointer: () => false,
    MetaStore: { has: () => false },
    _commGet: () => 'FAKE-TEST-KEY',
    generateSyncPayload: () => { throw new Error('SIMULATED setup-phase throw'); },
    submitCommandInput: () => {},
    console,
  };
  vm.createContext(sandbox);
  vm.runInContext(src196, sandbox);
  (async () => {
    let threw = null;
    try { await vm.runInContext('transmitMessage()', sandbox); } catch (e) { threw = e; }
    const ok = !threw &&
      els.uiPanel.style.opacity === '1' &&
      els.uiPanel.style.pointerEvents === 'auto' &&
      !sandbox.document.body.classList.contains('thermal-load') &&
      chatMessages.some(m => /TRANSMIT SETUP FAILURE/.test(m.text));
    console.log('RESULT:' + (ok ? '1' : '0'));
  })();
} catch (e) { console.log('RESULT:0'); }
"@
        $tmpScript196 = [System.IO.Path]::GetTempFileName() + '.js'
        [System.IO.File]::WriteAllText($tmpScript196, $testScript196, [System.Text.Encoding]::UTF8)
        try {
            $out196 = (node $tmpScript196 2>&1 | Out-String)
        } finally {
            Remove-Item -Path $tmpScript196 -Force -ErrorAction SilentlyContinue
        }
        $rm196 = [regex]::Match($out196, 'RESULT:([01])')
        if ($rm196.Success) {
            Check ($rm196.Groups[1].Value -eq '1') "196.29: transmitMessage() behavioral -- a setup-phase throw (e.g. generateSyncPayload() failing) no longer leaves #uiPanel dimmed/un-clickable; _resetTransmitUI() restores opacity/pointer-events/thermal-load and a clear error is posted to chat"
        } else {
            $err196 = if ([string]::IsNullOrWhiteSpace($out196)) { "No output from node" } else { $out196.Trim() }
            Fail "196.29: transmitMessage() behavioral USE-dim-lockup proof  (runtime error: $err196)"
        }
    } else {
        Fail "196.29: transmitMessage() behavioral USE-dim-lockup proof  (node not available in PATH)"
    }
} catch {
    Fail "196.29: transmitMessage() behavioral USE-dim-lockup proof  (harness error: $_)"
}

# 196.30  Owner report fix: the app-wide CRT refresh-bar sweep (.crt-overlay,
#         z-index:9999, spans the full scrollable page -- not just one
#         screen) was crossing over the CARTOGRAPHY TABLE's own legend/hint
#         text and the map's node labels. .table-frame/.survey-legend/
#         .kbd-hint now carry a comfortably-higher z-index (10000) so this
#         board's own content always paints above it, without touching the
#         global overlay itself (Protocol 22 -- no forked CRT effect).
$tableFrameRule196 = [System.Text.RegularExpressions.Regex]::Match($cssStripped196, '\.table-frame\s*\{[^\}]*\}').Value
$kbdHintRule196 = [System.Text.RegularExpressions.Regex]::Match($cssStripped196, '\.kbd-hint\s*\{[^\}]*\}').Value
$surveyLegendRule196 = [System.Text.RegularExpressions.Regex]::Match($cssStripped196, '\.survey-legend\s*\{[^\}]*\}').Value
foreach ($pair196 in @(
    @('table-frame', $tableFrameRule196),
    @('kbd-hint', $kbdHintRule196),
    @('survey-legend', $surveyLegendRule196)
)) {
    $name196 = $pair196[0]
    $rule196 = $pair196[1]
    Check (
        ($rule196 -match 'position:\s*relative') -and ($rule196 -match 'z-index:\s*10000')
    ) "196.30: .$name196 carries position:relative + z-index:10000 (renders above the global .crt-overlay sweep at z-index:9999)"
}

# 196.31  Owner report fix: zoomMapToZone()/resetMapZoom()/markLocationVisited()
#         each replace #worldMapDisplay's entire innerHTML -- destroying
#         whatever DOM node currently holds focus, which is a well-known
#         trigger for browsers to auto-scroll the page to an unrelated
#         position. All three now route through the SAME
#         _rerenderMapPreservingScroll() helper (Protocol 22) instead of
#         calling renderWorldMap() directly.
$resetFnBody196 = Get-FunctionBody $renderSrc196 '_rerenderMapPreservingScroll'
Check (
    ($resetFnBody196 -match "_scrollElFor\(\s*['`"]databank['`"]\s*\)") -and
    ($resetFnBody196 -match 'el\.scrollTop = scrollVal') -and
    ($resetFnBody196 -match 'window\.scrollTo\(0, scrollVal\)') -and
    ($resetFnBody196 -match 'renderWorldMap\(\)')
) '196.31: _rerenderMapPreservingScroll() captures the scroll offset via the shared _scrollElFor() lookup, re-renders, then restores it'
$zoomBody196 = Get-FunctionBody $renderSrc196 'zoomMapToZone'
$resetZoomBody196 = Get-FunctionBody $renderSrc196 'resetMapZoom'
$markVisitedBody196 = Get-FunctionBody $renderSrc196 'markLocationVisited'
# resetMapZoom() gained a Suite 198 refinement (Protocol 27 re-fix): it
# passes the pre-zoom anchor (_mapPreZoomAnchor) back into
# _rerenderMapPreservingScroll() instead of calling it bare -- still the
# SAME shared helper, never a direct renderWorldMap() call, so it's checked
# with its own (argument-aware) pattern below.
foreach ($pair196b in @(
    @('zoomMapToZone', $zoomBody196),
    @('markLocationVisited', $markVisitedBody196)
)) {
    $name196b = $pair196b[0]
    $body196b = $pair196b[1]
    Check (
        ($body196b -match '_rerenderMapPreservingScroll\(\);') -and (-not ($body196b -match 'renderWorldMap\(\);'))
    ) "196.31: $name196b() re-renders via _rerenderMapPreservingScroll() -- not a direct renderWorldMap() call"
}
Check (
    ($resetZoomBody196 -match [regex]::Escape('_rerenderMapPreservingScroll(_mapPreZoomAnchor);')) -and
    (-not ($resetZoomBody196 -match 'renderWorldMap\(\);'))
) '196.31: resetMapZoom() re-renders via _rerenderMapPreservingScroll(_mapPreZoomAnchor) -- not a direct renderWorldMap() call'

# 196.32  Owner report fix: the route segment leading to a freshly-surveyed
#         node used to render already fully drawn by the time the
#         (correctly-deferred) ping ring showed -- the user never watched
#         the line draw itself. pingZone is now computed BEFORE routeSegs
#         (was after) so the new segment can be identified and given a
#         one-shot stroke-dashoffset "draw itself" reveal, deferred by the
#         SAME pingZone/consumption gate as the ping ring.
$mapBody196b = Get-FunctionBody $renderSrc196 'renderWorldMap'
$pingZoneIdx196 = $mapBody196b.IndexOf('const pingZone = _pendingSurveyPing')
$routeSegsIdx196 = $mapBody196b.IndexOf('const routeSegs = [];')
$newRouteSegIdx196 = $mapBody196b.IndexOf('let newRouteSegIdx = -1;')
Check (
    ($pingZoneIdx196 -ge 0) -and ($routeSegsIdx196 -ge 0) -and
    ($pingZoneIdx196 -lt $routeSegsIdx196) -and ($newRouteSegIdx196 -gt $routeSegsIdx196)
) '196.32: pingZone is computed BEFORE routeSegs (moved earlier) so the newly-added segment can be identified for the deferred draw-in'
Check (
    ($mapBody196b -match 'if \(b === pingZone\) newRouteSegIdx = i;') -and
    ($mapBody196b -match 'route route-draw-in') -and
    ($mapBody196b -match '--route-len:\$\{len\}')
) '196.32b: only the segment arriving at pingZone gets the route-draw-in class + a computed --route-len'
Check (
    ($cssStripped196 -match '@keyframes route-draw-in') -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped196, "100% \{\s*stroke-dasharray:\s*5 4;\s*stroke-dashoffset:\s*0;\s*\}")) -and
    ([System.Text.RegularExpressions.Regex]::IsMatch($cssStripped196, "\.route\.route-draw-in \{\s*animation:\s*route-draw-in"))
) '196.32c: the route-draw-in keyframe is a plain @keyframes animation that settles into the SAME static "5 4" dasharray every other route line uses'

# 196.33  zero campaign-state write -- the map scroll-preserve fix is purely
#         transient (scrollTop/scrollY only), never state.*/saveState().
Check (
    (-not ($resetFnBody196 -match 'state\.\w+\s*=')) -and (-not ($resetFnBody196 -match 'saveState\(\)'))
) '196.33: _rerenderMapPreservingScroll() never assigns state.* or calls saveState() -- purely transient scroll bookkeeping'

# ===========================================================
# Suite 197 -- FEEDBACK ANIMATION WAVE 2: the 9 Tier-A animations + the
# one new additive item.added emit (planning/FEEDBACK_ANIMATION_BUILD_
# PLAN.md -- WAVE 2). item.added fires from three call sites (addItem()'s
# manual path, doLoot()'s loot-apply path, and the AI inventory-merge diff
# in autoImportState(), Protocol 14 AI-contract precedent). The 9 home-
# panel reactions live in _wireCoreEventBusSubscribers() (ui-core.js);
# the [home + echo] items (XP/SERVO/CRT-FLINCH/CAPS/MANIFEST-PUNCH) also
# get an annunciator echo push in _wireFeedbackEchoSubscribers() -- INK
# STAMP/WELD SPARKS/CLOCK SPIN-DOZE/HOLOTAPE COMMIT are home-only by
# owner decision and deliberately carry no echo.
# 26 tests
# ===========================================================
Sep "Suite 197 -- FEEDBACK ANIMATION WAVE 2: item.added + 9 Tier-A animations"
$coreSrc197 = Read-Src "js/ui-core.js"
$renderSrc197 = Read-Src "js/ui-render.js"
$apiSrc197 = Read-Src "js/api.js"
$css197 = Read-Src "css/terminal.css"
$cssStripped197 = [regex]::Replace($css197, '/\*[\s\S]*?\*/', '')

# 197.1  addItem() emits item.added on the manual-add path.
$addItemBody197 = Get-FunctionBody $renderSrc197 'addItem'
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch(
        $addItemBody197,
        "RobcoEvents\.emit\(\s*['`"]item\.added['`"][\s\S]{0,200}source:\s*'manual'"
    )
) "197.1: addItem() emits item.added with source:'manual' on every manual add"

# 197.2  doLoot() emits item.added on the LOOT-apply path.
$doLootBody197 = Get-FunctionBody $renderSrc197 'doLoot'
Check (
    [System.Text.RegularExpressions.Regex]::IsMatch(
        $doLootBody197,
        "RobcoEvents\.emit\(\s*['`"]item\.added['`"][\s\S]{0,200}source:\s*'loot'"
    )
) "197.2: doLoot() emits item.added with source:'loot' after _lootAdd() applies"

# 197.3  the AI inventory-merge in autoImportState() emits item.added ONLY
#        for genuinely new item names (a Set captured BEFORE the merge),
#        the collectible.acquired/quest.status AI-path precedent.
Check (
    ($apiSrc197 -match '_invNamesBefore = new Set') -and
    ($apiSrc197 -match 'if \(!_invNamesBefore\.has\(String\(it\.name\)\.toLowerCase\(\)\)\)') -and
    ([System.Text.RegularExpressions.Regex]::IsMatch(
        $apiSrc197,
        "RobcoEvents\.emit\(\s*['`"]item\.added['`"][\s\S]{0,80}source:\s*'ai'"
    ))
) "197.3: the AI inventory-merge emits item.added with source:'ai' only for names absent from the pre-merge Set"

# -- the 9 home-panel animations (_wireCoreEventBusSubscribers) --
$wireCoreBody197 = Get-FunctionBody $coreSrc197 '_wireCoreEventBusSubscribers'

# 197.4  #10 XP CHUNK FILL -- fires only on a genuine XP increase.
Check (
    ([System.Text.RegularExpressions.Regex]::IsMatch($wireCoreBody197, "p\.key === 'xp' &&[\s\S]{0,120}p\.newVal > p\.oldVal")) -and
    ($wireCoreBody197 -match 'xp-chunk-fill') -and
    ($wireCoreBody197 -match 'xp-ticker')
) '197.4: #10 XP CHUNK FILL fires only when newVal > oldVal, brightening #xp_bar_fill + a floating +N XP ticker'

# 197.5  #11 SERVO RECALIBRATE -- targets the changed SPECIAL channel's
#        ladder + letter via the existing data-fd-ladder/.fader markup,
#        and reuses the existing playChipClick() SFX (Protocol 22).
Check (
