  };
  vm.createContext(sandbox);
  vm.runInContext(declared, sandbox);
  vm.runInContext("travelToLocation('Primm');", sandbox);
  results.push(
    calls.onLocationChange.length === 1 && calls.onLocationChange[0] === 'Primm' &&
