const uiCoreSrc = rd('js/ui-core.js');
function extractBody(src, name) {
  var idx = src.indexOf('function ' + name);
  if (idx === -1) throw new Error('missing ' + name);
  var i = src.indexOf('{', idx);
  var depth = 0, start = i;
  while (i < src.length) {
